INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605148A$$, $$Tactical Intel Targeting Access Node (TITAN) EMD$$, $$rdte_army_ba5$$, $$peo_c3t$$, 2026, 44273000, 128784000, 149112000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "original_pe": "0605148A", "page_header": "Department of the Army"}$$::jsonb, $$The Tactical Intelligence Targeting Access Node (TITAN) is a key enabler of the Army Modernization Priorities in support of Army Cross Functional Teams. TITAN is a scalable and expeditionary intelligence ground station that supports commanders across the entire Multi-Domain Operations (MDO)/Joint All Domain Operations (JADO) battlefield framework with capabilities tailored to echelon. TITAN leverages Space, High Altitude, Aerial and Terrestrial layer sensors to provide targetable data to fires networks as well as multi-discipline intelligence support to targeting and Situation Awareness/Situation Understanding (SA/SU) in support of mission command. TITAN will support Artificial Intelligence/Machine Learning (AI/ML) tools through Project Linchpin and other government sources and leverage Critical Radio Frequency (RF) technologies as they become available. TITAN is the Army Intelligence, Surveillance, and Reconnaissance (ISR) ground station that consolidates the sensor processing capabilities in the current Distributed Common Ground System-Army (DCGS-A) Operational-Intelligence Ground Station (OGS), Tactical-Intelligence Ground Station (TGS), the Advanced Miniaturized Data Acquisition System Dissemination Vehicle (ADV) and the Remote Ground Terminal (RGT). Additionally, TITAN will access sensor data of Tactical Space Layer assets, National assets, the Multi-Domain Sensing Systems (MDSS) as well as commercial overhead sensors. Consequently, the TITAN ground station conducts deep sensing operations with the abilities to Task, Collect, Process, Exploit, and Disseminate (TCPED) information from Space, High Altitude, Aerial, and Terrestrial Layer sensors in support of Long Range Precision Fires (LRPF) operations. The FY 2026 cost of the Titan Intelligence Targeting Access Node (TITAN) Middle Tier of Acquisition effort is $23.7 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                       Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0605148A / Tactical Intel Targeting Access Node (TITAN) EMD Development & Demonstration (SDD)$$, NULL, 39431000, 39736000, 39750000, NULL, NULL, 147, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 149112000, 44273000, 35769000, 35769000, NULL, 35769000, 40147000, $$TITAN is a scalable and expeditionary intelligence ground station that supports commanders across the entire Multi-Domain Operations (MDO)/Joint All Domain Operations (JADO) battlefield framework with capabilities tailored to echelon. TITAN leverages Space, High Altitude, Aerial and Terrestrial layer sensors to provide targetable data to fires networks as well as multi-discipline intelligence support to targeting and Situation Awareness/Situation Understanding (SA/SU) in support of mission command. TITAN will utilize Artificial Intelligence/Machine Learning (AI/ML) capabilities and leverage advanced Radio Frequency (RF) technologies as they become available. The FY27 RDTE Dollars in the amount of $35.769M supports and integrates high altitude, aerial and terrestrial sensor data feeds. See Classified QUAD for more information.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1203174SF$$, $$Space Innovation, Integration and Rapid Technology Development$$, $$rdte_sf_ba7$$, $$starcom$$, 2026, 82399000, 0, 48900000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Space Innovation, Integration, and Rapid Technology Development (SIIRTD) program element delivers enterprise capabilities and solutions to field combat-ready forces and secure space domain superiority in an evolving threat environment. Enterprise Training Services Development (ETSD) delivers operationally realistic space combat training capabilities via a system-of-systems architecture to generate, assess, and sustain Guardian lethality. Capabilities developed are in accordance with the USSF Operational Test and Training Infrastructure (OTTI) Strategic Requirements Document (SRD) and Space Training and Readiness Command and Space Operations Command requirements and priorities. ETSD capabilities are delivered as multi-mission collaborative training systems and platforms; networks; models; and modeling and simulation tools. Space Analysis and Application Development (SA&AD) develops and modifies modeling and simulation tools that USSF/Space Operations Command uses for operational analysis and assessment. Provides operational assessments using analytic rigor to tackle senior leader questions associated with the joint all-domain fight using Combatant Command OPORDS. Leads assessments on space operations, security cooperation activities, and the COMSPACEFOR component space plans while also performing strategic analysis to develop digital HQ data standards and tools. Analyzes and assesses USSF's current and future SDA systems for data accuracy. Provides analyses and develops tools for USSF tactical units, operations centers, and mission partners to solve short-duration mission-related problems on tactically relevant timescales. SA&AD projects respond to changes - both existing and projected - in space operations, technology, and threats to ensure space operators are provided accurate and relevant data and capabilities. SA&AD operationalizes the state of the art in digital tools, modeling, simulation, and analysis. These efforts increase readiness and lethality at each level of operations. This program element may include necessary civilian pay expenses required to manage, execute, and deliver ETSD and SA&AD training system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                    Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:         PE 1203174SF / Space Innovation, Integration and Rapid Technology Development Operational Systems Development$$, NULL, 10908000, 11112000, 11318000, NULL, NULL, 59, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 47216000, 81046000, 10538000, 10538000, 0, 10538000, 11544000, $$The Space Innovation, Integration, and Rapid Technology Development (SIIRTD) program element delivers enterprise capabilities and solutions to field combat-ready forces and ensure space domain superiority in an evolving threat environment. Enterprise Training Services Development (ETSD) delivers operationally realistic space combat training capabilities via a system-of-systems architecture to generate, assess, and sustain Guardian lethality. Capabilities developed are in accordance with the USSF Operational Test and Training Infrastructure (OTTI) Strategic Requirements Document (SRD) and Space Training and Readiness Command and Space Operations Command requirements and priorities. ETSD capabilities are delivered as multi-mission collaborative training systems and platforms; networks; models; and modeling and simulation tools. Space Analysis and Application Development (SA&AD) develops and modifies modeling and simulation tools that USSF/Space Operations Command uses for operational analysis and assessment. Provides operational assessments using analytic rigor to tackle senior leader questions associated with the joint all-domain fight using Combatant Command OPORDS. Leads assessments on space operations, security cooperation activities, and the COMSPACEFOR component space plans while also performing strategic analysis to develop digital HQ data standards and tools. Analyzes and assesses USSF's current and future SDA systems for data accuracy. Provides analyses and develops tools for USSF tactical units, operations centers, and mission partners to solve short-duration mission-related problems on tactically relevant timescales. SA&AD projects respond to changes - both existing and projected - in space operations, technology, and threats to ensure space operators are provided accurate and relevant data and capabilities. SA&AD operationalizes the state of the art in digital tools, modeling, simulation, and analysis. These efforts increase readiness and lethality at each level of operations. This program falls within the Science and Technology (S&T) and Test & Evaluation (T&E) mission area which provides the S&T initiatives, demonstrations, experiments, and studies towards developing next-generation space capabilities. The T&E mission area provides all efforts required to establish and operate the test infrastructure for USSF capabilities. Space Force investment program interdependencies include: RDT&E Budget Line Items: Defense Research Sciences (0601102SF); Major T&E Investments - Space (1206759SF); Small Business Innovation Research (1205502SF); Space Advanced Tech Dev / Demo (1206616SF); Space Rapid Capabilities Office (1206857SF); Space Science and Technology (1206310SF); Space Systems Prototype Transition (1206427SF); Space Technology (1206601SF); Space Test and Evaluation (1202051SF); Space Test Program (1206864SF); University Research Initiatives (0601103SF); Operational Test & Training Infrastructure (1206617SF) and elements of Procurement Budget Line Item: General Information Tech - Space (GNRLIT) Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:          PE 1203174SF / Space Innovation, Integration and Rapid Technology Development Operational Systems Development Beginning in FY 2027, project 674671, Enterprise Training Services Development, funding has been moved to new PE 1206617SF, Operational Test & Training Infrastructure, project 644441, Operational Test & Training Infrastructure. This program element may include necessary civilian pay expenses required to manage, execute, and deliver ETSD and SA&AD training system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L062$$, $$Tactical/Mobile C4I Systems$$, $$proc_navy_1810_ba2$$, $$peo_aasm$$, 2026, 97262000, 88114000, 90586000, NULL, $${"page": 98, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "62", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 57", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 62581, "p1_line_num": 57, "fy27_total_K": 62581}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 72104, "li_num": 57, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 97262000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 66470000, 64901000, 62581000, 62581000, 0, 62581000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605152N$$, $$Studies & Analysis Supt - Navy$$, $$rdte_navy_ba6$$, $$navy_cno$$, 2026, 3596000, 3078000, 6216000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605152N", "page_header": "Department of the Navy"}$$::jsonb, $$This program provides analytical support to the Secretary of the Navy and the Chief of Naval Operations as a basis for major policy, planning and acquisition program execution decisions. It supports research and development strategy development and planning. It supports studies in the areas of manpower, personnel, training, and aviation. It also develops analytical tools for evaluating effectiveness of U.S. weapons against potential foreign threat ships and submarines. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation.$$, NULL, 3872000, 3795000, 3822000, NULL, NULL, 189, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 5534000, 3596000, 4336000, 4336000, NULL, 4336000, 3891000, $$This program provides analytical support to the Secretary of the Navy and the Chief of Naval Operations as a basis for major policy, planning and acquisition program execution decisions. It supports research and development strategy development and planning. It supports studies in the areas of manpower, personnel, training, and aviation. It also develops analytical tools for evaluating effectiveness of U.S. weapons against potential foreign threat ships and submarines. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605154N$$, $$Center For Naval Analyses$$, $$rdte_navy_ba6$$, $$mc$$, 2026, 31695000, 43834000, 43648000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605154N", "page_header": "Department of the Navy"}$$::jsonb, $$The Department of the Navy's (DON) Studies and Analysis Federally Funded Research and Development Center (DON S&A FFRDC - hereinafter referred to as the FFRDC) provides independent, objective, and expert analyses based on its unique access to sensitive data and hands-on exposure to fleet operations gained through a world-wide field program. The FFRDC's research program is centrally funded by this program element and is primarily concentrated along one Marine Corps category and thirteen Navy categories of study called product areas. These product areas are structured to enhance the FFRDC's focus of research and analysis upon the major present and future needs and issues of the Navy and the Marine Corps. Because of rapid advances in technology, changes in the fleet, the increasing complexity of weapon systems, and reductions in manpower, force structure, budgets, the current security environment, and Department of Defense (DOD) transformation, the Navy and Marine Corps have a greater need for analyses that are sophisticated, relevant, and timely. The FFRDC conducts research and analysis at all security classification levels, to include Sensitive Compartmented Information (SCI) and Special Access Programs (SAP). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, NULL, 32998000, 32055000, 31720000, NULL, NULL, 190, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 42277000, 31695000, 28310000, 28310000, NULL, 28310000, 27236000, $$The Department of the Navy's (DON) Studies and Analysis Federally Funded Research and Development Center (DON S&A FFRDC - hereinafter referred to as the FFRDC) provides independent, objective, and expert analyses based on its unique access to sensitive data and hands-on exposure to fleet operations gained through a world-wide field program. The FFRDC's research program is centrally funded by this program element and is primarily concentrated along one Marine Corps category and thirteen Navy categories of study called product areas. These product areas are structured to enhance the FFRDC's focus of research and analysis upon the major present and future needs and issues of the Navy and the Marine Corps. Because of rapid advances in technology, changes in the fleet, the increasing complexity of weapon systems, and reductions in manpower, force structure, budgets, the current security environment, and Department of War (DOW) transformation, the Navy and Marine Corps have a greater need for analyses that are sophisticated, relevant, and timely. The FFRDC conducts research and analysis at all security classification levels, to include Sensitive Compartmented Information (SCI) and Special Access Programs (SAP). Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605164F$$, $$Air Refueling Capability Modernization$$, $$rdte_af_ba4$$, $$aflcmc_aa$$, 2026, 0, 15201000, 13661000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0605164F"}$$::jsonb, $$Accelerating future tanker capability and recapitalizing the Air Force's aging tanker fleet is a top priority for the Department of the Air Force. In FY 2024, the Department of the Air Force broke from its previous recapitalization approaches (KC-X, KC-Y, KC-Z) in favor of more agile methods, prioritizing and accelerating the right capabilities to deliver fuel to the fight. This new approach continues Tanker Recapitalization (PE 0605164F) efforts between KC-46A (PE 040221F) and the Next Generation Air- refueling System (NGAS) (PE 0605057F). The Department of the Air Force (DAF) will use the Tanker Recapitalization program to replace up to 15 KC-135s legacy tankers per year as they retire. The total number of Tanker Recap aircraft procured will be influenced by the FY 2024 NGAS Analysis of Alternatives and dependent on NGAS's first delivery. The Tanker Recapitalization program will deliver an air-refuelable, commercial derivative, limited development tanker that provides fuel to U.S. and coalition aircraft receivers via a boom or drogue system that can operate in day/night and adverse weather conditions to enable deployment, employment, sustainment, and redeployment of U.S. and coalition forces. The Tanker Recapitalization program will have communication, navigation, and surveillance equipment to support worldwide operations and refueling competences in chemical, biological and hostile threat environments through self-defense/protection (both active and passive) capabilities to include the necessary battlespace awareness to mitigate threats. The dynamics and mission urgency of the post-production (post DD-250) environment require the program to maintain a flexible and responsive posture to support a broad range of mission support needs. Tanker Recapitalization program will identify, design, develop, integrate, verify, certify, produce, install, field, and sustain a comprehensive range of non-recurring and recurring post-production, air vehicle enhancements and field support needs to include but not limited to programmed Mobility Air Force (MAF) requirements, Combatant Commander Joint or Urgent Operational Needs (JUON/UON), non-programmed Federal Aviation Administration (FAA) directives, requirements identified and supported by HHQ Enterprise Capability Collaboration Teams (i.e., High Value Airborne Asset [HVAA], Air Superiority 2030, and Multi-Domain Command and Control [MDC2]), or correction of field deficiencies. Tanker Recapitalization program will develop, field, and sustain warfighter capabilities to meet evolving threats and mission support requirements through Block or discrete modification or modernization programs depending on mission urgency, available funding, and programmatic and technical risks. Post-production requirements Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0605164F / Air Refueling Capability Modernization Component Development & Prototypes (ACD&P) may include but not limited to avionics and structural systems/architecture and subsystem updates, general mission equipment updates and procurement, general sustainment support, studies and analyses, future tanker requirements simulation and training, and correction of field deficiencies. Project 645164, Continued Tanker Recapitalization RDT&E will also support Program Support Costs (PSC) activities to include but not limited to market research, acquisition planning, pre-milestone activities, RFP development, test planning, mission planning capability development, future tanker development, and various studies and analyses. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $5.589 million was expended for civilian pay expenses in this program element, in FY 2025 $9.575 million is forecast for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 0, 0, 0, NULL, NULL, 62, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 13600000, 0, 0, 0, 0, 0, 0, $$Accelerating future tanker capability and recapitalizing the Air Force's aging tanker fleet is a top priority for the Department of the Air Force. In FY 2024, the Department of the Air Force broke from its previous recapitalization approaches (KC-X, KC-Y, KC-Z) in favor of more agile methods, prioritizing and accelerating the right capabilities to deliver fuel to the fight. This new approach continues Tanker Recapitalization (PE 0605164F) efforts between KC-46A (PE 040221F) and the Next Generation Air- refueling System (NGAS) (PE 0605057F). The Department of the Air Force (DAF) will use the Tanker Recapitalization program to replace up to 15 KC-135s legacy tankers per year as they retire. The total number of Tanker Recap aircraft procured will be influenced by the FY 2024 NGAS Analysis of Alternatives and dependent on NGAS's first delivery. The Tanker Recapitalization program will deliver an air-refuelable, commercial derivative, limited development tanker that provides fuel to U.S. and coalition aircraft receivers via a boom or drogue system that can operate in day/night and adverse weather conditions to enable deployment, employment, sustainment, and redeployment of U.S. and coalition forces. The Tanker Recapitalization program will have communication, navigation, and surveillance equipment to support worldwide operations and refueling competences in chemical, biological and hostile threat environments through self defense/protection (both active and passive) capabilities to include the necessary battlespace awareness to mitigate threats. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                 Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0605164F / Air Refueling Capability Modernization Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605170D8Z$$, $$Support to Networks and Information Integration (NII)$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 15597000, 10120000, 8580000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605170D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to deter aggression, defend the homeland, and build enduring advantage. The Networks and Information Integration (NII) program supports Military Global Positioning System (GPS) User Equipment (MGUE) modernization, alternative positioning, navigation, and timing (PNT) policy, and the DoD's PNT Oversight Council. It also supports interagency activities related to space-based PNT and electromagnetic spectrum (EMS) management. In support of the National Defense Strategy, resilient PNT and GPS services provide a battlespace advantage through precision targeting, intelligence, surveillance, and reconnaissance (ISR), efficient logistics, and force tracking. The joint force is modernizing PNT capabilities to use GPS M-code and incorporate alternate PNT information via a modular open systems approach. The integrated planning and management project oversees national-level command and control (C2) capabilities development and interoperability through the National Leadership Command Capabilities Management Office (NMO). The NMO ensures timely situational awareness and decision tools for senior leaders, supporting the DoD CIO's oversight of critical command, control, and communications (C3) assets. Focus areas include national leadership C3 systems, national security/emergency preparedness, DoD support to civil authorities, continuity of government, and cyber mission indications and warnings. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:           PE 0605170D8Z / Support to Networks and Information Integration (NII) RDT&E Management Support$$, NULL, 25850000, 27102000, 27921000, NULL, NULL, 177, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 9366000, 15496000, 26878000, 26878000, NULL, 26878000, 28277000, $$This program supports the Department's initiatives to defend the homeland and deter China. The Networks and Information Integration program supports executing congressionally mandated DoW positioning, navigation, and timing (PNT) governance through the PNT Oversight Council, Military Global Positioning System (GPS) user equipment (MGUE) modernization, developing alternative PNT capabilities, managing PNT policy, and participating in interagency PNT support to U.S. national critical infrastructure through the National Space-based PNT Executive Committee. In support of the interim National Defense Strategy, resilient PNT and GPS services provide a battlespace advantage through precision targeting, intelligence, surveillance, and reconnaissance (ISR), efficient logistics, and force tracking. The joint force is modernizing PNT capabilities to use GPS M-code and incorporate alternate PNT information via a modular open systems approach. Assured PNT services are a critical requirement to successfully prosecute joint military operations and protect the homeland. The integrated planning and management project oversees national-level command and control capabilities development and interoperability through the National Leadership Command Capabilities Management Office (NMO). The NMO ensures timely situational awareness and decision tools for senior leaders, supporting the DoW CIO's oversight of critical command, control, and communications (C3) assets. Focus areas include national leadership C3 systems, national security/emergency preparedness, DoW support to civil authorities, continuity of government, and cyber mission indications and warnings.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605180N$$, $$TACAMO MODERNIZATION$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 1243978000, 200494000, 755316000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0605180N", "page_header": "Department of the Navy"}$$::jsonb, $$The E-6 Take Charge and Move Out (TACAMO) Recapitalization Program (E-130J) provides for air vehicle replacement and mission systems modernization to augment and eventually replace the aging E-6B aircraft for the TACAMO mission. The TACAMO mission provides an airborne capability for survivable, endurable and reliable airborne command, control and communications between the United States (U.S.) National Command Authority (NCA) and the U.S. strategic forces. This mission is critical in the deterrence and management of a nuclear conflict. A dedicated communications platform, TACAMO aircraft features the ability to communicate on virtually every radio frequency band from very low frequency (VLF) up through advanced extremely high frequency (AEHF) using a variety of modulations, encryptions and networks, maximizing the likelihood an emergency message is received by U.S. strategic forces. The EMD Hardware Development efforts for the design, architecture, and integration of a cyber-resilient communications systems to transform a modified C-130J-30 into E-130J through an Engineering & Manufacturing Development (EMD) Contract awarded in FY 2025. Included in these efforts are Government and Contractor Systems Integration Laboratories, Contractor System Test Integration Laboratory, Government Furnished Property (National Security Agency approved encryption devices, Ultra High Frequency modems), High Frequency and the Advanced Extremely High Frequency solutions, Top Secret network development and building required infrastructure includes power generation systems, cooling, flight deck avionics, Electric Magnetic Pulse (EMP) hardening, cyber hardening, and structural modifications to support integration of E-130J mission system equipment. FY 2026 funding includes purchase for startup materials needed for three (3) C-130J-30 Government Furnished Equipment (GFE) System Demonstration Test Articles (SDTA) for mission system integration.$$, NULL, 1781601000, 1826306000, 1348165000, NULL, NULL, 163, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 727931000, 1043978000, 1662723000, 1662723000, NULL, 1662723000, 1106505000, $$The E-6B Take Charge and Move Out (TACAMO) Recapitalization Program (E-130J) provides for air vehicle replacement and mission systems modernization to augment and eventually replace the aging E-6B aircraft for the TACAMO mission. The TACAMO mission provides an airborne capability for survivable, endurable and reliable airborne command, control and communications between the United States (U.S.) National Command Authority (NCA) and the U.S. strategic forces. This mission is critical in the deterrence and management of a nuclear conflict. A dedicated communications platform, TACAMO aircraft features the ability to communicate on virtually every radio frequency band from very low frequency (VLF) up through Advanced Extremely High Frequency (AEHF) using a variety of modulations, encryptions and networks, maximizing the likelihood an emergency message is received by U.S. strategic forces. The Engineering & Manufacturing Development (EMD) Hardware Development efforts for the design, architecture, and integration of a cyber-resilient communications systems to transform a modified C-130J-30 into E-130J through an EMD contract awarded in FY 2025. Included in these efforts are Government and Contractor Systems Integration Laboratories, Contractor System Test Integration Laboratory, Government Furnished Property (National Security Agency approved encryption devices, Ultra High Frequency modems), High Frequency and the Advanced Extremely High Frequency solutions, Top Secret network development and building required infrastructure includes power generation systems, cooling, flight deck avionics, Electric Magnetic Pulse (EMP) hardening, cyber hardening, and structural modifications to support integration of E-130J mission system equipment. FY 2027 funding includes purchase of three (3) C-130J-30 Government Furnished Equipment (GFE) System Demonstration Test Articles (SDTA) for mission system integration and the integration of three (3) Engineering Development Model (EDM) aircraft developed for engineering and testing purposes.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605200D8Z$$, $$General Support to OUSD(Intelligence and Security)$$, $$rdte_dw_ba6$$, $$dw_ousd_re$$, 2026, 3468000, 7979000, 6155000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605200D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 8468, "fy26_v182_supp_K": 5000, "fy26_v182_total_K": 13468, "fy26_v182_note_name": "RDT&E", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 40878}$$::jsonb, $$This RDT&E program supports the Department's initiatives to Defend the Homeland, Build Sustainable and Long-Term Advantage, and Taking Care of People. Funding enables oversight and advances intelligence and security innovation, develops Artificial Intelligence (AI), and enables technical analysis & assessments. Some initiatives span multiple fiscal years, whereas some are one-year initiatives. The interim National Defense Strategy (NDS) describes an efficient and effective Department with an ability meet U.S. policy goals and objectives. It supports the NDS line of effort to build a more lethal force by conducting research and evaluation of global Defense Intelligence & Security Enterprise (DISE) topics to modernize key capabilities and develop AI. This innovation effort is closely coordinated with other Office of the Secretary of Defense (OSD) organizations, enabling efficiency and reformation of outdated business processes, sustaining security “best practices”, and minimizing risk. This PE provides guidance, counsel, and options to national leaders on improving the near-term efficiency and effectiveness of Intelligence, Surveillance, and Reconnaissance (ISR) capabilities by spearheading the expedited delivery of ISR systems, technologies, policies, and processes in support of warfighter operations around the globe. Funding promotes technology research and development across the DISE. Intelligence research activities support ISR efficiency, advance AI, and proliferate the usage of intelligence data. Activities also include proof of concept and application development related to enabling process improvement, efficiencies, and innovation. Funding also supports activities that support testing and evaluation across the DISE. Intelligence research activities support ISR efficiency, advance AI, and proliferate the usage of intelligence data. Activities also include proof of concept and application development related to enabling process improvement, efficiencies, and innovation. Funding also supports activities that support testing and evaluation across the DISE. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                            Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:       PE 0605200D8Z / General Support to OUSD(Intelligence and Security) RDT&E Management Support$$, NULL, 9323000, 9480000, 9361000, NULL, NULL, 178, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 8555000, 13468000, 10695000, 10695000, NULL, 10695000, 9532000, $$This RDT&E program supports the 2025 National Security Strategy (NSS) and the 2026 National Defense Strategy (NDS). Funding will develop the capabilities to defend the homeland; deter China in the Indo-Pacific; increase burden-sharing with U.S. Allies and Partners; and supercharge the Defense Industrial Base. Funding advances global Defense Intelligence Enterprise (DIE) and Defense Security Enterprise (DSE) initiatives that address emerging trends in data & AI architecture, technology oversight, and technology acceleration. Initiatives will establish an enterprise-wide, agentic data federation; architect solutions with industry and the interagency; and synchronize technical requirements. They will align decision-making and technical oversight; deploy technical workflows; publish technical metrics; and enhance governance. Finally, they will accelerate strategic-level data science; oversee academic engagement and enhanced capabilities; and accelerate tactical- level prototyping and integration. Specifically, this effort will align with the Office of the Under Secretary of War for Research & Engineering (OUSW(R&E)) to build DISE capabilities that support Applied Artificial Intelligence (AAI) and Quantum and Battlefield Information Dominance (Q-BID) capabilities. The 2026 NDS and Defense Planning Guidance (DPG) provide prioritization of budget items. The FY 2026 spend plan amount for RDT&E includes $8,468 thousand of discretionary and $5,000 thousand of mandatory (reconciliation) for total of $13,468 thousand. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0605200D8Z / General Support to OUSD(Intelligence and Security) RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605203A$$, $$Army System Development &$$, $$rdte_army_ba5$$, $$dw_dote$$, 2026, 0, 81657000, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605203A", "page_header": "Department of the Army"}$$::jsonb, $$The Army System Development & Demonstration budget line includes multiple efforts across the Army's Battlefield Operational Systems necessary to support projects in engineering and manufacturing development for use on programs that have not received approval for full-rate. System performance is near or at planned operational system levels. Projects are characterized by mature system development, integration, demonstration to support Milestone C decisions, conducting live fire test and evaluation, and initial operational test and evaluation of production representative articles. Selected programs within this budget line will exhibit a logical progression of program phases, development and production funding within the FYDP, consistent with the Department's full funding policy.$$, NULL, NULL, NULL, NULL, NULL, NULL, 148, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605205A$$, $$Small Unmanned Aerial Vehicle (SUAV) (6.5)$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 0, 20865000, 24474000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605205A", "page_header": "Department of the Army"}$$::jsonb, $$The Family of Small Uncrewed Aircraft systems are critical to the Army's Transformation in Contact. These systems ensure Army formations have the best existing and emerging technology at Battalion and below to allow ground-based forces to project power from land into other domains to defeat highly capable enemies, secure terrain, and consolidate gains. The Rucksack Portable Uncrewed Aircraft System (RPUAS) Family of Small Uncrewed Aircraft System (FoSUAS) requirements are transitioning to the Joint Small Uncrewed Aircraft System sUAS Capability Development Document (J-sUAS CDD) to solve current and emergent operational gaps by incorporating Modular Open Systems Approach (MOSA) including swappable payloads, advanced autonomy and software scalability. These systems provide battalion and below ground maneuver elements with critical situational awareness and enhanced force protection. The systems provide an organic and responsive reconnaissance and targeting capability with real-time Full Motion Video and sensor data. Each system will include aircraft, ground support equipment, ground control station and Uncrewed Vehicle Control (UVC) software. The Short Range Reconnaissance (SRR) provides organic maneuver platoons an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition. The system has an aircraft weight of less than 5 lbs, a range of 3-5 km, and an endurance of 30 minutes. The system includes modular payloads, obstacle avoidance, target recognition, automated following, and networked capability. The Medium Range Reconnaissance (MRR) System will be informed by the Company Level Directed Requirement and provides Company level Intelligence, Surveillance and Reconnaissance (ISR) capability within the Brigade Combat Teams. The systems will have a 10km range and 8-hour endurance. System will include Assured Positioning, Navigation and Timing (APNT), Electro-Optical/Infra-Red (EO/IR), laser targeting, and kinetic architectures in a contested environment. The Long Range Reconnaissance (LRR) System will provide organic maneuver battalions an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition (RSTA) efforts. The system will have an aircraft weight of less than 55 lbs., a range of 40-60 km and endurance of 5-10 hours. System will include Assured Positioning, Navigation and Timing (APNT), Electro-Optical/Infra-Red (EO/IR), laser targeting, and kinetic architectures in a contested environment. The Joint Tactical Autonomous Aerial Resupply System (JTAARS) is an autonomous aerial cargo delivery system, organic to the maneuver commander, that provides options for rapid and agile sustainment of highly mobile tactical combat forces, operating in a widely dispersed manner in the tactical support and close areas. JTAARS enables maneuver by reducing the tactical force's dependence on ground lines of communication and sustainment, reducing threats to manned convoys and manned aerial systems, lightening Soldier load, and shrinking the supply chain. JTAARS provides a lift capability of 125 lbs. over 13 km one way (26 km round trip). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System                 PE 0605205A / Small Unmanned Aerial Vehicle (SUAV) (6.5) Development & Demonstration (SDD) Purpose Built Attritable System (PBAS) provides organic maneuver platoons an uncrewed air vehicle designed to support the ability to achieve lethal effects. PBAS shall have a range of at least 2 km and 15 minutes of endurance. The PBAS system consists of First Person Viewer (FPV) goggles, controller, leader display, two 10" air vehicles and four 5" air vehicles with modular payload(s) to include ability to integrate and employ a variety of lethal/non-lethal armaments and munitions. SRR funding will be used for system integration, testing and evaluation for SRR Next Generation. MRR funding will be used for system interface architecture to fully develop and employ modular mission payload in concert with targeting and intelligence identification and classification. Funding will also develop Type-1 encryption and survivability. LRR funding will be used for system development and test of critical components such as APNT, Type 1 encryption, and survivability. Funding will also be utilized for integration of modular mission payloads (communication relay, electronic warfare payloads and lethal munitions payloads). JTAARS funding in FY2026 to develop technical data, finalization of assessment tasks, evaluation and resolution of technology gaps, UVC software integration, range and battery power improvements, and C5ISR/EW Modular Open Suite of Standards (CMOSS) compliance. PBAS funding will be used for system integration, testing and evaluation.$$, NULL, NULL, NULL, NULL, NULL, NULL, 149, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 23581000, 0, NULL, NULL, NULL, NULL, NULL, $$The Family of Small Uncrewed Aircraft systems are critical to the Army's Transformation in Contact. The Joint Small Uncrewed Aircraft System sUAS Capability Development Document (J-sUAS CDD) solves current and emergent operational gaps by incorporating Modular Open Systems Approach (MOSA) including swappable payloads, advanced autonomy and software scalability. These systems provide battalion and below ground maneuver elements with critical situational awareness and enhanced force protection as well as responsive reconnaissance and targeting capability with real-time Full Motion Video and sensor data. Each system will include aircraft, ground support equipment, ground control station and Uncrewed Vehicle Control (UVC) software. The Short Range Reconnaissance (SRR) provides organic maneuver platoons an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition (RSTA). The system has an aircraft weight of less than 5 lbs, a range of 3-5 km, and an endurance of 30 minutes. The system includes modular payloads, obstacle avoidance, target recognition, automated following, and networked capability. The Medium Range Reconnaissance (MRR) system, informed by the Company Level Directed Requirement (SUAS DR), provides organic RSTA capability within the Maneuver Company of Brigade Combat Teams. The systems will have 10 km range and 8-hour endurance. System will include Assured Positioning, Navigation and Timing (APNT), Electro-Optical/Infra-Red (EO/IR), laser targeting, and kinetic architectures in a contested environment. The Long Range Reconnaissance (LRR) System will provide organic maneuver battalions an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition (RSTA) efforts. The system will have an aircraft weight of less than 55 lbs., a range of 40-60 km and endurance of 5-10 hours. System will include Assured Positioning, Navigation and Timing (APNT), Electro-Optical/Infra-Red (EO/IR), laser targeting, and kinetic architectures in a contested environment. The Joint Tactical Autonomous Aerial Resupply System (JTAARS) is an autonomous aerial cargo delivery system, organic to the maneuver commander, that provides options for rapid and agile sustainment of highly mobile tactical combat forces, operating in a widely dispersed manner in the tactical support and close areas. JTAARS enables maneuver by reducing the tactical force's dependence on ground lines of communication and sustainment, reducing threats to manned convoys and manned aerial systems, lightening Soldier load, and shrinking the supply chain. JTAARS provides a lift capability of 125 lbs. over 13 km one way (26 km round trip). Purpose Built Attritable System (PBAS) provides organic maneuver platoons an uncrewed air vehicle designed to support the ability to achieve lethal effects. PBAS shall have a range of at least 2 km and 15 minutes of endurance. The PBAS system consists of First Person Viewer (FPV) goggles, controller, leader display, two 10" air vehicles and four 5" air vehicles with modular payload(s) to include ability to integrate and employ a variety of lethal/non-lethal armaments and munitions. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605205A / Small Unmanned Aerial Vehicle (SUAV) (6.5) Development & Demonstration (SDD) LRR funding will be used for system development and test of critical components such as APNT, Type 1 encryption, and survivability. Funding will also be utilized for integration of modular mission payloads (communication relay, electronic warfare payloads and lethal munitions payloads). JTAARS funding in FY2026 to develop technical data, finalization of assessment tasks, evaluation and resolution of technology gaps, UVC software integration, range and battery power improvements, and C5ISR/EW Modular Open Suite of Standards (CMOSS) compliance.$$, $$Budget J-Books/FY27/Army/RDTEVol3BudgetActivity5C.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605206A$$, $$CI and HUMINT Equipment Program-Army (CIHEP-A)$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 0, 2170000, 1296000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605206A", "page_header": "Department of the Army"}$$::jsonb, $$The Counterintelligence (CI) / Human Intelligence (HUMINT) Equipment Program - Army (CIHEP-A) provides CI and HUMINT collectors (Army Military Intelligence Brigades) a full set of expeditionary capabilities. CIHEP-A will be a scalable and modular equipping program. CIHEP-A capabilities detect and mitigate insider threats, enables military source operations (MSO), and supports interrogations and debriefing operations to identify and counter adversary intelligence efforts. CIHEP-A kits will provide the collection capability to CI and HUMINT teams to identify and counter adversary threats. CIHEP-A is a direct replacement to Counterintelligence/Human Intelligence Automated Reporting and Collection Systems (CHARCS) which reaches end of useful life FY27. CIHEP-A will primarily consist of Commercial Off-the-Shelf (COTS)/Government off-the-Shelf (GOTS) components.$$, NULL, NULL, NULL, NULL, NULL, NULL, 150, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 1296000, 0, NULL, NULL, NULL, NULL, NULL, $$The Counterintelligence (CI) / Human Intelligence (HUMINT) Equipment Program - Army (CIHEP-A) provides CI and HUMINT collectors (Army Military Intelligence Brigades) a full set of expeditionary capabilities. CIHEP-A will be a scalable and modular equipping program. CIHEP-A capabilities detect and mitigate insider threats, enables military source operations (MSO), and supports interrogations and debriefing operations to identify and counter adversary intelligence efforts. CIHEP-A kits will provide the collection capability to CI and HUMINT teams to identify and counter adversary threats. CIHEP-A is a direct replacement to Counterintelligence/Human Intelligence Automated Reporting and Collection Systems (CHARCS) which reaches end of useful life FY27. CIHEP-A will primarily consist of Commercial Off-the-Shelf (COTS)/Government off-the-Shelf (GOTS) components.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605210D8Z$$, $$Defense-Wide Electronic Procurement Capabilities$$, $$rdte_dw_ba5$$, $$dw$$, 2026, 9366000, 6647000, 9485000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 75, "fy27_mand_k": 17607, "original_pe": "0605210D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Defense Industrial Base"}$$::jsonb, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. Defense-wide Electronic Procurement Capabilities provides for the development of critical enterprise-wide e-business requirements for the procurement community. These requirements result from statute, regulation, process re-engineering, internal control requirements, and audit findings. This program provides for the introduction of innovative, time and cost-saving technologies into procurement processes across the Department. Resources are provided to conduct agile software development and testing on new or modified defense-wide e-business applications to ensure system and application development, integration, and demonstration of production representative systems and capabilities.$$, NULL, 8138000, 8247000, 8423000, NULL, NULL, 153, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 9138000, 9234000, 7918000, 7918000, 17607000, 25525000, 8592000, $$This program supports the Department's initiative to Build Sustainable and Long-Term Advantage. Defense-wide Electronic Procurement Capabilities, Defense Pricing, Contracting, & Acquisition Policy (DPCAP) provides for the development of critical enterprise-wide e-business requirements for the procurement community. These requirements result from statute, regulation, process re-engineering, internal control requirements, and audit findings. This program provides for the introduction of innovative, time and cost-saving technologies into procurement processes across the Department. Resources are provided to conduct agile software development and testing on new or modified defense-wide e-business applications to ensure system and application development, integration, and demonstration of production representative systems and capabilities. The FY 2027 request for Research, Development, Test & Evaluation, Defense-Wide for ASW(A)/DPCAP includes $7,918 thousand of discretionary and $17,607 thousand of mandatory for a total of $25,525 thousand. Defense Industrial Base: The mandatory funds will be used to accelerate Acquisition Transformation initiatives and comply with Executive Order (Jan 7 2026) “Prioritizing the warfighter in Defense Contracting and Secretary of War Directive (Nov 7, 2025) "Transforming the Defense Acquisition System into the Warfighting Acquisition System to Accelerate Fielding of Urgently Needed Capabilities to Our Warriors" – Specifically resources will help Stabilize Demand Signals, Increase Supplier responsiveness, and operate a Wartime Production Unit to ensure Department of War operates at maximum capability and the Defense Industrial Base is poised to respond to increases in production needed by the Department. Plans will focus on deploying additional enterprise-wide capabilities in to increase capability of the acquisition workforce to execute Rapid Acquisition Services and Agile Prototyping as part of overall Acquisition Transformation and partnership with the defense industrial base. Acquisition Transformation efforts within DPCAP, including Deal Team negotiations and efforts, strategies to eliminate late cost and pricing submissions that drive higher contract costs, and regulatory updates to accelerate acquisition timelines. Support will also develop new tools for clearance officials and contract negotiators, such as pricing indices, commercial parts pricing and lookup capabilities, and enhanced Bill of Materials (BOM) discovery, to improve negotiation outcomes. Additionally, the effort advances Defense Federal Acquisition Regulation Supplement (DFARS) transformation and Federal Acquisition Regulation (FAR) rewrite acceleration, reduces commercial item masking practices, and expands approaches to strengthen Intellectual Property sharing when government funds research and development. Initiatives will increase focus on current capabilities with AI enhancements. We will develop enterprise requirements coming from emerging statutes and regulations for the procurement Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                    Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:              PE 0605210D8Z / Defense-Wide Electronic Procurement Capabilities System Development & Demonstration (SDD) community, which we expect because of the Revolutionary Federal Acquisition Regulation Overhaul. We will continue to enhance supply chain performance and risk data mining and data collection capabilities in the Supplier Performance Risk System (SPRS) supporting on-going statutory requirements and DoW supply chain initiatives, and we will continue to develop the procurement analytics area of ADVANA, leveraging artificial intelligence capabilities to support senior leader decision making.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605212M$$, $$CH-53K$$, $$rdte_navy_ba5$$, $$dw_dote$$, 2026, 135432000, 154067000, 71381000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 34, "original_pe": "0605212M", "page_header": "Department of the Navy"}$$::jsonb, $$The CH-53K is a next generation fly by wire heavy-lift helicopter that provides significant improvements in range, payload, performance, cargo handling, turn-around times, reliability, maintainability, interoperability and survivability. It is the only marinized heavy-lift helicopter in the world and the Department of Defense's only heavy- lift helicopter. The CH-53K mission is to support the Marine Air-Ground Task Force (MAGTF) Commander by providing assault support transport of heavy equipment, combat troops, and supplies, day or night under all weather conditions during expeditionary, joint, or combined operations. - Provides a greater payload at greater ranges than any current or emerging rotorcraft to support the rapid transition of Joint and Coalition forces from contact to blunt layer activities in a contested environment. - Addresses current connector shortfalls making it a critical enabler in the execution of distributed operations; a key component of the Marine Corps' Expeditionary Advanced Base Operations concept which supports the President's National Security Strategy, the Tri-Service Maritime Strategy and the Navy's Distributed Maritime Operational concept. - Capable of integrating into the current battlefield and taking advantage of future technologies, such as manned/unmanned teaming and MAGTF digital interoperability. - The modern fly by wire system provides greater safety, survivability, and reliability compared to other joint rotorcraft. - When compared to the legacy aircraft, improves reliability and decreases operations and support costs by reducing maintenance man hours per flight hour while maximizing work effectiveness and efficiency. Total aircraft quantities for the CH-53K program are 205 helicopters. This currently includes one Ground Test Vehicle (GTV), four Engineering Development Models (EDMs) for System Development and Demonstration (SDD), and four System Demonstration Test Articles (SDTAs) purchased with Research, Development, Test & Evaluation (RDT&E) funds. The remaining 196 aircraft are funded with Aircraft Procurement, Navy (APN). The CH-53K SDD program received a successful Milestone C decision on 4 April 2017. Initial Operational Test & Evaluation (IOT&E) completed April 2022, Initial Operating Capability (IOC) achieved in May 2022, Full Rate Production (FRP) approved in December 2022. Remaining Project Unit (PU) 3059 funding is required to complete SDD and test activities. PU 3069 began in FY2024 and established the Heavy Lift program's organic test and evaluation efforts and follow-on software development. This effort supports correction of deficiencies for fleet aircraft and developmental test to facilitate Preplanned Product Improvement (P3I) requirements and Reliability & Maintainability initiatives. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0605212M / CH-53K Development & Demonstration (SDD) JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to a full-rate production decision.$$, NULL, 95009000, 91551000, 92610000, NULL, NULL, 164, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 71398000, 135432000, 139273000, 139273000, NULL, 139273000, 94220000, $$The CH-53K is an intelligent next generation fly by wire heavy-lift helicopter that provides significant improvements in range, payload, performance, cargo handling, turn-around times, reliability, maintainability, interoperability and survivability. It is the only marinized heavy-lift helicopter in the world and the Department of War's only heavy-lift helicopter. The CH-53K mission is to support the Marine Air-Ground Task Force (MAGTF) Commander by providing assault support transport of heavy equipment, combat troops, and supplies, day or night under all weather conditions during expeditionary, joint, or combined operations. - Provides a greater payload at greater ranges than any current or emerging rotorcraft to support the rapid transition of Joint and Coalition forces from contact to blunt layer activities in a contested environment. - Addresses current connector gaps making it a critical enabler in the execution of distributed operations; a key component of the Marine Corps' Expeditionary Advanced Base Operations concept which supports the President's National Security Strategy, the Tri-Service Maritime Strategy and the Navy's Distributed Maritime Operational concept. - Capable of integrating into the current battlefield and taking advantage of future technologies, such as manned/unmanned teaming and MAGTF digital interoperability. - The modern fly by wire system provides greater safety, survivability, and reliability compared to other joint rotorcraft. - When compared to the legacy aircraft, improves reliability and decreases operations and support costs by reducing maintenance man hours per flight hour while maximizing work effectiveness and efficiency. Total aircraft quantities for the CH-53K program are 205 helicopters. This currently includes one Ground Test Vehicle (GTV), four Engineering Development Models (EDMs) for System Development and Demonstration (SDD), and four System Demonstration Test Articles (SDTAs) purchased with Research, Development, Test & Evaluation (RDT&E) funds. The remaining 196 aircraft are funded with Aircraft Procurement, Navy (APN). The CH-53K SDD program received a successful Milestone C decision on 4 April 2017. Initial Operational Test & Evaluation (IOT&E) completed April 2022, Initial Operating Capability (IOC) achieved in May 2022, Full Rate Production (FRP) approved in December 2022. Full Operational Capability (FOC) will be achieved in May 2032. Project Unit (PU) 3059 concludes with FY2025 funding. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                      Date: April 2026 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System                   PE 0605212M / CH-53K Development & Demonstration (SDD) PU 3069 began in FY2024 and established the Heavy Lift program's organic test and evaluation efforts and follow-on software development. This effort supports correction of deficiencies for fleet aircraft and developmental test to facilitate Preplanned Product Improvement (P3I) requirements and Reliability & Maintainability initiatives. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to a full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605215N$$, $$Mission Planning$$, $$rdte_navy_ba5$$, $$navair$$, 2026, 120255000, 82144000, 115390000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0605215N", "page_header": "Department of the Navy"}$$::jsonb, $$The Mission Planning PE is used to develop automated mission planning systems to support Naval Aviation. The Joint Mission Planning System (JMPS) (Proj 2213) is the designated automated mission planning system for Naval Aviation, supporting over 40 Type/Model/Series (T/M/S) of U.S. Navy and Marine Corps aircraft, expeditionary forces as well as Joint and Coalition forces. The Joint Mission Planning System - Maritime (JMPS-M) enables weapon system employment by providing the information, automated tools, and decision aids needed to rapidly plan aircraft, weapon, or sensor missions, load mission data into aircraft and weapons, conduct mission rehearsal, execute missions, and conduct post-mission analysis. The Joint Mission Planning System - Expeditionary (JMPS-E) is a scalable, tailorable, and collaborative web-based mission planning and execution monitoring tool for Amphibious Squadron staffs embarked with each Amphibious Ready Group and Expeditionary Strike Group. Electronic Kneeboard (EKB) is a mobile computing device configured with various software applications and features to support aircrew during pre-flight planning, in-flight re-planning and mission execution, and post-mission debriefing and analysis. Preflight mission planning, data loading, rehearsals, mission execution and post mission analyses are conducted at all appropriate security classification levels. The JMPS program is sun-setting in FY 2027 with a hybrid transition to CMPC. The Standardized Tester of Reprogrammable Munitions (STORM) system (Proj 2213) replaces the legacy Common Munitions Built-in-Test (BIT)/Reprogramming Equipment (CMBRE) and provides USN/USMC forces the critical capability to perform built-in test and programming/reprogramming of various advanced weapons. The STORM system supports advanced operational capabilities, addresses legacy CMBRE system obsolescence, enhances cybersecurity posture to improve readiness, and improves sortie generation rate. The STORM program is not experiencing cost growth, the funding increase in FY 2026 accounts for the transition from Section 804 Middle Tier of Acquisition to STORM program of record. Additional budget provides funding for Munitions Application Program (MAP) and STORM Software development and integration activities and non-recurring engineering activities The Collaborative Mission Planning Continuum (CMPC) formerly called Next Generation Naval Mission Planning System (NGNMPS), will address critical capability gaps and deficiencies in the legacy JMPS that are required for modern 21st century integrated mission-centric and collaborative multi-domain mission planning, execution and analysis. The CMPC will replace Naval Aviation's legacy JMPS no later than FY 2027 while also affordably leveraging prior investments across the systems of systems to deliver integrated and collaborative capability. The CMPC will affordably address technological obsolescence while also delivering collaborative and automated capabilities in an integrated virtual collaborative data environment. The CMPC capability provides advanced multiple aircraft planning capabilities focused on emerging, high-threat mission areas. Current mission planning capabilities support individual aircraft and weapon initialization requirements. The emerging, near-peer threat environment demands a much more capable system that enables a team of aircraft to cooperate effectively across multiple mission areas, domains, and security Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0605215N / Mission Planning Development & Demonstration (SDD) levels. The CMPC will also leverage service-oriented architecture to provide revolutionary improvements in workflow, usability, cybersecurity. Additionally CMPC will provide information and decision aids needed to rapidly plan/employ/maximize effectiveness of aircraft/weapon/sensor/payload mission plans. This functionality includes advanced pre-mission rehearsal/analysis, loading mission data into aircraft and weapons, dynamic replanning/retargeting against evolving threats in contested environments, and advanced post-mission debrief/ analysis. The CMPC will incorporate cross-domain solution capabilities. These mission planning, mission execution, and mission analysis functions meet the National Defense Strategy and Interim National Security Strategic Guidance key objectives. The CMPC will conduct preflight mission planning, data loading, rehearsals, mission execution and post mission analyses at all appropriate security classification levels. The Stores Planning and Weaponeering Module, also referred to as Weaponeering and Stores Planning (WASP) (Proj 2311), is an integrated software product that allows aircrew to determine the best combinations of weapons and delivery conditions to achieve the desired level of target damage. The WASP program performs detailed weapons employment planning for F/A-18 and E/A-18G aircraft. The WASP program provides inherent safety checks which eliminate weapon delivery solutions that violate aircraft T/M/S specific safety-of-flight envelopes. FY 2024 and out includes funding for the research and development in order to develop WASP for other Navy and Marine Corps platforms, and support WASP development and integration with CMPC. The FY 2026 cost of the STORM Middle Tier of Acquisition effort is $29 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 cost of the CMPC Middle Tier of Acquisition effort is $76 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT & DEMONSTRATION (SDD) because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision.$$, NULL, 74667000, 67275000, 66534000, NULL, NULL, 165, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 113212000, 120255000, 82618000, 82618000, NULL, 82618000, 60658000, $$The Mission Planning PE is used to develop automated mission planning systems to support Naval Aviation. (Proj 2213) The Joint Mission Planning System (JMPS) is the designated automated mission planning system for Naval Aviation, supporting over 40 Type/Model/Series (T/M/S) of U.S. Navy and Marine Corps aircraft, expeditionary forces as well as Joint and Coalition forces. The Joint Mission Planning System - Maritime (JMPS-M) enables weapon system employment by providing the information, automated tools, and decision aids needed to rapidly plan aircraft, weapon, or sensor missions, load mission data into aircraft and weapons, conduct mission rehearsal, execute missions, and conduct post-mission analysis. The Joint Mission Planning System - Expeditionary (JMPS-E) is a scalable, tailorable, and collaborative web-based mission planning and execution monitoring tool for Amphibious Squadron staffs embarked with each Amphibious Ready Group and Expeditionary Strike Group. Electronic Kneeboard (EKB) is a mobile computing device configured with various software applications and features to support aircrew during pre-flight planning, in-flight re-planning and mission execution, and post-mission debriefing and analysis. Preflight mission planning, data loading, rehearsals, mission execution and post mission analyses are conducted at all appropriate security classification levels. The JMPS program is sun-setting in FY 2027 with a hybrid transition to CMPC. (Proj 2213) The Standardized Tester of Reprogrammable Munitions (STORM) & Common Munitions Built-in-Test (BIT)/Reprogramming Equipment- Cyber Enhanced (CMBRE CE) system replaces the legacy Common Munitions Built-in-Test (BIT)/Reprogramming Equipment (CMBRE) and provides USN/USMC forces the critical capability to perform built-in test and programming/reprogramming of various advanced weapons. The STORM/CMBRE CE systems support advanced operational capabilities, addresses legacy CMBRE system obsolescence, enhances cybersecurity posture to improve readiness, and improves sortie generation rate. Funding in FY 2027 continues the STORM/CMBRE CE program of record, providing funding for Munitions Application Program (MAP) and STORM/CMBRE CE software development and integration activities and non-recurring engineering activities The Collaborative Mission Planning Continuum (CMPC) formerly called Next Generation Naval Mission Planning System (NGNMPS), will address critical capability gaps and deficiencies in the legacy JMPS that are required for modern 21st century integrated mission-centric and collaborative multi-domain mission planning, execution and analysis. The CMPC will begin replacing Naval Aviation's legacy JMPS no later than FY 2027 while also affordably leveraging prior investments across the systems of systems to deliver integrated and collaborative capability. The CMPC will address technological obsolescence while delivering enhanced capabilities to support the current Air Wing and the Air Wing of the future. The CMPC capability provides advanced multiple aircraft planning capabilities focused on emerging, high-threat mission areas. Current mission planning capabilities support individual aircraft and weapon initialization requirements. The emerging, near-peer threat environment demands a much more capable system that enables a team of aircraft to cooperate effectively across multiple mission areas, domains, and security levels. The CMPC will also Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0605215N / Mission Planning Development & Demonstration (SDD) leverage modernized architecture to provide revolutionary improvements in workflow, usability, cybersecurity. Additionally, CMPC will provide information and decision aids needed to rapidly plan, employ, and maximize effectiveness of aircraft/weapon/sensor/payload mission plans. This functionality includes advanced pre-mission rehearsal/analysis, loading mission data into aircraft and weapons, dynamic replanning/retargeting against evolving threats in contested environments, and advanced post-mission debrief/ analysis. The CMPC will incorporate cross-domain solution capabilities. The CMPC system will also conduct work support advanced technology maturation, risk reduction activities, and system demonstrations supporting future mission planning needs for both USN and USMC users. These mission planning, mission execution, and mission analysis functions will be designed to meet the National Defense Strategy objectives. The CMPC will conduct preflight mission planning, data loading, rehearsals, mission execution and post mission analyses at all appropriate security classification levels. (Proj 2311) The Stores Planning and Weaponeering Module, also referred to as Weaponeering and Stores Planning (WASP), is an integrated software product that performs detailed weapons employment planning for F/A-18 and E/A-18G aircraft. The WASP program provides inherent safety checks which eliminate weapon delivery solutions that violate aircraft T/M/S specific safety-of-flight envelopes. FY 2025 and out includes funding for the research and development in order to develop WASP for other Navy and Marine Corps platforms, and support WASP development and integration with CMPC. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT & DEMONSTRATION (SDD) because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605216A$$, $$Joint Targeting Integrated Command and Coordination Suite (JTIC2S)$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 0, 8951000, 21415000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 18, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605216A", "page_header": "Department of the Army"}$$::jsonb, $$FY 2026 funding and beyond, this project was realigned to PE 0604818A / Army Tactical Command & Control Hardware & Software, Projects EJ6 and EK9, in support of Army-prioritized Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, for the Data and Application Layers. The capability being developed under this project remains critical and relevant to the Warfighter. This capability, along with its resources and requirement will transition under the overarching NGC2 capability to eliminate stove-piping, reduce duplication of effort, and provide capability within a single NGC2 core architecture. Joint Targeting Integrated Command and Coordination Suite (JTIC2S) software will provide critical fires/targeting capability for joint and organic Army fire support management and a joint fires/targeting common operational picture (COP) for joint and coalition partners, as well as at echelon for target development. It will enable commanders to functionally integrate targeting efforts in a federated method. Military service branches at echelon will utilize the functions within JTIC2S for a synchronized targeting tactical picture with Army and Joint Fires COP to support Joint All Domain Command and Control and Multi Domain Operations against a near peer adversary. JTIC2S development efforts began in FY24. JTIC2S will replace the currently fielded legacy Joint Automated Deep Operations Coordination System (JADOCS) developed in 2005, which is approaching end of useful life and is facing obsolescence issues due to outdated software architecture and code. JTIC2S is a software only program using a Continuous Integration/Continuous Delivery (CI/CD) model to develop software and deploy capabilities. The CI/CD approach employs modern agile software development methodologies, tools/techniques (e.g., DEVSECOPS) and human-centered design processes (e.g., Soldier Touch Points [STPs]) to iteratively develop and deliver Fires Safety Critical Baseline (FSCB) software with shared common services and backend architecture with fire support C2 technical and tactical fire direction systems that meets Warfighter priority needs. The CI/CD approach features testing and user engagements (STPs) as integral parts of its process to ensure delivered capabilities satisfy requirements and add value for the Warfighter. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0605216A / Joint Targeting Integrated Command and Coordination Suite (JTIC2S) Development & Demonstration (SDD)$$, NULL, NULL, NULL, NULL, NULL, NULL, 151, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 20633000, 0, NULL, NULL, NULL, NULL, NULL, $$FY 2026 funding and beyond was realigned to PE 0604818A / Army Tactical Command & Control Hardware & Software, Projects EJ6 and EK9, in support of Army- prioritized Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, for the Data and Application Layers. The capability being developed under this project remains critical and relevant to the Warfighter. This capability, along with its resources and requirement will transition under the overarching NGC2 capability to eliminate stove-piping, reduce duplication of effort, and provide capability within a single NGC2 core architecture. Joint Targeting Integrated Command and Coordination Suite (JTIC2S) software will provide critical fires/targeting capability for joint and organic Army fire support management and a joint fires/targeting common operational picture (COP) for joint and coalition partners, as well as at echelon for target development. It will enable commanders to functionally integrate targeting efforts in a federated method. Military service branches at echelon will utilize the functions within JTIC2S for a synchronized targeting tactical picture with Army and Joint Fires COP to support Joint All Domain Command and Control and Multi Domain Operations against a near peer adversary. JTIC2S development efforts began in FY24. JTIC2S will replace the currently fielded legacy Joint Automated Deep Operations Coordination System (JADOCS) developed in 2005, which is approaching end of useful life and is facing obsolescence issues due to outdated software architecture and code. JTIC2S is a software only program using a Continuous Integration/Continuous Delivery (CI/CD) model to develop software and deploy capabilities. The CI/CD approach employs modern agile software development methodologies, tools/techniques (e.g., DEVSECOPS) and human-centered design processes (e.g., Soldier Touch Points [STPs]) to iteratively develop and deliver Fires Safety Critical Baseline (FSCB) software with shared common services and backend architecture with fire support C2 technical and tactical fire direction systems that meets Warfighter priority needs. The CI/CD approach features testing and user engagements (STPs) as integral parts of its process to ensure delivered capabilities satisfy requirements and add value for the Warfighter. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                      Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System        PE 0605216A / Joint Targeting Integrated Command and Coordination Suite (JTIC2S) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L063$$, $$Intelligence Surveillance and Reconnaiss...$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 72104000, 88309000, 75508000, NULL, $${"page": 98, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "63", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 58", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 35620, "p1_line_num": 58, "fy27_total_K": 35620}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 52171, "li_num": 58, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 72104000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 16946000, 12112000, 35620000, 35620000, 0, 35620000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605217N$$, $$Common Avionics$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 67944000, 79224000, 87053000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0605217N", "page_header": "Department of the Navy"}$$::jsonb, $$This project provides for the identification, study, design, development, demonstration, test, evaluation, and qualification of standard avionics capabilities for Navy use, and wherever practicable, use across all Services and Foreign Military Sales. Such air combat electronics developments include communications and airborne networking, navigation and sensors, flight avionics, safety systems, and flight mission information systems for both forward fit and retrofit aircraft. These efforts continue to maintain federated systems while encouraging transition of procurements to support a modular system for enhanced performance and affordability. Consideration is given up front to reduce acquisition costs through larger procurement quantities that satisfy multi-aircraft customer requirements and that reduce life cycle costs in the areas of reliability, maintainability, and training. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision. The FY 2026 cost of the Digital Interoperability (DI)/Marine Air Ground Task Force (MAGTF) Agile Networking Gateway Link (MANGL) (DI/MANGL) Middle Tier of Acquisition effort is $22.249 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, NULL, 106862000, 89071000, 67935000, NULL, NULL, 166, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 85470000, 67944000, 133855000, 133855000, NULL, 133855000, 56409000, $$This project provides for the identification, study, design, development, demonstration, test, evaluation, and qualification of standard avionics capabilities for Navy use, and wherever practicable, use across all Services and Foreign Military Sales. Such air combat electronics developments include communications and airborne networking, navigation and sensors, flight avionics, safety systems, and flight mission information systems for both forward fit and retrofit aircraft. These efforts continue to maintain federated systems while encouraging transition of procurements to support a modular system for enhanced performance and affordability. Consideration is given up front to reduce acquisition costs through larger procurement quantities that satisfy multi-aircraft customer requirements and that reduce life cycle costs in the areas of reliability, maintainability, and training. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full-rate production decision. The total cost of the Digital Interoperability (DI)/Marine Air Ground Task Force (MAGTF) Agile Networking Gateway Link (MANGL) (DI/MANGL) Middle Tier of Acquisition effort is $201.6 million, including RDT&E and procurement of prototype units. The DI/MANGL is fully funded through FY27.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605220N$$, $$Ship-to-Shore Connector (SSC)$$, $$rdte_navy_ba5$$, $$mc$$, 2026, 8955000, 1339000, 5697000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "original_pe": "0605220N", "page_header": "Department of the Navy"}$$::jsonb, $$The Ship to Shore Connector (SSC) program provides the capability to rapidly move assault forces within the littoral operational environment to accomplish Unified Command Plan (UCP) missions and ensures the Joint Force Commander's (JFCDR's) ability to conduct amphibious operations and operate over the high water mark, including movement over ice, mud, rivers, swamps and marshes. SSC provides the functional replacement for the Landing Craft, Air Cushion (LCAC) Class of ships, which began reaching extended service life in 2015. This PE directly funds and supports the detail design, development, construction, issue resolution, certification, integration and testing of the Ship to Shore Connector (SSC). The lead craft (Craft 100) will be maintained as a test and training platform throughout its life cycle. Note: This effort was previously funded under PE 0604567N under projects 3133 and 3137 (FY 2014 and prior).$$, NULL, 1608000, 1332000, 1412000, NULL, NULL, 167, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 6115000, 15948000, 4519000, 4519000, NULL, 4519000, 1438000, $$The Ship-to-Shore Connector (SSC), also known as the LCAC 100 class, is the direct, one-for-one replacement for the U.S. Navy's aging fleet of Landing Craft, Air Cushion (LCAC) vehicles, which have an average age of 32 years and began reaching their extended service life in 2015. It will replace legacy LCAC capacity in enabling the rapid response of the Amphibious Ready Group and Marine Expeditionary Unit operations. The SSC is an aluminum air-cushion vehicle (hovercraft) designed to enhance the Navy and Marine Corps' capability to execute a broad spectrum of missions from humanitarian assistance to major combat. Its primary role is to efficiently transport weapon systems, equipment, cargo, and personnel of the Marine Air/Ground Task Force. As a high-speed, amphibious craft, it projects power by being fully compatible with all allied amphibious ships, while performing assaults and operational maneuvers from ship to shore and across the beach. This PE directly funds and supports the detail design, development, construction, issue resolution, certification, integration and testing of the Ship to Shore Connector (SSC). The lead craft (Craft 100) will be maintained as a test and training platform throughout its life cycle. The FY 2026 spend plan for SSC included $7,267 thousand of discretionary and $1,688 thousand of mandatory (reconciliation) for a total of $8,955 thousand. The mandatory funding funds the operations and maintenance of Craft 100, the test and training craft. Note: This effort was previously funded under PE 0604567N under projects 3133 and 3137 (FY 2014 and prior). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0605220N / Ship-to-Shore Connector (SSC) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605223F$$, $$Advanced Pilot Training$$, $$rdte_af_ba5$$, $$aflcmc_aa$$, 2026, 172378000, 58803000, 248589000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0605223F"}$$::jsonb, $$The Advanced Pilot Training (APT)/T-7A Red Hawk program will replace the Air Education Training Command's (AETC) aging T-38C fleet with new aircraft, Ground Based Training System (simulators, training devices, computer based training systems, academics, etc.), Maintenance Training System, and support infrastructure currently used in the fighter/bomber advanced Specialized Undergraduate Pilot Training track as well as in the Introduction to Fighter Fundamentals program. The APT/T-7A Red Hawk program acquisition strategy was approved by OSD (AT&L) in December 2016. In addition, the APT/T-7A Red Hawk Team completed their Development Request for Proposal (RFP) Release Defense Acquisition Board and subsequently released the RFP to industry on 30 December 2016. The Program completed source selection evaluations and Milestone B and awarded a Fixed Price Incentive Firm (FPIF) Indefinite Delivery/Indefinite Quantity (ID/IQ) contract to The Boeing Company on 27 September 2018. The Maintenance Training System (MTS) effort is a Delivery Order under a separate ID/IQ Contract and was competitively awarded on 11 April 2025 to Pinnacle Solutions, LLC. The T-7A MTS will provide maintainers with the foundational skills and core competencies required to maintain the T-7A aircraft and its associated subsystems. The MTS will be a blended training solution to include: a.) a suite of Maintenance Training Devices (MTDs) with associated support equipment; b.) Interactive Multimedia Instruction (IMI)/courseware and training material; c.) smart classrooms to facilitate instructor-led training; and d.) support environments to manage training schedules, student data, and updates to all training capabilities. The T-7A MTS program will encompass the design, development, integration, and test of the most efficient and effective combination of training capabilities, as well as Contractor Logistics Support (CLS) performance. Funding contained in this platform's documentation directly aids AETC flying training enterprise to continue its overall future pilot production increase that began in FY 2020, thus reducing the USAF Pilot Shortage. The service originally planned to award Boeing its first Low Rate Initial Production (LRIP) production contract to build the seven T-7s in FY 2025. The service will now award a contract for 14 LRIP Aircraft in FY 2026 under a revised acquisition strategy . This new strategy will procure four additional T-7 production Relevant Test Vehicles (PRTVs) using FY 2025 research and development funds that will be delivered in FY 2026. The Incentive Strategy will expedite closure of EMD testing, increase Boeing's production readiness at its facility in St Louis, MS, and accelerate entrance into Initial Operational Test and Evaluation (IOT&E) at Randolph Air Force Base in Texas. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0605223F / Advanced Pilot Training Development & Demonstration (SDD) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $2.423 million was expended for civilian pay expenses in this program element, and in FY 2025 $2.695 million is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $1.814 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 49441000, 56883000, 8769000, NULL, NULL, 101, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 240513000, 163138000, 72174000, 72174000, 0, 72174000, 5418000, $$The Advanced Pilot Training (APT)/T-7A Red Hawk program will replace the Air Education and Training Command's (AETC) aging T-38C fleet with an affordable and integrated system. This system includes 351 new aircraft, a Ground Based Training System (GBTS), a Maintenance Training System (MTS), and the necessary infrastructure to meet AETC's need date of FY 2027. The training systems will feature simulators, training devices, and computer-based academics for the Advanced Specialized Undergraduate Pilot Training and Introduction to Fighter Fundamentals program tracks. Under an updated 2025 acquisition strategy, four T-7 Production Representative Test Vehicles (PRTVs) were procured and are scheduled for delivery in FY 2026 and FY 2027. This plan includes incentives to expedite Engineering Manufacturing Development (EMD) testing, improve Boeing's production readiness at its St. Louis, MO facility, and accelerate entrance into Initial Operational Test and Evaluation (IOT&E) at Joint Base San Antonio-Randolph, Texas. Funding for FY2027 continues aircraft developmental test and evaluation (DT&E) and initiates IOT&E. The MTS will provide maintainers with the foundational skills to maintain the T-7A aircraft through a blended training solution. This includes a suite of Maintenance Training Devices (MTDs) with support equipment, Interactive Multimedia Instruction (IMI) courseware, smart classrooms for instructor-led training, and support environments to manage schedules and data. FY2027 funding continues the design, development, integration, and test of these training capabilities. This funding request directly aids AETC's flying training enterprise to continue increasing its future pilot production, an effort that began in FY 2020 to reduce the 250 per year USAF pilot shortage. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0605223F / Advanced Pilot Training Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605229F$$, $$HH-60W$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 0, 1996041000, 0, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The HH-60W also referred to as the Combat Rescue Helicopter (CRH) will replace the aging HH-60G. The HH-60G currently supports the Air Force's core function of Personnel Recovery. The primary mission of the HH-60G is to conduct day / night / marginal weather Combat Search and Rescue (CSAR) in order to recover downed aircrew or other isolated personnel in hostile or non-permissive environments. The CRH will be capable of employment day or night, in adverse weather, and across the full spectrum of threats to include chemical, biological, radiological, and nuclear. On-board defensive capabilities will permit the CRH system to operate with less risk than legacy systems in an increased threat environment. An in-flight air refueling capability will provide an airborne alert capability and extend its combat mission range. The CRH system is capable of conducting combat search and rescue airborne mission commander duties. The aircraft will be self-supporting to the maximum extent practical. The CRH system may also conduct other collateral missions inherent in their capabilities to conduct Personnel Recovery, such as non-conventional assisted recovery, non-conventional evacuation operations, defense support to civil authorities, civil search and rescue, international aid, emergency aeromedical evacuation, disaster/humanitarian relief, counter-drug activities, support for National Aeronautics and Space Administration flight operations, and insertion/extraction of combat forces. The CRH development program procured a total of 11 aircraft as follows: 4 Engineering, Manufacturing, and Development (EMD) aircraft, 5 System Demonstration Test Article (SDTA) aircraft, and 2 modernization flight test aircraft. The CRH program office will procure necessary ground and flight assets required for both Development Test (DT) and Initial Operational Test & Evaluation (IOT&E). The CRH EMD program includes development of the complete CRH training system to include CRH Weapon System Trainer (WST), Operational Flight Trainer (OFT), Airframe Systems Trainer (AST), Avionics Desktop Trainer (AVDTT), other training devices, with associated spares and support equipment, as well as courseware required to perform flight, aircrew and maintenance training. Other development efforts include a systems integration laboratory, an avionics integration support facility, procurement of data rights and licenses, spares, aircraft, Government test, product support and program support costs (PSC). The CRH program will also pursue modernization efforts to develop and integrate enhancements in mission/defensive systems Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                                 Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System       PE 0605229F / HH-60W Development & Demonstration (SDD) and additional system upgrades to address critical capability gaps. The program office will utilize the additional flight test aircraft in support of modernization efforts to address emerging threats and evolving mission needs. The Delta Training Device (DTD) effort will procure additional training assets, including but not limited to, maintenance and aircrew Crew Chief Part Task Trainers (CCPTT), aircrew Hoist Procedural Trainers (HPT), Virtual Reality (VR)/Mixed Reality (MR) maintenance aircrew trainers, associated spares and support equipment, as well as Type 1 training. Capability upgrades and modernization development efforts for the CRH may include, but are not limited to, the following priorities: Situational Awareness Data Link/ Automatic Direction Finder (SADL/ADF) Removal, Directional Infrared Countermeasures (DIRCM), Electro Optical/Infrared (EO/IR) Tactical Overlay, Global Positioning System Anti-Jam/Anti-Spoof (GPS-AJ), Degraded Visual Environment (DVE) system, Integrated Vehicle Health Monitoring System Control (IVHMS), Video Data Link (VDL), Radio Frequency Jammer (RF-Jammer), Mobile User Objective System (MUOS), Link 16, Joint Range Extension Applications Protocol (JREAP), Electronic Flight Bags, and Automated Dependent Surveillance Broadcast - In Device. Capability upgrades and modernization also supports inclusion for mandates, system enhancements, hardware and software changes for diminishing manufacturing sources and material shortages as well as Deficiency Report Resolutions. In addition, studies, development, prototyping, testing and integration of emerging technology and support equipment opportunities to increase the effectiveness of the platform are considered in capability upgrades and modernization initiatives. The CRH program funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/ demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024, $4.997 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0605229F / HH-60W Development & Demonstration (SDD)$$, NULL, 123794000, 82274000, 72897000, NULL, NULL, 102, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 31646000, 40474000, 87881000, 87881000, 0, 87881000, 60130000, $$The HH-60W Jolly Green is the US Air Force's Combat Rescue Helicopter (CRH). HH-60W, now in Full Rate Production (FRP) provides the modernization and upgrade to the legacy HH-60G Pave Hawk helicopter. HH-60W modernization funding is crucial to ensure the HH-60W fleet can support the new theater and revitalize support for not only the crew but the rescues they save. RDT&E efforts include but are not limited to the Software Upgrade Program (SUP) Delivery Order 1 (DO1) Agile software Program, Advanced Infrared Countermeasures (AIRCM), Mobile User Objective System (MUOS) with Joint Range Extension Applications Protocol (JREAP), Degraded Visual Environment System (DVES), Global Positioning System Anti-Jam (GPS-AJ), Link-16, Personnel Locator System (PLS), Joint Tactical Terminal (JTT), Radio Frequency (RF) Threat Jamming, HF Radio System, Snow Skis, Tactical Flight Symbology, Next Gen Crypto Mod, Electronic Flight Bags, Automated Dependent Surveillance Broadcast - In Device, and Air Force District of Washington (AFDW) mission requirement modifications. Follow-On Capability Upgrade Systems (FOCUS) includes three (3) capabilities; GPS-AJ, MUOS, and JREAP. MUOS provides narrow band military Beyond Line-of- Sight (BLOS) communication capability with improved availability for voice and video communications and is the Department of War (DoW) directed replacement to Ultra Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:           PE 0605229F / HH-60W Operational Systems Development High Frequency (UHF) Satellite Communication (SATCOM). With MUOS, The HH-60W will be compatible with future satellite communication standards. MUOS adds JREAP capability for Link-16 over the horizon/BLOS, Common Interactive Broadcast (CIB), and future data formats. JREAP is a joint protocol per Military Standard (MIL-STD) 3011E, which allows for extension of J-series and Common Message Format messages through long back- haul means BLOS range, e.g. SATCOM, land lines, and specifically used with MUOS. GPS-AJ will enable Combat Search and Rescue (CSAR) operations in contested environments and areas with high jamming risk, especially where no other means of navigation exist, greatly reducing risk and significantly increasing combat capability in multiple theaters. SUP provides software enhancements, deficiency corrections, and crypto-modernization mandates to the HH-60W fleet on an annual release cycle primarily through the Delivery Order 1 (DO1) contract. SUP enables yearly development, test and fielding of Deficiency Report Fixes (DRs) to the operational fleet. DO 1 will not only give the warfighter the ability to rapidly fix these aging issues, but to also implement new software capability at the direction of the MAJCOM. DO1 previously included Link 16 development and testing efforts that were transferred to Link 16 (major thrust) for the 2027 PB. SUP also includes Radar Warning Receiver (RWR) study and software update and is supported by Training Systems, Government Test, Civilian Payroll, Software Depot Capability Upgrades, Mission Planning, Other Agile updates and Small Business Innovation Research (SBIR) Tax. This Program shall be reoccurring to accomplish 5 years of agile support and software to the fleet via contract. Air Combatant Command (ACC) designated this critical to accomplish any other mandates or specific requirements. After contractor software development is complete, SUP will transition to an organic software engineering squadron for execution of annual software development. Gun Mount System Performance Improvement will help complete development of design enhancements, testing, and integration of gun mount components needed to address deficiencies identified during FOT&E. New software will not be required. Communications Block Modification includes Joint Tactical Terminal-Next Generation (JTT-NG) and Hybrid SATCOM upgrades. A recent CRH decision will move the Link-16 program under Communications Block Modification on the next R-Document cycle. The JTT-NG project will replace the ENTR V4 Radio system with the JTT- NG. New software will be developed and integrated to make the system work with the platform. Hybrid SATCOM integrates high bandwidth Beyond Line of Site (BLOS) data transfer capability in parallel with existing line of site SATCOM capabilities, including installing the Hybrid SATCOM system (transceiver and amplifier units with their trays), and all necessary connectors and cables. New software will be developed and integrated to make the system work with the platform. Other Programs include DVES which significantly reduces operational risk in all HH-60W regimes of flight, especially in-route navigation and terminal area operations in unprepared operational locations where the combat rescue mission is performed. A DVES material and technical solution to the DoW's #1 flight rotary wing flight risk, reduces operator workload, increases ability to operate in limited visibility conditions, and reduces mishaps saving lives and equipment. Link 16 test and development, which was previously done under DO1, will now be a major thrust (Link 16) and progress to hardware updates. Advanced Infrared Countermeasures (AIRCM) is another program planned. This funding also supports Training Systems, Support Equipment, Initial Spares, Operation Site Activation, Program Support Costs (PSC) activities, Other Government Costs (OGC), various studies and analysis, upgrades, future HH-60W planning activities, and resolution of Diminishing Manufacturing Sources/Material Shortages Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:          PE 0605229F / HH-60W Operational Systems Development (DMSMS) and/or obsolescence issues. DMSMS activities may include, but are not limited to, bridge buys, life of type buys, buys to protect production schedule, and engineering efforts for redesign. The HH-60W program budget request also supports innovation activities to include testing, integrated master plans, studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Planned work includes program testing and development, effects testing, development of baseline integrated master plans and mission planning system analysis. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605231A$$, $$Precision Strike Missile (PrSM)$$, $$rdte_army_ba5$$, $$peo_ms$$, 2026, 197184000, 262829000, 184046000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605231A", "page_header": "Department of the Army", "fy26_v182_disc_K": 0, "fy26_v182_supp_K": 197184, "fy26_v182_total_K": 197184, "fy26_v182_note_name": "Precision Strike Missile (PrSM)", "fy26_v182_source_file": "RDTE - Vol 3 - Budget Activity 5D.txt", "fy26_v182_source_line": 1376}$$::jsonb, $$Precision Strike Missile (PrSM) funding line is directly aligned to the Army Long Range Precision Fires (LRPF) modernization priority. PrSM is part of the Army Transformation Initiative. PrSM is the Army's next generation surface-to-surface missile that replaces and improves upon Army Tactical Missile System (ATACMS) capabilities. The PrSM program is a component of an integrated fires development effort that includes survivability, resiliency, and effectiveness improvements against advanced threats from near-peer adversaries. These efforts include integration with an evolving common fires mission command, common development tools and processes, and annual test and evaluation to provide data to support program assessments and progress toward closure of performance gaps. PrSM requirements include: threshold max range of 400 kilometers (km), specified lethality against the designated target set, a launch pod missile container (LPMC) that holds two missiles, survivability in a threat environment, and compatibility with the existing launcher platforms (M270A2 Multiple Launch Rocket System (MLRS) and M142 High Mobility Artillery Rocket System (HIMARS)). PrSM will meet cluster and insensitive munition (IM) requirements and is designed with an open system approach that provides the capability for future growth to counter new and emerging threats. PrSM is an incremental development program. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605231A / Precision Strike Missile (PrSM) Development & Demonstration (SDD) The munitions developed under this funding line are part of the MLRS Family of Munitions (MFOM) that are deployed by the M142 HIMARS and M270 MLRS launchers. The mission of PrSM Increment 1 is to attack/neutralize/suppress/destroy targets using missile delivered indirect precision fires. PrSM will provide joint force commanders with a 24/7, all-weather capability to attack critical and time sensitive area and point targets including threat air defense, missile launchers, command and control centers, assembly/staging areas and high payoff targets at all depths of the multi-domain battlefield. PrSM will counter the enemy's ability to conduct combat maneuver and air defense operations. Project DL2: PrSM Increment 2 integrates multi-mode seeker technology to enable engagement of critical, time sensitive, moving, maritime, relocating, relocatable, and imprecisely located land targets. Project DL4: PrSM Increment 4 adds an extended range capability to engage targets at greater ranges than PrSM Increment 1. FY 2026 funding supports follow-on development of PrSM Increment 1 and Increment 2 technology maturation, integration, and risk reduction efforts leading to system level prototype flights. The FY 2026 request for Precision Strike Missile (PrSM) includes $0 thousand of discretionary and $197,184 thousand of mandatory (reconciliation) for a total of $197,184 thousand. The mandatory funds initiate development of the M-Code guidance set redesign and the proximity sensor redesign; the mandatory funds also integrate multi-mode seeker technology into PrSM Increment 1. Further information for this reconciliation request is provided in Section 20004 (Munitions & Supply Chain) of the Reconciliation Exhibit. The FY 2026 request was reduced by $3.758 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 135572000, 114851000, 284522000, NULL, NULL, 153, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 177328000, 197184000, 288304000, 288304000, NULL, 288304000, 317822000, $$Precision Strike Missile (PrSM) funding line is directly aligned to the Army Long Range Precision Fires (LRPF) modernization priority. PrSM is the Army's next generation surface-to-surface missile that replaces and improves upon Army Tactical Missile System (ATACMS) capabilities. The PrSM program is a component of an integrated fires development effort that includes survivability, resiliency, and effectiveness improvements against advanced threats from adversaries. These efforts include integration with an evolving common fires mission command, common development tools and processes, and annual test and evaluation to provide data to support program assessments and progress toward closure of performance gaps. PrSM requirements include: threshold max range of 400 kilometers (km), specified lethality against the designated target set, a launch pod missile container (LPMC) that holds two missiles, survivability in a threat environment, and compatibility with the existing launcher platforms (M270A2 Multiple Launch Rocket System (MLRS) and M142 High Mobility Artillery Rocket System (HIMARS)). PrSM will meet cluster and insensitive munition (IM) requirements and is designed with an open system approach that provides the capability for future growth to counter new and emerging threats. PrSM is an incremental development program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605231A / Precision Strike Missile (PrSM) Development & Demonstration (SDD) The munitions developed under this funding line are part of the MLRS Family of Munitions (MFOM) that are deployed by the M142 HIMARS and M270 MLRS launchers. The mission of PrSM Increment 1 is to attack, neutralize, suppress, destroy targets using missile delivered indirect precision fires. PrSM will provide joint force commanders with a 24/7, all-weather capability to attack critical and time sensitive area and point targets including threat air defense, missile launchers, command and control centers, assembly/staging areas and high payoff targets at all depths of the multi-domain battlefield. PrSM will counter the enemy's ability to conduct combat maneuver and air defense operations. Project DL2: PrSM Increment 2 integrates multi-mode seeker technology to enable engagement of critical, time sensitive, moving, maritime, relocating, relocatable, and imprecisely located land targets. Project DL4: PrSM Increment 4 adds an extended range capability to engage targets at greater than 1,000 km. FY 2027 funding supports follow-on development of PrSM Increment 1; Increment 2 technology maturation, integration, and risk reduction efforts leading to system level prototype flights; and Increment 4 development, technology maturation, and risk reduction efforts.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605238F$$, $$Ground Based Strategic Deterrent EMD$$, $$rdte_af_ba5$$, $$afnwc_nd$$, 2026, 4147563000, 4327250000, 2011024000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0605238F"}$$::jsonb, $$The GBSD program has been designated as the LGM-35A Sentinel. The LGM-35A Sentinel weapon system, being developed in the Sentinel Systems Program Office of the ICBM Systems Directorate, incorporates the Sentinel weapon system which is called out in related ICBM Systems Directorate portfolio programs that includes Intercontinental Ballistic Missile (ICBM) Reentry Vehicles and ICBM Fuze Modernization. The LGM-35A Sentinel program is modernizing the U.S. ground-based nuclear deterrent by replacing the aging Minuteman III ICBM system. The Sentinel program will develop, produce, and deploy a fully integrated ICBM weapon system designed for enhanced safety, security, reliability, and effectiveness. This next-generation system aims to lower lifecycle costs while closing key capability gaps and addressing vulnerabilities identified in prior assessments. The program also mitigates the diminishing effectiveness of the current land-based deterrent caused by the age and obsolescence of Minuteman III components. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System          PE 0605238F / Ground Based Strategic Deterrent EMD Development & Demonstration (SDD) Integrated with the Minuteman III program office within the ICBM Systems Directorate, the Sentinel program will manage the complex transition between systems. This includes overseeing contractor development of essential support equipment, data systems, flight test infrastructure, and training systems. Throughout this process, the program prioritizes risk mitigation and ensures adherence to strict nuclear surety, certification, and vulnerability assessment protocols. Key technical areas include: Flight Systems (missile boosters, re-entry vehicle, and guidance systems); Command & Launch (secure and reliable communication and control systems); Infrastructure & Deployment (training, maintenance, and launch infrastructure; fielding and system deployment); Software (robust and resilient weapon system software ecosystem); Systems Engineering (overall system design, cybersecurity, and modular architectures); and Test (developmental, operational, and live fire testing for safety and effectiveness). Effective program management will leverage digital engineering capabilities, oversee program execution, and manage major contracts. The FY 2026 funding will continue execution of the prime contract and advance key Sentinel program activities. These include systems engineering, IT infrastructure, data management, and analytical capabilities necessary to deliver a flexible, integrated weapon system critical design. Resources will be allocated to modernize analytical environments and laboratories, establish a collaborative digital engineering ecosystem, and continue development of air vehicle equipment, command and launch systems, cybersecurity infrastructure, training systems, security architecture, transportation subsystems, specialized support equipment, and associated ground technologies. Software development, integration, modular architecture design, and product lifecycle management will also be refined, along with strengthening the certification strategy for nuclear surety, cybersecurity, and nuclear safety. Further development of test capabilities at Vandenberg Space Force Base and the Western Range, supporting both developmental and operational testing. The program will also continue development of capabilities to meet the requirement for dual-capable, air- based, secondary launch platform. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 9.538M was expended for civilian pay expenses in this program element, and in FY 2025 40.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0605238F / Ground Based Strategic Deterrent EMD Development & Demonstration (SDD)$$, NULL, 4657064000, 4319388000, 4743299000, NULL, NULL, 103, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 1942400000, 2616352000, 4521370000, 4521370000, 0, 4521370000, 4384420000, $$The GBSD program has been designated as the LGM-35A Sentinel. The LGM-35A Sentinel weapon system, being developed in the Sentinel Systems Program Office of the ICBM Systems Directorate, incorporates the Sentinel weapon system which is called out in related ICBM Systems Directorate portfolio programs that includes Intercontinental Ballistic Missile (ICBM) Reentry Vehicles and ICBM Fuze Modernization. The LGM-35A Sentinel program is modernizing the U.S. ground-based nuclear deterrent by replacing the aging Minuteman III ICBM system. The Sentinel program will develop, produce, and deploy a fully integrated ICBM weapon system designed for enhanced safety, security, reliability, and effectiveness. This next-generation system aims to lower lifecycle costs while closing key capability gaps and addressing vulnerabilities identified in prior assessments. The program also mitigates the diminishing effectiveness of the current land-based deterrent caused by the age and obsolescence of Minuteman III components. Integrated with the Minuteman III program office within the ICBM Systems Directorate, the Sentinel program will manage the complex transition between systems. This includes overseeing contractor development of essential support equipment, data systems, flight test infrastructure, and training systems. Throughout this process, the program prioritizes risk mitigation and ensures adherence to strict nuclear surety, certification, and vulnerability assessment protocols. Key technical areas include: Flight Systems (missile boosters, re-entry vehicle, and guidance systems); Command & Launch (secure and reliable communication and control systems); Infrastructure Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0605238F / Ground Based Strategic Deterrent EMD Development & Demonstration (SDD) & Deployment (training, maintenance, and launch infrastructure; fielding and system deployment); Software (robust and resilient weapon system software ecosystem); Systems Engineering (overall system design, cybersecurity, and modular architectures); and Test (developmental, operational, and live fire testing for safety and effectiveness). Effective program management will leverage digital engineering capabilities, oversee program execution, and manage major contracts. The FY 2027 funding will continue execution of the prime contract and advance key Sentinel program activities. These include systems engineering, IT infrastructure, data management, and analytical capabilities necessary to deliver a flexible, integrated weapon system critical design. Resources will be allocated to modernize analytical environments and laboratories, establish a collaborative digital engineering ecosystem, and continue development of air vehicle equipment, command and launch systems, cybersecurity infrastructure, training systems, security architecture, transportation subsystems, specialized support equipment, and associated ground technologies. Software development, integration, modular architecture design, and product lifecycle management will also be refined, along with strengthening the certification strategy for nuclear surety, cybersecurity, and nuclear safety. Further development of test capabilities at Vandenberg Space Force Base and the Western Range, supporting both developmental and operational testing. The program will also continue development of capabilities to meet the requirement for dual-capable, air- based, secondary launch platform. The FY 2026 spend plan amount for Research, Development, Test & Evaluation includes $2,616,352 thousand of discretionary and $2,189,000 thousand of mandatory (reconciliation) for a total of $4,805,352 thousand. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. FY27 RDT&E funding for PE 0605238F, Program LGM-35A Sentinel is in is compliance with budgeted end items per the approved test strategy and FY24 Omnibus, Sec. 8057. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System       PE 0605238F / Ground Based Strategic Deterrent EMD Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605241A$$, $$Future Long Range Assault Aircraft Development$$, $$rdte_army_ba5$$, $$peo_aviation$$, 2026, 1248544000, 0, 1253637000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605241A", "page_header": "Department of the Army", "fy26_v182_disc_K": 1220568, "fy26_v182_supp_K": 310000, "fy26_v182_total_K": 1530568, "fy26_v182_note_name": "Future Long Range Assault Aircraft Development", "fy26_v182_source_file": "RDTE - Vol 3 - Budget Activity 5D.txt", "fy26_v182_source_line": 3679}$$::jsonb, $$This funding line directly aligns to the Future Vertical Lift (FVL) Army modernization priority. FVL is an initiative to develop a family of vertical lift aircraft for the United States Armed Forces. The Department of Defense (DOD) established FVL to focus vertical lift capabilities and technology development as well as retain long-term industrial base capabilities. The Deputy Secretary of Defense issued the FVL Strategic Plan in 2012 to outline a joint approach for the next generation vertical lift aircraft for all military services. The Strategic Plan provided a foundation for replacing the current fleet with advanced capability by shaping the development of vertical lift aircraft for the next 25 to 40 years. In Fiscal Year (FY) 2017, the Army identified FVL as one of the Army's six modernization priorities and established the FVL Cross Functional Team (CFT). The FVL objectives are increased vertical lift maneuverability, range, speed, payload, survivability, and reliability while reducing the logistics footprint. This capability will provide critical vertical lift aviation capability in multi-domain operations to the joint warfighter and maneuver force. The Future Long Range Assault Aircraft (FLRAA) weapon system provides Combatant Commanders with deterrence, power projection, and tactical capabilities at operational and strategic distances. The Army competitively awarded the weapon system development contract in December 2022, using a hybrid acquisition approach. FLRAA integrates advanced technologies, using a modular open systems approach, and design configurations with appropriate trades to ensure affordability. In FY 2025, funding previously planned in PE 0603801A (Aviation - Adv Dev) / Project B47 (Future Vertical Lift) transitioned to Budget Activity 6.5 PE 0605241A (Future Long Range Assault Aircraft Development)/ Project DG5 (Future Long Range Assault Aircraft) for execution of Engineering and Manufacturing Development and to support Budget Activity guidance for programs achieving Milestone B. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System          PE 0605241A / Future Long Range Assault Aircraft Development Development & Demonstration (SDD)$$, NULL, 1583673000, 986512000, 527542000, NULL, NULL, 158, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 1015350000, 1530568000, 2140569000, 2140569000, NULL, 2140569000, 531834000, $$This funding line directly aligns to the Future Vertical Lift (FVL) Army modernization priority. FVL is an initiative to develop a family of vertical lift aircraft for the United States Armed Forces. The Department of War (DOW) established FVL to focus vertical lift capabilities and technology development as well as retain long-term industrial base capabilities. The Deputy Secretary of War issued the FVL Strategic Plan in 2012 to outline a joint approach for the next generation vertical lift aircraft for all military services. The Strategic Plan provided a foundation for replacing the current fleet with advanced capability by shaping the development of vertical lift aircraft for the next 25 to 40 years. In Fiscal Year (FY) 2017, the Army identified FVL as one of the Army's six modernization priorities and established the FVL Cross Functional Team (CFT). The FVL objectives are increased vertical lift maneuverability, range, speed, payload, survivability, and reliability while reducing the logistics footprint. This capability will provide critical vertical lift aviation capability in multi-domain operations to the joint warfighter and maneuver force. The Future Long Range Assault Aircraft (FLRAA) weapon system provides Combatant Commanders with deterrence, power projection, and tactical capabilities at operational and strategic distances. The Army competitively awarded the weapon system development contract in December 2022, using a hybrid acquisition approach. FLRAA integrates advanced technologies, using a modular open systems approach, and design configurations with appropriate trades to ensure affordability. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605241A / Future Long Range Assault Aircraft Development Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605242A$$, $$Theater SIGINT System (TSIGS)$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 0, 0, 3660000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605242A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element focuses on Theater SIGINT Systems (TSIGS) which provides Army commanders with a forward deployable, remote or locally controlled, signals intelligence (SIGINT) system for contingency operations. TSIGS, made up of the Trojan Soldier Portable Remote Intelligence Group (TSPRING) and Picketline, are currently in the field. Project DJ4 supports the continuous software sustainment of Theater SIGINT System (TSIGS) which is comprised of Persistent (fixed site), Non-persistent (mobile), and Survey (man portable) subsystems. TSIGS provides SIGINT integrated solutions to support Multi Domain Battle capability gaps and provide force protection, situational development, and information superiority to Army Service Component Commands (ASCCs) and Combatant Commands (COCOMs) at the strategic level. TSIGS equips Military Intelligence Brigades with non-persistent mobile capabilities, persistent static capabilities, and portable survey capabilities to their subordinate formations. Enables integration and interoperability with sustained capabilities in support of theater aligned Military Intelligence units and Intelligence Community (IC) collection priorities, as well as Transformation in Contact (TiC) initiatives, Presidential Directives and Operational Needs Statements.$$, NULL, NULL, NULL, NULL, NULL, NULL, 159, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 3660000, 0, NULL, NULL, NULL, NULL, NULL, $$This Program Element focuses on Theater SIGINT Systems (TSIGS) which provides Army commanders with a forward deployable, remote or locally controlled, signals intelligence (SIGINT) system for contingency operations. TSIGS, made up of the Trojan Soldier Portable Remote Intelligence Group (TSPRING) and Picketline, are currently in the field. Project DJ4 supports the continuous software sustainment of Theater SIGINT System (TSIGS) which is comprised of Persistent (fixed site), Non-persistent (mobile), and Survey (man portable) subsystems. TSIGS provides SIGINT integrated solutions to support Multi Domain Battle capability gaps and provide force protection, situational development, and information superiority to Army Service Component Commands (ASCCs) and Combatant Commands (COCOMs) at the strategic level. TSIGS equips Military Intelligence Brigades with non-persistent mobile capabilities, persistent static capabilities, and portable survey capabilities to their subordinate formations. Enables integration and interoperability with sustained capabilities in support of theater aligned Military Intelligence units and Intelligence Community (IC) collection priorities, as well as Transformation in Contact (TiC) initiatives, Presidential Directives and Operational Needs Statements.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605247A$$, $$Spectrum Situational Awareness System (S2AS)$$, $$rdte_army_ba5$$, $$asa_alt$$, 2026, 0, 0, 4665000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605247A", "page_header": "Department of the Army"}$$::jsonb, $$Spectrum Situational Awareness System (S2AS) supports Army key modernization initiatives by allowing commanders to sense and see themselves in the Electro- Magnetic Spectrum (EMS), preventing electronic fratricide, helping shape the electronic operating environment, and increasing Command Post (CP) survivability. Operationally S2AS allows commanders to determine and impact their visibility to enemy fire chain. S2AS is a dedicated EMS situational awareness management system that provides the Commander with real time EMS Situational Awareness to support Emissions Control (EMCON) decisions, Electromagnetic Interference (EMI) Resolution, and detect/warn operations centers of unauthorized or intentional sources of interference on today's complex battlefield. S2AS will employ sophisticated hardware and software to strengthen the capabilities of the Army and ensuring resilience against potential adversarial threat. S2AS will address current and future EMS challenges, ensuring awareness and secure use of the EMS. Enables integration, interoperability and force modernization with emerging capabilities in support of USAREUR-AF and USARPAC Operational Needs Statements, Transformation in Contact (TiC) initiatives, and Presidential Directives.$$, NULL, NULL, NULL, NULL, NULL, NULL, 161, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 4495000, 0, NULL, NULL, NULL, NULL, NULL, $$Spectrum Situational Awareness System (S2AS) supports Army key modernization initiatives by allowing commanders to sense and see themselves in the Electro- Magnetic Spectrum (EMS), preventing electronic fratricide, helping shape the electronic operating environment, and increasing Command Post (CP) survivability. Operationally S2AS allows commanders to determine and impact their visibility to enemy fire chain. S2AS is a dedicated EMS situational awareness management system that provides the Commander with real time EMS Situational Awareness to support Emissions Control (EMCON) decisions, Electromagnetic Interference (EMI) Resolution, and detect/warn operations centers of unauthorized or intentional sources of interference on today's complex battlefield. S2AS will employ sophisticated hardware and software to strengthen the capabilities of the Army and ensuring resilience against potential adversarial threat. S2AS will address current and future EMS challenges, ensuring awareness and secure use of the EMS. Enables integration, interoperability and force modernization with emerging capabilities in support of USAREUR-AF and USARPAC Operational Needs Statements, Transformation in Contact (TIC) initiatives, and Presidential Directives.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605278F$$, $$HC/MC-130 Recap RDT&E$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 50845000, 13195000, 16085000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0605278F"}$$::jsonb, $$HC/MC-130 Recapitalization provides a Medium-lift tanker aircraft to replace the aging USAF fleet of combat rescue HC-130P/N and special operations MC-130E/H/P/ W and AC-130H/U/W aircraft for Combat Search and Rescue (CSAR) and Air Force Special Operation Forces, which are experiencing airworthiness, maintainability, and operations limitations. HC/MC-130 Recap incorporates production line modifications to the C-130J production aircraft to convert them to an HC/MC model, providing a common baseline configuration aircraft. The program also funds post-production modifications to add special mission systems required for behind- enemy-line operations required of CSAR and Special Operations aircraft. The HC-130J aircraft provides combat search and rescue infiltration and exfiltration including aerial refueling of aircraft in combat search and rescue operations as well as acting as an airborne command post during rescue operations. The MC-130J can provide specialized mobility capability to position, supply, re-supply and recover specialized ground tactical units. The AC-130J is an MC-130J that has been highly modified to provide close air support and armed reconnaissance. The Research, Development, Testing and Evaluation (RDT&E) portion of the Recap program funds engineering support and studies to conduct rapid development activities, and develops upgrades to deliver specific increments of capability in common configurations across the fielded fleet, which includes AC/HC/MC-130J. The RDT&E activities in PE 0605278F currently include, but are not limited to, Block 7.0/8.1, and Communications Modernization and related efforts to meet the Cryptographic Modernization Mandates, Resilient Positioning, Navigation, and Timing (R-PNT) STAR XIII Mission Computer Operational Flight Program (OFP) development. Block 7.0/8.1 leverages the baseline C-130J (PEC 0401132F) Block 7.0/8.1 upgrade, but funds unique AC/HC/MC-130J configuration integration requirements. The Block 7.0/8.1 project will deliver Communication, Navigation and Surveillance/Air Traffic Management (CNS/ATM) capabilities required for compliance with evolving international airspace standards. It also incorporates a new Flight Management System (FMS) that allows AC/HC/MC-130J aircraft to maintain hardware and software commonality with the C-130J Enterprise. The remaining capabilities 7.0/8.1 provides are Link-16, Civil GPS Navigation and Data Link, Identification Friend or Foe (IFF) Transponder Mode-5, and Automatic Dependent Surveillance-Broadcast Out (ADS-B Out). The USAF has also initiated the Communications Modernization program to comply with Cryptographic Modernization 1 and 2 requirements, including but not limited to meeting Mobile User Objective System (MUOS) and VINSON/ ANDVT Cryptographic Modernization (VACM) mandates, as well as deliver Second-generation Anti-jam Tactical UHF Radio for NATO (SATURN), Single Channel Ground and Airborne Radio System (SINCGARS), Airborne Mission Network (AbMN) integration, and HF Modernization capabilities to resolve DMS issues. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0605278F / HC/MC-130 Recap RDT&E Operational Systems Development The Air Force decoupled IFF Mode 5 and ADS-B from the Block 7.0/8.1 program to accelerate fielding to address DoD mandates. Additionally, in 2018 the USAF significantly revamped its HC-130J Block 7.0/8.1. upgrade strategy, de-scoping the MC-130J from the current Block 7.0/8.1 program to allow the MC-130J to prioritize other (SOCOM- funded) modifications while allowing Air Combat Command (ACC) to move forward with Block 7.0/8.1 on the HC-130J. The majority of the AC/MC-130J Block 7.0/8.1 requirements, including meeting the DoD MUOS and VACM mandates, will be addressed through the Communications Modernization program. The remaining capabilities will be addressed at a future date. Resilient Positioning, Navigation, and Timing (R-PNT) will provide reliable and accurate R-PNT solutions to ensure safe aerial navigation, delivery of precision fires, and support precise time coordination. This capability will also provide the foundation to counter emerging and continuously evolving electronic and cyber threats to R-PNT. R-PNT will integrate hardware and software to enable transit in GPS degraded/denied environments and support documented strategy requirements for uncompromised CSAR and SOF infil/exfil operations in contested environments. The chosen R-PNT solution will comply with the CSAF Capability Development Guidance Memorandum (CDGM), dated 4 Oct 2022. The STAR XIII Mission Computer OFP program will develop, verify, and certify a software release to enable fleet interoperability with the new STAR XIII Mission Computer. The program will involve a Trial Kit Installation, development testing, and Product Support Package development and validation in advance of production and fielding. HC/MC-130J Recap funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/ demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. It also covers integration and certification for Diminishing Manufacturing Sources Materiel Solutions (DMSMS) and other development activities under the Continuous Improvement Program (CIP) as needed to keep the AC/HC/MC programs effective against emerging threats. This development funding covers associated aircraft costs for testing purposes to include but not limited field level maintenance such as day-to-day launch, recovery, inspection, servicing, and removal and replacement of LRUs within the capabilities and qualifications of its maintenance team, support equipment needed to support flight test, maintenance repair team support during the transfer ferry sortie if the aircraft diverts and all test related aircraft flying hour costs. The program may also include any Contractor Manpower Equivalent (CME)/A&AS support deemed necessary to support the program objectives. The HC/MC-130 Recap RDT&E permits the initiation and employment of rapid acquisition authorities to respond to emerging threats and requirements as needed. The FY 2026 request was reduced by $2.069 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 3.267M was expended for civilian pay expenses in this program element, and in FY 2025 4.328M is forecast for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0605278F / HC/MC-130 Recap RDT&E Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 26730000, 26401000, 25369000, NULL, NULL, 158, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 43597000, 77079000, 34932000, 34932000, 0, 34932000, 25882000, $$HC/MC-130 Recapitalization provides a Medium-lift tanker aircraft to replace the aging USAF fleet of combat rescue HC-130P/N and special operations MC-130E/H/P/ W and AC-130H/U/W aircraft for Combat Search and Rescue (CSAR) and Air Force Special Operation Forces, which are experiencing airworthiness, maintainability, and operations limitations. HC/MC-130 Recap incorporates production line modifications to the C-130J production aircraft to convert them to an HC/MC model, providing a common baseline configuration aircraft. The program also funds post-production modifications to add special mission systems required for behind- enemy-line operations required of CSAR and Special Operations aircraft. The HC-130J aircraft provides combat search and rescue infiltration and exfiltration including aerial refueling of aircraft in combat search and rescue operations as well as acting as an airborne command post during rescue operations. The MC-130J can provide specialized mobility capability to position, supply, re-supply and recover specialized ground tactical units. The AC-130J is an MC-130J that has been highly modified to provide close air support and armed reconnaissance. The Research, Development, Testing and Evaluation (RDT&E) portion of the Recap program funds engineering support and studies to conduct rapid development activities, and develops upgrades to deliver specific increments of capability in common configurations across the fielded fleet, which includes AC/HC/MC-130J. The RDT&E activities in PE 0605278F currently include, but are not limited to, Block 7.0/8.1, Communications Modernization and related efforts to meet the Cryptographic Modernization Mandates, Resilient Positioning, Navigation, and Timing (R-PNT), and STAR XIII Mission Computer Operational Flight Program (OFP) development. HC/MC-130J Recap funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/ demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. It also covers integration and certification for Diminishing Manufacturing Sources Materiel Solutions (DMSMS) and other development activities under the Continuous Improvement Program (CIP) as needed to keep the AC/HC/MC programs effective against emerging threats. This development funding covers associated aircraft costs for testing purposes to include but not limited field level maintenance such as day-to-day launch, recovery, inspection, servicing, and removal and replacement of LRUs within the capabilities and qualifications of its maintenance team, support equipment needed to support flight test, maintenance repair team support during the transfer ferry sortie if the aircraft diverts and all test related aircraft flying hour costs. The program may also include any Contractor Manpower Equivalent (CME)/Advisory and Assistance Services (A&AS) support deemed necessary to support the program objectives. The HC/MC-130 Recap RDT&E permits the initiation and employment of rapid acquisition authorities to respond to emerging threats and requirements as needed. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0605278F / HC/MC-130 Recap RDT&E Operational Systems Development This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605285N$$, $$Next Generation Fighter$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 74320000, 0, 453828000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 34, "fy27_mand_k": 72115, "original_pe": "0605285N", "page_header": "Department of the Navy", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Air Superiority"}$$::jsonb, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, NULL, NULL, NULL, NULL, NULL, NULL, 168, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, NULL, NULL, 68498000, 68498000, 72115000, 140613000, NULL, NULL, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605294D8Z$$, $$Trusted and Assured Microelectronics$$, $$rdte_dw_ba5$$, $$dw$$, 2026, 169475000, 202757000, 150436000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 75, "original_pe": "0605294D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This effort supports the Department's initiatives to Build Sustainable and Long-Term Advantage, Defend the Homeland, and Deter Aggression. This program supports microelectronics modernization activities that enable defense systems to keep pace with commercial microelectronics technological advances, reduce reliance on obsolete microelectronics, and mitigate the Department’s reliance on sole source foundries for assured state-of-the-art (SOTA) microelectronics. It addresses the challenges of 1) having enduring access to a multiplicity of modern manufacturing processes that require commercial volumes to maintain long term viability and 2) protecting the intellectual property (IP) of the microelectronic parts that are manufactured. Microelectronics technology is a critical enabler for the development of new systems and sustainment of fielded systems. In addition, this program directly supports the priority of building a resilient Joint Force and defense ecosystem through modernization of key capabilities and fostering pathways to adapt SOTA commercial and dual- use technologies to Defense needs. The program also supports the objective of Making the Right Technology Investments by supporting the domestic microelectronics innovation ecosystem and partnering with industry to quickly incorporate market-driven commercial advances with military-relevant capabilities. Recognizing that an assured supply of microelectronics is a U.S. Government-wide concern, this activity will interface with the services and interagency partners and stakeholders to capture requirements, opportunities for collaboration, and strategic decisions develop capabilities to address multiple missions, to limit the overall cost of these requirements to the USG, limit unneeded duplication, and enable technology transition and adoption. This activity is being led by the Under Secretary of Defense for Research and Engineering. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:           PE 0605294D8Z / Trusted and Assured Microelectronics System Development & Demonstration (SDD)$$, NULL, 55868000, 59492000, 62011000, NULL, NULL, 154, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 145532000, 132785000, 51202000, 51202000, NULL, 51202000, 62011000, $$This program provides microelectronics demonstration activities that enable warfighting systems and platforms to keep pace with commercial microelectronics technological advances, reduce reliance on obsolete microelectronics, and mitigate the Department’s reliance on sole source and offshore foundries for assured state- of-the-art (SOTA) microelectronics. It focuses on enduring access to a multiplicity of modern on shore manufacturing processes, leveraging commercial volumes to maintain long term viability and protects the intellectual property (IP) of the microelectronic parts that are manufactured. These activities support the 2026 National Defense Strategy Line of Effort to supercharge the United States Defense Industrial Base through building out capacity, empowering innovators and adopting new advancements in technology, guided by the Department’s policy on Assured Access to Trusted Microelectronics. Additionally, the National Defense Authorization Act (NDAA) for Fiscal Year 2025, Sec 922, codifies the assurance needs of the DoW by ensuring, pursuant to policies related to hardware and software assurance and supply chain risk management, that the software and hardware developed, acquired, maintained, and used by the Department are free from intentional and unintentional vulnerability during the life-cycle of development and deployment of assured, trustworthy defense systems. Microelectronics are critical enablers for all existing and future warfighting systems. This program delivers trusted and assured microelectronics-enabled capabilities to the warfighter in three ways: • First, by providing the Department access to SOTA microelectronics design and emulation tools and IP libraries, advanced fabrication nodes, and advanced packaging and test capabilities, leveraging commercial device implementations as well as the development of unique DoW-designed devices for both warfighting and dual use; • Second, by increasing assurance in the integrity and performance of microelectronics through evidence-based assurance methodologies; the development and application of analytic techniques and methods for verification and validation of microelectronics designs, 3rd party IP, physical implementations, functionality, and Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:             PE 0605294D8Z / Trusted and Assured Microelectronics System Development & Demonstration (SDD) supply chain. It improves situational and counterintelligence awareness of threats to DoW microelectronics; and develops and implements technology protection best practices; and • Third, by developing technologies to improve size, weight, power, latency, bandwidth and resilience of DoW systems and platforms. It does this through advanced chip manufacturing and packaging, developing next-generation multi-chip packages, radiation hardened microelectronics, and demonstrating advanced analog, digital, and mixed-signal technologies leveraging an array of materials for communications, radar, munitions, electronic warfare, sensors and imaging applications. • This program’s technology investments and innovations support the U.S. domestic microelectronics ecosystem including fostering partnerships with industry to rapidly incorporate market-driven commercial advances within military systems. In addition, this program directly supports the priority of building a resilient Joint Force and warfighting ecosystem of key capabilities and builds pathways to adapt SOTA commercial and dual-use technologies to DoW needs. The program stimulates the domestic microelectronics innovation ecosystem and partnering with industry to rapidly incorporate market-driven commercial advances to improve military capabilities. An assured supply of trusted microelectronics is a U.S. Government-wide concern, this program interfaces with the services and interagency partners and stakeholders to capture requirements, create opportunities for collaboration and joint force alignment, to reduce the overall cost of microelectronics technologies, limit unneeded duplication, and enable faster technology transition to the warfighter. This activity is being led by the Under Secretary of War for Research and Engineering.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605296F$$, $$Microelectronics Secure Enclave$$, $$rdte_af_ba5$$, $$dw_osd$$, 2026, 104990000, 0, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0605296F"}$$::jsonb, $$In support of the Secretary of Defense's priority to rebuild the military through reviving the U.S. defense industrial base, the Microelectronics Secure Enclave (MSE) program office was established inside the Department of the Air Force to provide oversight and direction of the nation's investment in a secure state-of-the-art (SOTA) microelectronics advanced fabrication and packaging capability. Per direction in the Commerce, Justice, Science and Related Agencies Appropriations Act, 2024, development of a Secure Enclave capability was funded via Federal Financial Assistance (FFA) through the Creating Helpful Incentives to Produce Semiconductors and Science Act (CHIPS Act) of 2022. As part of the FFA requirements, these funds may only be executed by the commercial activity to which they were awarded and may not be used to offset costs for U.S. Government oversight of their execution. Therefore, this program element (PE) provides funding for program office support requirements, including civilian pay and contractor manpower, facilities and other direct costs incident to executing MSE scope of work. In addition, this funding will initiate pilot projects to design and produce SOTA microelectronics for earliest possible integration into critical weapon systems and will invest in sustained production output from the Secure Enclave to support the nation's most sensitive warfighting capabilities. This PE includes necessary civilian pay expenses required to manage, execute, and deliver system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in PE 0207433F, 0702806F and 0901212F. In FY 2026, 3M is forecasted for civilian pay expenses in this PE. Additional details may be provided through classified channels. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0605296F / Microelectronics Secure Enclave Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 304365000, 323904000, 335780000, NULL, NULL, 104, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 103608000, 224664000, 224664000, 0, 224664000, 342578000, $$In support of the Secretary of War's priority to rebuild the military through reviving the U.S. defense industrial base, the Microelectronics Secure Enclave (MSE) program office was established inside the Department of the Air Force to provide oversight and direction of the nation's investment in a secure state-of-the-art (SOTA) microelectronics advanced fabrication and packaging capability. Per direction in the Commerce, Justice, Science and Related Agencies Appropriations Act, 2024, development of a Secure Enclave capability was funded via Federal Financial Assistance (FFA) through the Creating Helpful Incentives to Produce Semiconductors and Science Act (CHIPS Act) of 2022. As part of the FFA requirements, these funds may only be executed by the commercial activity to which they were awarded and may not be used to offset costs for U.S. Government oversight of their execution. Therefore, this program element (PE) provides funding for program office support requirements, including civilian pay and contractor manpower, facilities and other direct costs incident to executing MSE scope of work. In addition, this funding will initiate pilot projects to accelerate the adoption of SOTA microelectronics for integration into critical weapon systems and will invest in sustained production output from the Secure Enclave to support the nation's most sensitive warfighting capabilities. This PE includes necessary civilian pay expenses required to manage, execute, and deliver system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in PE 0207433F, 0702806F and 0901212F. In FY 2026, $3M is forecasted for civilian pay expenses in this PE. In FY 2027, $6M is forecasted for civilian pay expenses in this PE. Additional details may be provided through classified channels. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System         PE 0605296F / Microelectronics Secure Enclave Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605310D8Z$$, $$Military Aviation and Installation Assurance Siting Clearinghouse$$, $$rdte_dw_ba5$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 4402000, 4482000, 4651000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 4072000, 4072000, NULL, 4072000, 4616000, $$The Clearinghouse was established under USC, Title 10, Section 183a, directing the establishment of a Military Aviation and Installation Assurance Clearinghouse for review of mission obstructions Siting Clearinghouse (…to be referred to as the "Clearinghouse"). The Clearinghouse: (a) coordinates Department of War (DoW) review of applications for energy projects or antenna structure projects filed with the Secretary of Transportation pursuant to section 44718 of title 49 and received by the DoW from the Secretary of Transportation; (b) provides procedures to ensure affected local military installations are consulted; (c) accelerates the development of planning tools necessary to determine the acceptability to the Department of War of proposals included in an application for an energy project or antenna structure project submitted pursuant to such section; (d) reviews and assesses proposed actions likely scope, duration, and level of risk of any adverse impact of such energy project or antenna structure project on military operations and readiness; and (e) identifies any feasible and affordable actions that could be taken by the Department, the developer of such energy project or antenna structure project, or others to mitigate the adverse impact and to minimize risks to national security while allowing the energy project or antenna structure project to proceed with development.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605326A$$, $$Concepts Experimentation Program$$, $$rdte_army_ba6$$, $$afc$$, 2026, 58606000, 86765000, 80845000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605326A", "page_header": "Department of the Army"}$$::jsonb, $$The Army Concepts Experimentation Program supports current and future concepts and capabilities involving Soldiers and Leaders within live, virtual, and constructive environments by exploring concepts, capability requirements and solutions across Doctrine, Organization, Training, Materiel, Leadership and Education, personnel, and Facilities (DOTMLPF) domains. The purpose of Concepts Experimentation is to clarify and mitigate risk for current and future forces. Experiments and projects inform Army futures concepts and assess high-risk conceptual assumptions in order to focus required capabilities and represent user requirements in the future Army, to field the Army. Army experiments use the combined resources of Army Battle Laboratories, operational units, research labs, materiel developers, concept developers, industry and academia to collaborate in the development, refinement, and assessment of future force concepts. Simulated Experiments (SIMEX) will integrate and assess Army Concepts and Force Design phases with Army-level issues across the breadth of a campaign that highlights validation and integration of MDO capabilities. This Program Element (PE) enhances Joint Capabilities Integration and Development System (JCIDS) development in support of Program Executive Offices (PEOs) and Program Managers (PMs) for acquisition milestone decisions. Funding ensures AFC/FCC serves as the voice of the warfighter and compliments the materiel developer in providing total capability management ensuring the integration of DOTMLPF solutions. This PE resources the Army's Continuous Learning Campaign, currently known as Project Convergence (PC). PC is the Army's campaign of learning based on a continuous, structured series of demonstrations and experiments, designed to aggressively advance and integrate our Army's contributions to Joint Force overmatch. It ensures the Army, as part of the Joint fight, can rapidly and continuously integrate or "converge" effects across all domains to overmatch our adversaries in competition and conflict. PC is part of the Army's intent to achieve a full Multi-Domain Operations (MDO) capability. Capstone is the periodic, joint, multinational experiment within Project Convergence that pulls together concepts, technology, gaps, and requirements at scale for the Army and applies them to the Indo-Pacific and European theaters. Capstone experiments on ways to defeat our pacing threat in the Indo- Pacific and the five key functions the Army performs in this theater: building and defending bases, command and control for Combined Joint Force (CJF), sustaining logistical supply lines, defensive fires through long-range precision strikes, and counter-attack forces. In addition, Capstone experiments against near-peer adversaries in the European theater, against which the CJF demonstrates pulsed operations to enable a land-centric exploitation. Capstone focuses on Army with the immediate need to integrate select technologies to keep the Army ahead of our peers and on the leading edge of development. This PE provides funding for Defender, Forager. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                           Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E         PE 0605326A / Concepts Experimentation Program Management Support These experiments help the Army evaluate emerging concepts, new formations, integrate new technologies, and promote interoperability between the Army, other services and multinational partners. The Soldier-Centered Analysis Future Force Project (33B) will provide early application of human performance and human figure modeling tools in the development of Soldier-focused requirements to shape technology for Future Force development. These efforts include design analyses, constructive simulations, and Soldier-in-the loop assessments to ensure that manpower requirements and workload and skill demands are considered, avoiding information and physical task overloads and taking optimum advantage of aptitudes, individual and collective training, and numbers of Soldiers for an affordable Future Force. The FY 2026 request was reduced by $26.443 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.219 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 68241000, 76479000, 73679000, NULL, NULL, 178, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 77909000, 63606000, 55596000, 55596000, NULL, 55596000, 74414000, $$The Army Concepts Experimentation Program supports current and future concepts and capabilities involving Soldiers and Leaders within live, virtual, and constructive environments by exploring concepts, capability requirements and solutions across Doctrine, Organization, Training, Materiel, Leadership and Education, personnel, and Facilities (DOTMLPF) domains. The purpose of Concepts Experimentation is to clarify and mitigate risk for current and future forces. Experiments and projects inform Army futures concepts and assess high-risk conceptual assumptions in order to focus required capabilities and represent user requirements in the future Army, to field the Army. Army experiments use the combined resources of Army Battle Laboratories, operational units, research labs, materiel developers, concept developers, industry and academia to collaborate in the development, refinement, and assessment of future force concepts. Simulated Experiments (SIMEX) will integrate and assess Army Concepts and Force Design phases with Army-level issues across the breadth of a campaign that highlights validation and integration of MDO capabilities. This Program Element (PE) enhances Joint Capabilities Integration and Development System (JCIDS) development in support of Program Executive Offices (PEOs) and Program Managers (PMs) for acquisition milestone decisions. Funding ensures AFC/FCC serves as the voice of the warfighter and compliments the materiel developer in providing total capability management ensuring the integration of DOTMLPF solutions. This PE resources the Army's Continuous Learning Campaign, currently known as Project Convergence (PC). PC is the Army's campaign of learning based on a continuous, structured series of demonstrations and experiments, designed to aggressively advance and integrate our Army's contributions to Joint Force overmatch. It ensures the Army, as part of the Joint fight, can rapidly and continuously integrate or "converge" effects across all domains to overmatch our adversaries in competition and conflict. PC is part of the Army's intent to achieve a full Multi-Domain Operations (MDO) capability. Capstone is the periodic, joint, multinational experiment within Project Convergence that pulls together concepts, technology, gaps, and requirements at scale for the Army and applies them to the Indo-Pacific and European theaters. Capstone experiments on ways to defeat our pacing threat in the Indo- Pacific and the five key functions the Army performs in this theater: building and defending bases, command and control for Combined Joint Force (CJF), sustaining logistical supply lines, defensive fires through long-range precision strikes, and counter-attack forces. In addition, Capstone experiments against near-peer adversaries in the European theater, against which the CJF demonstrates pulsed operations to enable a land-centric exploitation. Capstone focuses on Army with the immediate need to integrate select technologies to keep the Army ahead of our peers and on the leading edge of development. This PE provides funding for Defender, Forager. These experiments help the Army evaluate emerging concepts, new formations, integrate new technologies, and promote interoperability between the Army, other services and multinational partners. The Soldier-Centered Analysis Future Force Project (33B) will provide early application of human performance and human figure modeling tools in the development of Soldier-focused requirements to shape technology for Future Force development. These efforts include design analyses, constructive simulations, and Soldier-in-the Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E              PE 0605326A / Concepts Experimentation Program Management Support loop assessments to ensure that manpower requirements and workload and skill demands are considered, avoiding information and physical task overloads and taking optimum advantage of aptitudes, individual and collective training, and numbers of Soldiers for an affordable Future Force. The FY 2026 request was reduced by $26.443 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.219 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L028$$, $$SCALABLE CONTROL INTERFACE (SCI)$$, $$proc_army_2031_ba2$$, $$peo_aviation$$, 2026, 1257000, 0, 0, NULL, $${"page": 12, "ba_num": "02", "source": "p1_fy26", "ba_name": "Modification of aircraft", "line_no": "28", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 1257, "li_num": 18, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 1257000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 1257000, 2061000, 2061000, 0, 2061000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605327N$$, $$T-AO 205 Class$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 0, 71000, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 35, "original_pe": "0605327N", "page_header": "Department of the Navy"}$$::jsonb, $$Test and Evaluation (T&E) requirements to support the T-AO 205 John Lewis Fleet Oiler Class recapitalization of the existing T-AO 187 Fleet Oiler Class. The Navy's Combat Logistics Force (CLF) oilers supply fuel and dry cargo to Navy ships at sea. The T-AO 205 Class will operate as shuttle ships from resupply ports to customer ships. Additionally, in conjunction with a T-AKE, they will accompany and stay on-station with a Carrier Strike Group (CSG) to provide fuel as required to customer ships.$$, NULL, NULL, NULL, NULL, NULL, NULL, 169, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605330A$$, $$C2 Transport$$, $$rdte_army_ba5$$, $$peo_c3t$$, 2027, 0, 0, 0, NULL, $${"fy26_v180": {"note": "FY27_only_PE_no_FY26_reality", "source": "b1_null_zero_v180"}}$$::jsonb, NULL, NULL, 43219000, 40991000, 41037000, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 45370000, 45370000, NULL, 45370000, 41395000, $$C2 Transport 0605330A is not a new start line, it is a consolidation of MILSATCOM System Engineering (0303142 456), Unified Network Technology Trans & Integ (UNTTI) (0604818 DD1), and Protected Tactical Satellite (0303142 CO7), CMFF Radio Cards (0604805 DH4), and Integrated Tactical Network/Enterprise Network (0604541 BT5). The C2 Transport Layer supports the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems. The RDT&E funding line consists of two portfolios: Satellite and Network Modernization (C2A) and Radio Modernization (C2B). The Capability Program Executive Command, Control and Information Network (CPE C2IN) is responsible for prioritizing, programming, managing and executing the projects detailed below and ensuring these funds are available to support the Army modernization priorities. Project C2A FY2027 funding supports two (2) distinct lines of effort: Protected SATCOM Resilient Anti-Jam Modem (RAM) Development and Unified Network Technology Transition and Integration (UNTTI). Protected SATCOM provides funding for continued Resilient Anti-Jam Modem (RAM) development, testing and certification of production representative modems, incorporating Army requirements, to support continued spiral development of critical protected communications capabilities to address resiliency in jamming environments. RAM provides the ability for Army tactical terminals to be resilient in a contested environment and protect against catastrophic loss of situational awareness and command and control during critical battle movement with Anti-Jam capabilities. RAM will provide on the move and early entry satellite terminals with adaptive, anti-jam communications for the highest levels of protected communications in multi domain operations and offer the tactical Army protection against interference that is either intentional or unintentional. Satellite and Network Modernization funding supports UNTTI an RDT&E initiative enabling transport agnostic, high-capacity and resilient tactical communications for expeditionary operations. These efforts support system/subsystem development and demonstration, aimed at integration, maturation, evaluation, and testing to demonstrate systems against requirements. TEM Projects, Line of Sight Modernization, SATCOM Modernization, Transport Modernization, Secure Cellular, and System of Systems (SoS) Training. These technologies support new and improved communications capabilities with reduced Size, Weight, and Power (SWAP), while increasing throughput, providing network resiliency and Low Probability of Intercept/Low Probability of Detection (LPI/LPD) capabilities. Satellite and Network Modernization procures, modifies, integrates, and tests system prototypes to demonstrate enhanced capabilities in accordance with Army modernization priorities. It Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                    Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System               PE 0605330A / C2 Transport Development & Demonstration (SDD) supports developing technical, logistics, training, and other acquisition documentation to assist with the transition, insertion, and integration of efforts across PM C2 Transport and enables the transition of developing and new technologies to support Next Generation Command and Control (NGC2). Project C2B - Radio Modernization: Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) Radio Card Mid-Tier Acquisition (MTA) Rapid Prototype (RP) program delivers Software Defined Radio (SDR) cards, Cryptographic Subsystem (CSS) cards, Digital Radio Heads (DRH) and Victory Audio Adapter (VAX) required by the CMOSS Mounted Form Factor (CMFF) Abbreviated Capability Development Document (A-CDD) for the Ground and Aviation's tactical communication requirements utilizing an Other Transaction Authority(OTA) contracting strategy. CMFF Radio Cards provide simultaneous transmission and reception of multiple waveforms across multiple channels in a single or multiple SDR card(s) integrated in the CMFF chassis with NSA certifiable CSS and interoperable with the Digital Radio Head. CMFF Radio cards initial capability development includes but is not limited to Single Channel Ground and Airborne Radio System (SINCGARS), Air Traffic Control (ATC), Warrior Robust Enhanced Network (WREN) and future advanced networking waveforms; initial Cryptographic Subsystem Card (CSS), Digital Radio Head (DRH), and Victory Audio Adapter (VAX). Advanced capability development includes but is not limited to Mobile User Objective System (MUOS), Link-16, High Frequency (HF), HAVEQUICK (HQ), Second generation Anti-jam Tactical UHF Radio for NATO (SATURN), Demand Assigned Multiple Access (DAMA) and future advanced networking waveforms; and final CSS, DRH and VAX. The total cost of the CMFF RC Middle Tier of Acquisition (MTA) effort is $96.1 million RDT&E from FY25 to FY29. FY2027 funding supports Hardware and Software Development (SDR card, CSS card, Digital Radiohead and Victory Audio Adapter), Test, Integration and Evaluation, and Program Management Support. This funding directly supports the Army's Next Generation Command and Control (NGC2) initiative, specifically targeting the modernization of the Command and Control (C2) Transport Layer. The C5ISR Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF) is a cornerstone of this effort, embodying the key tenets of NGC2 to deliver a more agile, interoperable, and data-centric communications backbone for ground and aviation platforms. Funding has been realigned into this line to support the Army's Next Generation Command and Control (NGC2) initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605331A$$, $$C2 Applications$$, $$rdte_army_ba5$$, $$asa_alt$$, 2027, 0, 0, 0, NULL, $${"fy26_v180": {"note": "FY27_only_PE_no_FY26_reality", "source": "b1_null_zero_v180"}}$$::jsonb, NULL, NULL, 600526000, 653938000, 772574000, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 488401000, 488401000, NULL, 488401000, 789255000, $$Army's Next Generation Command and Control (NGC2) is the Army's highest Command and Control (C2) modernization priority and will enhance the ability to conduct multi-domain operations by integrating advanced technologies, improving interoperability, and increasing the speed and accuracy of decision-making processes. This funding line supports the Command and Control (C2) Application Layer within the NGC2 ecosystem. A fully integrated C2 Application Layer is essential for maintaining operational superiority in a complex battlefield environment. The Army is modernizing its C2 approach to achieve battlefield superiority by implementing a horizontally integrated software services framework within the NGC2 ecosystem. The C2 Application Layer of this framework is dedicated to developing and delivering innovative common and warfighting applications that enhance synchronization and effectiveness across all warfighting functions (WfF) (Command and Control, Movement and Maneuver, Intelligence, Fires, Protection, and Sustainment) providing Commanders with globally accessible C2 Applications facilitating faster and better-informed decision making to outpace the enemy. Warfighters interact with the C2 Data Layer through the C2 Application Layer using Common and Warfighter C2 Applications compatible with diverse form factors (i.e., tablets, radios, goggles) to enhance operational mobility. The C2 Application Layer leverages a flexible, open architecture and continuous integration and continuous delivery (CI/CD) pipelines for rapid integration and deployment of critical capabilities, supported by a modular C2 Data Layer. C2 Applications will rely on modern approaches, including CI/CD pipelines, application programming interfaces (APIs), software development kits (SDKs), Modular Open Systems Approach (MOSA), and Natural Language Processing (NLP). Project C2C / COMMON C2 APPLICATIONS delivers a suite of common applications (i.e., Clock, Map, Weather and Compass) and a globally accessible storefront for the C2 Application Layer of the NGC2 ecosystem, drawing from and contributing to the single, unified C2 Data Layer. This initiative ensures every soldier accesses the same consistent, real-time information, which feeds directly into essential Warfighter C2 Applications. The result is enhanced interoperability and a reliable operational picture for commanders, enabling faster and more effective decision-making. To ensure universal access, the storefront allows soldiers to find and download approved Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System              PE 0605331A / C2 Applications Development & Demonstration (SDD) Common and Warfighter C2 Applications to their operational devices, much like a commercial app store. By employing a CI/CD pipeline, the project rapidly develops and integrates these tools, replacing numerous, disparate systems into a suite of common applications. Project C2D / WARFIGHTER C2 APPLICATIONS delivers a new generation of agile applications focused on enhancing synchronization and effectiveness across the six core warfighting functions for the C2 Application Layer of the NGC2 ecosystem. These specialized tools are designed to seamlessly interoperate with Common C2 Applications, drawing from and contributing to the single, unified C2 Data Layer. Built to be inherently modular, scalable, and secure, Warfighter C2 Applications break down traditional warfighting silos and ensure operational resilience in Denied, Degraded, Intermittent, or Limited (DDIL) environments. By leveraging a CI/CD pipeline, Project C2D dramatically accelerates the deployment of Warfighter C2 capabilities from prototype to the warfighter. The result is a cohesive operational environment that provides commanders with shared situational awareness, enabling the swift, informed decisions necessary to achieve and maintain battlefield superiority. Funding has been realigned into this line to support the Army's Next Generation Command and Control (NGC2) initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605332A$$, $$C2 Data$$, $$rdte_army_ba5$$, $$asa_alt$$, 2027, 0, 0, 0, NULL, $${"fy26_v180": {"note": "FY27_only_PE_no_FY26_reality", "source": "b1_null_zero_v180"}}$$::jsonb, NULL, NULL, 312123000, 318364000, 324735000, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 306019000, 306019000, NULL, 306019000, 331229000, $$NGC2 is the Army's highest Command and Control (C2) modernization priority and will enhance the ability to conduct multi-domain operations by integrating advanced technologies, improving interoperability, and increasing the speed and accuracy of decision-making processes. This funding line supports the C2 Data Layer within the NGC2 ecosystem providing commanders a common layer of persistently available C2 data facilitating faster and better-informed decision making to outpace the enemy. A fully integrated C2 Data Layer using real-time data across warfighting functions provides seamless Artificial Intelligence/Machine Learning (AI/ML) for soldiers and commanders facilitating rapid Sensor-to-Shooter targeting, fires, airspace management, cyber, and non-kinetic effects capabilities. Inclusive of common services for credentialing, data ingestion and data management that enable applications. C2E/C2 Data: The C2 Data layer delivers an integrated, seamless, threat informed, scalable, resilient, converged and meshed data platform inclusive of common services for credentialing, data ingestion and data management with sufficient capacity at each echelon, enabling dynamic and collective Warfighting Command and Control while operating in a disrupted, disconnected, intermittent and low-bandwidth (DDIL) tactical environment. C2F/AI/ML: The C2 Data layer AI/ML decision tools augment operations at the speed and scale required by rapidly synthesizing large volumes of data giving commanders the right information, at the right time, to support the right decision. The C2 Data layer AI/ML tools enable consistent and constant evolution of the NGC2 ecosystem maintaining pace with the accelerated change in the modern digital battlefield. FY 2027 funding supports contract award deploying the C2 Data layer system to the Army, and ensuring continuous integration and continuous deployment (CI/CD) for a secure, high performing, and adaptive centerpiece to the NGC2 technology stack. FY 2027 funding additionally supports integration of AI/ML decision tools into the C2 data layer system optimizing the ecosystem and providing commanders a digital data-centric tactical advantage. This funding encompasses the continuation of network Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0605332A / C2 Data Development & Demonstration (SDD) operation and credentialing management tools development with additional capabilities for data ingestion, and intelligent data orchestration enabling commanders to dynamically reconfigure or reallocate resources to match emergent mission needs against a thinking, data-centric adversary. Funding has been realigned into this line to support the Army's Next Generation Command and Control (NGC2) initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605333A$$, $$C2 Infrastructure$$, $$rdte_army_ba5$$, $$devcom_c5isr$$, 2027, 0, 0, 0, NULL, $${"fy26_v180": {"note": "FY27_only_PE_no_FY26_reality", "source": "b1_null_zero_v180"}}$$::jsonb, NULL, NULL, 63870000, 61181000, 57541000, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 64849000, 64849000, NULL, 64849000, 58063000, $$Program Element (PE) 0605333A Command and Control (C2) Infrastructure is established in FY 2027 as part of a new funding structure for the Next Generation Command and Control (NGC2) investment in modernization of Army C2 systems. A funding line consolidation and structure change for the NGC2 investment provides clarity and transparency for the NGC2 four-layered approach (Applications, Data, Transport, and Infrastructure). This C2 Infrastructure PE supports NGC2 efforts under the Infrastructure layer and does not constitute a new program or effort. Funding for NGC2 Infrastructure activities was provided in FY2026 under PE 0604818A Project 323 Common Hardware Systems, PE 0608418A Project C34 Army Tactical Command and Control Systems Engineering, PE 0604818A Project ER9 Expeditionary Army Command Post, PE 0604805A Project DH5 Mounted Form Factor Chassis , PE 0605236A Project CQ1 Tactical Communication Network Evaluation and PE 0604541A Project BT2 Command Post Mobility/Survivability. Project C2G, Modular C2 Infrastructure supports the Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Modular Open Suite of Standards (CMOSS) Mounted Form Factor (CMFF), a defined suite of open architecture which utilizes a modular open systems approach (MOSA) that implements C5ISR capabilities away from separate "boxes" on individual platforms and ensures commonality across multiple vehicles and platforms. The CMFF Mounted Common Infrastructure (MCI) Chassis will use open standards which make it simpler and more cost-effective to upgrade capabilities and/or keep pace with commercial technology by eliminating complex integration challenges and proprietary interfaces. Project C2H, C2 SYSTEMS ENGINEERING supports the Army's Network Modernization Strategy priorities including Army Unified Network Plan, Multi-Domain Operations, Joint All Domain Command and Control (JADC2), Data Modernization and emerging data-centric requirements. This funding supports the modernization of C2 systems by integrating complex networked systems at scale. It enables the continuous design, testing, and validation of multiple network architectures, incorporating direct end-user feedback to enhance the security and resiliency and ensure network cohesiveness and effectiveness. This project coordinates technical efforts across and outside of CPE Command, Control, Communications, and Network (C3N) to ensure integration with the current and future Mission Command Network; provides technical support to programs, informing design and solutions with specific emphasis on the ability for different program efforts to be integrated and interoperable with one another. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605333A / C2 Infrastructure Development & Demonstration (SDD) Project C2I, Mounted C2 Development, supports Army's initiative to modernize C2 systems. Mounted C2 Development delivers a drop-in replacement for existing systems, using available platform space and power applications. The capability provides on-the-move bandwidth needed for Warfighting Applications in support of the Army NGC2 initiative to modernize C2 systems, Infrastructure layer. A modular open systems approach is used to maximize flexibility through rapid technology insertion and non-proprietary technologies and provides resilient communications. Mounted C2 Development focuses on continuous improvements for on the move operations, modular command posts, and survivability. Project C2G, Modular C2 Infrastructure: FY 2027 funding request completes the CMFF MCI Block 1 chassis product development effort (hardware and software development and prototype manufacturing), conduct the Block 1 Soldier Touch Point (STP) Development Test, and supports the start of Block 2 chassis development efforts. The total cost of the CMFF MCI Middle Tier of Acquisition (MTA) Rapid Prototyping (RP) effort is $82.5 million RDT&E from FY25 to FY27. The remainder of the CMFF MCI MTA RP is fully funded across the Future Years Defense Program Project C2H, C2 SYSTEMS ENGINEERING: FY 2027 funding request supports the CPE C3N System of Systems (SoS) Engineering and integration, acquisition management, testing, fielding and sustainment support to ensure interoperability and affordability within the CPE C3N portfolio, with increased emphasis on immediate Warfighter needs as well as leveraging emerging technologies. This funding supports the modernization of C2 systems by integrating complex networked systems at scale. It enables the continuous design, testing, and validation of multiple network architectures, incorporating direct end-user feedback to enhance the security and resiliency and ensure network cohesiveness and effectiveness. Project C2I, Mounted C2 Development: FY 2027 funding request supports development and systems engineering efforts, as well as enhancing command post capabilities. This funding emphasizes continuous improvements for on-the-move operations, modular command posts, and survivability. Additionally, it covers test and evaluation activities, logistical support, and program management to ensure the successful implementation of these initiatives. Funding has been realigned into this line to support the Army's Next Generation Command and Control (NGC2) initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605384BP$$, $$Chemical and Biological Defense Program$$, $$rdte_dw_ba6$$, $$dw_cbdp$$, 2026, 67263000, 75027000, 83238000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605384BP", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 75427000, 74389000, 75403000, NULL, NULL, NULL, NULL, NULL, FALSE, 77455000, 68563000, 89467000, 89467000, 0, 89467000, 76146000, $$This program element (PE) resources to research, development, test, and evaluation (RDT&E) management support as a key enabler across the Understand, Protect, Mitigate, and Enabling Investments portfolios. Chemical and Biological Defense Program (CBDP) investments provide an integrated, layered capability to enable Department of War (DoW) missions in a chemical and biological environment, ranging from combat operations to domestic incident prevention and response. The Projects in this PE support sustainment and modernization of laboratory infrastructure, test capabilities, studies and analyses, Joint doctrine and training, and program and financial management support. FY 2027 funding accelerates characterization and situational awareness of emerging biothreats and accelerates delivery of improved protection from and mitigation of biothreats, including rapid repurposing of available therapeutics and development of new vaccines. Individual Projects include: - Laboratory Support (LS6): Operating support for sustainment and modernization efforts for surety laboratory infrastructure in order to maintain and enhance DoW infrastructure capabilities to counter an expanding threat space, exploit advances in technology, and develop and transition CB defense equipment and countermeasures to the warfighter. - Management Support (MS6): Management support for the DoW CBDP to allow program overview and integration of overall medical and physical programs by the Assistant Secretary of War for Nuclear Deterrence, Chemical, and Biological Defense, Policy and Programs (OASW(ND-CBD)), through the Deputy Assistant Secretary of War for CBRN Defense (DASW(CBRND)). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Chemical and Biological Defense Program                                          Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0605384BP / Chemical and Biological Defense Program RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_CBDP_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605414N$$, $$Unmanned Carrier Aviation (UCA)$$, $$rdte_navy_ba5$$, $$peo_uw$$, 2026, 305487000, 275329000, 255031000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 35, "original_pe": "0605414N", "page_header": "Department of the Navy"}$$::jsonb, $$The MQ-25 program, PU 3278, rapidly develops an unmanned capability to embark on Carrier Vessel, Nuclear (CVN) as part of the Carrier Air Wing (CVW) to conduct aerial refueling as a primary mission and provide Intelligence, Surveillance, and Reconnaissance (ISR) capability as a secondary mission. MQ-25 extends Carrier Air Wing mission effectiveness range, partially mitigates the current Carrier Strike Group (CSG) organic ISR shortfall and fills the future Carrier Air Wing-tanker gap, mitigating Strike Fighter shortfall and preserving F/A-18E/F Fatigue Life Expenditure for its primary missions. As the first carrier-based, Group 5 Unmanned Aircraft System (UAS), MQ-25 will pioneer the integration of manned and unmanned operations, mature, complex sea-based Command, Control, Communications, Computers, and Intelligence (C4I) technologies, and pave the way for future multi-faceted, multi-mission Unmanned Aircraft Systems to pace emerging threats. The MQ-25 system will enhance CVN capability and versatility for the Joint Forces Commander through the integration of a persistent, sea-based, multi-mission aerial refueling and ISR Unmanned Aircraft System into the Carrier Air Wing. MQ-25 is comprised of an Air System which will integrate with the UMCS program. These architectural segments will be managed by the PMA-268 Government Lead Systems Integrator (LSI) that provides system-of-systems integration and is also responsible for managing enterprise-level Unmanned Carrier Aviation architecture and associated interfaces. MQ-25 Development includes development and test of the air vehicle to include software, peculiar support equipment, training systems and other logistics elements. In FY 2026, the program will continue Ground Control Station (GCS) integration and continue flight test with the air vehicles. All four Engineering Development Models (EDMs), and one of the three System Demonstration Test Articles (SDTAs) will continue to support ground and flight testing. The program will continue to develop and integrate increased software capabilities into the aircraft in support of carrier suitability and mission systems evaluations. The program will continue to develop and integrate obsolescence redesign of critical flight system avionics to establish the production baseline. The program will continue development and integration efforts to incorporate capabilities necessary to enable and align MQ-25 operations with the Navy's Unmanned Campaign Plan and future unmanned carrier aviation requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System              PE 0605414N / Unmanned Carrier Aviation (UCA) Development & Demonstration (SDD) The UMCS program, PU 3279, is the system-of-systems required for MQ-25 vehicle and payload control, both shipboard and shore based. UMCS consists of all ground and ship-based hardware, software, and networks associated with the planning and execution of flight operations and tactical missions. In addition to the GCS, consisting of Air Vehicle Pilot (AVP) workstations and servers, the UMCS program builds hardware to support line of sight (LOS) communications, beyond line of sight (BLOS) satellite communications (SATCOM), and integration with ship/shore-based systems. There are three GCS variants: MD-5C (CVN-based), MD-5D (Shore- based), and MD-5E (Embarkable system for use on CVNs that do not yet have permanent GCS systems installed). UMCS leverages existing Programs of Record (PoR) for network integration and LOS/BLOS communications and builds MQ-25 unique systems (e.g. an ARC-210 based LOS communication system and a Video Management System (VidMS) for AVP situational awareness). GCS streamlines software development, supports multiple classification levels, and positions MQ-25A interoperability with other DoD systems. Hardware development and fabrication is one facet of the program. UMCS develops and integrates software and modifies several aircraft carrier spaces to install and integrate the GCS and communication systems, in support of MQ-25A test events and operations aboard select NIMITZ Class CVNs. The UMCS program modifies and integrates with existing, external Command, Control, Communication, Computers, and Intelligence systems to provide network paths for air vehicle and mission payload data using a variety of wideband and narrowband communication paths. UMCS accomplishes this by integrating the GCS and the MQ-25A air vehicle with multiple networks and systems both at sea and on shore. In addition to controlling the MQ-25, UMCS will provide the GCS for Collaborative Combat Aircraft and the Air Wing of the Future (AWOTF). In FY 2026, UMCS will complete integration testing of the MD-5E Embarkable system. The Embarkable system consists of a subset of the final GCS configuration hardware and test unique instrumentation installed and integrated with existing ship communication and network systems. UMCS will also complete baseline GCS software development and continue developing Correction of Deficiency (CoD) builds in support of MQ-25 at sea testing events in late 2025 and 2026. UMCS will continue developing Technical Data Packages for system level components and continue providing system engineering, program management, and development support for the program. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to a full-rate production decision.$$, NULL, 0, 0, 0, NULL, NULL, 170, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 251254000, 314754000, 0, 0, NULL, 0, 0, $$The MQ-25 program, PU 3278, rapidly develops an unmanned capability to embark on Carrier Vessel, Nuclear (CVN) as part of the Carrier Air Wing (CVW) to conduct aerial refueling as a primary mission and provide Intelligence, Surveillance, and Reconnaissance (ISR) capability as a secondary mission. MQ-25 extends Carrier Air Wing mission effectiveness range, partially mitigates the current Carrier Strike Group (CSG) organic ISR gap and fills the future Carrier Air Wing-tanker gap, mitigating Strike Fighter gap and preserving F/A-18E/F Fatigue Life Expenditure for its primary missions. As the first carrier-based, Group 5 Unmanned Aircraft System (UAS), MQ-25 will pioneer the integration of manned and unmanned operations, mature, complex sea-based Command, Control, Communications, Computers, and Intelligence (C4I) technologies, and pave the way for future multi-faceted, multi-mission Unmanned Aircraft Systems to pace emerging threats. The MQ-25 system will enhance CVN capability and versatility for the Joint Forces Commander through the integration of a persistent, sea-based, multi-mission aerial refueling and ISR Unmanned Aircraft System into the Carrier Air Wing. MQ-25 is the Air System which will integrate with the UMCS program. These architectural segments will be managed by the PMA-268 Government Lead Systems Integrator (LSI) that provides system-of-systems integration and is also responsible for managing enterprise-level Unmanned Carrier Aviation architecture and associated interfaces. MQ-25 Development includes development and test of the air vehicle to include software, peculiar support equipment, training systems and other logistics elements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0605414N / Unmanned Carrier Aviation (UCA) Development & Demonstration (SDD) Reference new PE 0207255N for FY27 funding explanation. The UMCS program, PU 3279, is the system-of-systems required for MQ-25 vehicle and payload control, both shipboard and shore based. UMCS consists of all ground and ship-based hardware, software, and networks associated with the planning and execution of flight operations and tactical missions. In addition to the GCS, consisting of Air Vehicle Pilot (AVP) workstations and servers, the UMCS program builds hardware to support line of sight (LOS) communications, beyond line of sight (BLOS) satellite communications (SATCOM), and integration with ship/shore-based systems. There are three GCS variants: MD-5C (CVN-based), MD-5D (Shore- based), and MD-5E (Embarkable system for use on CVNs that do not yet have permanent GCS systems installed). UMCS leverages existing Programs of Record (PoR) for network integration and LOS/BLOS communications and builds MQ-25 unique systems (e.g. an ARC-210 based LOS communication system and a Video Management System (VidMS) for AVP situational awareness). GCS streamlines software development, supports multiple classification levels, and positions MQ-25A interoperability with other DoW systems. Hardware development and fabrication is one facet of the program. UMCS develops and integrates software and modifies several aircraft carrier spaces to install and integrate the GCS and communication systems, in support of MQ-25A test events and operations aboard select NIMITZ Class CVNs. The UMCS program modifies and integrates with existing, external Command, Control, Communication, Computers, and Intelligence systems to provide network paths for air vehicle and mission payload data using a variety of wideband and narrowband communication paths. UMCS accomplishes this by integrating the GCS and the MQ-25A air vehicle with multiple networks and systems both at sea and on shore. In addition to controlling the MQ-25, UMCS will provide the GCS for Collaborative Combat Aircraft and the Air Wing of the Future (AWOTF). JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to a full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605450A$$, $$Joint Air-to-Ground Missile (JAGM)$$, $$rdte_army_ba5$$, $$peo_ms$$, 2026, 0, 2904000, 3030000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605450A", "page_header": "Department of the Army"}$$::jsonb, $$The AGM-179 Joint Air-to-Ground Missile (JAGM) program is an Army-led, Acquisition Category (ACAT) 1C Major Defense Acquisition Program (MDAP) with joint interest with the Navy, Marine Corps, and Air Force. JAGM is the next generation, multi-mode, air-to-ground munition replacing legacy HELLFIRE (HF) and HF Longbow munitions. JAGM will be used for destruction of high-value land and maritime targets, moving or stationary, and is capable of being fired from any platform currently firing HF from a US Army-issued M299 launcher. JAGM utilizes a HF back-end (propulsion, warhead and control system) with a new-design, Millimeter Wave (MMW) and Semi-Active Laser (SAL), multi-mode guidance section. The multi-mode capability provides fire-and-forget and precision-point targeting as well as unique, blended modes of each, for improved capability over legacy munitions.$$, NULL, NULL, NULL, NULL, NULL, NULL, 162, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 2919000, 0, NULL, NULL, NULL, NULL, NULL, $$The AGM-179 Joint Air-to-Ground Missile (JAGM) program is an Army-led, Acquisition Category (ACAT) 1C Major Defense Acquisition Program (MDAP) with joint interest with the Navy, Marine Corps, and Air Force. JAGM is the next generation, multi-mode, air-to-ground munition replacing legacy HELLFIRE (HF) and HF Longbow munitions. JAGM will be used for destruction of high-value land and maritime targets, moving or stationary, and is capable of being fired from any platform currently firing HF from a US Army-issued M299 launcher. JAGM utilizes a HF back-end (propulsion, warhead and control system) with a new-design, Millimeter Wave (MMW) and Semi-Active Laser (SAL), multi-mode guidance section. The multi-mode capability provides fire-and-forget and precision-point targeting as well as unique, blended modes of each, for improved capability over legacy munitions.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605450M$$, $$Joint Air-to-ground Missile (JAGM)$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 59077000, 378000, 20654000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 35, "original_pe": "0605450M", "page_header": "Department of the Navy"}$$::jsonb, $$The Joint Air-to-Ground Missile (JAGM) is an air-launched missile system that utilizes dual-mode seeker technology thus providing advanced line-of-sight and beyond- line-of-sight capabilities, including precision point and fire-and-forget seeker targeting and increased lethality against soft, hardened, moving, stationary, land, maritime threats. JAGM provides robust capability in adverse weather, day or night and in obscured/countermeasure environments. The JAGM Increment 1 system replaces aviation-launched, tube-launched, optically-tracked, wire-guided (TOW), and Helicopter Launched Fire-&-Forget Missile (HELLFIRE) Systems. JAGM is an Army- led joint program that addresses rotary wing, fixed wing, and unmanned aerial vehicle requirements. Funding includes support of platform integration activities of the AH-1Z, the Department of Navy threshold platform for the JAGM integration. The JAGM system includes missiles, trainers, containers, support equipment and software modifications to the M-299 launcher. Future JAGM follow on efforts could include extending the weapon's range, developing a fixed wing variant, and developing potential follow on increments. The JAGM program is part of the Navy's Integrated Fire Control (IFC) approach to address advanced threat capabilities in the Anti-Access/Area-Denial (A2AD) environment. IFC solutions enable individual system capabilities to be leveraged across an effects chain, placing the full spectrum of tactical capability in the hands of the warfighter. IFC solutions that push engagement distances beyond the launch platform's radar horizon and allow the United States Navy to operate in, and control, contested battle space in littoral waters and A2/AD environments are increasingly critical as more and more scenarios require compressed and coordinated fire control timelines. Precision Attack Strike Munition (PASM) - PASM is the Program of Record follow-on to the Long Range Attack Munition (LRAM) Joint Capability Technology Demonstration (JCTD). The program was renamed from LRAM to PASM to reflect its shorter range compared to other DON weapons and to differentiate the Program of Record from JCTD activities. The PASM program develops a new network-enabled, longer range precision strike weapon capable of deterring and destroying maritime and land-based targets. PASM builds off of the subsystem maturation, integration, and demonstration efforts of the LRAM JCTD. PASM will provide asymmetric advantages in range, stand-off and lethality. PASM is designed with a Weapons Open System Architecture (WOSA) to form fit multiple types of payloads based on mission while using common rail mounting systems and launchers to simplify logistics requirements. PASM is initially designed to utilize mature, non-integrated capabilities for the fire control system. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0605450M / Joint Air-to-ground Missile (JAGM) Development & Demonstration (SDD) The FY 2026 cost of the PASM Middle Tier of Acquisition effort is $58.697 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under system development and demonstration because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 102303000, 55269000, 33866000, NULL, NULL, 171, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 20027000, 59077000, 189866000, 189866000, NULL, 189866000, 28405000, $$The Joint Air-to-Ground Missile (JAGM) is an air-launched missile system that utilizes dual-mode seeker technology thus providing advanced line-of-sight and beyond- line-of-sight capabilities, including precision point and fire-and-forget seeker targeting and increased lethality against soft, hardened, moving, stationary, land, maritime threats. JAGM provides robust capability in adverse weather, day or night and in obscured/countermeasure environments. The JAGM Increment 1 system replaces aviation-launched, tube-launched, optically-tracked, wire-guided (TOW), and Helicopter Launched Fire-&-Forget Missile (HELLFIRE) Systems. JAGM is an Army-led joint program that addresses rotary wing, fixed wing, and unmanned aerial vehicle requirements. Funding includes support of platform integration activities of the AH-1Z, the Department of Navy threshold platform for the JAGM integration. The JAGM system includes the missile, trainers, containers, support equipment, M299 Launcher, and system software modification. Future JAGM follow on efforts could include extending the weapon's range, developing a fixed wing variant, and developing potential follow on increments. The JAGM program is part of the Navy's Integrated Fire Control (IFC) approach to address advanced threat capabilities in the Anti-Access/Area-Denial (A2AD) environment. IFC solutions enable individual system capabilities to be leveraged across an effects chain, placing the full spectrum of tactical capability in the hands of the warfighter. IFC solutions that push engagement distances beyond the launch platform's radar horizon and allow the United States Navy to operate in, and control, contested battle space in littoral waters and A2/AD environments are increasingly critical as more and more scenarios require compressed and coordinated fire control timelines. Precision Attack Strike Munition (PASM) - PASM is the Program of Record follow-on to the Long Range Attack Munition (LRAM) Joint Capability Technology Demonstration (JCTD). The program was renamed from LRAM to PASM to reflect its shorter range compared to other DON weapons and to differentiate the Program of Record from JCTD activities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                  Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System               PE 0605450M / Joint Air-to-ground Missile (JAGM) Development & Demonstration (SDD) The Precision Attack Strike Munition provides a longer-range, precision strike weapon capable of deterring and engaging maritime and land-based targets. PASM builds off of the subsystem maturation, integration, and demonstration efforts of the LRAM JCTD. PASM will provide asymmetric advantages in range, stand-off and lethality. PASM is designed with a Weapons Open System Architecture (WOSA) to form fit multiple types of payloads based on mission while using common mounting systems and launchers to simplify logistics requirements. PASM is initially designed to utilize mature, non-integrated capabilities for the fire control system. The AH-1Z is the threshold platform for the USMC. The PASM system includes missiles, trainers, containers, federated platform integration solution, support equipment, modular payloads, and software modifications. The Modular Common Launcher (MCL) is the next generation multi-purpose launcher for USN and USMC Vertical Take Off Landing (VTOL) platforms. The MCL enables multiple carriage of the Precision Attack Strike Munition (PASM) on the AH-1Z aircraft. The PASM fills a long-range Precision Guided Munition (PGM) capability gap for the AH-1Z. The modular concept enables mixed loadouts and carriage of up to four weapon systems from a single aircraft station that significantly enhances mission lethality and flexibility. The MCL provides a platform for future integration of legacy weapons (e.g. Hellfire, JAGM, APKWS and unguided 2.75 in rockets) and emerging weapons (e.g. PASM, expanded APKWS and Air Launched Effects) on the AH-1Z, MH-60, and other platforms. The MCL adds capability and flexibility to better align loadouts with mission requirements and significantly simplifies sustainment/logistics support. As the MCL is subsequently qualified for carriage of legacy stores, it provides a cost-effective and highly supportable way to mitigate readiness issues with LAU series Hydra 70 2.75-inch aircraft rocket launchers and to resolve significant obsolescence issues afflicting the M299 HELLFIRE Missile Launcher (HML). The FY 2027 cost of the PASM Middle Tier of Acquisition and MCL efforts is $193.512 million, including RDTE and procurement of Prototype units for operational utility demonstration. The Department will certify FYDP funding in a future budget submission. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under system development and demonstration because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605457A$$, $$Army Integrated Air and Missile Defense (AIAMD)$$, $$rdte_army_ba5$$, $$peo_ms$$, 2026, 146056000, 285411000, 587068000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605457A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is directly aligned to the U.S. Army Air and Missile Defense (AMD) Modernization Priority. The Army Integrated Air and Missile Defense (AIAMD) program is a designated Major Defense Acquisition Program (MDAP), a critical component of the Army's AMD strategy, and is a top AMD Cross Functional Team modernization priority program. AIAMD is directly aligned to the U.S. Army Air and Missile Defense (AMD) Modernization Priority. The AIAMD program is a direct response to the U.S. Army AMD Concept and Operational and Organizational (O&O) Plan for the Future Force, the AIAMD System of Systems (SoS) Capabilities Development Document (CDD) and the AMD Task Force Concept of Operations (CONOPS) and a top Cross Functional Team Priority. The AIAMD Program is uniquely structured to enable the development of an overarching SoS capability with all participating Department of Defense (DoD) Air Defense Artillery (ADA) components functioning interdependently to provide total operational capabilities not achievable by the individual element systems. This funding will optimize effort to modernize air defense systems under an Integrated Fires architecture to manage and defend the battlespace in a joint environment against complex threats using the Integrated Battle Command System (IBCS) as the centerpiece. The AIAMD program achieves this objective by establishing the AIAMD SoS architecture and developing (1) the IAMD Battle Command Systems (IBCS) Engagement Operations Center (EOC) to provide the common Mission Command capability, (2) the Integrated Fire Control Relay capability for fire control connectivity and distributed operations, and (3) the common Plug and Fight (P&F) Kits to network-enable multiple sensor and weapon components including the IBCS EOC. The funding in this PE provides for hardware upgrade of end items to include design engineering and development changes needed prior to implementation into the baseline. Funding in FY 2026 also supports convergence of AMDPCS into the IBCS hardware baseline. In FY 2026, funds were realigned to PE 0606118A, AIAMD Software Development & Integration to support entering into the Software Pathway. The FY 2026 request was reduced by $8.25 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                           Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System           PE 0605457A / Army Integrated Air and Missile Defense (AIAMD) Development & Demonstration (SDD)$$, NULL, 35798000, 22752000, 19201000, NULL, NULL, 163, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 566078000, 143446000, 126623000, 126623000, NULL, 126623000, 19393000, $$This funding line is directly aligned to the U.S. Army Air and Missile Defense (AMD) Modernization Priority. The Army Integrated Air and Missile Defense (AIAMD) program is a designated Major Defense Acquisition Program (MDAP), a critical component of the Army's AMD strategy, and is a top AMD Cross Functional Team modernization priority program. The AIAMD program is a direct response to the U.S. Army AMD Concept and Operational and Organizational (O&O) Plan for the Future Force, the AIAMD System of Systems (SoS) Capabilities Development Document (CDD) and the AMD Task Force Concept of Operations (CONOPS) and a top Cross Functional Team Priority. The AIAMD Program is uniquely structured to enable the development of an overarching SoS capability with all participating Department of War (DoW) Air Defense Artillery (ADA) components functioning interdependently to provide total operational capabilities not achievable by the individual element systems. This funding will optimize effort to modernize air defense systems under an Integrated Fires architecture to manage and defend the battlespace in a joint environment against complex threats using the Integrated Battle Command System (IBCS) as the centerpiece. The AIAMD program achieves this objective by establishing the AIAMD SoS architecture and developing (1) the IAMD Battle Command Systems (IBCS) Engagement Operations Center (EOC) to provide the common Mission Command capability, (2) the Integrated Fire Control Relay capability for fire control connectivity and distributed operations, and (3) the common Plug and Fight (P&F) Kits to network-enable multiple sensor and weapon components including the IBCS EOC. The funding in this PE provides for hardware upgrade of end items to include design engineering and development changes needed prior to implementation into the baseline. Funding in FY 2026 also supports convergence of AMDPCS into the IBCS hardware baseline. In FY 2026, appropriate efforts and funds were realigned to PE 0606118A, AIAMD Software Development & Integration to support entering into the Software Pathway. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605457A / Army Integrated Air and Missile Defense (AIAMD) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605500N$$, $$Multi-Mission Maritime Aircraft (MMA) (P-8A)$$, $$rdte_navy_ba5$$, $$peo_aasm$$, 2026, 41129000, 35218000, 34096000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 35, "original_pe": "0605500N", "page_header": "Department of the Navy"}$$::jsonb, $$The P-8A Multi-mission Maritime Aircraft (MMA) program was initiated in response to the Joint Requirements Oversight Council (JROC) validated Mission Needs Statement, "Broad Area Maritime and Littoral Armed Intelligence, Surveillance and Reconnaissance" and the requirements for the program are defined in the P-8A Capability Production Document #791-88-09, validated and approved on 22 June 2009. A successful Critical Design Review was completed in June 2007. In August 2007 the Design Readiness Review was conducted and resulted in approval to obligate funding for the fabrication of the Stage II flight test aircraft. The first flight of P-8A occurred on 25 Apr 2009. Milestone C was successfully completed on 11 August 2010. The program completed Initial Operational Test and Evaluation (IOT&E) in March 2013 and achieved Initial Operational Capability (IOC) in November 2013. The Acquisition Decision Memorandum approved entry into Full Rate Production on January 3, 2014. During the initial Systems Development and Demonstration (SDD) phase (PE 0605500N PU 2696), which completed in 2020, the program performed the system detailed design, developed and produced Systems Integration Labs, developed and built ground and flight test articles, and conducted ground and flight tests to successfully achieve program milestones. Ground testing included the conduct of static testing, fatigue testing and Live Fire Test and Evaluation. Additionally, six (6) flight test aircraft were built, and grouped into two stages based on which phase of the test program the aircraft supported. SDD Stage I flight test aircraft (FY06/Qty-3) supported Integrated Test and Evaluation (IT&E). SDD Stage II flight test aircraft (FY09/Qty-3) supported the completion of IT&E and IOT&E after being updated to the production configuration. The SDD contract also included the development and initial building of training devices to support IOT&E, all activities necessary to facilitate an efficient transition of the fleet to achieve the P-8A IOC in CY13, and the engineering and verification of corrected deficiencies identified in testing and Fleet operational use. P-8A entered Production and Deployment phase in the 4th quarter of FY10 and entered Full Rate Production in 2nd quarter of FY14. P-8A MMA program follow-on SDD activities (PU 3368) include Assured Maritime Dominance Anti-Submarine Warfare (ASW), Anti-Surface Warfare (ASuW), and Intelligence, Surveillance, and Reconnaissance (ISR) activities implemented as a sequence of Rapid Capability Insertions (RCI) and rapid development efforts to respond to evolving threats and adversary capabilities, which will retain cost effectiveness for winning major combat operations. In order to pace the threat, these efforts will incorporate incremental software and/or hardware improvements that increase/exceed the current performance envelope, to include reliability/maintainability improvements, obsolescence, periodic technology insertion, urgent operational needs, correction of deficiencies and flight safety issues to existing sensor capabilities, communications systems, mission systems, airframe and engine component systems, weapons capabilities, training systems and Tactical Operations Center (TOC) / Tacmobile support to build on the initial P-8A SDD (PU 2696) capability baseline. These planned and emergent requirements will be prioritized through either the Navy Integration and interoperability (I&I) aligned Capability Prioritization Process (CPP), P-8A Tier 3 Capability Roadmap and/or through Fleet identification of an Urgent Operational Need. The CPP process is supported by detailed analysis and the maturations of developing technologies. Budget Activity 5. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System         PE 0605500N / Multi-Mission Maritime Aircraft (MMA) (P-8A) Development & Demonstration (SDD) JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, NULL, 107177000, 84626000, 55029000, NULL, NULL, 172, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 32992000, 41129000, 87173000, 87173000, NULL, 87173000, 56010000, $$The P-8A Multi-mission Maritime Aircraft (MMA) program was initiated in response to the Joint Requirements Oversight Council (JROC) validated Mission Needs Statement, "Broad Area Maritime and Littoral Armed Intelligence, Surveillance and Reconnaissance" and the requirements for the program are defined in the P-8A Capability Production Document #791-88-09, validated and approved on 22 June 2009. A successful Critical Design Review was completed in June 2007. In August 2007 the Design Readiness Review was conducted and resulted in approval to obligate funding for the fabrication of the Stage II flight test aircraft. The first flight of P-8A occurred on 25 Apr 2009. Milestone C was successfully completed on 11 August 2010. The program completed Initial Operational Test and Evaluation (IOT&E) in March 2013 and achieved Initial Operational Capability (IOC) in November 2013. The Acquisition Decision Memorandum approved entry into Full Rate Production on January 3, 2014. During the initial Systems Development and Demonstration (SDD) phase (PE 0605500N PU 2696), which completed in 2020, the program performed the system detailed design, developed and produced Systems Integration Labs, developed and built ground and flight test articles, and conducted ground and flight tests to successfully achieve program milestones. Ground testing included the conduct of static testing, fatigue testing and Live Fire Test and Evaluation. Additionally, six (6) flight test aircraft were built, and grouped into two stages based on which phase of the test program the aircraft supported. SDD Stage I flight test aircraft (FY06/Qty-3) supported Integrated Test and Evaluation (IT&E). SDD Stage II flight test aircraft (FY09/Qty-3) supported the completion of IT&E and IOT&E after being updated to the production configuration. The SDD contract also included the development and initial building of training devices to support IOT&E, all activities necessary to facilitate an efficient transition of the fleet to achieve the P-8A IOC in CY13, and the engineering and verification of corrected deficiencies identified in testing and Fleet operational use. P-8A entered Production and Deployment phase in the 4th quarter of FY10 and entered Full Rate Production in 2nd quarter of FY14. P-8A MMA program follow-on SDD activities (PU 3368) include Assured Maritime Dominance Anti-Submarine Warfare (ASW), Anti-Surface Warfare (ASuW), and Intelligence, Surveillance, and Reconnaissance (ISR) activities implemented as a sequence of Rapid Capability Insertions (RCI) and rapid development efforts to respond to evolving threats and adversary capabilities, which will retain cost effectiveness for winning major combat operations. In order to pace the threat, these efforts will incorporate incremental software and/or hardware improvements that increase/exceed the current performance envelope, to include reliability/maintainability improvements, obsolescence, periodic technology insertion, urgent operational needs, correction of deficiencies and flight safety issues to existing sensor capabilities, communications systems, mission systems, airframe and engine component systems, weapons capabilities, training systems and Tactical Operations Center (TOC) / Tacmobile support to build on the initial P-8A SDD (PU 2696) capability baseline. These planned and emergent requirements will be prioritized through either the Navy Integration and interoperability (I&I) aligned Capability Prioritization Process (CPP), P-8A Tier 3 Capability Roadmap and/or through Fleet identification of an Urgent Operational Need. The CPP process is supported by detailed analysis and the maturations of developing technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0605500N / Multi-Mission Maritime Aircraft (MMA) (P-8A) Development & Demonstration (SDD) Budget Activity 5. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes those projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirement prior to full-rate production decision.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L029$$, $$CH-47 Cargo Helicopter Mods (MYP)$$, $$proc_army_2031_ba2$$, $$peo_aviation$$, 2026, 17709000, 50689000, 38925000, NULL, $${"page": 12, "ba_num": "02", "source": "p1_fy26", "ba_name": "Modification of aircraft", "line_no": "29", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 17709, "li_num": 19, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 17709000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 38925000, 17709000, 108408000, 108408000, 0, 108408000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605502A$$, $$Small Business Innovative Research$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 0, 409981000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605502A", "page_header": "Department of the Army"}$$::jsonb, $$The Small Business Innovation Research (SBIR) program is a United States Government program, coordinated by the Small Business Administration, in which 3.2% of the total extramural research budgets of all federal agencies with extramural research budgets in excess of $100 million are reserved for contracts or grants to small businesses. A similar program, the Small Business Technology Transfer Program (STTR), uses a similar approach to the SBIR program to expand public/private sector partnerships between small businesses and nonprofit U.S. research institutions, and is currently funded at .45% of the relevant agencies' extramural research budgets. There is no Fiscal Year (FY) 2024 or FY 2025 budget programming for Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR). Funds for SBIR / STTR are redistributed in the year of execution from across the Army Research, Development, Test & Evaluation portfolio. This Program Element is used exclusively to account for SBIR / STTR program funding in the year of execution.$$, NULL, NULL, NULL, NULL, NULL, NULL, 179, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 356228000, 0, NULL, NULL, NULL, NULL, NULL, $$The Small Business Innovation Research (SBIR) program is a United States Government program, coordinated by the Small Business Administration, in which 3.2% of the total extramural research budgets of all federal agencies with extramural research budgets in excess of $100 million are reserved for contracts or grants to small businesses. A similar program, the Small Business Technology Transfer Program (STTR), uses a similar approach to the SBIR program to expand public/private sector partnerships between small businesses and nonprofit U.S. research institutions, and is currently funded at .45% of the relevant agencies' extramural research budgets. Funds for SBIR/STTR are not requested in the President's Budget and are redistributed in the year of execution from across the Army Research, Development, Test, and Evaluation portfolio. This Program Element is used exclusively to account for SBIR / STTR program funding in the year of execution.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605502BP$$, $$Small Business Innovative Research - Chemical Biological Def$$, $$rdte_dw_ba6$$, $$dw_cbdp$$, 2026, 0, 31904000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605502BP", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 23554000, 0, 0, 0, 0, 0, 0, $$The overall objective of the Chemical Biological Defense (CBD) Small Business Innovative Research (SBIR) program is to improve the transition or transfer of innovative CBD technologies between Department of War (DoW) components and the private sector for mutual benefit. The CBD SBIR program includes those technology efforts that maximize a strong defensive posture in a biological or chemical environment using passive and active means as deterrents. These technologies include chemical and biological detection; information assessment, which includes identification, modeling, and intelligence; contamination avoidance; and protection of both individual soldiers and equipment.$$, $$Budget J-Books/FY27/DW/RDTE_CBDP_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605502BR$$, $$SMALL BUSINESS INNOVATION RESEARCH$$, $$rdte_dw_ba6$$, $$dw_dtra$$, 2026, 0, 17801000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605502BR", "page_header": "Defense-Wide"}$$::jsonb, $$The Small Business Innovation Research (SBIR) and the Small Business Technology Transfer (STTR) programs provide the means for stimulating technological innovation in the private sector, strengthens the role of small business in meeting the Department of Defense (DoD) research and development needs; fosters and encourages participation of minority and disadvantaged businesses in technological innovation; and increases the commercial application of the DoD supported research and development results. These efforts are responsive to Public Law 106-554 and the SBIR and STTR Extension Act of 2022 (Public Law 117-183).$$, NULL, 0, 0, 0, NULL, NULL, 181, $$RDTE_DTRA_PB_2026.pdf$$, $$DTRA$$, FALSE, 15758000, 0, 0, 0, NULL, 0, 0, $$The Small Business Innovation Research (SBIR) and the Small Business Technology Transfer (STTR) programs provide the means for stimulating technological innovation in the private sector, strengthens the role of small business in meeting the Department of War (DoW) research and development needs; fosters and encourages participation of minority and disadvantaged businesses in technological innovation; and increases the commercial application of the DoW supported research and development results. These efforts are responsive to Public Law 106-554 and the SBIR and STTR Extension Act of 2022 (Public Law 117-183).$$, $$Budget J-Books/FY27/Remaining/RDTE_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605502C$$, $$Small Business Innovation Research - MDA$$, $$rdte_dw_ba6$$, $$dw_mda$$, 2026, 0, 144679000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605502C", "page_header": "Defense-Wide"}$$::jsonb, $$Small Business Innovation Research (SBIR) explores innovative concepts pursuant to Public Law 106-554 (Small Business Reauthorization Act of 2000) and Public Law 107-50 (Small Business Technology Transfer Program Reauthorization Act of 2001), which mandates a two-phase competition for small businesses with innovative technology that can be commercialized. SBIR and Small Business Technology Transfer (STTR) programs will develop new dual-use technology for future Missile Defense Agency (MDA) Missile Defense System needs. Dual-use means that the technology will be judged on the potential for future private sector investment both as a vehicle for reducing development time and cost, unit costs of new Missile Defense System technology, and as a route to national economic growth through new commercial products. MDA will conduct the competition, award, and manage the contracts.$$, NULL, 0, 0, 0, NULL, NULL, 182, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 110040000, 0, 0, 0, NULL, 0, 0, $$Small Business Innovation Research (SBIR) explores innovative concepts pursuant to Public Law 106-554 (Small Business Reauthorization Act of 2000) and Public Law 107-50 (Small Business Technology Transfer Program Reauthorization Act of 2001), which mandates a two-phase competition for small businesses with innovative technology that can be commercialized. SBIR and Small Business Technology Transfer (STTR) programs will develop new dual-use technology for future Missile Defense Agency (MDA) Missile Defense System needs. Dual-use means that the technology will be judged on the potential for future private sector investment both as a vehicle for reducing development time and cost, unit costs of new Missile Defense System technology, and as a route to national economic growth through new commercial products. MDA will conduct the competition, award, and manage the contracts.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L064$$, $$CANES Intell$$, $$proc_navy_1810_ba2$$, $$peo_c4i$$, 2026, 52171000, 59195000, 59602000, NULL, $${"page": 99, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "64", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 59", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 2976, "p1_line_num": 59, "fy27_total_K": 2976}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 5105, "li_num": 59, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 52171000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, 130090000, 1084193000, NULL, NULL, NULL, FALSE, 50654000, 46281000, 2976000, 2976000, 0, 2976000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605502D8Z$$, $$Small Business Innovation Research/Small Business Technology Trans$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 0, 257786000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605502D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$DoD Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) programs are designed to provide small, high-tech businesses opportunities to propose innovative ideas and solutions in response to technological challenges posed by the DoD Components that will address existing and emerging national security threats and to develop new military capabilities. The SBIR and STTR programs are critical pathways for the Department to tap the innovation of America’s small business community and research institutions to support development of cutting-edge technologies that will increase the readiness, modernization and lethality of the Joint Force.$$, NULL, NULL, NULL, NULL, NULL, NULL, 183, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 236706000, 0, NULL, NULL, NULL, NULL, NULL, $$DoW Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) programs are designed to provide small, high-tech businesses opportunities to propose innovative ideas and solutions in response to technological challenges posed by the DoW Components that will address existing and emerging national security threats and to develop new military capabilities. The SBIR and STTR programs are critical pathways for the Department to tap the innovation of America’s small business community and research institutions to support development of cutting-edge technologies that will increase the readiness, modernization and lethality of the Joint Force.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605502E$$, $$SMALL BUSINESS INNOVATION RESEARCH$$, $$rdte_dw_ba6$$, $$dw_darpa$$, 2026, 0, 129397000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605502E", "page_header": "Defense-Wide"}$$::jsonb, $$In accordance with Public Law No: 116-92 (National Defense Authorization Act 2020) and the Small Business Act (15 U.S.C. 638), the DARPA Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) programs are designed to provide small, high-tech businesses and academic institutions the opportunity to propose radical, innovative, high-risk approaches to address existing and emerging national security threats, thereby supporting DARPA's overall strategy to enable fundamental discoveries and technological breakthroughs that provide new military capabilities.$$, NULL, 0, 0, 0, NULL, NULL, 184, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 130133000, 0, 0, 0, NULL, 0, 0, $$In accordance with Public Law No: 116-92 (National Defense Authorization Act 2020) and the Small Business Act (15 U.S.C. 638), the DARPA Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) programs are designed to provide small, high-tech businesses and academic institutions the opportunity to propose radical, innovative, high-risk approaches to address existing and emerging national security threats, thereby supporting DARPA's overall strategy to enable fundamental discoveries and technological breakthroughs that provide new military capabilities.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605502F$$, $$Small Business Innovation Research$$, $$rdte_af_ba6$$, $$afnwc$$, 2026, 0, 947652000, 0, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605502F"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 904678000, 0, 0, 0, 0, 0, 0, $$The Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) program implements 15 U.S.C Section 638 to maximize the creative, innovative, and entrepreneurial spirit of small businesses to solve technological problems. AFWERX administers the Department of Air Force (DAF) SBIR/STTR program with a vision to empower an innovation ecosystem that delivers disruptive Air & Space capabilities. AFWERX accelerates agile and affordable capability transitions by teaming innovation technology developers with Airmen and Guardian talent. AFWERX accomplishes this through (1) connecting diverse, innovative industry, academia, and Government entities; (2) creating capability options and prototype opportunities for the DAF; (3) facilitating streamlined acquisition processes; and (4) fostering a culture of innovation. Funding is spread across multiple focus areas that change from year to year based on known and emerging technology gaps, warfighting demand signals, and broader assessments of the military industrial base in light of its reliance on foundational commercial industries. SBIR/STTR investments will be made in Open Topic, Specific Topic, and TACFI/STRATFI programs based on demand signals, timeliness of funds allocation and availability, and changes to strategic guidance or priorities. The DAF SBIR/STTR program implements three different approaches to provide funding and opportunities to small businesses. Open Topic: The Open Topic Program uses a technology-agnostic solicitation which encourages commercial industry to submit dual-use technology solutions without having a known end-user. It is used to capture the best capabilities and emerging technologies and allows industry to bring novel solutions to the DAF. Specific Topic: The Specific Topic Program seeks innovative solutions for SECAF identified Operational Imperatives and defined problem sets by a DAF end user or customer. Specific Topics have clearly-defined requirements and a known DAF customer built into the topic solicitation. STRATFI/TACFI: The STRATFI (Strategic Funding Increase) and TACFI (Tactical Funding Increase) Programs help to scale Phase II efforts to the level needed to achieve technology transitions. These programs de-risk development through syndication with multiple transition-focused partners and leveraging outside investment. Administrative costs to support the SBIR program and due diligence are also included in this program. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E        PE 0605502F / Small Business Innovation Research Management Support$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605502N$$, $$Small Business Innovative Research$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2026, 0, 655593000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605502N", "page_header": "Department of the Navy"}$$::jsonb, $$The Small Business Innovation Research (SBIR) program requires each Federal agency that has an extramural budget for Research and Development (R&D) in excess of $100,000,000 to set aside 3.2% for SBIR. This funds R&D at small businesses. The program goals are to stimulate technological innovation; increase small business participation in federally funded R&D; foster participation by minority and disadvantaged firms in technological innovation; and increase private sector commercialization of federal R&D.$$, NULL, 0, 0, 0, NULL, NULL, 191, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 585723000, 0, 0, 0, NULL, 0, 0, $$The Department of the Navy (DON) SBIR Program is a mission-oriented program that delivers innovative solutions to Naval requirements through a three-phase competitive awards process. Qualified small business concerns propose dual-use solutions, that primarily address naval needs, to Research and Development (R&D) topics aligned to Program Offices with resources to transition R&D-developed technology to warfighting capability. The SBIR Program requires each Federal agency that has an extramural budget for Research and Development in excess of $100,000,000 to set aside 3.2% for SBIR to engage domestic small businesses in Federal Research/Research and Development (R/R&D) and chart a path toward commercialization. The program's statutory goals are to stimulate technological innovation; increase small business participation in federally funded R&D; and increase private sector commercialization of federal R&D.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605502S$$, $$Small Business Innovative Research (SBIR)$$, $$rdte_dw_ba6$$, $$dw_dla$$, 2026, 0, 8468000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605502S", "page_header": "Defense-Wide"}$$::jsonb, $$Defense Logistics Agency’s (DLA's) ability to deliver Americans the right logistics solution in every transaction requires more than successful management of the Agency's wholesale supplies and suppliers. It requires supply chain excellence. Our military's ability to generate and sustain combat readiness indefinitely, anywhere on the globe requires that DLA-managed materiel flow seamlessly and as needed from the nation's industrial base to where it is ultimately used. DLA's Small Business Innovative Research (SBIR) program seeks to solicit innovative research and development proposals from the small business community to address DLA’s strategic and operational requirements. All selections shall demonstrate and involve some technical risk with yet to be determined technical feasibility. Phase I proposals should demonstrate the feasibility of the proposed technology and provide a strong business case for Phase II investment for a prototype or at least a proof-of-concept demonstration. A favorable return on investment and commercialization potential have a strong influence on Phase II selections.$$, NULL, NULL, NULL, NULL, NULL, NULL, 185, $$RDTE_DLA_PB_2026.pdf$$, $$DLA$$, FALSE, 9711000, 0, NULL, NULL, NULL, NULL, NULL, $$Defense Logistics Agency’s (DLA's) ability to deliver Americans the right logistics solution in every transaction requires more than successful management of the Agency's wholesale supplies and suppliers. It requires supply chain excellence. Our military's ability to generate and sustain combat readiness indefinitely, anywhere on the globe requires that DLA-managed materiel flow seamlessly and as needed from the nation's industrial base to where it is ultimately used. DLA's Small Business Innovative Research (SBIR) program seeks to solicit innovative research and development proposals from the small business community to address DLA’s strategic and operational requirements. All selections shall demonstrate and involve some technical risk with yet to be determined technical feasibility. Phase I proposals should demonstrate the feasibility of the proposed technology and provide a strong business case for Phase II investment for a prototype or at least a proof-of-concept demonstration. A favorable return on investment and commercialization potential have a strong influence on Phase II selections.$$, $$Budget J-Books/FY27/Remaining/RDTE_DLA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605504N$$, $$Multi-Mission Maritime (MMA) Inc III$$, $$rdte_navy_ba5$$, $$peo_aasm$$, 2026, 103397000, 123347000, 124366000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 35, "original_pe": "0605504N", "page_header": "Department of the Navy"}$$::jsonb, $$The P-8A Increment 3 program consists of incremental enhancement Engineering Change Proposals (ECPs) to system capabilities that will retain cost-wise effectiveness for major combat operations. Increment 3 will incorporate improvements to aircraft systems including significant war-altering Anti-Submarine Warfare (ASW) capabilities of Enhanced Multi-Static Active Coherent (MAC-E) and ASW Signal Intelligence (SIGINT) which are enabled by the incorporation of Combat System hardware and architecture improvements, ASW and Anti-Surface Warfare (ASuW) sensor improvements, communication capability upgrades, ASuW Net Enabled Weapon (NEW), Higher-Than-Secret (HTS) security capability, and associated pre/post-flight ground system development to support Increment 3 aircraft and Increment 3 ground system requirements. These capabilities will be developed as a series of ECPs for the P-8A and are as follows: - ECP 6 - ASW SIGINT, Anti-Submarine Warfare (ASW) capability, Wide Band SATCOM, Higher Than Secret (HTS) processing, Enhanced track management (Minotaur), Applications Based Architecture (ABA) and Combat System. - ECP 7 - Enhanced Multi-Static Active Coherent (MAC-E). - Pre/Post-Flight Ground System Development - System upgrades to the associated ground support system and Tactical Operations Center (TOC)/Aircraft Media Gateway (AMG) systems. To expedite fielding of the ASW critical capability to the P-8A Fleet, ECP 6 and ECP 7 software are being integrated concurrently on to the platform. ECP 7 is reliant on ECP 6's Combat System hardware and architecture to operate on the P-8A. Enhanced MAC-E (ECP 7) is developed within Program Element (PE) 0604261N and integrated via the Platform Integration contract within this PE. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes requirements identified under the baseline P-8 program between Milestone B and the Full Rate Production Decision (FRPD). Subsequent to the P-8 FRPD, the DoD Acquisition Authority directed in 2016 these Increment 3 requirements be satisfied as Engineering Change Proposals (ECPs) under the existing P-8 program vice under a separate acquisition program. Note: ECP 6/7 fielding planned with initial scheduled Fleet deployment in 3Q FY 2026. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0605504N / Multi-Mission Maritime (MMA) Inc III Development & Demonstration (SDD)$$, NULL, 9732000, 0, 0, NULL, NULL, 173, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 120834000, 103397000, 52951000, 52951000, NULL, 52951000, 0, $$The P-8A Increment 3 program consists of incremental enhancement Engineering Change Proposals (ECPs) to system capabilities that will retain cost-wise effectiveness for major combat operations. Increment 3 will incorporate improvements to aircraft systems including significant war-altering Anti-Submarine Warfare (ASW) capabilities of Enhanced Multi-Static Active Coherent (MAC-E) and ASW Signal Intelligence (SIGINT) which are enabled by the incorporation of Combat System hardware and architecture improvements, ASW and Anti-Surface Warfare (ASuW) sensor improvements, communication capability upgrades, ASuW Net Enabled Weapon (NEW), Higher-Than-Secret (HTS) security capability, and associated pre/post-flight ground system development to support Increment 3 aircraft and Increment 3 ground system requirements. These capabilities will be developed as a series of ECPs for the P-8A and are as follows: - ECP 6 - ASW SIGINT, Anti-Submarine Warfare (ASW) capability, Wide Band SATCOM, Higher Than Secret (HTS) processing, Enhanced track management (Minotaur), Applications Based Architecture (ABA) and Combat System. - ECP 7 - Enhanced Multi-Static Active Coherent (MAC-E). ECP 7 software are being integrated concurrently on to the platform. ECP 7 is reliant on ECP 6's Combat System hardware and architecture to operate on the P-8A. Enhanced MAC-E (ECP 7) is developed within Program Element (PE) 0604261N and integrated via the Platform Integration contract within this PE. - Pre/Post-Flight Ground System Development - System upgrades to the associated ground support system and Tactical Operations Center (TOC)/Aircraft Media Gateway (AMG) systems. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes requirements identified under the baseline P-8 program between Milestone B and the Full Rate Production Decision (FRPD). Subsequent to the P-8 FRPD, the DoW Acquisition Authority directed in 2016 these Increment 3 requirements be satisfied as Engineering Change Proposals (ECPs) under the existing P-8 program vice under a separate acquisition program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System            PE 0605504N / Multi-Mission Maritime (MMA) Inc III Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605512N$$, $$MEDIUM UNMANNED SURFACE VEHICLES (MUSVs)$$, $$rdte_navy_ba4$$, $$peo_usc$$, 2026, 39426000, 152005000, 101838000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 31, "original_pe": "0605512N", "page_header": "Department of the Navy"}$$::jsonb, $$Projects under this Program Element provide resources for the unmanned platforms in the Navy's Future Surface Combatant Force (FSCF), Medium Unmanned Surface Vehicle (MUSV), Sea Hunter, and Seahawk. No Manning Required Ship (NOMARS) is also planned to transition from DARPA to PMS406 in FY 2025, which will be vital in the technology development and risk reduction efforts to support the MUSV PoR. MUSV is defined as having a reconfigurable mission capability which is accomplished via modular payloads with an initial capability to support Battlespace Awareness through supporting Intelligence, Surveillance, Reconnaissance, and Targeting (ISR-&T), Counter-ISR&T, and Information Operations (IO) mission areas. MUSVs provide affordable, high endurance, reconfigurable ships able to accommodate various payloads for unmanned missions and augment the Navy's manned surface force. MUSVs will be capable of autonomous operation, with operators in-the-loop or on-the-loop, as required. USV Command and Control (C2) will be maintained via an afloat element (i.e., embarked on a United States Navy (USN) combatant/other assigned afloat asset) or via an ashore element (C2 station ashore). While unmanned surface vehicles are new additions to fleet units, MUSV is intended to combine robust and proven commercial vessel specifications with existing military payloads to rapidly and affordably expand the capacity and capability of the surface fleet. The MUSV program leverages years of investment and full scale demonstration efforts in autonomy, endurance, command and control, payloads, and testing from the Defense Advanced Research Projects Agency (DARPA) Anti- Submarine Warfare Continuous Trail Unmanned Vessel (ACTUV), Office of Naval Research (ONR) Medium Displacement Unmanned Surface Vehicle (MDUSV)/Sea Hunter (FY 2017 to FY 2021), and Office of the Secretary of Defense Strategic Capabilities Office (OSD SCO) Ghost Fleet Overlord Large USV experimentation effort (FY 2018 to FY 2021). The combination of fleet-ready C2 solutions developed by the Ghost Fleet Overlord program and initial man-in-the-loop or man-on-the-loop control will reduce the risk of fleet integration of unmanned surface vehicles and allow autonomy and payload technologies to develop in parallel with fielding vehicles with standardized interfaces. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                  Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0605512N / MEDIUM UNMANNED SURFACE VEHICLES (MUSVs) Component Development & Prototypes (ACD&P) Small Unmanned Surface Vehicle (sUSV) Family of Systems is designed to meet an urgent Geographic Combatant Command Requirement leveraging technologies developed by MUSV. sUSV is an inexpensive Maritime capability leveraging the best of commercial technology and innovations at speed and scale.$$, NULL, 0, 0, 0, NULL, NULL, 96, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 98858000, 0, 0, 0, NULL, 0, 0, $$Projects under this Program Element provide resources for the unmanned platforms in the Navy's Future Surface Combatant Force (FSCF), Medium Unmanned Surface Vehicle (MUSV) (also referred to as Modular Attack Surface Craft (MASC)), and the prototypes in the PMS 406 portfolio (Sea Hunter, Seahawk, Ranger, Mariner, Vanguard, and No Manning Required Ship (NOMARS). These vessels and prototypes are vital in the technology development and risk reduction efforts to support future USV efforts and to provide capability to the Fleet by providing platforms for employing various payloads. MUSV is defined as having a reconfigurable mission capability which is accomplished through the ability to interface with modular payloads to support various mission areas such as supporting Intelligence, Surveillance, Reconnaissance, and Targeting (ISR-&T), Counter-ISR&T, Kinetic payloads, and Information Operations (IO) mission areas. MUSVs provide affordable, high endurance, reconfigurable ships able to accommodate various payloads for unmanned missions and augment the Navy's manned surface force. MUSVs will be capable of autonomous operation, with operators in-the-loop or on-the-loop, as required. USV Command and Control (C2) will be maintained via an afloat element (i.e., embarked on a United States Navy (USN) combatant/other assigned afloat asset) or via an ashore element (C2 station ashore). While unmanned surface vehicles are new additions to fleet units, MUSV is intended to combine robust and proven commercial vessel specifications with existing military payloads to rapidly and affordably expand the capacity and capability of the surface fleet. The MUSV program leverages years of investment and full scale demonstration efforts in autonomy, endurance, command and control, payloads, and testing from the Defense Advanced Research Projects Agency (DARPA) Anti- Submarine Warfare Continuous Trail Unmanned Vessel (ACTUV), Office of Naval Research (ONR) Medium Displacement Unmanned Surface Vehicle (MDUSV)/Sea Hunter (FY 2017 to FY 2021), and Office of the Secretary of Defense Strategic Capabilities Office (OSD SCO) Ghost Fleet Overlord Large USV experimentation effort (FY 2018 to FY 2021). The combination of fleet-ready C2 solutions developed by the Ghost Fleet Overlord program and initial man-in-the-loop or man-on-the-loop control will reduce the risk of fleet integration of unmanned surface vehicles and allow autonomy and payload technologies to develop in parallel with fielding vehicles with standardized interfaces. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0605512N / MEDIUM UNMANNED SURFACE VEHICLES (MUSVs) Component Development & Prototypes (ACD&P) MASC will support the Navy's ability to produce, deploy and disburse ISR&T/C-ISR&T/IO capabilities in sufficient quantities and provide/improve distributed situational awareness in maritime Areas of Responsibility (AORs). These USVs will be capable of weeks-long deployments and trans-oceanic transits and can operate aggregated with Carrier Strike Groups (CSGs) and Surface Action Groups (SAGs), as well as independently. These USVs will be a key enabler of the Navy's Distributed Maritime Operations (DMO) concept. The Sea Hunter, Seahawk, Ranger, Marinera, Vanguard, and NOMARS prototypes are experimentation vessels operated by PMS406 and the Navy's Surface Development Squadron, and are currently homeported in San Diego, CA. Through continued operations and demonstrations utilizing prototypes, the Navy continues to gain valuable insights and lessons learned in the utilization of unmanned systems and their associated payloads. This knowledge influences both Concept of Operation/ Employment doctrine to guide fleet operations, as well as requirements documents for the MASC program. USV prototypes will provide a means for demonstrating a payload's ability to operate in an autonomous manner with no engineering support for multi-day operations simulating a MUSV operational environment. USV Prototypes will inform PMS 406 on technologies for MUSV that demonstrate successfully the Navy's ability to produce, deploy and disburse ISR&T/C- ISR&T/IO and Strike capabilities in sufficient quantities and provide/improve distributed situational awareness in maritime Areas of Responsibility (AORs). The FY 2026 spend plan for Medium Unmanned Surface Vehicles (UUVs) includes $0 funds of discretionary funding and $39,426 thousands of mandatory (reconciliation) for a total of $39,426 thousand.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605513N$$, $$UNMANNED SURFACE VEHICLE ENABLING CAPABILITIES$$, $$rdte_navy_ba4$$, $$peo_usc$$, 2026, 55712000, 162300000, 89372000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 31, "original_pe": "0605513N", "page_header": "Department of the Navy"}$$::jsonb, $$Project 3067, in partnership with industry partners, delivers integrated Unmanned Surface Vehicle (USV) capabilities critical to the Navy's Future Surface Combatant Force (FSCF) and Unmanned Surface Vehicle (USV) Family of Systems (FoS). This project focuses on advancing and transitioning key technologies, including: USV autonomy Command and Control (C2) Perception capabilities and track management Engineering Operations (EO) and Machinery Control System (MCS) Autonomy infrastructure: Unmanned Maritime Autonomy Architecture (UMAA), Naval Autonomy Test System (NATS), End-to-End Lab, and Unmanned C2 Lab Embarkable USV combat system and USV compatible launchers USV C4I Systems; leveraging a hybrid approach of commercial systems and industry unmanning Vehicle and payload integration Through at-sea and shore-based test events and fleet exercises, Project 3067 will demonstrate the maturity and effectiveness of these technologies, paving the way for their integration into USV programs that support manned-unmanned teaming and operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                  Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced            PE 0605513N / UNMANNED SURFACE VEHICLE ENABLING CAPABILITIES Component Development & Prototypes (ACD&P)$$, NULL, 287238000, 285888000, 287455000, NULL, NULL, 97, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 102122000, 24115000, 255135000, 255135000, NULL, 255135000, 292954000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. This Research, Development, Test, and Evaluation (RDT&E) Program Element (PE) executes the CNO's Hedge Strategy by funding the development, maturation, and integration of the Unmanned Surface Vehicle (USV) Family of Systems (FoS). The PE develops and tests the Tailored Offsets required to augment the main battle force, as mandated by the CNO's Fighting Instructions. The objective is to create and validate capabilities across a range of critical mission areas, including kinetic and non-kinetic effects, containerized multi-mission payloads, contested logistics, and Counter-Unmanned Aircraft Systems (CUAS). This PE funds the engineering and experimentation for the entire USV FoS, which includes systems such as the Medium Unmanned Surface Vehicle (MUSV), Small USV Family of Systems (sUSV FoS), Expeditionary One Way Attack (ExOWA), and the Autonomous Low Profile Vessel (ALPV), to forge a decisive warfighting advantage. This domain-centered portfolio of unmanned systems will support the integration of mission specific sensors and payloads to support current and future mission requirements, such as Intelligence Surveillance and Reconnaissance (ISR), Anti-Submarine Warfare (ASW), and Strike Warfare (STW) missions. The program functions as the foundry for unmanned surface warfare, transforming concepts and technology into validated, production-ready capabilities. It addresses the CNO's imperative to integrate Robotic and Autonomous Systems (RAS) into the standard force delivery model by establishing common interfaces, standards, and software for the portfolio. Through a warfighter-centric approach focused on rapid innovation and iterative testing, this PE prioritizes continuous experimentation to convert innovation into proven, effective capabilities ready for transition to procurement. The development activities within this PE enable a cohesive, mission-driven unmanned force design capable of executing Distributed Maritime Operations (DMO). The validated systems and technologies that result from this RDT&E effort provide the foundational designs for an agile and mobile force, intended to confound adversary detection and targeting and enable the fleet to seize and maintain the initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0605513N / UNMANNED SURFACE VEHICLE ENABLING CAPABILITIES Component Development & Prototypes (ACD&P) The FY 2026 spend plan for Unmanned Surface Vehicle Enabling Capabilities includes $3,712 thousand of discretionary and $315,330 thousand of mandatory for a total of $319,042 thousand.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605514M$$, $$GROUND BASED ANTI-SHIP MISSILE$$, $$rdte_navy_ba4$$, $$mc$$, 2026, 29004000, 33409000, 50916000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 31, "original_pe": "0605514M", "page_header": "Department of the Navy"}$$::jsonb, $$As the Marine Corps' first Ground Based Anti-Ship Missile (GBASM) capability, the Navy/Marine Expeditionary Ship Interdiction System (NMESIS) is a priority central to the Marine Corps' contribution to the Naval Expeditionary Force's (NEF) anti-surface warfare campaign. This is a critical Service modernization capability requirement focused specifically on countering the Nation's pacing threat. Ground based launchers add a new type of threat against a peer adversary, stress different surveillance, and offensive systems, are hard to detect and track in a cluttered environment and add a significant level of persistence and depth to existing anti-ship capabilities. NMESIS will be employed by Medium-range Missile (MMSL) batteries serving as part of Marine Littoral Regiments (MLR) conducting Expeditionary Advanced Base Operations (EABO) while persisting inside the adversary's Weapons Engagement Zone (WEZ). When integrated into sensor and communication networks supporting a naval/maritime mission thread, and synchronized with employment of other missile systems, the Marine Corps' MMSL battery will serve as a component of the NEF "stand-in force" in support of the naval sea control effort. This PE also develops improvements to the Naval Strike Missile. NMESIS consists of two Naval Strike Missiles (NSM) and a launcher/weapon control system integrated on to a ground-based, teleoperated carrier (called ROGUE- Fires). It will provide a ground based anti-access/area denial, anti-ship capability. This program includes design, development, and test of the NSM launcher, ROGUE- Fires carrier, Leader kit, Weapons Control System (WCS), NSM Improvements, and Command and Control (C2) connections to enable the transport and firing of NSMs. NMESIS makes use of proven sub-systems, such as the Joint Light Tactical Vehicle (JLTV) chassis, the U.S. Navy's Naval Strike Missile, and its WCS.$$, NULL, 44849000, 52890000, 45657000, NULL, NULL, 98, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 48953000, 57965000, 16307000, 16307000, NULL, 16307000, 30246000, $$As the Marine Corps' first Ground Based Anti-Ship Missile (GBASM) capability, the Navy/Marine Expeditionary Ship Interdiction System (NMESIS) is a priority central to the Marine Corps' contribution to the Naval Expeditionary Force's (NEF) anti-surface warfare campaign. This is a critical Service modernization capability requirement focused specifically on countering the Nation's pacing threat. Ground based launchers add a new type of threat against peer adversary, stress different surveillance, and offensive systems, are hard to detect and track in a cluttered environment and add a significant level of persistence and depth to existing anti-ship capabilities. NMESIS will be employed by Medium-range Missile (MMSL) batteries serving as part of Marine Littoral Regiments (MLR) conducting Expeditionary Advanced Base Operations (EABO) while persisting inside the adversary's Weapons Engagement Zone (WEZ). When integrated into sensor and communication networks supporting a naval/maritime mission thread, and synchronized with employment of other missile systems, the Marine Corps' MMSL battery will serve as a component of the NEF "stand-in force" in support of the naval sea control effort. This PE also develops improvements to the Naval Strike Missile. NMESIS consists of two Naval Strike Missiles (NSM) and a launcher/weapon control system integrated on to a ground-based, teleoperated carrier (called ROGUE- Fires). It provides a ground based anti-access/area denial, anti-ship capability. This program includes design, development, and tests of the NSM launcher, ROGUE- Fires carrier, Leader kit, Weapons Control System (WCS), NSM Improvements, and Command and Control (C2) connections to enable the transport and firing of NSMs. NMESIS makes use of proven sub-systems, such as the Joint Light Tactical Vehicle (JLTV) chassis, the U.S. Navy's Naval Strike Missile, and WCS. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced       PE 0605514M / GROUND BASED ANTI-SHIP MISSILE Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605516M$$, $$LONG RANGE FIRES$$, $$rdte_navy_ba4$$, $$peo_uw$$, 2026, 0, 29587000, 30092000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 31, "original_pe": "0605516M", "page_header": "Department of the Navy"}$$::jsonb, $$The Long Range Fires (LRF) program sought to provide Combatant Commanders with the ability to employ an agile, mobile, land-based system, capable of launching Tomahawk cruise missiles to complement surface and sub-surface launched missiles. The LRF weapon system consisted of a ROGUE-Fires carrier (same design as the Navy and Marine Corps Expeditionary Ship Interdiction System (NMESIS) carrier), integrated with a single cell MK-41 vertical launch system launcher (a similar configuration to those employed by the US Navy) for the employment of an encanistered Tomahawk missile, and Tactical Tomahawk Weapons Control System.$$, NULL, 0, 0, 0, NULL, NULL, 99, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 19934000, 0, 0, 0, NULL, 0, 0, $$The Long Range Fires (LRF) program sought to provide Combatant Commanders with the ability to employ an agile, mobile, land-based system, capable of launching Tomahawk cruise missiles to complement surface and sub-surface launched missiles. The LRF weapon system consisted of a ROGUE-Fires carrier (same design as the Navy and Marine Corps Expeditionary Ship Interdiction System (NMESIS) carrier), integrated with a single cell MK-41 vertical launch system launcher (a similar configuration to those employed by the US Navy) for the employment of an encanistered Tomahawk missile, and Tactical Tomahawk Weapons Control System. The LRF program was terminated. It was concluded that the LRF system was not able to be employed in austere, expeditionary, littoral environments. As a result, the Marine Corps, in conjunction with the Office of the Secretary of War, terminated the LRF program.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605518N$$, $$CONVENTIONAL PROMPT STRIKE (CPS)$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 798337000, 1076050000, 903927000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "navy", "page_num": 31, "fy27_mand_k": 451041, "original_pe": "0605518N", "page_header": "Department of the Navy", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Munitions"}$$::jsonb, $$Conventional Prompt Strike (CPS) capability will enable precise and timely strike in contested environments across multiple platforms. In coordination with the Army, the Navy CPS Program is designing a common All Up Round (AUR) comprised of a Common Hypersonic Glide Body (C-HGB) and a 34.5" two-stage booster. The Navy is responsible for C-HGB design and plans to assume responsibility for C-HGB production from the Army in FY 2026. The Navy will design, develop, and produce the missile booster, and will integrate the missile booster with the C-HGB. Each service will use the resulting common hypersonic missile while developing individual weapon control systems and launchers tailored for launch from sea or land. Development efforts under this program element lead to a weapon system capability that: (1) is non- ballistic over the majority of the flight path; (2) controls stage drop; (3) provides positive control and precision accuracy from launch to impact; (4) provides adequate cross-range/maneuverability to avoid over-flight issues; (5) provides prompt lethal effects on targets; and (6) is man-safe and deployable for surface and submerged platforms. The FY 2026 cost of the CPS Middle Tier of Acquisition effort is $798.337 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, NULL, 1101943000, 1122643000, 837191000, NULL, NULL, 100, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 874781000, 763394000, 1341416000, 1341416000, 451041000, 1792457000, 624011000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. Conventional Prompt Strike (CPS) capability will enable precise and timely strike in contested environments across multiple platforms. In coordination with the Army, the Navy CPS Program is designing a common All Up Round (AUR) comprised of a Common Hypersonic Glide Body (C-HGB) and a 34.5" two-stage booster. The Navy is responsible for C-HGB design and assumed responsibility for C-HGB production from the Army in FY 2026. The Navy will design, develop, and produce the missile booster, and will integrate the missile booster with the C-HGB. Each service will use the resulting common hypersonic missile while developing individual weapon control systems and launchers tailored for launch from sea or land. Development efforts under this program element lead to a weapon system capability that: (1) is non-ballistic over the majority of the flight path; (2) controls stage drop; (3) provides positive control and precision accuracy from launch to impact; (4) provides adequate cross-range/ maneuverability to avoid over-flight issues; (5) provides prompt lethal effects on targets; and (6) is man-safe and deployable for surface and submerged platforms. The FY 2027 budget for the Conventional Prompt Strike (CPS) program includes $1,341,416 thousand of discretionary funding to support design, development, and platform integration efforts of a hypersonic conventional strike weapon system and $451,041 thousand of mandatory funding to support the marinization of the Box Erector Launcher System (BELS) and acceleration of TI-development for a total of $1,792,457 thousand. The mandatory funds supports marinized BELs development and technical analysis; TI-27 system development efforts; threat mitigation, modeling, and analysis; cyber design and survivability efforts; and funding to support TI-27 Design Agent work. The FY 2027 cost of the CPS Middle Tier of Acquisition (MTA) effort is $868.890 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                     Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced              PE 0605518N / CONVENTIONAL PROMPT STRIKE (CPS) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605520M$$, $$MARINE CORPS AIR DEFENSE WEAPONS SYS$$, $$rdte_navy_ba7$$, $$mc$$, 2026, 90346000, 96443000, 86108000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 37, "original_pe": "0605520M", "page_header": "Department of the Navy", "fy26_v182_deferred": true, "fy26_v182_source_file": "RDTEN_BA7-8_Book.txt", "fy26_v182_source_line": 8403, "fy26_v182_supp_K_skipped": 35901, "fy26_v182_deferred_reason": "parser_disc_does_not_match_db_disc"}$$::jsonb, NULL, NULL, 50450000, 36078000, 32760000, NULL, NULL, NULL, NULL, NULL, FALSE, 82640000, 63863000, 133041000, 133041000, NULL, 133041000, 33425000, $$The modern battlefield has been irrevocably altered by the proliferation of low-altitude aerial threats, particularly Unmanned Aerial Systems (UAS). This program element directly confronts this new reality, ensuring the Marine Air-Ground Task Force (MAGTF) can not only survive but dominate in an increasingly transparent and lethal environment. It funds the critical modernization of our Low Altitude Air Defense (LAAD) capabilities, providing an essential protective shield for our maneuver forces, forward operating bases, and critical command posts against the full spectrum of aerial threats. To counter the immediate and ever-present danger posed by enemy drones, this program is aggressively pursuing more lethal and survivable Short-Range Air Defense (SHORAD) systems. A key component of this effort is the transition from the venerable HMMWV to the Joint Light Tactical Vehicle (JLTV) as the primary weapons platform. This move provides our LAAD Marines with a vehicle that offers superior armored protection and the maneuverability required to keep pace with the ground forces they are sworn to protect. This initiative is not a single upgrade but the beginning of a continuous modernization spiral, designed to field progressively more advanced Counter-UAS capabilities and ensure we remain ahead of the threat for the foreseeable future. Simultaneously, this PE addresses the more sophisticated threat of cruise missiles and other advanced aerial weapons with the development of the Medium Range Intercept Capability (MRIC). This system is designed to provide robust, dedicated defense for fixed and operationally fixed sites?the critical infrastructure that supports the entire MAGTF. While its primary mission is to defeat cruise missiles, MRIC also possesses a formidable capability against UAS and other aircraft that penetrate its engagement zone. Crucially, MRIC is not a standalone system. It is engineered to be fully integrated into the joint Integrated Air and Missile Defense (IAMD) architecture. This integration is vital, as it allows the Marine Corps to contribute to and benefit from a comprehensive, multi-layered defense, ensuring that from the individual Marine on the move to the most critical command installation, our forces are protected by a seamless and resilient air defense network. The FY 2026 spend plan amount for GBAD: Medium Range Intercept Capability (MRIC) includes $3,782 thousands of discretionary and $35,901 thousands of mandatory (reconciliation) for a total of $39,683 thousands. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational    PE 0605520M / MARINE CORPS AIR DEFENSE WEAPONS SYS Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605601A$$, $$Army Test Ranges and Facilities$$, $$rdte_army_ba6$$, $$afc$$, 2026, 425108000, 441173000, 466085000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605601A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) provides the institutional funding required to operate developmental Test and Evaluation (T&E) activities in accordance with Public Law 107-314 (National Defense Authorization Act for Fiscal Year 2003) Section 232 ("Objective for institutional funding of test and evaluation facilities") in support of Department of Defense (DoD) Program Executive Officers, Program and Product Managers, Research, Development, and Engineering Centers and to the Army Futures Command (AFC). Resources provided by this PE operate eight elements of the DoD Major Range and Test Facility Base (MRTFB): White Sands Test Center (WSTC) - White Sands Missile Range (WSMR), New Mexico; Aberdeen Test Center (ATC) - Aberdeen Proving Ground (APG), Maryland; Electronic Proving Ground (EPG), Arizona; Yuma Test Center (YTC) - Yuma Proving Ground (YPG), Arizona; Arctic Regions Test Center (ARTC) - Fort Greely, Alaska; Tropic Regions Test Centers (TRTC) at various locations; and West Desert Test Center (WDTC) and Biological Test Division (BTD) at Dugway Proving Ground (DPG), Utah. This PE also funds the Army's test capability at Redstone Test Center (RTC) - Redstone Arsenal, Alabama. This PE finances the overhead (institutional) test operating costs not billable to DoD test customers per DoD Instruction (DoDI) 3200.18 and DoD Financial Management Regulation (DoDFMR) 7000.14-R, which include: recurring test infrastructure/capability sustainment requirements; replacement of test equipment; test operating procedures; and test revitalization/upgrade projects to maintain $8.6 billion of T&E capabilities; and improvements to the safety, environmental protection, and efficiency of test operations. The T&E capabilities at these ranges have been uniquely established and are designated as national assets needed to support T&E requirements of funded acquisition programs across all Services, and are required to assure technical performance, adherence to safety requirements, reliability, logistics supportability, Title 10 Live Fire Test and Evaluation, transportability, environmental effects, cyber, electromagnetic effects, and quality of materiel in development and in production. This PE sustains the T&E capabilities required to support Army Transformation as well as other Army, Joint, or Other Service systems, materiel, and technologies. Types of systems scheduled for testing include, but are not limited to: Aircraft, Air Delivery, Unmanned Aerial Systems, Counter Unmanned Aerial Systems, Air and Missile Defense Systems, Engineering Equipment, Direct fire, Indirect fire, Ammunition, Automotive Systems both manned and unmanned, Intelligence Surveillance and Reconnaissance, Ground Soldier Systems, Missiles, Rockets, Mission Command Network, Tactical Command, Control, and Communications, Robotics/Unmanned Autonomous Systems, Soldier Lethality, Assured Position, Navigation and Timing, Title 10 Live-Fire Survivability, Nuclear survivability, directed energy, and extreme natural environments. These T&E capabilities enable Army Futures Command transformation efforts and readiness. This funding line supports T&E of Army Transformation Priority Programs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E           PE 0605601A / Army Test Ranges and Facilities Management Support The FY 2026 request was reduced by $5.143 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $2.454 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 461572000, 467110000, 469998000, NULL, NULL, 180, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 490192000, 436708000, 469723000, 469723000, NULL, 469723000, 473803000, $$This Program Element (PE) provides the institutional funding required to operate developmental Test and Evaluation (T&E) activities in accordance with Public Law 107-314 (National Defense Authorization Act for Fiscal Year 2003) Section 232 ("Objective for institutional funding of test and evaluation facilities") in support of Department of War (DoW) Program Executive Officers, Program and Product Managers, Research, Development, and Engineering Centers and to the Army Futures Command (AFC). Resources provided by this PE operate eight elements of the DoW Major Range and Test Facility Base (MRTFB): White Sands Test Center (WSTC) - White Sands Missile Range (WSMR), New Mexico; Aberdeen Test Center (ATC) - Aberdeen Proving Ground (APG), Maryland; Electronic Proving Ground (EPG), Arizona; Yuma Test Center (YTC) - Yuma Proving Ground (YPG), Arizona; Arctic Regions Test Center (ARTC) - Fort Greely, Alaska; Tropic Regions Test Centers (TRTC) at various locations; and West Desert Test Center (WDTC) and Biological Test Division (BTD) at Dugway Proving Ground (DPG), Utah. This PE also funds the Army's test capability at Redstone Test Center (RTC) - Redstone Arsenal, Alabama. This PE finances the overhead (institutional) test operating costs not billable to DoW test customers per DoD Instruction (DoDI) 3200.18 and DoW Financial Management Regulation (DoWFMR) 7000.14-R, which include: recurring test infrastructure/capability sustainment requirements; replacement of test equipment; test operating procedures; and test revitalization/upgrade projects to maintain $8.6 billion of T&E capabilities; and improvements to the safety, environmental protection, and efficiency of test operations. The T&E capabilities at these ranges have been uniquely established and are designated as national assets needed to support T&E requirements of funded acquisition programs across all Services, and are required to assure technical performance, adherence to safety requirements, reliability, logistics supportability, Title 10 Live Fire Test and Evaluation, transportability, environmental effects, cyber, electromagnetic effects, and quality of materiel in development and in production. This PE sustains the T&E capabilities required to support Army Transformation as well as other Army, Joint, or Other Service systems, materiel, and technologies. Types of systems scheduled for testing include, but are not limited to: Aircraft, Air Delivery, Unmanned Aerial Systems, Counter Unmanned Aerial Systems, Air and Missile Defense Systems, Engineering Equipment, Direct fire, Indirect fire, Ammunition, Automotive Systems both manned and unmanned, Intelligence Surveillance and Reconnaissance, Ground Soldier Systems, Missiles, Rockets, Mission Command Network, Tactical Command, Control, and Communications, Robotics/Unmanned Autonomous Systems, Soldier Lethality, Assured Position, Navigation and Timing, Title 10 Live-Fire Survivability, Nuclear survivability, directed energy, and extreme natural environments. This funding line supports T&E of Army Transformation Priority Programs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0605601A / Army Test Ranges and Facilities Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605602A$$, $$Army Technical Test Instrumentation and Targets$$, $$rdte_army_ba6$$, $$devcom_avmc$$, 2026, 69328000, 45679000, 74004000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605602A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line supports test and evaluation (T&E) of Army Transformation Initiative Priority Programs. This Program Element (PE) provides critical investments for development of: new test methodologies and standards; advanced test technology concepts; future T&E; advanced modeling, simulation and instrumentation prototypes; and full-scale development of T&E capabilities for the United States (U.S) Army Test and Evaluation Command (ATEC), which includes the Operational Test Command (OTC) at Ft Hood, Texas; Army Evaluation Center (AEC) and Aberdeen Test Center (ATC), Aberdeen Proving Ground, Maryland; White Sands Test Center (WSTC) at White Sands Missile Range (WSMR), New Mexico; Electronic Proving Ground (EPG), Fort Huachuca, Arizona; Yuma Test Center (YTC) at Yuma Proving Grounds (YPG), Arizona (including the Arctic Regions Test Center (ARTC), Fort Greely, Alaska and the Tropics Regions Test Center (TRTC), at various locations); and Redstone Test Center (RTC), Redstone Arsenal, Alabama. OTC consists of four forward Test Directorates (Airborne and Special Operations Test Directorate, Fort Liberty, North Carolina; Air and Missile Defense Test Directorate, Fort Bliss, Texas; Fires Test Directorate, Fort Sill, Oklahoma; and the Intelligence Electronic Warfare Test Directorate, Fort Huachuca, Arizona) together with four other Test Directorates (Aviation; Maneuver; Mission Command; Maneuver Support and Sustainment) at Ft Cavazos, Texas. These T&E capabilities are required to support T&E requirements of Army signature transformation efforts to support development of Multi-Domain Operations (MDO)- capable Forces. These activities enable readiness and support the development and fielding cycle of all Army acquisition programs including rapid fielding initiatives and programs of record. This funding modernizes existing T&E capabilities at all locations by refreshing unreliable, uneconomical, obsolete, and irreparable instrumentation, as well as incremental upgrades of hardware and software for modeling, simulation, and instrumentation systems to assure adequate test data collection capabilities. This data supports acquisition milestone decisions for all test mission areas throughout the Army including programs such as the 105-mm Mobile Howitzer, 30mm/40mm ammunition, Active Protection System (APS), AH-64 Block III, APR-39C(V)1 Radar, Army Integrated Air-Missile Defense (AIAMD), Lower Tier Air and Missile Defense Sensor (LTAMDS), Army Tactical Missile System (ATACMS), CH-47F Chinook, Command Post Computing Environment (CPCE), Command Post Mobility/Survivability (CPI2), Common Infrared Counter Measures (CIRCM), Counter Small Unmanned Aerial System (c-SUAS), Counter Rocket Artillery Mortar (C-RAM), Dismounted Assured PNT System (DAPS), Distributed Common Ground System - Army (DCGS-A), Capability Drop 2, , Enhanced Night Vision Goggle- Binocular (ENVG-B), Family of Medium Tactical Vehicles (FMTV), Guided Multiple Launch Rocket System (GMLRS), Human Machine Integrated Formations (HMI-F), Integrated Fires Protection Capability (IFPC), Integrated Tactical Network (ITN), Integrated Visual Augmentation System (IVAS), Javelin, Joint Air-to- Ground Missile (JAGM) for US Navy, Launch Effects (LE), Leader Radio, M109A7 Paladin/M992A3, M1A2 Abrams, M1E3 Abrams Modernization, M-2/3 Bradley Expedited Active Protection System (ExAPS), M-2/3 Bradley Fist, M776 Chrome Tube, Maneuver Short Range Air Defense (M-SHORAD) also known as SGT STOUT, ManPack (MP), Mounted Assured PNT System (MAPS), Next Generation Squad Weapon (NGSW), Patriot 3 (PAC-3), Precision Guidance Kit (PGK), Precision Strike Missile (PrSM), Shadow Tactical Unmanned Aircraft System (TUAS), Stinger Shelf life Extension Program (SLEP), Stryker, Systems for All Domain Sensing (ADS), Tactical Intelligence Targeting Access Node Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E           PE 0605602A / Army Technical Test Instrumentation and Targets Management Support (TITAN), Terminal High-Altitude Area Defense (THAAD), UH-60M Black Hawk, XM113, and XM30 Mechanized Infantry Combat Vehicle (MICV). Also supports Army Signature Transformation efforts to include Project Convergence and PNT Assessment Exercise (PNTAX). The FY 2026 request was reduced by $4 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.381 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 59111000, 59399000, 59033000, NULL, NULL, 181, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 71303000, 67775000, 62303000, 62303000, NULL, 62303000, 59618000, $$This Program Element (PE) provides critical investments for development of: new test methodologies and standards; advanced test technology concepts; future T&E; advanced modeling, simulation and instrumentation prototypes; and full-scale development of T&E capabilities for the United States (U.S) Army Test and Evaluation Command (ATEC), which includes the Operational Test Command (OTC) at Ft Hood, Texas; Army Evaluation Center (AEC) and Aberdeen Test Center (ATC), Aberdeen Proving Ground, Maryland; White Sands Test Center (WSTC) at White Sands Missile Range (WSMR), New Mexico; Electronic Proving Ground (EPG), Fort Huachuca, Arizona; Yuma Test Center (YTC) at Yuma Proving Grounds (YPG), Arizona (including the Arctic Regions Test Center (ARTC), Fort Greely, Alaska and the Tropics Regions Test Center (TRTC), at various locations); and Redstone Test Center (RTC), Redstone Arsenal, Alabama. OTC consists of four forward Test Directorates (Airborne and Special Operations Test Directorate, Fort Liberty, North Carolina; Air and Missile Defense Test Directorate, Fort Bliss, Texas; Fires Test Directorate, Fort Sill, Oklahoma; and the Intelligence Electronic Warfare Test Directorate, Fort Huachuca, Arizona) together with four other Test Directorates (Aviation; Maneuver; Mission Command; Maneuver Support and Sustainment) at Ft Cavazos, Texas. These T&E capabilities are required to support T&E requirements of Army signature transformation efforts to support development of Multi-Domain Operations (MDO)- capable Forces. These activities enable readiness and support the development and fielding cycle of all Army acquisition programs including rapid fielding initiatives and programs of record. This funding modernizes existing T&E capabilities at all locations by refreshing unreliable, uneconomical, obsolete, and irreparable instrumentation, as well as incremental upgrades of hardware and software for modeling, simulation, and instrumentation systems to assure adequate test data collection capabilities. This data supports acquisition milestone decisions across a large cross section of Army Warfighting capabilities. Included in this effort are programs for, Weapon Systems, Ammunition, Protection Systems, Rotary Wing, Command and Control, Soldier Systems, Navigation and Timing, Tactical Vehicles, Missiles, Unmanned Systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0605602A / Army Technical Test Instrumentation and Targets Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605604A$$, $$Survivability/Lethality Analysis$$, $$rdte_army_ba6$$, $$afc$$, 2026, 31306000, 37005000, 36815000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605604A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) funds objective vulnerability assessment products necessary for the inherently-governmental Army Test & Evaluation Command/Army Evaluation Center (ATEC/ AEC) mission and for the Research and Development and analysis communities. Products result from investigating, analyzing, assessing, experimenting and reporting on the survivability of Soldiers, and on the survivability, lethality and vulnerability (SLV) of the highest-priority Army and threat systems. Products are leveraged within the Army Futures Command (AFC), the Cross Functional Teams (CFTs) and Program Managers / Program Executive Offices (PM/PEO) to exercise constructive design influence over materiel development and to provide credible engineering-level underpinning and input to the Army Analytical Community. This PE provides quantitative analyses and data for fielded and developmental systems as the Army pursues its modernization priorities and ensures readiness through the fielding of lethal and survivable systems for multi-domain operations. This PE funds engineering level analysis and experimentation supporting all CFTs including Long Range Precision Fires systems, Next Generation Combat Vehicles, Future Vertical Lift, Network / Command, Control, Communications (C3I), Air & Missile Defense, Soldier Lethality, and other high Army priority efforts. Principal data and analysis domains are integrated materiel performance, cyber resilience, human engineering and performance, Electronic Warfare threat defense, and mission threat analysis. Assessments funded by this PE are conducted across the spectrum of multi-domain battlefield threats to include: guns, missiles, mines and other methods of inflicting physical damage; jammers, countermeasures, and other electronic warfare techniques; cyber threats from insiders to nation states; and directed energy weapons. Many different kinds of technical capabilities are used to generate these analyses, including specialized equipment, modeling & simulation, and experimental facilities. This PE ensures these capabilities can represent a live, virtual, or constructive hostile environment required for credible assessment, thus enabling evaluators, developers, users, and decision makers to make informed acquisition judgments. This technical data from earliest AFC experimentation to final operational test is retained and serves as AFC's repository of analysis and information for supporting an ever-improving body of evidence to drive Milestone Decisions. This body of evidence enables properly informed decisions concerning acquisition and production; maximizes Army overmatch in systems and tactics; informs investment priorities; and mitigates system weaknesses prior to actual combat. Technical data and analysis results funded by this PE are efficiently leveraged for many different Army uses, reducing total cost to the Army by eliminating the need for duplicative capabilities funded by individual system developers. Central funding of this mission assures accurate and consistent technical treatment across all formal system Evaluations, and across the Army's analytical community as it conducts analyses of alternatives and other studies. The United States (U.S.) Army Combat Capabilities Development Command (DEVCOM) and ATEC/AEC integrate the results from the work program into Army's formal Evaluation process to ensure ATEC can comply with its legally-mandated responsibility to assess system survivability along with effectiveness and suitability. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E           PE 0605604A / Survivability/Lethality Analysis Management Support The FY 2026 request was reduced by $0.167 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.39 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 31819000, 31994000, 31950000, NULL, NULL, 182, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 36815000, 31306000, 31283000, 31283000, NULL, 31283000, 32268000, $$This Program Element (PE) funds objective vulnerability assessment products necessary for the inherently-governmental Army Test & Evaluation Command/Army Evaluation Center (ATEC/ AEC) mission and for the Rresearch and development and analysis communities. Products result from investigating, analyzing, assessing, experimenting and reporting on the survivability of Soldiers, and on the survivability, lethality and vulnerability (SLV) of the highest-priority Army and threat systems. Products are leveraged within the Transformation & Training Command (T2COM), the Futures and Concepts Command (FCC), and Portfolio Acquisition Executives (PAEs) to exercise constructive design influence over materiel development and to provide credible engineering-level underpinning and input to the Army analytical community. This PE provides quantitative analyses and data for fielded and developmental systems as the Army pursues its modernization priorities and ensures readiness through the fielding of lethal and survivable systems for multi-domain operations. This PE funds engineering level analysis and experimentation supporting all PAEs including Fires, Command and Control (C2)/counter-C2, Maneuver Ground, Maneuver Air, Agile Sustainment and Ammunition, and Layered Protection & Chemical, Biological, Radiological & Nuclear (CBRN) and other Army priorities. Principal data and analysis domains are integrated materiel performance, cyber resilience, human engineering and performance, Electromagnetic Warfare (EW) threat defense, and mission threat analysis. Assessments funded by this PE are conducted across the spectrum of multi-domain battlefield threats to include: guns, missiles, mines and other methods of inflicting physical damage; jammers, countermeasures, and other electronic warfare techniques; cyber threats from insiders to nation states; and directed energy weapons. Many different kinds of technical capabilities are used to generate these analyses, including specialized equipment, modeling & simulation, and experimental facilities. This PE ensures these capabilities can represent a live, virtual, or constructive hostile environment required for credible assessment, thus enabling evaluators, developers, users, and decision makers to make informed acquisition judgments. The technical data from earliest T2COM/FCC experimentation through developmental testing and final operational test is retained and serves as T2COM's repository of analysis and information for supporting an ever-improving body of evidence to drive milestone decisions. This body of evidence enables properly informed decisions concerning acquisition and production; maximizes Army overmatch in systems and tactics; informs investment priorities; and mitigates system weaknesses prior to actual combat. Technical data and analysis results funded by this PE are efficiently leveraged for many different Army uses, reducing total cost to the Army by eliminating the need for duplicative capabilities funded by individual system developers. Central funding of this mission assures accurate and consistent technical treatment across all formal system Evaluations, and across the Army's analytical community as it conducts analyses of alternatives and other studies. The United States (U.S.) Army Combat Capabilities Development Command (DEVCOM) and ATEC/AEC integrate the results from the work program into Army's formal evaluation process to ensure ATEC can comply with its legally-mandated responsibility to assess system survivability, lethality and vulnerability (SLV) along with effectiveness and suitability. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E            PE 0605604A / Survivability/Lethality Analysis Management Support Work in this project is performed by the United States Army T2COM / FCC - Transformation Decision Analysis Center (TDAC).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605606A$$, $$Aircraft Certification$$, $$rdte_army_ba6$$, $$usasoc$$, 2026, 1887000, 2718000, 2201000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605606A", "page_header": "Department of the Army"}$$::jsonb, $$The Airworthiness Certification Program Element (PE) assures safe flight operation of Army aircraft and aviation systems by means of technical design approval and qualification of systems to appropriate airworthiness standards. This PE supports independent airworthiness qualification for all assigned developmental and in-production Army aircraft, both manned and unmanned, as required by Army Regulation (AR) 70-62, "Airworthiness of Aircraft Systems", and is essential for assuring the safe operation of Army aircraft. This PE performs engineering functions (design, analysis, testing, demonstrations, and system specification compliance) essential for certifying the airworthiness of nearly 20,000 assigned Army aircraft. This PE also supports: management/execution of the Army Military Airworthiness Certification Criteria (AMACC) program; management/execution of airworthiness approval for new systems and materiel changes for all assigned Army aircraft systems; airworthiness engineering support for major development/modification and future systems/subsystems requirements of the Program Executive Officer for Aviation (PEO AVN) and U.S. Army Special Operations Command's Technology Applications Program Office (TAPO); and management of test and evaluation processes in support of the airworthiness qualification process. The Airworthiness Certification PE also performs general research and development in support of aircraft qualification and overarching airworthiness projects that involve multiple aircraft models, and supports the application of other critical aviation subsystems onto Army aircraft. This PE also supports: airworthiness certification for military-use civil derivative aircraft technical qualification through the Federal Aviation Administration's Military Certification Office; development of airworthiness procedures, specifications, critical standards, and other design and qualification documents; participation in senior leadership mandated airworthiness tri-service activities (e.g., National Airworthiness Council) and international airworthiness related activities mandated by treaty (e.g., Flight Into Non-segregated Airspace (FINAS)). The Aircraft Certification line is the only legal means per fiscal law to proactively establish certification criteria for priority research areas per the Army Modernization Strategy being leveraged in Army Aviation programs of record. This includes airworthiness involvement in Technology Transition projects such as the Future Long Range Assault Aircraft, Advanced Unmanned Aircraft Systems, Modular Open System Architecture, Autonomy/Artificial Intelligence/Machine Learning, Digital Engineering, Electric and Hybrid Propulsion and additive manufacturing. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM), Aviation & Missile Center (AvMC), Redstone Arsenal, AL. The FY 2026 request was reduced by $0.143 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.012 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                      Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E          PE 0605606A / Aircraft Certification Management Support$$, NULL, 2015000, 1770000, 1680000, NULL, NULL, 183, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 2201000, 4887000, 1983000, 1983000, NULL, 1983000, 1715000, $$The Airworthiness Certification Program Element (PE) assures safe flight operation of Army aircraft and aviation systems by means of technical design approval and qualification of systems to appropriate airworthiness standards. This PE supports independent airworthiness qualification for all assigned developmental and in-production Army aircraft, both manned and unmanned, as required by Army Regulation (AR) 70-62, "Airworthiness of Aircraft Systems", and is essential for assuring the safe operation of Army aircraft. This PE performs engineering functions (design, analysis, testing, demonstrations, and system specification compliance) essential for certifying the airworthiness of nearly 20,000 assigned Army aircraft. This PE also supports: management/execution of the Army Military Airworthiness Certification Criteria (AMACC) program; management/execution of airworthiness approval for new systems and materiel changes for all assigned Army aircraft systems; airworthiness engineering support for major development/modification and future systems/subsystems requirements of the Program Executive Officer for Aviation (PEO AVN) and U.S. Army Special Operations Command's Technology Applications Program Office (TAPO); and management of test and evaluation processes in support of the airworthiness qualification process. The Airworthiness Certification PE also performs general research and development in support of aircraft qualification and overarching airworthiness projects that involve multiple aircraft models and supports the application of other critical aviation subsystems onto Army aircraft. This PE also supports: airworthiness certification for military-use civil derivative aircraft technical qualification through the Federal Aviation Administration's Military Certification Branch; development of airworthiness procedures, specifications, critical standards, and other design and qualification documents; participation in senior leadership mandated airworthiness tri-service activities (e.g., National Airworthiness Council) and international airworthiness related activities mandated by treaty (e.g., Flight Into Non-segregated Airspace (FINAS)). The Aircraft Certification line is the only legal means per fiscal law to proactively establish certification criteria for priority research areas per the Army Modernization Strategy being leveraged in Army Aviation programs of record. This includes airworthiness involvement in Technology Transition projects such as the Future Long Range Assault Aircraft, Advanced Unmanned Aircraft Systems, Modular Open System Architecture, Autonomy/Artificial Intelligence/Machine Learning, Digital Engineering, Electric and Hybrid Propulsion and advanced manufacturing. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM), Aviation & Missile Center (AvMC), Redstone Arsenal, AL. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E              PE 0605606A / Aircraft Certification Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605611M$$, $$MC AVS Development & Demonstration$$, $$rdte_navy_ba5$$, $$peo_lsmc$$, 2026, 44644000, 87681000, 46739000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 35, "original_pe": "0605611M", "page_header": "Department of the Navy"}$$::jsonb, $$This is a CMC Force Design program. ACV provides protected mobility to otherwise dismounted infantry formations and enables littoral maneuver from ship-to-shore and from shore-to-shore. Equipped with modern communications systems and weapons for infantry support-by-fire, the ACV significantly improves the ability of Fleet Marine Forces to access, seize, and hold key maritime terrain in the execution of Expeditionary Advanced Base Operations. The Amphibious Combat Vehicle is imperative to realizing Marine Corps requirements for Fleet Marine Force 2030. The capability to project power from the sea ensures joint freedom of maneuver against increasingly sophisticated area denial and anti-access strategies across the range of military operations in areas vital to our national interest. To this end, an ACV creates operational and tactical options through rapid maneuver on sea and land, provides for the seamless transition of combat power from sea to land, enables rapid response to crisis, enables the introduction of joint follow-on forces and can impose disproportionate costs on our enemies who must extend their defenses. This program has delivered the initial capability of Personnel variants (ACV-Ps) in November 2020 and delivered the initial capability of Command variants (ACV-Cs) in 1st quarter of FY 2025. The Improved Lethality variants (ACV-30s) are on track to deliver in the 3rd quarter of FY 2026, and Recovery variants (ACV-Rs) in the 1st quarter of FY 2028. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                               Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0605611M / MC AVS Development & Demonstration Development & Demonstration (SDD)$$, NULL, 5172000, 4400000, 2107000, NULL, NULL, 175, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 44472000, 49471000, 12461000, 12461000, NULL, 12461000, 2152000, $$This is a Commandant of the Marine Corps (CMC) Force Design program that provides protected mobility to otherwise dismounted infantry formations and enables littoral maneuver from ship-to-shore and from shore-to-shore. Equipped with modern communications systems and weapons for infantry support-by-fire. The ACV significantly improves the ability of Fleet Marine Forces to access, seize, and hold key maritime terrain in the execution of Expeditionary Advanced Base Operations. The Amphibious Combat Vehicle is imperative to realizing Marine Corps requirements for Fleet Marine Force. The capability to project power from the sea ensures joint freedom of maneuver against increasingly sophisticated area denial and anti-access strategies across the range of military operations in areas vital to our national interest. To this end, an ACV creates operational and tactical options through rapid maneuver on sea and land, provides for the seamless transition of combat power from sea to land, enables rapid response to crisis, enables the introduction of joint follow-on forces and can impose disproportionate costs on our enemies who must extend their defenses. This program delivered the initial capability of Personnel variants (ACV-Ps) in November 2020 and the initial capability of Command variants (ACV-Cs) in 1st quarter of FY 2025. The Improved Lethality variant (ACV-30s) is on track to deliver in the 3rd quarter of FY 2026, and the Recovery variant (ACV-Rs) in the 1st quarter of FY 2028. Starting in FY 2027, the program begins the transition from the Production & Deployment phase to the Operations & Sustainment phase of the System Development Lifecycle. As ACV-30 and ACV-R vehicles procured in prior years complete production and begin fielding to operational units, the program will develop, evaluate, and integrate capability improvements to mitigate emerging threats while providing lifecycle support to ensure cost-effective combat readiness. This is accomplished through continuous review of components and subsystems to maintain system supportability and safety, procurement of replacement systems for obsolescence, fielding of Engineering Change Proposals (ECPs) for capability improvements, reduced total ownership cost initiatives, and improved sustainment and readiness. The ACV Modernization and Sustainment Line evaluates, integrates, and procures modernized components and subsystems that impact safe and reliable use of the ACV Family of Vehicles, such as the Enhanced Situational Awareness system, Counter-small Unmanned Aerial Systems (C-sUAS), CROWS-Javelin, Active Protective System (APS), Programmable Airburst Munition (PABM), and incorporating new/emerging Command and Control technologies into the Command variant, as well Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System             PE 0605611M / MC AVS Development & Demonstration Development & Demonstration (SDD) as sustainment initiatives such as improved shocks, brake calipers, and Central Tire Inflation System (CTIS) to increase reliability, improve corrosion protection, and manage parts obsolescence.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605649D8Z$$, $$Acquisition Integration and Interoperability (AI2)$$, $$rdte_dw_ba5$$, $$dw$$, 2026, 13556000, 0, 15618000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 75, "fy27_mand_k": 575868, "original_pe": "0605649D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Defense Industrial Base"}$$::jsonb, $$The FY 2026 request for AI2 includes $13.556 million for AI2. The AI2 was established to create an enduring acquisition infrastructure for delivering integrated joint, system-of-systems capabilities, and establish the necessary policies, forums, and processes to (1) Enable the delivery of integrated defense capabilities, leveraging Military Department and service-specific system acquisition; (2) Drive adoption of threat-based mission thread analysis to inform acquisition, resourcing, and requirements decisions; and (3) Support acquisition portfolio reviews to drive resourcing and enterprise decisions. Program funding institutionalizes the lessons learned from the Department’s Competitive Advantage Pathfinders (CAP) and Integrated Acquisition Portfolio Reviews (IAPR) and aligns service-specific system acquisition programs, prototypes, and Science and Technology (S&T) projects to deliver joint integrated capabilities. The program executes studies, analyses, and pathfinding efforts to (1) Govern the processes across the Defense Acquisition System to integrate and align portfolios and programs across the lifecycle from Services, Office of the Secretary of Defense (OSD) Components, and Combatant Commands (COCOMs); (2) Create an enduring infrastructure, tools, and processes for Service and OSD teams to better integrate system-of-systems capabilities; and (3) Remove regulatory and institutional barriers towards leveraging service-unique acquisitions for joint requirements.$$, NULL, 95552000, 99234000, 102265000, NULL, NULL, 155, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 14167000, 13365000, 92689000, 92689000, 575868000, 668557000, 105183000, $$The FY 2027 request for Acquisition Integration and Interoperability (AI2) includes $92,689 thousand of discretionary and $575,868 thousand of mandatory for a total of $668,557 thousand. The mandatory funds support Program 952 Acquisition Integration and Interoperability which delivers significant return on investment for the Department’s Acquisition Transformation Strategy through incentivizing development and execution of operational integration activities earlier in the development cycle of key systems when costs are lower. This funding will also support the expansion of the Defense Industrial Base through rapidly operationalizing mature capabilities from non-traditional or small business vendors that do not have immediate access to warfighters, test ranges, labs, or program offices. The Acquisition Integration and Interoperability (AI2) program spearheads the Department’s effort to create an enduring acquisition infrastructure for delivering integrated joint, system-of-systems capabilities, and establish the necessary policies, forums, and processes to (1) enable the delivery of integrated defense capabilities, leveraging Military Department and service-specific system acquisition; (2) drive adoption of threat-based mission thread analysis to inform acquisition, resourcing, and requirements decisions; and (3) support acquisition portfolio reviews to drive resourcing and enterprise decisions. The AI2 mission supports the Secretary of War's (SECWAR’s) goals of reforming our acquisition process and rapidly fielding emerging technologies. Program institutionalizes the lessons learned from the Department’s Competitive Advantage Pathfinders (CAP) and Integrated Acquisition Portfolio Reviews (IAPR) and aligns service-specific system acquisition programs, prototypes, and Science and Technology (S&T) projects to deliver joint integrated capabilities. The program executes studies, analyses, and pathfinding efforts to (1) govern the processes across the Defense Acquisition System to integrate and align portfolios and programs across the lifecycle from Services, Office of the Secretary of War (OSW) Components, and Combatant Commands (COCOMs); (2) executes operational integration to support the acceleration of joint, low-cost, near-term capabilities and create an enduring infrastructure, tools, and processes for Service and OSW teams to better integrate system-of-systems capabilities; and (3) remove regulatory and institutional barriers towards leveraging service-unique acquisitions for joint requirements. Program supports the Joint Operational Integration Program (JOIP) to execute operational integration costs to facilitate, enable, and accelerate capability development and delivery of joint capabilities. The JOIP agilely applies funding against existing or emerging systems requiring system-of-systems integration, rapid operationalization of new or dual-use technologies, or sharing capabilities across the Services. The JOIP is a critical part of the Department’s Acquisition Transformation Strategy and will deliver significant return on investment through incentivizing developing and executing operational integration activities earlier in the development cycle of key systems when costs are lower. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:         PE 0605649D8Z / Acquisition Integration and Interoperability (AI2) System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605706A$$, $$Materiel Systems Analysis$$, $$rdte_army_ba6$$, $$cft_lrpf$$, 2026, 19100000, 23402000, 23338000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605706A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) resources the U.S. Army Combat Capabilities Development Command (DEVCOM) Analysis Center (DAC) to conduct integrated material performance analyses to support Army decisions in technology, materiel acquisition, and the design, development, fielding and sustainment of Army materiel systems. The analysis products funded by this PE are leveraged to support Materiel Acquisition decisions and influence the design, development, and sustainment of Army weapon/materiel systems in support of the current and future force in the areas of Long-Range Precision Fires, Next Generation Combat Vehicles, Future Vehicle Lift, Network/Command, Control, Communications and Intelligence, Air and Missile Defense, Soldier Lethality and other Army Priority efforts. As the Army's center for integrated materiel performance analysis, the DAC supports Army and Department of Defense (DoD) decision makers throughout the entire acquisition process in responding to analytical requirements across the full spectrum of materiel. The DAC's unique in-house, consistent, integrated analytical capability provides the U.S. Army Futures Command (AFC) and Army leadership with timely, independent, unbiased, reliable, and high quality analysis to support complex decisions required for Current Operations and the development of the Future Force. The DAC's integrated set of skills, tools, and data repository are focused on the highest Army Priorities with a core mission to build the body of evidence and deliver objective analysis and experimentation across the entire life cycle to ensure Readiness today and a more lethal Future Force tomorrow. This PE develops and certifies system level, and systems-of-systems level, performance and effectiveness data across a broad range of capabilities such as target acquisition, probability of inflicting catastrophic damage, personnel and vehicle survivability, mobility, network, system reliability, and several additional capability areas used in Army studies. The PE funds the development of item-level performance methodology, and Models and Simulations (M&S) for the current and future operational environments and emerging threats. The M&S capabilities support the development, linkage and accreditation of live, virtual, and constructive simulations, and provide unique tools that support systems analysis of individual systems and the combined arms environment. This M&S infrastructure provides a hierarchical modeling framework that is unique to the DAC and allows for a comprehensive performance and effectiveness analysis and prediction capability that can be utilized to support trade-off and investment decisions prior to extensive and expensive hardware testing of proposed systems/technologies. This PE funds the Center for Reliability Growth (CRG), to develop critical tools, methodologies, policies, guidance and educational materials required to help acquisition programs achieve required reliability during the acquisition process. The CRG develops and applies engineering approaches to assess the reliability of Army materiel and provides recommendations on ways to improve reliability, thereby, reducing logistics footprints and life cycle costs, and extending failure-free periods for materiel. The CRG has developed an integrated set of skills and tools focused on its core competencies to be responsive in delivering objective data and analysis across the entire life cycle to ensure Readiness today and a more lethal future force tomorrow. The FY 2026 request was reduced by $0.142 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E            PE 0605706A / Materiel Systems Analysis Management Support$$, NULL, 19086000, 19122000, 19303000, NULL, NULL, 184, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 23338000, 19100000, 19013000, 19013000, NULL, 19013000, 19496000, $$This Program Element (PE) resources the U.S. Army Futures and Concepts Command (FCC) Transformation Decision Analysis Center (TDAC) to conduct integrated materiel performance analyses to support Army decisions in technology, materiel acquisition, and the design, development, fielding and sustainment of Army materiel systems. The analysis products funded by this PE are leveraged to support acquisition decisions and influence the design, development, and sustainment of Army weapon/materiel systems in support of the current and future force in Portfolio Acquisition Executive (PAE) areas of Fires, Command and Control (C2) and counter-C2, Maneuver Gound, Maneuver Air, Agile Sustainment & Ammunition, Layered Protection & Chemical, Biological, Radiological and Nuclear (CBRN), and other Army priority efforts. As the Army's center for integrated materiel performance analysis, the TDAC supports Army and Department of War (DoW) decision makers throughout the entire acquisition process in responding to analytical requirements across the full spectrum of materiel. The TDAC's unique in-house, consistent, integrated analytical capability provides the Transformation & Training Command (T2COM) and Army leadership with timely, independent, unbiased, reliable, and high quality analysis to support complex decisions required for current operations and the development of the Future Force. The TDAC's integrated set of skills, tools, and data repository are focused on the highest Army priorities with a core mission to build the body of evidence and deliver objective analysis and experimentation across the entire life cycle to ensure readiness today and a more lethal future force tomorrow. This PE develops and certifies system level, and systems-of-systems level, performance and effectiveness data across a broad range of capabilities such as target acquisition, probability of inflicting catastrophic damage, personnel and vehicle survivability, mobility, network, system reliability, and additional capability areas used in Army studies. The PE funds the development of item-level performance methodology, and Models and Simulations (M&S) for the current and future operational environments and emerging threats. The M&S capabilities support the development, linkage and accreditation of live, virtual, and constructive simulations, and provide unique tools that support systems analysis of individual systems and the combined arms environment. This M&S infrastructure provides a hierarchical modeling framework that is unique to the TDAC and enables a comprehensive performance and effectiveness analysis and prediction capability that can be utilized to support trade-off and investment decisions prior to extensive and expensive hardware testing of proposed systems/technologies. This PE funds the Center for Reliability Growth (CRG), to develop critical tools, methodologies, policies, guidance and educational materials required to help systems improve and achieve required reliability during the acquisition process. The CRG develops and applies engineering approaches to assess the reliability of Army materiel and provides recommendations on ways to improve reliability, thereby, reducing logistics footprints and life cycle costs, and extending failure-free periods for materiel. The CRG has developed an integrated set of skills and tools focused on its core competencies to be responsive in delivering objective data and analysis across the entire life cycle to ensure readiness today and a more lethal future force tomorrow. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0605706A / Materiel Systems Analysis Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605709A$$, $$Exploitation of Foreign Items$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 6277000, 7805000, 6245000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605709A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) will continue to support the acquisition, exploitation, and inventory of foreign ground materiel with potential advanced technology threats to United States (U.S.) systems, as well as emerging and destructive threats such as cyber vulnerabilities and biometric systems. The primary aim of the PE is to maximize the efficiency of research and development for force and materiel development by reducing the uncertainties associated with these threats. The PE also answers scientific and technical intelligence requirements, provides materiel for realistic testing and training, and aids in the development of countermeasures to threat systems, materiel, and technologies. Operations have increased the amount of captured threat materiel that require immediate exploitation to develop countermeasures and force protection measures for U.S. forces. Acquisition and exploitation are executed according to Army Foreign Materiel Program (FMP) Plan prioritization and with the approval of the Army Deputy Chief of Staff for Intelligence (G2).$$, NULL, 11109000, 11594000, 12434000, NULL, NULL, 185, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 6245000, 6277000, 10481000, 10481000, NULL, 10481000, 12347000, $$This Program Element (PE) will continue to support the acquisition, exploitation, and inventory of foreign ground materiel with potential advanced technology threats to United States (U.S.) systems, as well as emerging and destructive threats such as cyber vulnerabilities and biometric systems. The primary aim of the PE is to maximize the efficiency of research and development for force and materiel development by reducing the uncertainties associated with these threats. The PE also answers scientific and technical intelligence requirements, provides materiel for realistic testing and training, and aids in the development of countermeasures to threat systems, materiel, and technologies. Operations have increased the amount of captured threat materiel that require immediate exploitation to develop countermeasures and force protection measures for U.S. forces. Acquisition and exploitation are executed according to Army Foreign Materiel Program (FMP) Plan prioritization and with the approval of the Army Deputy Chief of Staff for Intelligence (G2).$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605711D8Z$$, $$Critical Technology Analysis$$, $$rdte_dw_ba6$$, $$dw_ousd_re$$, 2026, 11781000, 0, 11422000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 76, "original_pe": "0605711D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Office of the Under Secretary of Defense for Research and Engineering OUSD(R&E) works closely with the Military Services, Combatant Commands, industry, academia, and other stakeholders to ensure that the Department's critical technology area strategy addresses the key national security challenges- from rising seas to a rising China- that the United States faces today and will face in the future. Within OUSD(R&E), the Office of the Assistant Secretary of Defense for Critical Technologies OASD(CT) is responsible for managing and overseeing the set of critical technology areas (CTAs) vital to maintaining the United States' national security that are designated by the USD(R&E). While many technologies may cross between these categories, these groupings represent the broad and different approaches that are required to advance technologies crucial to the Department. By focusing efforts and investments into these designated critical technology areas, the Department will accelerate transitioning key capabilities to the Military Services and Combatant Commands. As the Department's technology strategy evolves and technologies change, the critical technology areas will be updated to the technology priorities. The Critical Technology Analysis (CTA) Program Element (PE) funds engineering, scientific, and analytical support for the designated CTAs and programs within OASD(CT). Funds in this PE directly support the organization and are critical to developing and continuously updating research and technology development roadmaps, studies, and analysis as required by Section 217 of the National Defense Authorization Act for fiscal year 2021. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:           PE 0605711D8Z / Critical Technology Analysis RDT&E Management Support$$, NULL, 16070000, 27124000, 18098000, NULL, NULL, 186, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 11129000, 11665000, 10913000, 10913000, NULL, 10913000, 32176000, $$The Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) is the focal point on all matters pertaining to the Department’s Research and Engineering (R&E) enterprise, technology development and transition, developmental prototyping, experimentation, and administration of testing ranges and activities. The OUSW(R&E) mission is to ensure continuous advancement of technology and innovation within the DOW enterprise and oversight lead for critical capabilities managed by defense agencies and field activities. Within OUSW(R&E), the Office of the Assistant Secretary of War for Critical Technologies OASW(CT) is responsible for managing and overseeing the set of critical technology areas (CTAs) vital to maintaining the United States' national security that are designated by the OUSW(R&E). While many technologies may cross between these categories, these groupings represent the broad and different approaches that are required to advance technologies crucial to the Department. By focusing efforts and investments into these designated critical technology areas, the Department will accelerate transitioning key capabilities to the Military Services and Combatant Commands. As the Department's technology strategy evolves and technologies change, the critical technology areas will be updated to the technology priorities. The Critical Technology Analysis (CTA) program funds engineering, scientific, and analytical support for the designated CTAs and programs within OASW(CT). Funds in this PE directly support the organization and are critical to developing and continuously updating research and technology development roadmaps, studies, and analysis as required by Section 217 of the National Defense Authorization Act for fiscal year 2021. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0605711D8Z / Critical Technology Analysis RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605712A$$, $$Support of Operational Testing$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 63637000, 74128000, 76088000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605712A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line supports testing of Army Transformation Priority Programs. This Program Element (PE) provides resources to the United States (U.S.) Army Test and Evaluation Command (ATEC) to operate the Army's Operational Test Command (OTC). OTC conducts independent operational tests that provide significant data to Army decision-makers on key Army systems and concepts. This PE finances recurring costs for OTC that are essential for conducting realistic and continuous testing in the critical areas of equipment, doctrine, force design and training. These recurring costs include civilian pay, requirements for test support contracts, sustainment of test technology, network support, temporary duty, training, supplies, and equipment. The FY 2026 request was reduced by $5.863 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.46 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 60280000, 61644000, 63371000, NULL, NULL, 186, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 75146000, 63637000, 60733000, 60733000, NULL, 60733000, 63969000, $$This funding line supports testing of Army Transformation Priority Programs. This Program Element (PE) provides resources to the United States (U.S.) Army Test and Evaluation Command (ATEC) to operate the Army's Operational Test Command (OTC). OTC conducts independent operational tests that provide significant data to Army decision-makers on key Army systems and concepts. This PE finances recurring costs for OTC that are essential for conducting realistic and continuous testing in the critical areas of equipment, doctrine, force design and training. These recurring costs include civilian pay, requirements for test support contracts, sustainment of test technology, network support, temporary duty, training, supplies, and equipment.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605712F$$, $$Initial Operational Test & Evaluation$$, $$rdte_af_ba6$$, $$aedc$$, 2026, 13872000, 13720000, 14247000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605712F"}$$::jsonb, $$The program element funds the Air Force Operational Test and Evaluation Center (AFOTEC) to conduct Congressionally mandated Initial Operational Test and Evaluation (IOT&E) to support major weapon system acquisition decisions beyond Low-Rate Initial Production (LRIP), Milestone C, full rate production, fielding, and declaration of Initial Operational Capability (IOC). For Major Defense Acquisition Programs (MDAP), the law requires IOT&E be completed under realistic operating conditions before proceeding beyond LRIP. IOT&E is planned to answer all critical operational issues (COI) as thoroughly as possible. IOT&E is conducted to determine the operational effectiveness and suitability, and resolve overall mission capability, of systems undergoing research and development (R&D) efforts. It is an evaluation of a system's performance when the complete system is tested and evaluated against operational criteria by personnel with the same qualifications as those who will operate, maintain, and support the system when deployed. In general, IOT&E is performed on new systems in development, major modifications, and other systems as directed. This PE also funds participation in Multiservice Operational Test and Evaluation (MOT&E), and Follow-on Operational Test and Evaluation (FOT&E) when it is the continuation of IOT&E activities passed the full rate production decision. FOT&E answers specific questions about unresolved COIs and test issues or completes areas not finished during the IOT&E. The PE funds related Operational Test & Evaluation (OT&E) activities such as conducting Continuous Operational Testing (COT), Early Influence, agile release tests, Integrated Test and Evaluation (IT&E), Operational Utility Evaluations (OUE), Early Operational Assessments (EOA), Operational Assessments (OA) and operationally realistic evaluations of advanced technologies which informs military utility determination. These tests support releases and major milestones and decision points prior to Milestone C, full rate production, fielding, or declaration of IOC. IOT&E programs are identified in four system categories: Air; Weapons; Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR); and Combat Support. This program element is driven by Congressional and DoD acquisition-mandated requirements for operational testing. AFOTEC schedules and executes tests according to the forecasted test readiness of the MDAP program offices. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E       PE 0605712F / Initial Operational Test & Evaluation Management Support$$, NULL, 14032000, 14293000, 14564000, NULL, NULL, 129, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 14247000, 13681000, 13562000, 13562000, 0, 13562000, 14859000, $$The program element funds the Air Force Operational Test and Evaluation Center (AFOTEC) to conduct Congressionally mandated Initial Operational Test and Evaluation (IOT&E) to support major weapon system acquisition decisions beyond Low-Rate Initial Production (LRIP), Milestone C, full rate production, fielding, and declaration of Initial Operational Capability (IOC). IOT&E is conducted to determine the operational effectiveness and suitability, and resolve overall mission capability, of systems undergoing research and development (R&D) efforts. This PE funds participation in Multiservice Operational Test and Evaluation (MOT&E), and Follow-on Operational Test and Evaluation (FOT&E) when the continuation of IOT&E activities passed the full rate production decision. FOT&E answers specific questions about unresolved COIs and test issues or completes areas not finished during the IOT&E. The PE funds related Operational Test & Evaluation (OT&E) activities such as conducting Continuous Operational Testing (COT), Early Influence, agile release tests, Integrated Test and Evaluation (IT&E), Operational Utility Evaluations (OUE), Early Operational Assessments (EOA), Operational Assessments (OA) and operationally realistic evaluations of advanced technologies which informs military utility determination. These tests support releases and major milestones and decision points prior to Milestone C, full rate production, fielding, or declaration of IOC. IOT&E programs are identified in three system categories: Air; Weapons; and Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR). This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E       PE 0605712F / Initial Operational Test & Evaluation Management Support$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605716A$$, $$Army Evaluation Center$$, $$rdte_army_ba6$$, $$afc$$, 2026, 62343000, 71118000, 73220000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605716A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line supports test and evaluation (T&E) of Army Transformation Priority Programs. This Program Element (PE) provides the resources to operate the Army Evaluation Center (AEC), the Army's independent evaluator for Army Futures Command (AFC) Cross Functional Team (CFT) efforts and all other Army and Joint Service programs (currently over 900 programs in total). AEC is the lead agent to plan, direct, and evaluate all required program testing and is the unbiased, independent authority for reporting on system progress to enable the Army to dominate in the multi-domain operational environment. AEC is the focal point in test strategy development, system safety verification, and data analyses from early developmental consumer tests through operational tests. AEC develops Critical Operational Issues and Criteria in conjunction with AFC to narrow the focus of testing to what is essential. AEC reviews and shapes system requirements to ensure they do not drive unnecessary testing. AEC provides critical independent assessments on system effectiveness, suitability, survivability (ESS), and safety to include cybersecurity; electronic warfare (EW); artificial intelligence (AI); machine learning (ML); safety of materiel solutions; and viability of emerging technologies and engineering change proposals to support major acquisition/fielding decisions including but not limited to acquisition milestones, materiel changes, and materiel releases. AEC is responsible for all assigned developmental and independent operational evaluations of Army materiel, information, and acquisition systems. AEC must remain independent from the development community. AEC assists the Chief of Staff of the Army decision making process by supporting Army Capabilities Integration Development System processes as well as supporting the AFC through the CFT concept. AEC evaluates operational effectiveness by determining if the system provides intended benefits to the Force. AEC assesses, confirms, and releases system safety for use by Soldiers upon fielding and during government sponsored experiments and demonstrations. AEC determines impacts to readiness through Human Systems Integration, Unit Systems Integration, and Army Systems Integration, as well as doctrine, organization, training, materiel, leadership and education, personnel, facilities, and policy impacts. AEC evaluates ballistics survivability and lethality missions, adversarial assessments/threat computer network operations, cooperative vulnerability and penetration assessments, and EW (attack, support) countermeasures in support of the National Defense Authorization Act 2016 Section 1647, establishment of Cybersecurity and Electromagnetic Affects. AEC manages, plans, and executes Information Assurance operational assessments during annual Combatant Command and Army Service exercises in support of the congressionally mandated Office of the Secretary of Defense Director, Operational Test and Evaluation assessment, and performs operational test agency duties for the Missile Defense System of Systems. This PE funds direct civilian labor and minimum non-labor requirements to include personnel training, career development, supplies and equipment, hardware, software, temporary duty travel, and other external Other Government Agency support as well as methodology development required to evaluate emerging technologies and instrumentation requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                               Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E               PE 0605716A / Army Evaluation Center Management Support AEC consists of seven directorates - Analytics, AI, and Digital Engineering Evaluation Directorate; Aviation-Fires Evaluation Directorate; Ballistic Missile Defense Evaluation Directorate (primarily funded by the Missile Defense Agency); Command, Control, Communications, Computers, Cyber, and Intelligence, Surveillance, Reconnaissance Evaluation Directorate; Mounted Systems Evaluation Directorate; Soldier Evaluation Directorate; and Survivability Evaluation Directorate - and a lean headquarters (HQ) element as AEC receives staff services from the Army Test and Evaluation Command HQ. AEC provides direct support to AFC with personnel geographically co-located with eight CFTs - Long Range Precision Fires; Next Generation Combat Vehicle; Future Vertical Lift; Network; Assured Positioning, Navigation, and Timing; Air and Missile Defense; Soldier Lethality; and Synthetic Training Environment - and the Rapid Capabilities Critical Technology Office and the AI Task Force. The AEC primary competencies are: identify what decision makers need to know; plan and direct T&E strategies; evaluate operational ESS, and safety; and provide senior leadership unbiased advice on Army and Joint Service programs. The FY 2026 request was reduced by $1.1 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.389 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 65768000, 66483000, 67339000, NULL, NULL, 187, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 73220000, 62343000, 65565000, 65565000, NULL, 65565000, 68245000, $$This funding line supports test and evaluation (T&E) of Army Transformation Priority Programs. This Program Element (PE) provides the resources to operate the Army Evaluation Center (AEC), the Army's independent evaluator for Army Futures Command (AFC) Cross Functional Team (CFT) efforts and all other Army and Joint Service programs (currently over 900 programs in total). AEC is the lead agent to plan, direct, and evaluate all required program testing and is the unbiased, independent authority for reporting on system progress to enable the Army to dominate in the multi-domain operational environment. AEC is the focal point in test strategy development, system safety verification, and data analyses from early developmental consumer tests through operational tests. AEC develops Critical Operational Issues and Criteria in conjunction with AFC to narrow the focus of testing to what is essential. AEC reviews and shapes system requirements to ensure they do not drive unnecessary testing. AEC provides critical independent assessments on system effectiveness, suitability, survivability (ESS), and safety to include cybersecurity; electronic warfare (EW); artificial intelligence (AI); machine learning (ML); safety of materiel solutions; and viability of emerging technologies and engineering change proposals to support major acquisition/fielding decisions including but not limited to acquisition milestones, materiel changes, and materiel releases. AEC is responsible for all assigned developmental and independent operational evaluations of Army materiel, information, and acquisition systems. AEC must remain independent from the development community. AEC assists the Chief of Staff of the Army decision making process by supporting Army Capabilities Integration Development System processes as well as supporting the AFC through the CFT concept. AEC evaluates operational effectiveness by determining if the system provides intended benefits to the Force. AEC assesses, confirms, and releases system safety for use by Soldiers upon fielding and during government sponsored experiments and demonstrations. AEC determines impacts to readiness through Human Systems Integration, Unit Systems Integration, and Army Systems Integration, as well as doctrine, organization, training, materiel, leadership and education, personnel, facilities, and policy impacts. AEC evaluates ballistics survivability and lethality missions, adversarial assessments/threat computer network operations, cooperative vulnerability and penetration assessments, and EW (attack, support) countermeasures in support of the National Defense Authorization Act 2016 Section 1647, establishment of Cybersecurity and Electromagnetic Affects. AEC manages, plans, and executes Information Assurance operational assessments during annual Combatant Command and Army Service exercises in support of the congressionally mandated Office of the Secretary of Defense Director, Operational Test and Evaluation assessment, and performs operational test agency duties for the Missile Defense System of Systems. This PE funds direct civilian labor and minimum non-labor requirements to include personnel training, career development, supplies and equipment, hardware, software, temporary duty travel, and other external Other Government Agency support as well as methodology development required to evaluate emerging technologies and instrumentation requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                               Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E               PE 0605716A / Army Evaluation Center Management Support AEC consists of seven directorates - Analytics, AI, and Digital Engineering Evaluation Directorate; Aviation-Fires Evaluation Directorate; Ballistic Missile Defense Evaluation Directorate (primarily funded by the Missile Defense Agency); Command, Control, Communications, Computers, Cyber, and Intelligence, Surveillance, Reconnaissance Evaluation Directorate; Mounted Systems Evaluation Directorate; Soldier Evaluation Directorate; and Survivability Evaluation Directorate - and a lean headquarters (HQ) element as AEC receives staff services from the Army Test and Evaluation Command HQ. AEC provides direct support to AFC with personnel geographically co-located with eight CFTs - Long Range Precision Fires; Next Generation Combat Vehicle; Future Vertical Lift; Network; Assured Positioning, Navigation, and Timing; Air and Missile Defense; Soldier Lethality; and Synthetic Training Environment - and the Rapid Capabilities Critical Technology Office and the AI Task Force. The AEC primary competencies are: identify what decision makers need to know; plan and direct T&E strategies; evaluate operational ESS, and safety; and provide senior leadership unbiased advice on Army and Joint Service programs.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605718A$$, $$Army Modeling & Sim X-Cmd Collaboration & Integ$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 11825000, 6136000, 11257000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605718A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) promotes the Army's Modeling and Simulation (M&S) strategy, defined by five guiding priorities: (1) formulate Army M&S policies; (2) develop and employ management processes for models, simulations and data; (3) develop M&S standards, architectures, networks and environments; (4) develop/ employ new M&S tools and simulation technology; (5) develop an M&S workforce. Specifically, this PE focuses on priorities 3 and 4 to include the modernization of the Center for Army Analysis (CAA) models, simulations, and analytic capabilities. M&S Standards, Architectures, Networks and Environments: The consistent use of standards, architectures, networks and environments advances the goal of interoperability. The Army coordinates with Joint, Interagency, Intergovernmental, and Multinational (JIIM) partners along with industry and academia to develop/employ standards that promote collaboration and facilitate the sharing of tools, data and information. The Army oversees procedures and processes for the appropriate use of standards to foster common formats and increase M&S and data reuse. The Army ensures these standards, architectures, networks and environments are readily accessible and can be reliably applied by users. M&S Tools and Simulation Technology: The Army must have credible M&S tools and data to support the full range of Army organizational missions and functional responsibilities. M&S results that are timely and credible enhance decision making. The Army must develop and accredit reliable M&S tools so that decision makers and senior leaders benefit from the results and thus support the continued development, integration and use of such tools. To ensure credibility and reliability of results, M&S managers, developers and users must make the capabilities, constraints, limitations and assumptions of their M&S tools readily accessible. PE 0605718A provides for the development and employment of tools in the form of models, simulations and data that support the full range of Army missions and deliver timely information to Army senior leaders. Moreover, these tools can be documented, verified, validated and accredited for their intended purpose in order to provide timely, credible results. This program element supports modernization of the analytic tools utilized by Center for Army Analysis. CAA conducts analysis of senior-level decisions for current and future national security issues. The suite of models, simulations, and analytic tools must remain relevant, current, and responsive to the ever-changing Operational Environment in order to support effectively the Army's analytic requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                  Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E                PE 0605718A / Army Modeling & Sim X-Cmd Collaboration & Integ Management Support This program element supports the Center for Army Analysis (CAA) mission to conduct decision support analysis across the spectrum of conflict in joint and multinational contexts for the purpose of supporting senior level decisions on current and future national security issues. In partial furtherance of this mission, CAA leverages a theater campaign model representing joint and combined operational maneuver that requires updating to suitably reflect emerging operational concepts such as Multi-Domain Operations. This program element enables realization of a modernized theater campaign analysis model that provides a tractable, flexible, and extensible representation of Army capabilities and their effects on major combat operations in crisis and conflict. The FY 2026 request was reduced by $0.668 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.015 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 15286000, 14517000, 14490000, NULL, NULL, 188, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 10846000, 11825000, 15608000, 15608000, NULL, 15608000, 14382000, $$This Program Element (PE) promotes the Army's Modeling and Simulation (M&S) strategy, defined by five guiding priorities: (1) formulate Army M&S policies; (2) develop and employ management processes for models, simulations and data; (3) develop M&S standards, architectures, networks and environments; (4) develop/ employ new M&S tools and simulation technology; (5) develop an M&S workforce. Specifically, this PE focuses on priorities 3 and 4 to include the modernization of the Center for Army Analysis (CAA) models, simulations, and analytic capabilities. M&S Standards, Architectures, Networks and Environments: The consistent use of standards, architectures, networks and environments advances the goal of interoperability. The Army coordinates with Joint, Interagency, Intergovernmental, and Multinational (JIIM) partners along with industry and academia to develop/employ standards that promote collaboration and facilitate the sharing of tools, data and information. The Army oversees procedures and processes for the appropriate use of standards to foster common formats and increase M&S and data reuse. The Army ensures these standards, architectures, networks and environments are readily accessible and can be reliably applied by users. M&S Tools and Simulation Technology: The Army must have credible M&S tools and data to support the full range of Army organizational missions and functional responsibilities. M&S results that are timely and credible enhance decision making. The Army must develop and accredit reliable M&S tools so that decision makers and senior leaders benefit from the results and thus support the continued development, integration and use of such tools. To ensure credibility and reliability of results, M&S managers, developers and users must make the capabilities, constraints, limitations and assumptions of their M&S tools readily accessible. PE 0605718A provides for the development and employment of tools in the form of models, simulations and data that support the full range of Army missions and deliver timely information to Army senior leaders. Moreover, these tools can be documented, verified, validated and accredited for their intended purpose in order to provide timely, credible results. This program element supports modernization of the analytic tools utilized by Center for Army Analysis. CAA conducts analysis of senior-level decisions for current and future national security issues. The suite of models, simulations, and analytic tools must remain relevant, current, and responsive to the ever-changing Operational Environment in order to support effectively the Army's analytic requirements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                  Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E                PE 0605718A / Army Modeling & Sim X-Cmd Collaboration & Integ Management Support This program element supports the Center for Army Analysis (CAA) mission to conduct decision support analysis across the spectrum of conflict in joint and multinational contexts for the purpose of supporting senior level decisions on current and future national security issues. In partial furtherance of this mission, CAA leverages a theater campaign model representing joint and combined operational maneuver that requires updating to suitably reflect emerging operational concepts such as Multi-Domain Operations. This program element enables realization of a modernized theater campaign analysis model that provides a tractable, flexible, and extensible representation of Army capabilities and their effects on major combat operations in crisis and conflict. The FY 2026 request was reduced by $0.668 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.015 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605755D8Z$$, $$Radiological and Nuclear Defense Modernization System Dev/Demo$$, $$rdte_dw_ba5$$, $$dw$$, 2026, 3307000, 0, 3575000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 75, "original_pe": "0605755D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This Program Element (PE) supports the Department's Defense Priorities to Rebuild our Military and Reestablish Deterrence. This PE supports the development and modernization of radiological and nuclear (R/N) defense capabilities that enable the Department to prevent R/N attacks on the homeland and Joint Force abroad through deterrence, as well as survive and operate in and through an R/N environment. This PE aligns to the Interim National Defense Strategy and addresses the challenges of keeping pace with our increasingly nuclear-capable adversaries through the development of modern R/N detection and identification capabilities that are networked into secure and hardened communications, command, and control (C3) systems. This PE supports the Office of the Under Secretary of Defense for Acquisition and Sustainment (OUSD(A&S)) Radiological and Nuclear Defense Capability Development (RNDCD) Program. The RNDCD Program is addressing the strategic objective of fielding modernized R/N detection capabilities to enable the Joint Force to operate more effectively in a R/N contaminated environment (Department of Defense (DoD) Strategic Management Plan for FY2022-2026). The RNDCD Program enhances DoD’s capabilities to campaign across the domains of threats and spectrums of conflict by improving the Department’s capability to campaign, fight, and win in a R/N environment. By building a R/N resilient Joint Force and National Guard Bureau, this program contributes to reestablishing deterrence by denying any strategic advantage our adversaries may perceive in using nuclear weapons on the homeland or Joint Force stationed abroad. This program is specifically geared to provide modern, networked R/N detection, indication, and identification capabilities to the warfighter and to replace obsolescing equipment, increasing capability to operate in a R/N environment (2023 CWMD Strategy). The RNDCD Program enables DoD to: prepare for and respond to any emergency involving nuclear and/or radiological events in the United States; provide a capability for the Joint Force to withstand, operate through, and recover from an R/N event; improve resilience; and promote integrated layered deterrence of WMD with state, local, and other federal agencies. This funding line is the only BA5 funding in the Department dedicated to providing improved R/N capability to the warfighter. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:               PE 0605755D8Z / Radiological and Nuclear Defense Modernization System Dev/Demo System Development & Demonstration (SDD) The Office of the Secretary of Defense uses the RNDCD Program to invest strategically in projects across the Military Services, Combatant Commands, and Defense Agencies. Funding is prioritized for projects that close Joint Force warfighter capability gaps. An annual investment strategy is used to meet emergent operational and capability needs which are validated by the Joint Force and the National Guard Bureau, yielding new fielded capabilities within one to three years. Through the Radiological and Nuclear Defense Modernization of Systems Development and Demonstration PE, the RNDCD Program will invest in the maturation of prototypes; integration of technologies, systems and components; developmental, environmental, and operational test and evaluation; and transition of capabilities that improve DoD’s capability to detect and identify radiological and nuclear threats. This program bridges the gap between basic research and fielded capabilities by accelerating and enabling the transition of technologies, by leveraging prior science and technology (S&T) investments made by the Department of Defense, other Federal agencies, and industry. Specifically, in FY2026, this PE will support the advanced development of (1) a hands-free, clandestine radiation detection system; (2) an underwater x-ray radiography system; (3) new detection systems using cadmium zinc telluride (CZT; (4) drop/leave behind sensors; (5) environmental testing for dismounted radiation sensors; (6) an R/N detection capability for GPS denied environments; and (7) phase ratio calibration for global nuclear detection monitors. All these projects will buy down Joint Force risk to mission and risk to force by ensuring efficient field detection systems that can identify and alert of the presence of radiation hazards. This program funds labor, materials, and travel to support the requirements of this program, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including RDT&E, assessments and analyses, research studies, education, and other activities related to capability development and fielding.$$, NULL, 3171000, 3200000, 3270000, NULL, NULL, 156, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 2041000, 3293000, 3090000, 3090000, NULL, 3090000, 3336000, $$This program supports the DoW’s priorities to Rebuild our Military and Reestablish Deterrence and supports the Office of the Under Secretary of War for Acquisition and Sustainment (OUSW(A&S)) Radiological and Nuclear Defense Capability Development (RNDCD) Program. It is dedicated to modernizing R/N capabilities for the warfighter. An annual investment strategy is used to meet emergent operational needs which are validated by the Joint Force and yield fielded capabilities within one to three years. The program supports the modernization of radiological and nuclear (R/N) defense capabilities that enable the Department to prevent R/N attacks on the homeland and the Joint Force abroad through integrated deterrence. The program provides the Joint Forces the tools needed to survive and operate in and through a R/N environment through networked R/N detection, indication, and identification capabilities in support of the National Defense Strategy’s deterrence by denial strategy and prioritization of the Nuclear Deterrence Posture within the FY 2027 Defense Planning Guidance. This program funds labor, materials, and travel to support the requirements of this program, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including Research, Development, Test, and Evaluation (RDT&E), assessments and analyses, research studies, education, and other activities related to capability development and fielding. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:         PE 0605755D8Z / Radiological and Nuclear Defense Modernization System Dev/Demo System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605766A$$, $$National Capabilities Integration (MIP)$$, $$rdte_army_ba5$$, $$peo_c3t$$, 2026, 16913000, 15129000, 16565000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605766A", "page_header": "Department of the Army"}$$::jsonb, $$Tactical Exploitation of National Capabilities (TENCAP) exploits national capabilities to pace evolving threats in support of operations during conflict and competition. TENCAP systems and technologies provide deep sensing to support commanders' situational understanding (patterns of life, threat intentions, etc.), indications & warnings (detection of enemy mobilization and hostile activity), and intelligence support to targeting (order of battle, electronic target folders, target detection, Battle Damage Assessment, etc.). TENCAP systems and technologies support Theater-level fires and effects, TENCAP systems enable integrated Signals Intelligence (SIGINT) / Electronic Warfare (EW) / and Cyberspace operations. TENCAP supports Army modernization priorities including Long Range Precision Fires, Assured Position Navigation and Timing/Space (PNT/S), Future Vertical Lift (FVL), and Air Missile Defense (AMD). In summary, TENCAP is a key enabler to defeating peer competitor Anti-Access / Area-Denial (A2/AD) strategies. This Program Element includes three separate projects described below. 1. Tactical Intelligence Targeting Access Node (TITAN) (BV3) - This project includes funding for system integration and testing of the TITAN Space Ground Station (SGS) that will provide Army units with assured access to space-based Intelligence, Surveillance, and Reconnaissance (ISR) sensor data from Commercial and National levels. The follow-on effort to the TITAN (SGS) is testing and integration of the Space Ground Component Kit (SGCK) into the TITAN program. The SGCK consists of antennas, other RF components, and other capabilities developed as part of the TITAN (SGS) effort. 2. National Integration to Tactical Systems (DX9) - This project enables the Army's Tactical Exploitation of National Capabilities (TENCAP) office to monitor, synchronize, and transition proven, advanced technologies, prototypes and standards, developed by the National Intelligence Community (IC), into Army tactical programs, systems and architectures during the most cost-effective, early stages of development. 3. Air Vigilance (AV) System Development (EX7) - This project provides System Development and Integration funds for the classified AV program. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                          Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System         PE 0605766A / National Capabilities Integration (MIP) Development & Demonstration (SDD)$$, NULL, 17410000, 17547000, 17557000, NULL, NULL, 167, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 16565000, 16913000, 17211000, 17211000, NULL, 17211000, 17732000, $$Tactical Exploitation of National Capabilities (TENCAP) exploits national capabilities to pace evolving threats in support of operations during conflict and competition. TENCAP systems and technologies provide deep sensing to support commanders' situational understanding (patterns of life, threat intentions, etc.), indications & warnings (detection of enemy mobilization and hostile activity), and intelligence support to targeting (order of battle, electronic target folders, target detection, Battle Damage Assessment, etc.). TENCAP systems and technologies support Theater-level fires and effects, TENCAP systems enable integrated Signals Intelligence (SIGINT) / Electronic Warfare (EW) / and Cyberspace operations. In summary, TENCAP is a key enabler to defeating peer competitor Anti-Access / Area-Denial (A2/AD) strategies. This Program Element includes three separate projects described below. 1.Tactical Intelligence Targeting Access Node (TITAN) (BV3) - This project includes funding for system integration and testing of the Space Ground Station (SGS) that will provide Army units with assured access to space-based Intelligence, Surveillance, and Reconnaissance (ISR) sensor data from Commercial and National levels. The follow-on effort to the SGS is testing and integration of the Space Ground Component Kit (SGCK) into the TITAN program. The SGCK consists of antennas, other RF components, and other capabilities developed as part of the SGS effort. 2. National Integration to Tactical Systems (DX9) - This project enables the Army's Tactical Exploitation of National Capabilities (TENCAP) office to monitor, synchronize, and transition proven, advanced technologies, prototypes and standards, developed by the National Intelligence Community (IC), into Army tactical programs, systems and architectures during the most cost-effective, early stages of development. 3. Air Vigilance (AV) System Development (EX7) - This project provides System Development and Integration funds for the classified AV program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System            PE 0605766A / National Capabilities Integration (MIP) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605772D8Z$$, $$Nuclear Command Control and Communications (NC3)$$, $$rdte_dw_ba5$$, $$dw$$, 2026, 3158000, 3935000, 3849000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 75, "fy27_mand_k": 7975, "original_pe": "0605772D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Defense Industrial Base"}$$::jsonb, $$This program supports the Under Secretary of Defense for Acquisition and Sustainment (OUSD(A&S)) roles as Principal Staff Assistant (PSA) for Nuclear Command Control and Communications (NC3) and NC3 Capability Portfolio Manager (CPM) as directed by the Secretary of Defense in the NC3 Governance Improvement (NGI) Implementation Plan and Department of Defense Directive 3730.02. The role of the NC3 PSA and NC3 CPM is to ensure alignment of NC3 acquisition, procurement, modernization, sustainment, interoperability and resources to deliver effective current and future NC3 capabilities, and proactively manage the NC3 portfolio to align NC3 programs with DoD nuclear weapons platform and delivery systems sustainment and modernization efforts. The NC3 Portfolio consists of approximately 200 systems, platforms, networks, and applications. The goals of the CPM are to 1) assess NC3 modernization programs and their integration, synchronization, and contribution to the NC3 enterprise, 2) monitor the readiness of operational NC3 systems, 3) identify performance gaps and make recommendations on technology upgrades and prototyping to enable the future capabilities to outpace the threat, and 4) support data-driven portfolio management by developing the necessary tools and processes to assess and manage integrated programmatic and technical risks. This includes the analytical expertise, and information storage and retrieval systems to support the continuing development of CPM for managing the complex NC3 enterprise. These efforts will simultaneously support the Commander, U.S. Strategic Command (USSTRATCOM) as NC3 Enterprise Lead; NC3 Enterprise Center (NEC); systems engineering and architecture development entities; the Under Secretary of Defense for Research and Engineering (USD(R&E)), the Joint Staff, and the Services. This program supports the capability portfolio-based approach (DoD Directive 7045.02, “Capability Portfolio Management”). This program funds development of new tools, technical assessments, and planning for the CPM to manage the NC3 enterprise. This includes: 1) developing analytical tools for improving NC3 enterprise-level management and programmatic and technical risk assessments; 2) supporting the office of primary responsibility for NC3 enterprise capability portfolio management, to include assessing current capability, complying with statutory mandates, and conducting NC3-related studies, analyses, and policy updates; 3) assessing DoD Component plans, programs, and budgets for adequacy and execution (including courses of action development and recommendations); 4) identifying, prototyping, evaluating, and recommending new technology for inclusion in the NC3 system; and 5) developing NC3 corrective action and risk mitigation plans to support the NC3 CPM investment recommendations to senior DoD leadership. . Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:         PE 0605772D8Z / Nuclear Command Control and Communications (NC3) System Development & Demonstration (SDD)$$, NULL, 2858000, 2870000, 2936000, NULL, NULL, 157, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 3708000, 3114000, 2985000, 2985000, 7975000, 10960000, 2995000, $$The FY 2027 request for Research, Development, Test & Evaluation, Defense-Wide for Under Secretary of War, Acquisition and Sustainment (USW(A&S)) includes $2,985 thousand of discretionary and $7,975 thousand of mandatory for a total of $10,960 thousand. The mandatory funds extend the NC3 Next Trade Space Study to analyze the appropriate mix of sensors, correlation centers, data processing computational needs, automation algorithms, and decision tools to support nuclear decision making when under threat of a growing quantity and type of missile threats. This analysis is currently ongoing under Phase 3 of the study, but the complexity of the modeling and simulation efforts will drive subsequent analysis that supports both USSTRATCOM as NC3 Enterprise Lead and the Golden Dome for America capabilities. Results will deliver acquisition ready solutions for decision and consideration in the FY 2029 program and budget review. Establish a program to commission a designated independent agency, such as a FFRDC to conduct an annual review of the NC3 Enterprise. This review would be executed independently but with access to Department plans, programs, data, and personnel. The agency would operate with a standing charter to provide a “Red Team” perspective on enterprise capabilities, vulnerabilities, strategies, and execution progress. The independent review would be chartered to establish a living oversight process focused on two primary efforts: first, tracking and assessing the Department's progress in addressing the findings and recommendations from the original Section 1649 report (i.e., "burning down" the action list); and second, continuously monitoring the evolving threat and technology landscape. This dynamic scope ensures the Department is held accountable for past findings while empowering the assessment and review team to generate new recommendations as adversaries develop new capabilities or as new technologies emerge that could strengthen or threaten the NC3 system. Deliver a tailored model-based analytical environment to support annual NC3 enterprise portfolio reviews that evaluate high priority risk areas and deliver decision-ready insight with supporting data. This effort expands a modeling tool built for the NC3 Next Trade Space Study to enable limited scope trade studies for near term risk areas that require resourcing and programmatic decisions by the NC3 Capability Portfolio Manager in the Office of the Under Secretary of War for Acquisition and Sustainment. In the upcoming fiscal year, this model would be tailored for the unique challenge associated with transitioning nearly 1,000 user terminals to a new constellation in an aggressive five-year timeframe Expand current efforts to protect critical information for NC3 Next Generation capabilities to address growing cyber threats, such as exfiltration of NC3 data from industrial base and the use of artificial intelligence to expose vulnerabilities. Establish guidelines, tools, and technical solutions for program offices to implement at the appropriate security classification level to address these risks. This program supports the Department's initiatives to Restoring Warrior Ethos, Rebuilding Military Capabilities and Re-establishing Deterrence Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                   Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:             PE 0605772D8Z / Nuclear Command Control and Communications (NC3) System Development & Demonstration (SDD) This program supports the Under Secretary of War for Acquisition and Sustainment (OUSW(A&S)) roles as Principal Staff Assistant (PSA) for Nuclear Command Control and Communications (NC3) and NC3 Capability Portfolio Manager (CPM) and Department of War Directive 3730.02. The role of the NC3 PSA and NC3 CPM is to ensure alignment of NC3 acquisition, procurement, modernization, sustainment, interoperability and resources to deliver effective current and future NC3 capabilities, and proactively manage the NC3 portfolio to align NC3 programs with DoW nuclear weapons platform and delivery systems sustainment and modernization efforts. The NC3 Portfolio consists of approximately 200 systems, platforms, networks, and applications. The goals of the CPM are to 1) assess NC3 modernization programs and their integration, synchronization, and contribution to the NC3 enterprise, 2) monitor the readiness of operational NC3 systems, 3) identify performance gaps and make recommendations on technology upgrades and prototyping to enable the future capabilities to outpace the threat, and 4) support data-driven portfolio management by developing the necessary tools and processes to assess and manage integrated programmatic and technical risks. This includes the analytical expertise, and information storage and retrieval systems to support the continuing development of CPM for managing the complex NC3 enterprise. These efforts will simultaneously support the Commander, U.S. Strategic Command (USSTRATCOM) as NC3 Enterprise Lead; NC3 Enterprise Center (NEC); systems engineering and architecture development entities; the Under Secretary of War for Research and Engineering (USW(R&E)), the Joint Staff, and the Services. This program supports the capability portfolio-based approach (DoW Directive 7045.02, “Capability Portfolio Management”). This program funds development of new tools, technical assessments, and planning for the CPM to manage the NC3 enterprise. This includes: 1) developing analytical tools for improving NC3 enterprise-level management and programmatic and technical risk assessments; 2) supporting the office of primary responsibility for NC3 enterprise capability portfolio management, to include assessing current capability, complying with statutory mandates, and conducting NC3-related studies, analyses, and policy updates; 3) assessing DoW Component plans, programs, and budgets for adequacy and execution (including courses of action development and recommendations); 4) identifying, prototyping, evaluating, and recommending new technology for inclusion in the NC3 system; and 5) developing NC3 corrective action and risk mitigation plans to support the NC3 CPM investment recommendations to senior DoW leadership.. . Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:         PE 0605772D8Z / Nuclear Command Control and Communications (NC3) System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605790D8Z$$, $$Small Business Innovation Research (SBIR) Small Business Technolog$$, $$rdte_dw_ba6$$, $$dw_darpa$$, 2026, 5411000, 3831000, 5346000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0605790D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department of Defense’s three priorities: Defend the Nation, Take Care of Our People, and Succeed through Teamwork. This program provides funding for the administration of the Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) Program Office. The authority to establish SBIR and STTR programs is codified in 15 U.S.C. 638. The statutory goals of the programs are to stimulate technological innovation, meet federal research and development (R&D) needs, foster and encourage participation in innovation and entrepreneurship by women and socially or economically disadvantaged persons, and increase private sector commercialization of innovations from federal R&D funding. In addition, the STTR program aims to foster technology transfer through cooperative R&D between small businesses and research institutions. The DoD SBIR/STTR programs set-aside over two billion dollars annually defense-wide to competitively fund scientific and technical innovation to specifically address the interim National Defense Strategy (NDS) modernization priorities and the mission needs of participating DoD components. The DoD components participating in the SBIR/STTR programs include: Army, Navy, Air Force, Defense Advanced Research Projects Agency (DARPA), Missile Defense Agency (MDA), Defense Threat Reduction Agency (DTRA), U.S. Special Operations Command (SOCOM), Joint Science & Technology Office for Chemical & Biological Defense (CBD), Defense Logistics Agency (DLA), Defense Microelectronics Activity (DMEA), Defense Health Agency (DHA), Chief Digital and Artificial Intelligence Office (CDAO), Defense Human Resources Activity (DHRA), Quantum Science, National Geospatial Intelligence Agency (NGA), Basic Research Office (BRO), 5G/Future G, and Strategic Capabilities Office (SCO). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                       Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:        PE 0605790D8Z / Small Business Innovation Research (SBIR) Small Business Technolog RDT&E Management Support                                                    y Transfer (STTR)$$, NULL, 8657000, 8818000, 9051000, NULL, NULL, 187, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 5346000, 8411000, 8435000, 8435000, NULL, 8435000, 9251000, $$This program supports the Department of War’s (DoW) Office for Small Business Innovation, which is responsible for the oversight, management and execution of the DoW’s Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) programs. These programs are a primary driver for the Secretary of War’s key lines of effort and critical technology areas by directly contributing to the U.S. defense industrial base, helping to deter China, and defending the homeland through technological superiority. By investing nearly three billion dollars annually in American small businesses. The SBIR/STTR programs build a resilient and secure domestic innovation ecosystem, fielding cutting-edge capabilities for the Warfighter and reducing reliance on foreign supply chains. Furthermore, these funds ensure the DoW Office for Small Business Innovation can plan, manage, and execute the statutory intent and goals of SBIR/STTR as identified in 15 U.S.C. 638. The DoW components participating in the SBIR/STTR programs include: Army, Navy (to include the Marine Corps), Air Force, Space Force, Defense Advanced Research Projects Agency (DARPA), Missile Defense Agency (MDA), Defense Threat Reduction Agency (DTRA), U.S. Special Operations Command (SOCOM), Defense Logistics Agency (DLA), Defense Microelectronics Activity (DMEA), Defense Health Agency (DHA), Defense Human Resources Activity (DHRA), and the Office of the Undersecretary of War for Research and Engineering (OSW).$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605798D8Z$$, $$Defense Technology Analysis$$, $$rdte_dw_ba6$$, $$dw_osd$$, 2026, 45134000, 53734000, 45370000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0605798D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department’s initiatives to rebuilding the military by rapidly fielding emerging technologies. This program provides mission support to the USD(R&E) covering a wide range of studies and analysis in support of the R&E program and its impacts on the Department's decision to fund RDT&E efforts. Such activities include: (1) identification and development of new technological opportunities; (2) insertion of new technologies into warfighting systems and operations; and (3) management and evaluation of the effectiveness of technology programs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                 Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:           PE 0605798D8Z / Defense Technology Analysis RDT&E Management Support$$, NULL, 112559000, 116179000, 62627000, NULL, NULL, 189, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 25744000, 44826000, 165450000, 165450000, NULL, 165450000, 66110000, $$This program supports the Department’s initiatives to rebuilding the military by rapidly fielding emerging technologies. This program provides mission support to the Under Secretary of War (USW), Research and Engineering (R&E) covering a wide range of studies and analysis in support of the R&E program and its impacts on the Department's decision to fund RDT&E efforts. Such activities include: (1) identification and development of new technological opportunities; (2) insertion of new technologies into warfighting systems and operations; and (3) management and evaluation of the effectiveness of technology programs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0605798D8Z / Defense Technology Analysis RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605801A$$, $$Programwide Activities$$, $$rdte_army_ba6$$, $$usamrdc$$, 2026, 54172000, 86384000, 91895000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605801A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) supports the non-Army Management Headquarters Activity (non-AMHA) Research, Development, Test, and Evaluation (RDTE) functions in support of the operation and management of United States (U.S.) Army Combat Capabilities Development Command (DEVCOM) Centers, not identifiable with specific research and development projects. This PE also supports the management and operation of multiple, globally located DEVCOM International Technology Centers (ITCs). The ITCs play an integral role in the U.S. Army efforts for international cooperative research, development and interoperability, and fulfill international memoranda of understanding requirements. Programwide activities also include: Army Science Board studies; non-AMHA Medical Command support at the U.S. Army Medical Research and Development Command (USAMRDC); non-AMHA management and administrative functions at the U.S. Army Research Institute (ARI); and travel and administrative support to the North Atlantic Treaty Organization (NATO) Army Armaments Group (NAAG). The FY 2026 request was reduced by $2.075 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E            PE 0605801A / Programwide Activities Management Support The FY 2026 request was reduced by $0.185 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 51954000, 51532000, 50940000, NULL, NULL, 189, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 203513000, 54172000, 52978000, 52978000, NULL, 52978000, 51490000, $$This Program Element (PE) supports the non-Army Management Headquarters Activity (non-AMHA) Research, Development, Test, and Evaluation (RDTE) functions in support of the operation and management of United States (U.S.) Army Combat Capabilities Development Command (DEVCOM) Centers, not identifiable with specific research and development projects. This PE also supports the management and operation of multiple, globally located DEVCOM International Technology Centers (ITCs). The ITCs play an integral role in the U.S. Army efforts for international cooperative research, development and interoperability, and fulfill international memoranda of understanding requirements. Program wide activities also include: Army Science Board studies; non-AMHA Medical Command support at the U.S. Army Medical Research and Development Command (USAMRDC); non-AMHA management and administrative functions at the U.S. Army Research Institute (ARI); and travel and administrative support to the North Atlantic Treaty Organization (NATO) Army Armaments Group (NAAG). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0605801A / Programwide Activities Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605801KA$$, $$Defense Technical Information Center$$, $$rdte_dw_ba6$$, $$dw_dtic$$, 2026, 60209000, 65167000, 71247000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0605801KA", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 58574000, 59764000, 60973000, NULL, NULL, NULL, NULL, NULL, FALSE, 70709000, 60002000, 57576000, 57576000, NULL, 57576000, 62193000, $$The Defense Technical Information Center (DTIC) serves as the foundation of the Department of War's research and innovation ecosystem. As the central repository for all research and development activity—from planning through execution—DTIC is undergoing a pivotal transformation. By expanding its vast collections and integrating with advanced artificial intelligence and machine learning models, DTIC is evolving into a proactive tool for strategic foresight. This in turn will empower the Department with collective awareness, horizon scanning, and trend analysis, enabling DoW researchers to avoid duplication, deploy resources more efficiently and effectively, and deliver enhanced capabilities to our warfighters faster. The transformation of DTIC’s infrastructure and platform in support of an AI-enabled repository is a critical investment, designed to accelerate our technical maturity and secure decision advantage for senior leaders. To realize the full potential of its transformation, DTIC must cultivate strong partnerships across the research ecosystem. The vision of leveraging DoW’s strategic research assets and artificial intelligence and machine learning capabilities explicitly acknowledges that DTIC cannot achieve its goals in isolation. Strategic collaboration with the Joint Staff, military departments, Combatant Commands, Office of the Chief Digital and Artificial Intelligence Officer, OUSW Comptroller, DCAPE, DoW CIO, FFRDCs, etc. is paramount. These partnerships provide access to data sources, cutting-edge technologies, and specialized expertise, that are essential for a complete collection and rapid integration of AI/ML for sophisticated analysis.$$, $$Budget J-Books/FY27/DW/RDTE_DTIC_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605803A$$, $$Technical Information Activities$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 26592000, 30422000, 32385000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 20, "original_pe": "0605803A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) supports oversight of the development and defense of the Army Science and Technology (S&T) budget, and development of Army S&T strategy, policy and guidance. Additionally, it supports upgrading the accuracy, timeliness, availability, and accessibility of scientific, technical, and management information at all levels of the Army Research and Development (R&D) community. Management of this information is critical to achieve the goals established by the Army's Senior Leadership. Use of accurate and timely technical information is essential to successfully meeting S&T transitions and milestones, allowing Army Science and Technology (S&T) leadership to refine investment strategy and quickly react to emerging opportunities and issues. This PE includes initiatives to improve information derivation, storage, access, display, validation, transmission, distribution, and interpretation, along with initiatives to develop and enhance a single business model for Army S&T knowledge management information technology and to provide for Independent Review Team analysis of technology maturity as part of the Technology Readiness Assessment. Develops and publishes Army S&T strategy and policies, sets Army S&T priorities, establishes and tracks S&T metrics to determine earned value and return on investment, and performs S&T studies in support of the ASA(ALT) in Project 727. Project 731 provides funding for support for Army high performance computing centers. Project 733 provides funding for improvements to the Army's acquisition process. Project CC2 provides funding for Expeditionary Technologies (xTech Search) to evaluate the feasibility and potential application of disruptive technologies to Army capability gaps. Project DW3 supports Army Geospatial Enterprise (AGE) Implementation with systems engineering, architecture, and test and certification of Army Acquisition Systems. The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology Critical Technology Areas and the Army Modernization Strategy. Work in this PE is performed by the Army Corps of Engineers' Engineer Research and Development Center (ERDC), Vicksburg, MS; the Army Geospatial Center (AGC) in Alexandria, VA; the Information Management Office, Arlington, VA; the Office of the Assistant Secretary of the Army, Acquisition, Logistics and Technology (ASA(ALT)), The Pentagon, Arlington, VA; Army Futures Command (AFC) Combat Capabilities Development Command (CCDC) Army Research Laboratory (ARL), Aberdeen Proving Ground, MD; and AFC CCDC Ground Vehicle Systems Center, Warren, MI. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E           PE 0605803A / Technical Information Activities Management Support The FY 2026 request was reduced by $6.87 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 27775000, 28464000, 31204000, NULL, NULL, 190, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 31508000, 26592000, 27004000, 27004000, NULL, 27004000, 31514000, $$This Program Element (PE) supports oversight of the development and defense of the Army Science and Technology (S&T) budget, and development of Army S&T strategy, policy and guidance. Additionally, it supports upgrading the accuracy, timeliness, availability, and accessibility of scientific, technical, and management information at all levels of the Army Research and Development (R&D) community. Management of this information is critical to achieve the goals established by the Army's Senior Leadership. Use of accurate and timely technical information is essential to successfully meeting S&T transitions and milestones, allowing Army Science and Technology (S&T) leadership to refine investment strategy and quickly react to emerging opportunities and issues. This PE includes initiatives to improve information derivation, storage, access, display, validation, transmission, distribution, and interpretation, along with initiatives to develop and enhance a single business model for Army S&T knowledge management information technology and to provide for Independent Review Team analysis of technology maturity as part of the Technology Readiness Assessment. Develops and publishes Army S&T strategy and policies, sets Army S&T priorities, establishes and tracks S&T metrics to determine earned value and return on investment, and performs S&T studies in support of the ASA(ALT) in Project 727. Project 731 provides funding for support for Army high performance computing centers. Project 733 provides funding for improvements to the Army's acquisition process. Project CC2 provides funding for Expeditionary Technologies (xTech Search) to evaluate the feasibility and potential application of disruptive technologies to Army capability gaps. Project DW3 supports Army Geospatial Enterprise (AGE) Implementation with systems engineering, architecture, and test and certification of Army Acquisition Systems. The cited work is consistent with the Under Secretary of War for Research and Engineering Science and Technology Critical Technology Areas and the Army Modernization Strategy. Work in this PE is performed by the Army Corps of Engineers' Engineer Research and Development Center (ERDC), Vicksburg, MS; the Army Geospatial Center (AGC) in Alexandria, VA; the Information Management Office, Arlington, VA; the Office of the Assistant Secretary of the Army, Acquisition, Logistics and Technology (ASA(ALT)), The Pentagon, Arlington, VA; Transformation & Training Command (T2COM) Combat Capabilities Development Command (CCDC) Army Research Laboratory (ARL), Aberdeen Proving Ground, MD; and T2COM CCDC Ground Vehicle Systems Center, Warren, MI. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E           PE 0605803A / Technical Information Activities Management Support The FY 2026 request was reduced by $6.87 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605803SE$$, $$R&D in Support of DOD Enlistment, Testing and Evaluation$$, $$rdte_dw_ba6$$, $$dw_dhra$$, 2026, 30778000, 31037000, 26935000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0605803SE", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 26525000, 28135000, 27559000, NULL, NULL, NULL, NULL, NULL, FALSE, 25407000, 35778000, 34359000, 34359000, NULL, 34359000, 27946000, $$The Defense Human Resources Activity (DHRA) is a Field Activity chartered to support the Under Secretary of War for Personnel and Readiness (USW(P&R)). This PE includes application of R&D to expedite prototype development and mission support efforts to sustain and/or modernize operations required for general RDT&E. Project 1: Identity Credential Management (ICM). DMDC executes DHRA’s responsibility to provide a central source of identification and authorization of people throughout their affiliation with DoW for identity protection, security, and entitlements and benefits verification. This funding supports evaluation and testing of emerging technologies that develop more robust and secure capabilities for the Department’s ICM program. ICM will also research capabilities such as improved self-service solutions, and reusable-services that will enable more efficient credential delivery. DMDC plans to deploy a new credential management system (CMS), My DoD Identity Solution (MYDIS) in FY 2027, which will replace the current, legacy CMS, the Real-Time Automated Personnel Identification System (RAPIDS). MYDIS is a web based, commercial off the shelf solution that will deliver new features, efficiencies, and enhanced capabilities, like support for algorithm evolution and post quantum cryptography. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 DoD Human Resources Activity                                                         Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:             PE 0605803SE / R&D in Support of DOD Enlistment, Testing and Evaluation RDT&E Management Support Project 2: Office of People Analytics (OPA) Testing and Assessment Division administers testing programs, which enable the Armed Services to select highly qualified military recruits. The DoW uses a single test, the Armed Services Vocational Aptitude Battery (ASVAB), to determine eligibility of military applicants and students (high school and post-secondary) and to report recruit quality data to Congress. The ASVAB is administered annually to approximately 360,000 applicants for Military Service as part of the DoD Enlistment Testing program, and the ASVAB is administered to over 700,000 students in more than 13,000 high schools and post-secondary schools via the ASVAB career Exploration Program. Each Service also uses ASVAB test forms developed in this program as part of their in-service testing programs. This allows DoW to make measurement improvements as well as decreasing the likelihood of test compromise. Ongoing RDT&E efforts include development and evaluation of procedures which (1) reduce or eliminate threats to the validity of the ASVAB test scores generated; (2) improve the efficiency of the test development, calibration, and validation process; and (3) improve selection and classification decisions made by each Service through more effective use of test score information. In addition, periodic assessments are required to provide DoW manpower planners and Congress with information on aptitude trends in the population from which recruits are drawn. Project 05: The Federal Voting Assistance Program (FVAP) administers many of the federal responsibilities of the Uniformed and Overseas Citizens Absentee Voting Act (UOCAVA) of 1986 and other federal military voter registration and assistance laws. FVAP works to ensure Service members, their eligible family members and overseas citizens are aware of their right to vote and have the tools and resources to successfully do so from anywhere in the world. FVAP works to increase the level of awareness of available DoW voting assistance resources among Active Duty Members, in order to increase the likelihood of returning their absentee ballots. Utilizing a repository that maintains the record of 50 million military personnel, FVAP regularly reaches out directly to 1.3 million active duty service members, and attempts to assist the estimated 700,000 military spouses and dependents of voting age. FVAP also attempts to reach out to and assist the estimated 2.8 million overseas citizens of voting age. FVAP conducts voting research projects with States, local election jurisdictions and private entities to assist UOCAVA voters to register to vote and submit their absentee ballot and improve federal, State and local election processes and procedures. Project 6: Enterprise Data Services (EDS) governs the collection, storage, and distribution of DMDC data assets, as well as serving as the Master Data Management (MDM) arm of DMDC, EDS provides multiple services including data modeling, database standardization, data quality, database architecture, and data distribution. This funding supports Data Delivery Services (DDS), a streamlined methodology for sharing data with external partners. It will allow a real-time or batch broker service to any major DMDC database, including the Person Data Repository (PDR), Uniformed Services Human Resource Information System (USHRIS), and eventually most other DMDC data holdings and some DoW data holdings outside of DMDC. Authorized customers will be able to receive automated, real-time updates directly from these databases. This project supports data Application Programming Interfaces (API) necessary to realize Zero Trust (ZT) requirements and supply identities and credential assurance levels that meet security requirements and digital identity guidelines set by National Institute of Standards and Technology (NIST). It also has the potential to improve customer service and transaction efficiency for data processing throughout the DMDC enterprise. DDS supports specific external customer use cases, improves DMDC internal data processes, supports Zero Trust for the Department, and aligns DMDC’s data access and sharing with the DoW Data Strategy objectives. Project 7: The Defense Enrollment Eligibility Reporting System (DEERS) is the DoW’s authoritative eligibility and enrollment repository for manpower, personnel identity, affiliation data on military, civilians, retirees, family members, and other populations. Virtual Lifetime Electronic Record (VLER) programs provide support for evolving efforts to modernize medical records that can be used across the Federal enclave to support care in facilities managed by DoW, the Department of Veterans Affairs (VA), and other Federal partners. DEERS administers medical and other benefits seamlessly as individuals move through a “virtual lifetime” in the Uniformed Services and VA. VLER is designed to reduce the administrative burden on Service Members and Veterans when seeking benefits from DoW, the VA and other Federal partners. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 DoD Human Resources Activity                                                        Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:             PE 0605803SE / R&D in Support of DOD Enlistment, Testing and Evaluation RDT&E Management Support Servicemembers' Group Life Insurance Online Enrollment System (SOES) is the automated solution that allows Service members to submit updates and request changes to their SGLI and Family SGLI (FSGLI) online. SOES centralizes SGLI/FSGLI data into one authoritative system capable of providing consistent SGLI/FSGLI information to Service members and their leadership. A technology refresh of the VLER and SOES programs to respond rapidly to congressional changes in policy is in progress. Current technology limitations impede delivery of benefits to Service members, and veterans and their families. Project 08: The Personnel Support Programs (PSP) portfolio designs and implements technological solutions to gather, analyze, and share information on the physical location of DoW members and affiliated personnel to ensure the safety and enhance the readiness of the Armed Forces of the United States. This funding supports the Defense Travel System (DTS), the department’s authoritative travel system. The National Defense Authorization Act (NDAA) for FY 2024 Sec 1551 required an in- depth analysis on the future of DoW Travel. The result of the capability assessment was a DoW CIO certified plan to reinvest in DTS to deliver an efficient, audit-clean travel program that processes an estimated 3.6 million vouchers annually and serves approximately 2.8 million travelers across the department. The reinvestment in DTS aligns with overall DoW efforts to have audit ready financial management systems by FY 2028. Project 09: ADL Program has been discontinued. This program was originally established in response to Section 378 of Public Law 105-261, the NDAA for FY 1999. The ADL program directly supports all DoW Components, and as a leader in the field of digital learning technologies, also coordinates with other federal agencies, and partners. The program’s work falls into two categories: (A) Modernization and (B) Governance. The Modernization work involves advanced technology development in technical areas related to digital learning. These efforts inform the program’s Governance work, including transition and adoption of Enterprise Digital Learning Modernization (EDLM) technologies and the authoring and upkeep of technical guidance and policy documents, such as DoD Instruction 1322.26 governing Distributed Learning, and Total Learning Architecture (TLA) standards including but not limited to the experience API (IEEE 9274.1.1), cmi5 (IEEE 9274.3.1), Shareable Competency Definitions (IEEE 1484.20.3), Learning Metadata Terms (IEEE 2881), and Enterprise Learner Records (IEEE 2997) . This program’s modernization investments are vetted through the Defense ADL Advisory Committee (DADLAC), a working group of military personnel and DoW/Federal civilians who formally represent their organizations’ digital learning interests. They are also considered against emerging industry trends and technologies. Project 15: US Military Entrance Processing Command (USMEPCOM) : The United States Military Entrance Processing Command (USMEPCOM) is the vital link between recruiting and training America's armed forces. The Command applies established DoW standards during military processing, thereby providing continual military enlistments to the Army, Navy, Air Force, Marines, Coast Guard, and Space Force. USMEPCOM processes applicants for military service through its 65 Military Entrance Processing Stations (MEPS) across the Continental United States (CONUS) as well as Non-Foreign Outside the Continental United States (OCONUS) locations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 DoD Human Resources Activity                                                          Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:             PE 0605803SE / R&D in Support of DOD Enlistment, Testing and Evaluation RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_DHRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605804D8Z$$, $$Development Test & Evaluation$$, $$rdte_dw_ba6$$, $$dw_osd$$, 2026, 37381000, 36000000, 37233000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0605804D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program carries out the duties in accordance with Title 10 U.S.C. Section 133a, FY 2018 National Defense Authorization Act (NDAA) (Public Law 115-91) section 838, and the Department of Defense (DoD) Directive 5137.02 dated July 15, 2020. In FY 2020, the Under Secretary of Defense for Research and Engineering (USD(R&E)) established the Developmental Test, Evaluation, and Assessments (DTE&A) organization to provide consolidated Developmental Test and Evaluation (DT&E) and Independent Engineering Assessment functions in a single office. The Director, DTE&A, is the principal advisor to the Secretary of Defense; USD(R&E); and the Under Secretary of Defense, Acquisition and Sustainment (USD(A&S)) on DT&E, Independent Engineering Assessments, and Technical Risk Assessments in the Department of Defense (DoD). The assessment products developed by this program inform investment decisions for critical Warfighter capabilities that align to the Department's 17 priorities including Nuclear Modernization, Virginia-class submarines, executable surface ships, Homeland Missile Defense, One Way Attack/ Autonomous Systems, and Munitions. This program supports the Department's initiatives to rebuild the military and reestablish deterrence. The Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) engages with Major Defense Acquisition Programs (MDAPs) within the Adaptive Acquisition Framework, providing engineering and DT&E/Cybersecurity DT&E planning expertise to ensure decision-quality data is available at major engineering program reviews and program milestones. This engagement directly helps Program Managers succeed in rebuilding the military and rapidly fielding emerging technologies. OUSD(R&E) engages with programs to help meet interoperability requirements to deepen interoperability and Strengthen Alliances. Finally, OUSD(R&E) works with Director, Operational Test and Evaluation to streamline T&E policy and guidance to improve test efficiency and reduce acquisition cost and schedule to reform acquisition processes. This program supports and improves the engineering and DT&E efforts of Major Defense Acquisition Program (MDAP), Rapid Prototyping/Fielding efforts, and other Special Interest (SI) acquisition programs designated by USD(R&E) or USD(A&S) as they progress through the acquisition/development lifecycle; supports development of the defense acquisition workforce Test and Evaluation (T&E) career field; and supports development of policy and guidance for the conduct of DT&E and Cyber DT&E within the DoD. This program also provides dedicated resources to support MDAP and Rapid Prototyping/Fielding Program Managers, Chief Developmental Testers, Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                            Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:        PE 0605804D8Z / Development Test & Evaluation RDT&E Management Support and Lead Development Test & Evaluation organizations in the development of comprehensive, efficient, and innovative Cybersecurity DT&E strategies/plans to support key acquisition milestones and engineering/programmatic decisions.$$, NULL, 35059000, 35624000, 36443000, NULL, NULL, 192, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 36214000, 36990000, 35106000, 35106000, NULL, 35106000, 36426000, $$This program carries out the duties in accordance with Title 10 U.S.C. Section 133a, FY 2018 National Defense Authorization Act (NDAA) (Public Law 115-91) section 838, and Department of War (DoW) Directive 5137.02 dated July 15, 2020 and as outlined in the 2026 National Defense Strategy and the 2026 Acquisition Transformation Strategy. In FY 2020, the Under Secretary of War for Research and Engineering (OUSW(R&E)) established the Developmental Test, Evaluation, and Assessments (DTE&A) organization to provide consolidated Developmental Test and Evaluation (DT&E) and Independent Engineering Assessment functions in a single office. The DTE&A organization serves as the principal advisor to the Secretary of War; USW(R&E); and the Under Secretary of War, Acquisition and Sustainment (USW(A&S)) on DT&E, Independent Technical Risk Assessments and other independent engineering assessments in the DoW. The assessment products developed by this program inform investment decisions for Warfighter capabilities that align to critical Department priorities including Nuclear Modernization, Virginia-class submarines, executable surface ships, Homeland Missile Defense, One Way Attack/Autonomous Systems, and Munitions. This program supports the Department's initiatives to rebuild the military and reestablish deterrence. The Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)) engages with Major Defense Acquisition Programs (MDAPs) within the Adaptive Acquisition Framework, providing engineering and DT&E/Cybersecurity DT&E planning expertise to ensure decision-quality data is available at major engineering program reviews and program milestones. This engagement directly helps Program Managers succeed in rebuilding the military and rapidly fielding emerging technologies. OUSW(R&E) engages with programs to help meet interoperability requirements to deepen interoperability and Strengthen Alliances. Finally, OUSW(R&E) works with Director, Operational Test and Evaluation to streamline T&E policy and guidance to improve test efficiency and reduce acquisition cost and schedule to reform acquisition processes. This program supports and improves the engineering and DT&E efforts of MDAPs, Rapid Prototyping/Fielding efforts, and other Special Interest (SI) acquisition programs designated by USW(R&E) or USW(A&S) as they progress through the acquisition/development lifecycle; supports development of the acquisition workforce Test and Evaluation (T&E) career field; and supports development of policy and guidance for the conduct of DT&E and Cyber DT&E within the DoW. This program Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0605804D8Z / Development Test & Evaluation RDT&E Management Support also provides dedicated resources to support MDAP and Rapid Prototyping/Fielding Program Managers, Chief Engineers, Chief Developmental Testers, and Lead Development Test & Evaluation organizations in the development of comprehensive, efficient, and innovative Cybersecurity DT&E strategies/plans to support key acquisition milestones and engineering/programmatic decisions.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605804N$$, $$Technical Information Services$$, $$rdte_navy_ba6$$, $$dw_ousd_re$$, 2026, 0, 1492000, 1009000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605804N", "page_header": "Department of the Navy"}$$::jsonb, $$The Department of the Navy (DoN) Technology Transfer (T2) Program is a congressionally mandated program that requires federal laboratories to actively assess applications for Federal research and development projects, and to provide information and assistance to State or local government and to private industry (Stevenson- Wydler Act of 1980). The DoN Technology Transfer (T2) Program Management Office (DoN T2 PMO) is responsible for policy and guidance, as well as products and services that enable T2-designated commands and activities to facilitate the transfer of technology both into and out of the DoN to stimulate partnerships and advance naval technology needs. T2 Offices throughout the DoN enhance naval effectiveness by strategically leveraging industrial and technology into the NRE, and transfer appropriate Navy-developed innovative concepts, inventions, facilities, and materiel to the private sector for the purposes of dual-use commercialization, to benefit DoD, the public economy, and academia. This program provides the Department of the Navy interface to technology transfer and transition stakeholders such as the Small Business Innovation Research (SBIR) and Small Business Technology Transfer Programs (SBIR/STTR), Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)), National Institute of Standards and Technology (NIST)/Department of Commerce, Office of Science and Technology Policy (OSTP), and the Federal Laboratory Consortium (FLC) for matters relating to policy and reporting requirements for technology transfer. The DoN T2 PMO, under the purview of the Chief of Naval Research at ONR, is also aligned within the NavalX organization to support its Tech Bridge activities. Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E            PE 0605804N / Technical Information Services Management Support$$, NULL, 0, 0, 0, NULL, NULL, 192, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 1819000, 0, 0, 0, NULL, 0, 0, $$The Department of the Navy (DoN) Technology Transfer (T2) Program is a congressionally mandated program that requires federal laboratories to actively assess applications for Federal research and development projects, and to provide information and assistance to State or local government and to private industry (Stevenson- Wydler Act of 1980). The DoN Technology Transfer (T2) Program Management Office (DoN T2 PMO) is responsible for policy and guidance, as well as products and services that enable T2-designated commands and activities to facilitate the transfer of technology both into and out of the DoN to stimulate partnerships and advance naval technology needs. T2 Offices throughout the DoN enhance naval effectiveness by strategically leveraging industrial and technology into the NRE, and transfer appropriate Navy-developed innovative concepts, inventions, facilities, and materiel to the private sector for the purposes of dual-use commercialization, to benefit DoW, the public economy, and academia. This program provides the Department of the Navy interface to technology transfer and transition stakeholders such as the Small Business Innovation Research (SBIR) and Small Business Technology Transfer Programs (SBIR/STTR), Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)), National Institute of Standards and Technology (NIST)/Department of Commerce, Office of Science and Technology Policy (OSTP), and the Federal Laboratory Consortium (FLC) for matters relating to policy and reporting requirements for technology transfer. The DoN T2 PMO, under the purview of the Chief of Naval Research at ONR, is also aligned within the NavalX organization to support its Tech Bridge activities. Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                   Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E        PE 0605804N / Technical Information Services Management Support$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605805A$$, $$Munitions Standardization, Effectiveness and Safety$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 44465000, 56069000, 50766000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0605805A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) supports continuing technology investigations by providing a coordinated Tri-Service mechanism for the collection and free exchange of technical data on the performance and effectiveness of all non-nuclear conventional munitions and weapons systems in a realistic operational environment. Project 297 - Munitions Survivability & Logistics: This Project supports the future force by making Army units more survivable through the investigation, testing and demonstration of munitions logistics system improvements that prevent or minimize catastrophic explosive events and accelerate ammunition resupply. Key thrusts are munitions storage area survivability, Insensitive Munitions (IM) technology integration and compliance, ammunition management and asset visibility, weapon system rearm, munitions configured load enablers and advanced packaging and distribution system enhancements. Within each thrust, a broad array of solutions will be identified, tested, and evaluated against developed system measures of effectiveness. Optimum, cost effective and efficient solutions that enable the rapid projection of lethal and survivable forces will be demonstrated. The early stages of force deployment are especially critical. Theater ammunition storage areas are vulnerable and present the enemy with lucrative targets. These areas and distribution nodes contain the only available munitions stocks in theater. Loss of these munition stocks could cripple the force, jeopardize the mission, and result in high loss of life. This Project mitigates vulnerabilities and ensures a survivable fighting force. Project 857 - DoD Explosives Safety Standards: This Project supports the Research, Development, Test, and Evaluation efforts of the Department of Defense (DoD) Explosive Safety Standards Board. It supports explosive safety effects research and testing to quantify hazards and to develop techniques to mitigate those hazards in all DoD manufacturing, testing, transportation, maintenance, storage, disposal of ammunition and explosives operations, and also to develop risk based explosives safety standards. Results are essential to the development and improvement of quantity-distance standards, hazard classification procedures, cost effective explosion resistant facility design procedures, and personnel hazard/protection criteria. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                  Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E              PE 0605805A / Munitions Standardization, Effectiveness and Safety Management Support Project 858 - Army Explosives Safety Management Program: This Project establishes, validates or modifies explosives technical safety requirements per Department of Defense Manual 6055.09 and Department of the Army Pamphlet 385-64, Ammunition and Explosives Safety Standards. Project activities promote Research, Development, Test, and Evaluation (RDTE) of new and innovative explosives safety technologies that improve the survivability of Army personnel, facilities, and equipment as well as improve the health, safety and welfare of the general public (with highest priority directed to combat theater of operations). Project 859 - Life Cycle Pilot Process: This Project supports the implementation of the Single Manager for Conventional Ammunition (SMCA) Industrial Base Strategic Plan through technology investigations, model based process controls, pilot prototyping, and industrial assessments. It will assess life cycle production capabilities required for all ammunition families, address design for manufacturability to facilitate economical production, identify industrial and technology requirements, and address the ability of the production base to rapidly and cost effectively produce quality products. Cost reduction is an important part of the Life Cycle Pilot Process (LCPP). LCPP provides the resources to prototype critical technologies and develop the knowledge base to establish cost effective, environmentally safe and modern production processes in support of the munitions Industrial Base transformation. In addition, the LCPP program addresses Single Point Failures (SPFs) / No Source of supply within the National Technology Industrial Base (NTIB). LCPP provides support to reduce supply chain risk by investigating, developing and evaluating additional sources of supply for a known SPF. Project F21 - North Atlantic Treaty Organization (NATO) Ammunition Evaluation program funding ensures interchangeability of ammunition and weapons among all the NATO countries with all of the associated logistic, strategic and tactical advantages of the alliance. This Project involves development and testing compliance of NATO standardization agreements (STANAGS) and staffing of the North American Regional Test Center (NARTC). In addition, this Project supports small caliber ammunition, 50mm ammunition, 40mm grenade munitions, medium caliber cannon ammunition, and large caliber ammunition enhancements to lethality, effectiveness, survivability, accuracy, and general product improvements. This Project also supports the standardization and interchangeability of legacy and new production United States (US) weapons and ammunition with Allied Nations to maximize battlefield interchangeability/ compatibility under the auspices of international agreements to include NATO working groups, the Joint Ballistics Memorandum of Understanding (JBMOU), and information/ data exchange agreements. Maximizing standardization, interchangeability, and exportability will also potentially increase Foreign Military Sales (FMS) of US indirect fire weapon and munition products to support United States industrial base production and affordable Department of Defense pricing through increased economies of scale. Project F24: Conventional Munitions Demilitarization (Demil): The Conventional Munitions Demilitarization technology Project supports the SMCA responsibility per Department of Defense Instruction (DoDI) 5160.68 to plan, program, budget and fund a Joint Service Research and Development (R&D) program that develops capability and capacity as well as technology and facilities to support the SMCA mission to demil and dispose of conventional ammunition stored in the SMCA Resource, Recovery and Disposition Account (B5A). The program goals include SMCA efforts to increase efficiencies and effectiveness to reduce the demil stockpile; reduce processing costs including packaging, handling and crating; and increase capacity through improved demilitarization capabilities and processes. Project F24 includes activities: (1) to establish requirements and develop processes to focus investments, assess capabilities, analyze alternatives, and recommend and implement R&D projects; (2) to improve products and processes that support existing capabilities; (3) to develop or improve demil methods and processes related to advance the primary demilitarization core thrust areas of destruction, disassembly, removal, resource recovery and recycling, and waste stream treatment; (4) to ensure safe and environmentally acceptable demil operations; (5) to transition R&D products to United States Army depots or plants as well as commercial facilities performing demil; and (6) to mitigate risk and close-out project activities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E           PE 0605805A / Munitions Standardization, Effectiveness and Safety Management Support The FY 2026 request was reduced by $0.329 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 45302000, 45384000, 45570000, NULL, NULL, 191, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 48913000, 46965000, 44851000, 44851000, NULL, 44851000, 46068000, $$This Program Element (PE) supports continuing technology investigations by providing a coordinated Tri-Service mechanism for the collection and free exchange of technical data on the performance and effectiveness of all non-nuclear conventional munitions and weapons systems in a realistic operational environment. Project 297 - Munitions Survivability & Logistics: This Project supports the future force by making Army units more survivable through the investigation, testing and demonstration of munitions logistics system improvements that prevent or minimize catastrophic explosive events and accelerate ammunition resupply. Key thrusts are munitions storage area survivability, Insensitive Munitions (IM) technology integration and compliance, ammunition management and asset visibility, weapon system rearm, munitions configured load enablers and advanced packaging and distribution system enhancements. Within each thrust, a broad array of solutions will be identified, tested, and evaluated against developed system measures of effectiveness. Optimum, cost effective and efficient solutions that enable the rapid projection of lethal and survivable forces will be demonstrated. The early stages of force deployment are especially critical. Theater ammunition storage areas are vulnerable and present the enemy with lucrative targets. These areas and distribution nodes contain the only available munitions stocks in theater. Loss of these munition stocks could cripple the force, jeopardize the mission, and result in high loss of life. This Project mitigates vulnerabilities and ensures a survivable fighting force. Project 857 - DoD Explosives Safety Standards: This Project supports the Research, Development, Test, and Evaluation efforts of the Department of War (DoW) Explosive Safety Standards Board. It supports explosive safety effects research and testing to quantify hazards and to develop techniques to mitigate those hazards in all DoW manufacturing, testing, transportation, maintenance, storage, disposal of ammunition and explosives operations, and also to develop risk-based explosives safety standards. Results are essential to the development and improvement of quantity-distance standards, hazard classification procedures, cost-effective explosion- resistant facility design procedures, and personnel hazard/protection criteria. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                                Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E                 PE 0605805A / Munitions Standardization, Effectiveness and Safety Management Support Project 858 - Army Explosives Safety Management Program: This Project establishes, validates or modifies explosives technical safety requirements per Department of War Manual 6055.09 and Department of the Army Pamphlet 385-64, Ammunition and Explosives Safety Standards. Project activities promote Research, Development, Test, and Evaluation (RDTE) of new and innovative explosives safety technologies that improve the survivability of Army personnel, facilities, and equipment as well as improve the health, safety and welfare of the general public (with highest priority directed to combat theater of operations). Project 859 - Life Cycle Pilot Process: This Project supports the implementation of the Single Manager for Conventional Ammunition (SMCA) Industrial Base Strategic Plan through technology investigations, model-based process controls, pilot prototyping, and industrial assessments. It will assess life cycle production capabilities required for all ammunition families, address design for manufacturability to facilitate economical production, identify industrial and technology requirements, and address the ability of the production base to rapidly and cost effectively produce quality products. Cost reduction is an important part of the Life Cycle Pilot Process (LCPP). LCPP provides the resources to prototype critical technologies and develop the knowledge base to establish cost effective, environmentally safe and modern production processes in support of the munitions Industrial Base transformation. In addition, the LCPP program addresses Single Point Failures (SPFs) / No Source of supply within the National Technology Industrial Base (NTIB). LCPP provides support to reduce supply chain risk by investigating, developing and evaluating additional sources of supply for a known SPF. Project F21 - North Atlantic Treaty Organization (NATO) Ammunition Evaluation: The NATO Ammunition Evaluation project ensures interchangeability of ammunition and weapons among all the NATO countries with all of the associated logistic, strategic and tactical advantages of the alliance. This Project involves development and testing compliance of NATO standardization agreements (STANAGS) and staffing of the North American Regional Test Center (NARTC). In addition, this Project supports small caliber ammunition, 50mm ammunition, 40mm grenade munitions, medium caliber cannon ammunition, and large caliber ammunition enhancements to lethality, effectiveness, survivability, accuracy, and general product improvements. This project also supports the standardization and interchangeability of legacy and new production United States (US) weapons and ammunition with Allied Nations to maximize battlefield interchangeability/compatibility under the auspices of international agreements to include NATO working groups, the Joint Ballistics Memorandum of Understanding (JBMOU), and information/data exchange agreements. Maximizing standardization, interchangeability, and exportability will also potentially increase Foreign Military Sales (FMS) of US indirect fire weapon and munition products to support United States industrial base production and affordable Department of War pricing through increased economies of scale. Fiscal Year 2027 funding will support NATO and JBMOU artillery and small arms ammunition interchangeability group meetings, documentation, and test operations. Project F24: Conventional Munitions Demilitarization (Demil): The Conventional Munitions Demilitarization technology Project supports the SMCA responsibility per Department of Defense Instruction (DoDI) 5160.68 to plan, program, budget and fund a Joint Service Research and Development (R&D) program that develops capability and capacity as well as technology and facilities to support the SMCA mission to demil and dispose of conventional ammunition stored in the SMCA Resource, Recovery and Disposition Account (B5A). The program goals include SMCA efforts to increase efficiencies and effectiveness to reduce the demil stockpile; reduce processing costs including packaging, handling and crating; and increase capacity through improved demilitarization capabilities and processes. Project F24 includes activities: (1) to establish requirements and develop processes to focus investments, assess capabilities, analyze alternatives, and recommend and implement R&D projects; (2) to improve products and processes that support existing capabilities; (3) to develop or improve demil methods and processes related to advance the primary demilitarization core thrust areas of destruction, disassembly, removal, resource recovery and recycling, and waste stream treatment; (4) to ensure safe and environmentally acceptable demil operations; (5) to transition R&D products to United States Army depots or plants as well as commercial facilities performing demil; and (6) to mitigate risk and close-out project activities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0605805A / Munitions Standardization, Effectiveness and Safety Management Support The FY 2026 request was reduced by $0.329 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605807F$$, $$Test and Evaluation Support$$, $$rdte_af_ba6$$, $$aftc$$, 2026, 1098871000, 960429000, 936913000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605807F"}$$::jsonb, $$This program element provides resources to operate the Air Force Test Center (AFTC) test activities which are included in the Department of Defense (DoD) Major Range and Test Facility Base (MRTFB). Test facilities/capabilities include wind tunnels, rocket and jet engine test cells, hypersonic and subsonic testing, modeling and simulation, technology, limited space environmental simulation chambers, armament test ranges, hardware-in-the-loop test facilities, climatic test facilities, avionics test facilities, aircraft testbeds, dry lake bed landing sites, instrumented test ranges, and test aircraft maintenance, as well as USAF Test Pilot School (TPS). Test and Evaluation (T&E) Support funds institutional test infrastructure activities including: Command and supervisory staffs; supply stocks; maintenance, repair, and replacement of worn or obsolete test equipment and facilities; test infrastructure for data collection, transmission, reduction, and analysis; civilian salaries; temporary duty travel; range operations and material support contract costs for hardware and software engineering and maintenance; and minor improvement and modernization projects. It also funds institutional test aircraft depot level maintenance such as: Programmed Depot Maintenance (PDM), the calendar-based cyclic scheduling of aircraft into depots for update/inspection; modifications and any other depot level repairs required by the aircraft System Program Directors (SPD); engine overhauls; depot-provided area assistance; and assorted ground support equipment overhauls. Within AFTC, there are three Test Wings (TW). The first is Arnold Engineering and Development Complex (AEDC), located at Arnold Air Force Base (AFB), TN. The AEDC institutional test infrastructure supports operations of the largest complex of ground test facilities in the world (including transonic, supersonic, and hypersonic wind tunnels; rocket motor and turbine engine test cells; space environmental test chambers, hyper ballistic ranges; and other specialized facilities). AEDC also supports geographically separated facilities which include the National Full-Scale Aerodynamic Complex (NFAC) located at NASA's AMES Research Center, CA, and Tunnel 9 located at White Oak, MD. The 412TW is located at Edwards AFB, CA. Its institutional test infrastructure supports weapons system development and operational test and evaluation for aircraft, aircraft subsystems and aircraft weapon systems, aerospace research vehicles, unmanned miniature vehicles, cruise missiles, parachute delivery/recovery systems, cargo handling systems, communications, information operations, and Electronic Warfare (EW) systems for DoD and allied forces. The 412TW mission also includes the USAF TPS. Lastly, the 96 TW, located at Eglin AFB, FL, is a joint test and training complex comprised of 724 square miles of land area, and approximately 123,000 square miles of water area. The 96TW provides the institutional test infrastructure required to conduct developmental and operational test and evaluation of non-nuclear air armaments (including aircraft guns, ammunition, and air-to-surface and air-to-air guided munitions); Command, Control, Communications, Computers, Cyber and Intelligence/Surveillance/Reconnaissance (C5ISR) systems; target acquisition and weapon delivery systems; and special operations aircraft systems. 96TW provides a scientific test process that supports the development, production, sustainment, and enhancement of munitions systems that support tri-service digital weapons development. T&E support services contracts are awarded on the basis of full and open competition. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E           PE 0605807F / Test and Evaluation Support Management Support This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 2014089000, 1916972000, 1794451000, NULL, NULL, 130, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 936479000, 1113371000, 1802502000, 1802502000, 0, 1802502000, 1627512000, $$This program element provides resources to operate the Air Force Test Center (AFTC) test activities which are included in the Department of War (DoW) Major Range and Test Facility Base (MRTFB). Test facilities/capabilities include wind tunnels, rocket and jet engine test cells, hypersonic and subsonic testing, modeling and simulation, technology, limited space environmental simulation chambers, armament test ranges, hardware-in-the-loop test facilities, climatic test facilities, avionics test facilities, aircraft testbeds, dry lake bed landing sites, instrumented test ranges, and test aircraft maintenance, as well as USAF Test Pilot School (TPS). Test and Evaluation (T&E) Support funds institutional test infrastructure activities including: Supply stocks; maintenance, repair, and replacement of worn or obsolete test equipment and facilities; test infrastructure for data collection, transmission, reduction, and analysis; civilian salaries; temporary duty travel; range operations and material support contract costs for hardware and software engineering and maintenance; test aircraft operations and maintenance, including flying hour program (FHP), fuel, and weapon system sustainment; and minor improvement and modernization projects. It also funds institutional test aircraft depot level maintenance such as: Programmed Depot Maintenance (PDM), the calendar-based cyclic scheduling of aircraft into depots for update/inspection; modifications and any other depot level repairs required by the aircraft System Program Directors (SPD); engine overhauls; depot-provided area assistance; and assorted ground support equipment overhauls. The Air Force Test Center (AFTC) has three Test Wings (TW)- Arnold Engineering and Development Complex (Arnold AFB, TN): Operates the world's largest complex of ground test facilities for aerospace systems, including wind tunnels and engine test cells, and supports geographically separated facilities (National Full-Scale Aerodynamic Complex at NASA AMES, CA and Tunnel 9 at White Oak, MD). 412TW (Edwards AFB, CA): Tests and evaluates aircraft, weapons systems, unmanned vehicles, missiles, and related systems for the DoW and allies, and includes the USAF Test Pilot School (TPS). 96TW (Eglin AFB, FL): Tests and evaluates non-nuclear air armaments, Command. Control, Communications, Computers, Combat Systems, Intelligence, Surveillance, Reconnaissance (C5ISR) systems, and special operations aircraft systems, supporting digital weapons development for all branches of the military. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E         PE 0605807F / Test and Evaluation Support Management Support$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605812A$$, $$Joint Light Tactical Vehicle (JLTV) Engineering and Manufacturing Develo$$, $$rdte_army_ba5$$, $$peo_cscss$$, 2026, 2664000, 0, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0605812A", "page_header": "Department of the Army"}$$::jsonb, $$The JLTV Family of Vehicles (FoV), to include a companion trailer, is a United States Army (USA) acquisition lead, joint program with the U.S. Marine Corps (USMC). The JLTV is capable of performing multiple mission roles and designed to provide protected, sustained, networked mobility for personnel and payloads across the full range of military operations. The JLTV Trailer (JLTV-T) is the companion trailer to the JLTV and safely carries its payload while maintaining the same mobility characteristics of the prime mover. The JLTV and JLTV-T are required to be fielded as a system per the Capability Production Document (CPD) last validated 7 June 2019. JLTV and JLTV-T objectives include increased protection and performance over the current fleet; and, minimizing ownership costs by maximizing commonality, fuel efficiency, reliability, and maintaining effective competition throughout the life cycle. Commonality of components, maintenance procedures, training, etc., is expected to be inherent in FoV solutions across mission variants to minimize total ownership cost and to avoid unique service requirements when possible. The Follow- on JLTV Contract was awarded on 09 February 2023 as a single award five-year requirements contract with five one-year options. This program element supports modernization of the JLTV FoV by investigating capability upgrades/insertions, including but not limited to force protection/survivability improvements, predictive logistics, platform safety enhancements including operations in extreme environments, and technologies to meet other emerging operational needs. This program element also supports developing initial prototypes to enable refinement of Operational Requirements and early user feedback to support future sustainment and operational movement operating concepts. The JLTV Program is part of the Army Transformation Initiative. PB26 Justification: The FY 2026 budget funds of $2.664 million will be utilized for the development and assessment of emerging technologies to maintain operational relevancy. Technologies under consideration include but not limited to signature management, winter tires, Counter-Unmanned Aircraft System (cUAS) capabilities and improved force protection. The FY 2026 request was reduced by $0.001 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0605812A / Joint Light Tactical Vehicle (JLTV) Engineering and Manufacturing Develo Development & Demonstration (SDD)                                               pment Phase (EMD)$$, NULL, 3594000, 3042000, 2249000, NULL, NULL, 168, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, NULL, 0, 2749000, 2749000, NULL, 2749000, 2271000, $$The Joint Light Tactical Vehicle (JLTV) is the cornerstone of protected tactical mobility for the Army and Marine Corps. This RDT&E request is critical, time-sensitive investment to master the threats of today and tomorrow. Warfighters face a growing danger from Unmanned Aerial Systems (UAS), while the demand for on-board electrical power for advanced sensors, communication suites, and future weapons has surged. This creates an urgent capability gap. This funding request closes a capability gap by delivering tangible capabilities with a clear strategic impact. The program element supports modernization of the JLTV Family of Vehicles by investigating capability upgrades/insertions, including but not limited to force protection/ survivability improvements, predictive logistics, platform safety enhancements including operations in extreme environments, trailer integration and technologies to meet other emerging operational needs. Funding the integration of the priority efforts includes: previously developed Tactical Range Extender (TREE) and the electric Power Export and Expansion Kit (ePEEK) as well as development of the hardware needed to bring platforms to autonomy ready status. TREE and ePEEK are a unified, mobile power system that transforms any tactical vehicle into a power hub that can provide any High Voltage DC power or AC. It delivers the massive amounts of versatile, exportable electricity needed to run the Army's most advanced systems on the move. This investment works to make our vehicle platforms "autonomy-ready." It buys the essential power architecture that unlocks the next generation of modernization, from autonomous systems and predictive logistics to advanced survivability upgrades. This technology provides the power backbone necessary to integrate drone-killing systems directly onto the JLTV. It Increases Warfighter Survivability & Agility: By generating power on the move, it reduces the logistical burden on forces and shrinks their acoustic and thermal signatures, making a harder for the enemy to target. This funding ensures warfighters have the dominant tactical vehicle needed for the challenges of a complex world. FY 2027 Justification: The FY 2027 budget funds of $2.749 million will be utilized for the continuation of the development and assessment of emerging technologies to maintain operational relevancy. Technologies under consideration include but not limited to autonomy enablers, power generation (Tactical Range Extender Enhanced (TREE), electric Power Export and Expansion Kit (ePEEK),signature management, winter tires, Counter Unmanned Aircraft Systems (cUAS) capabilities, and improved force protection. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 5: System             PE 0605812A / Joint Light Tactical Vehicle (JLTV) Engineering and Manufacturing Develo Development & Demonstration (SDD)                                               pment Phase (EMD)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605813M$$, $$Joint Light Tactical Veh (JLTV) Sys Dev & Dem$$, $$rdte_navy_ba5$$, $$mc$$, 2026, 6984000, 2526000, 10748000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 35, "original_pe": "0605813M", "page_header": "Department of the Navy"}$$::jsonb, $$Joint Light Tactical Vehicle (JLTV) supports light fleet modernization and Force Design as the next generation replacement for legacy High Mobility Multipurpose Wheeled Vehicle (HMMWV) and light tactical trailers. Funding supports the JLTV Family of Vehicles (FoV) to include the development and testing of Command, Control, Communications, Computers, & Intelligence (C4I) for integration with the JLTV. JLTV is a joint program between the U.S. Army and the U.S. Marine Corps, of which the U.S. Army is the lead service. The JLTV FoV can perform multiple mission roles designed to provide protected, sustained, and networked mobility for personnel and payloads across the full Range of Military Operations. JLTV features include increased performance, protection, and payload over the current HMMWV fleet, reducing ownership costs by maximizing commonality, fuel efficiency, and reliability. The commonality of components, maintenance procedures, and training among vehicles are inherent in FoV solutions across mission variants to minimize total ownership costs. Unique service requirements have been minimized. RDT&E funding supports modernization of the JLTV Family of Vehicles by investigating technology insertions including, but not limited to, ambulance shelter kit design for the JLTV, vehicle electronics systems, and other emerging technologies and safety initiatives; engineering change orders (ECOs), and retrofits to maintain the configuration of the trucks being used to integrate various weapons platforms. Current Command, Control, Communications, Computers and Intelligence Surveillance and Reconnaissance (C4ISR) integration activities include integration of systems such as: Marine Air Defense Integrated System (MADIS) and Remote Weapons System (RWS) Cannon, Network on the Move (NOTM), Communications Emitter Sensing and Attack Systems (CESAS II), Joint Battle Command-Platform (JBC-P), Tactical Imagery Production System Next Generation (TIPS NG), Mobile Command Vehicle (MCV), and Navy Marine Expeditionary Ship Interdiction System (NMESIS) Key Leader Vehicle. FY 2026 budget activities for the JLTV Family of Vehicles (FoV) includes completion of JLTV ambulance shelter kit design, system engineering/integration, engineering design analysis, and test efforts. Efforts will focus on development/enhancement efforts required for the integration of C4ISR requirements on the JLTV FoV; cyber scans to evaluate emerging threats and technologies; cyber security vulnerability assessments; and development/integration of associated fielded and force design solution for the JLTV system and other system technical support to develop and integrate vehicle and software enhancements that support ongoing Marine Corps Force Design modernization efforts. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0605813M / Joint Light Tactical Veh (JLTV) Sys Dev & Dem Development & Demonstration (SDD)$$, NULL, 2513000, 2144000, 2081000, NULL, NULL, 176, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 9934000, 6984000, 2413000, 2413000, NULL, 2413000, 2127000, $$The JLTV and companion trailer is the Marine Corps' premier platform for modernizing the light fleet, replacing the HMMWV, and supporting Force Design capabilities. Funding supports the JLTV Family of Vehicles (FoV) to include the development and testing of Command, Control, Communications, Computers, & Intelligence (C4I) for integration with the JLTV. JLTV is a joint program between the U.S. Army and the U.S. Marine Corps, of which the U.S. Army is the procurement lead and primary inventory control authority (PICA) while the Marine Corps is the requirement lead. The JLTV FoV is capable of performing multiple mission roles designed to provide protected, sustained, and networked mobility for personnel and payloads across the full Range of Military Operations. RDT&E funding supports modernization of the JLTV Family of Vehicles by investigating technology insertions including, but not limited to, ambulance shelter kit design for the JLTV, vehicle electronics systems, and other emerging technologies and safety initiatives; engineering change orders (ECOs), and retrofits to maintain the configuration of the trucks being used to integrate various weapons platforms. Current Command, Control, Communications, Computers and Intelligence Surveillance and Reconnaissance (C4ISR) integration activities include integration of systems such as: Marine Air Defense Integrated System (MADIS) and Remote Weapons System (RWS) Cannon, Network on the Move (NOTM), Communications Emitter Sensing and Attack Systems (CESAS II), Joint Battle Command-Platform (JBC-P), Tactical Imagery Production System Next Generation (TIPS NG), Mobile Command Vehicle (MCV), and Navy Marine Expeditionary Ship Interdiction System (NMESIS) Key Leader Vehicle. FY 2027 budget activities for the JLTV Family of Vehicles (FoV) includes system engineering/integration, engineering design analysis, Diminishing Manufacturing Sources and Material Shortages (DMSMS), and test efforts. Efforts will focus on development/enhancement efforts required for the integration of C4ISR requirements on the JLTV FoV; cyber scans to evaluate emerging threats and technologies; cyber security vulnerability assessments; and development/integration of associated fielded and force design capabilities where JLTV is the prime mover and other system technical support. Develop and integrate vehicle and software enhancements that support ongoing Marine Corps Force Design modernization efforts. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System          PE 0605813M / Joint Light Tactical Veh (JLTV) Sys Dev & Dem Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605827F$$, $$Acq Workforce- Global Vig & Combat Sys$$, $$rdte_af_ba6$$, $$aflcmc$$, 2026, 0, 317901000, 327724000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605827F"}$$::jsonb, $$The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E       PE 0605827F / Acq Workforce- Global Vig & Combat Sys Management Support$$, NULL, 0, 0, 0, NULL, NULL, 131, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 339924000, 0, 0, 0, 0, 0, 0, $$The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
