                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E     PE 0605829F / Acq Workforce- Cyber, Network, & Bus Sys Management Support$$, NULL, 446530000, 455902000, 465474000, NULL, NULL, 133, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 466068000, 435918000, 439592000, 439592000, 0, 439592000, 475248000, $$The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605830A$$, $$Aviation Ground Support Equipment$$, $$rdte_army_ba5$$, $$peo_aviation$$, 2026, 930000, 1124000, 979000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "army", "page_num": 19, "original_pe": "0605830A", "page_header": "Department of the Army"}$$::jsonb, $$Aviation Ground Support Equipment (AGSE) Product Office tests and evaluates critical ground support equipment to enhance the functionality and maintenance of both the Army's enduring fleet of rotary wing aircraft and the Future Long Range Assault Aircraft (FLRAA). This is accomplished by providing aircraft diagnostic, repair and servicing capabilities essential to support aircraft maintenance and operational readiness. Priority efforts include modification of the Aviation Ground Power Unit (AGPU 1.1) to support FLRAA, the development of new products and a comprehensive study/analysis of AGSE's 24 enduring products to identify future capability gaps required to fully support the enduring fleet and FLRAA. Continued investments in AGSE's ability to develop, test and evaluate aircraft support equipment ensure Army Aviation can rapidly deploy, operate and sustain operations across the globe in a multi-domain environment, supporting the National Defense Strategy and National Military Strategy.$$, NULL, 964000, 969000, 969000, NULL, NULL, 169, $$RDTE - Vol 3 - Budget Activity 5D.pdf$$, NULL, FALSE, 943000, 930000, 951000, 951000, NULL, 951000, 979000, $$Aviation Ground Support Equipment (AGSE) Product Office tests and evaluates critical ground support equipment to enhance the functionality and maintenance of both the Army's enduring fleet of rotary wing aircraft and the Future Long Range Assault Aircraft (FLRAA). This is accomplished by providing aircraft diagnostic, repair and servicing capabilities essential to support aircraft maintenance and operational readiness. Priority efforts include modification of the Aviation Ground Power Unit (AGPU 1.1) to support FLRAA, the development of new products and a comprehensive study/analysis to identify AGSE future capability gaps required to fully support the enduring fleet and FLRAA. Continued investments in AGSE's ability to develop, test and evaluate aircraft support equipment ensure Army Aviation can rapidly deploy, operate and sustain operations across the globe in a multi-domain environment, supporting Army modernization, the National Defense Strategy and National Military Strategy.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605831F$$, $$Acq Workforce- Capability Integration$$, $$rdte_af_ba6$$, $$aflcmc$$, 2026, 1153165000, 273530000, 291444000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605831F"}$$::jsonb, $$The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E      PE 0605831F / Acq Workforce- Capability Integration Management Support$$, NULL, 1233291000, 1263403000, 1290195000, NULL, NULL, 134, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 305394000, 1153165000, 1206669000, 1206669000, 0, 1206669000, 1315566000, $$The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E      PE 0605831F / Acq Workforce- Capability Integration Management Support$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
