INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605833F$$, $$Acq Workforce- Nuclear Systems$$, $$rdte_af_ba6$$, $$afnwc$$, 2026, 368881000, 305322000, 343180000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605833F"}$$::jsonb, $$This program element directly funds the Air Force Nuclear Weapons Center (AFNWC)and Air Force Life Cycle Management Center (AFLCMC) nuclear acquisition workforce. AFNWC and AFLCMC equip U.S. forces with operational nuclear weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, technical and business capabilities needed to oversee Nuclear Systems acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. These program elements support both civilian pay and non-pay support requirements. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                               Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E     PE 0605833F / Acq Workforce- Nuclear Systems Management Support$$, NULL, 343598000, 350797000, 358151000, NULL, NULL, 136, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 328180000, 368881000, 342650000, 342650000, 0, 342650000, 365667000, $$This program element directly funds the Air Force Nuclear Weapons Center (AFNWC)and Air Force Life Cycle Management Center (AFLCMC) nuclear acquisition workforce. AFNWC and AFLCMC equip U.S. forces with operational nuclear weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, technical and business capabilities needed to oversee Nuclear Systems acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. These program elements support both civilian pay and non-pay support requirements. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E     PE 0605833F / Acq Workforce- Nuclear Systems Management Support$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605853N$$, $$Management, Technical & Intl Supt$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2026, 191398000, 153926000, 137521000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605853N", "page_header": "Department of the Navy", "fy26_v182_disc_K": 133538, "fy26_v182_supp_K": 68292, "fy26_v182_total_K": 201830, "fy26_v182_note_name": "Research, Development, Test and Evaluation, Navy", "fy26_v182_source_file": "RDTEN_BA6_Book.txt", "fy26_v182_source_line": 5498}$$::jsonb, $$PU 0149 International Cooperative RDT&E: Provide program management, execution, and support to implement a broad range of cooperative Naval Research and Development, Test and Evaluation initiatives to improve coalition interoperability, harmonize U.S. Navy requirements with allied and friendly nations, and identify cooperative international opportunities, and improve coalition interoperability. In addition, it develops coherent approaches, coordinating with partner nations, to sea-based missile defense, command, control, communications, computers and intelligence (C4I), and cooperative acquisition programs while also identifying technology to support the Global Maritime Partnership initiative. PU 1767 Naval War College Strategic Studies Support: Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E              PE 0605853N / Management, Technical & Intl Supt Management Support Provides research, analysis and gaming activities which serve as a focal point, stimulus, and major source of strategic and operational thought within the Navy, joint and interagency communities. These efforts generate strategic and operational alternatives, quantitative analysis, war gaming and political military assessments, and provide recommendations regarding the formulation and execution of maritime options. The War Gaming Department plans, designs, executes, analyzes and reports on the Navy's Title 10 war games. These war games provide analytical input to the Navy's Strategic Plan, assessments of future concepts, and recommendations to the Navy's Quadrennial Defense Review, force design, and strategy process. The War Gaming Department also designs, executes and analyzes war games for theater security cooperation plans and operational war fighting issues. PU 2098 Naval Postgraduate School (NPS) Studies Support: Navy Postgraduate School (NPS) Naval Research Program (NRP) supports senior decision-makers from the Department of the Navy, the Office of the Chief of Naval Operations, Budget Submission Offices and Fleet Commanders in reaching well-informed, objective decisions on strategic, operational, and programmatic issues through collaborative and interdisciplinary research which integrates traditional research and analysis with advanced decision support tools. Faculty conducted research, student theses and capstone projects are an integral part of this program in support of the critical research and analysis requirements across the Naval enterprise. PU 2221 Assessment Program: The Navy Assessment Program provides capability-based planning assessment for Joint Capabilities Integration and Development System (JCIDS), conducts analysis to affect war fighting capability trades and enterprise resources, identifies needs, gaps, and overlaps, and assesses alternative solutions to Joint needs. The program supports both the development and use of modeling, simulation and analytically-based warfare and provides business analyses and analytic tools that provide the basis for decision making with respect to concepts of operations (CONOPS), Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR) Systems (Information Dominance); warfare systems (Sea Strike, Sea Shield, and Sea Basing) and analytical underpinnings/basis for programmatic decisions of the Navy's top leadership regarding their architectures, force structure, and the Navy's core "organize, train, and equip mission" (the warfare and provider Enterprises). The program provides overarching Planning, Programming, Budgeting and Execution System (PPBES) analyses and guidance for PPBES which provides gap analysis and investment strategy and total obligation authority allocation. It provides independent capability analysis and assists in structuring follow-on Navy analyses. The program coordinates Navy's position for the enhanced planning process and conducts net assessments. It serves as the lead campaign analysis to approve Navy warfare and support requirements. The program supports "A Cooperative Strategy for 21st Century Seapower 21" as modified by the Maritime Strategy which charts a course for the Navy, Coast Guard and Marine Corps to work collectively with each other and international partners to prevent crises from occurring or reacting quickly should one occur to avoid negative impact to the United States. It serves as an independent assessor providing a broad-view perspective across the Navy staff apart from resource sponsors, with an integrated look at both war fighting and war fighting support programs. The program supports the world class modeling efforts to attain a level of Modeling and Simulation (M&S) capability that is world class and establishes the Navy as a leader in the Department of Defense (DoD) M&S community. It provides Navy alternatives in assessing the implications embedded within resource decisions in a quantified context of costs versus capability versus risk. The program provides independent analytic support to Navy leadership in conjunction with various executive level decision forums. It develops tools and analytical methodologies that assist in evaluating Navy programs and provides technical leadership for the analysis functional area of Naval Modeling and Simulation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                 Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E               PE 0605853N / Management, Technical & Intl Supt Management Support PU 3017 Enterprise Information Systems: This project funds the Office of Naval Research (ONR) Next Generation Enterprise Network (NGEN) Information Technology corporate costs. PU 3312 MTMD - Maritime Theater Missile Defense Forum: This project funds participation in Maritime Integrated Air and Missile Defense projects with other nations through the Maritime Missile Defense Projects Framework Memorandum of Understanding of 2004 (as amended 2009, 2015, 2016 and 2020). Known as the Maritime Theater Missile Defense (MTMD) Forum, it promotes interoperability with the Navies of twelve participating nations (Australia, Belgium, Canada, Denmark, France, Germany, Italy, Netherlands, Norway, Spain, United Kingdom and the United States). This project provides interoperability assessment and opportunities to Allies that directly contributes to increasing the number of countries capable of supporting NATO Ballistic Missile Defense (BMD). Engineering analysis and data analytics from MTMD activities are provided to European and Pacific Combatant Commands in direct support of theater Integrated Air and Missile Defense (IAMD) priorities. The MTMD Forum addresses challenges associated with integrating maritime Allied Air Defense in Support of Ballistic Missile Defense Operations into joint IAMD command and control. MTMD Forum nations leverage At- Sea Demonstration (ASD) test events, coupled with operational Fleet Exercises (Formidable Shield and Pacific Dragon), to integrate technology and validate national capabilities in operational constructs, supportive of operational force employment. The MTMD Forum encourages national development of systems and practices that enhance protection and defense against the proliferation of short, medium and long- range Ballistic Missile (BM) and Advanced Anti-Ship Cruise Missile (ASCM) threats through the development of interoperable sea-based Integrated Air and Missile Defense (IAMD) capability among MTMD Forum nations. The MTMD Forum enhances utilization of existing sea-based IAMD systems to protect against current threats, while measuring progressive improvement and development of compatible systems to better counter evolving threats. This project supports USN participation in a Maritime IAMD Project Arrangement focused on: (1) Battle Management Command, Control, Communications, Computers, and Intelligence (BMC4I) to define and develop architectures and perform engineering to address coalition capability gaps. (2) Modeling & Simulation (M&S) to establish and maintain a maritime coalition M&S testbed and to perform legacy and future systems simulation testing. (3) Hardware-in-the-Loop Testing of Coalition combat systems to assess interoperability within the Coalition Distributed Engineering Plant (CDEP). (4) Open Architecture (OA) work to develop Interface Standards and Data Models. (5) Test Planning and Execution (TPEX) to develop Test Plans, oversee exercise participation and conduct post event data analysis and reporting. (6) Operational Requirements (OR) to identify operational constraints and tactical constructs surrounding coalition maritime integrated air and missile defense activities, and their integration into joint operations. (7) Reciprocal Use of Test Facilities agreements with other nations to support Maritime IAMD and MTMD Forum-related demonstrations. PU 3330 Naval Research Laboratory (NRL) Facilities Modernization: Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E               PE 0605853N / Management, Technical & Intl Supt Management Support This program has been established to provide a systematic and planned approach to improve vital in-house science and technology (S&T) laboratory facilities which are reaching or have reached critical stages of deterioration. The program includes restoration and modernization (R&M) initiatives for about 350,000 net square feet, where the average age of the buildings is 67 years old. PU 3363 PACOM Initiative: This project supports the China Strategic Initiative (CSI) and Pacific Multi-Domain Training and Experimentation Capability (PMTEC) efforts. The CSI program is U.S. Indo-Pacific Command's (INDOPACOM) first Asia Rebalance initiative and provides cutting-edge research on adversary approaches to warfare, monitoring and analysis of adversary social media and censorship, unique understanding of effects of U.S. actions at the strategic and operational levels, sponsorship of Track 1.5/2 Strategic Nuclear Dialogue with China, etc. This funding is for a classified effort and details can be provided at a higher classification level. Pacific Multi-Domain Training and Experimentation Capability (PMTEC) is foundational to meeting Commander, USINDOPACOM's high-end warfighting capability, theater force posture, and Ally & Partner (A&P) objectives through the execution of joint experimentation in the Indo-Pacific. PMTEC is the joint synchronizer and integrator by bringing together OSD, Service RDT&E, other government agencies, industry, and academia with Combatant Commands, Service Components, warfighting units, and A&Ps to expedite experimentations of R&D projects/prototypes and to facilitate more rapid modernization and interoperability. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation.$$, NULL, 171110000, 178817000, 179009000, NULL, NULL, 193, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 138947000, 201830000, 124898000, 124898000, NULL, 124898000, 181818000, $$PU 0149 International Cooperative RDT&E: Provide program management, execution, and support to implement a broad range of cooperative Naval Research and Development, Test and Evaluation initiatives to improve coalition interoperability, harmonize U.S. Navy requirements with allied and friendly nations, and identify cooperative international opportunities, and improve coalition interoperability. In addition, it develops coherent approaches, coordinating with partner nations, to sea-based missile defense, command, control, communications, computers and intelligence (C4I), and cooperative acquisition programs while also identifying technology to support the Global Maritime Partnership initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E              PE 0605853N / Management, Technical & Intl Supt Management Support PU 1767 Naval War College Strategic Studies Support: Provides research, analysis and gaming activities which serve as a focal point, stimulus, and major source of strategic and operational thought within the Navy, joint and interagency communities. These efforts generate strategic and operational alternatives, quantitative analysis, war gaming and political military assessments, and provide recommendations regarding the formulation and execution of maritime options. The War Gaming Department plans, designs, executes, analyzes and reports on the Navy's Title 10 war games. These war games provide analytical input to the Navy's Strategic Plan, assessments of future concepts, and recommendations to the Navy's Quadrennial Defense Review, force design, and strategy process. The War Gaming Department also designs, executes and analyzes war games for theater security cooperation plans and operational war fighting issues. PU 2098 Naval Postgraduate School (NPS) Studies Support: Navy Postgraduate School (NPS) Naval Research Program (NRP) supports senior decision-makers from the Department of the Navy, the Office of the Chief of Naval Operations, Budget Submission Offices and Fleet Commanders in reaching well-informed, objective decisions on strategic, operational, and programmatic issues through collaborative and interdisciplinary research which integrates traditional research and analysis with advanced decision support tools. Faculty conducted research, student theses and capstone projects are an integral part of this program in support of the critical research and analysis requirements across the Naval enterprise. PU 2221 Assessment Program: The Navy Assessment Program provides capability-based planning assessment for Joint Capabilities Integration and Development System (JCIDS), conducts analysis to affect war fighting capability trades and enterprise resources, identifies needs, gaps, and overlaps, and assesses alternative solutions to Joint needs. The program supports both the development and use of modeling, simulation and analytically-based warfare and provides business analyses and analytic tools that provide the basis for decision making with respect to concepts of operations (CONOPS), Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR) Systems (Information Dominance); warfare systems (Sea Strike, Sea Shield, and Sea Basing) and analytical underpinnings/basis for programmatic decisions of the Navy's top leadership regarding their architectures, force structure, and the Navy's core "organize, train, and equip mission" (the warfare and provider Enterprises). The program provides overarching Planning, Programming, Budgeting and Execution System (PPBES) analyses and guidance for PPBES which provides gap analysis and investment strategy and total obligation authority allocation. It provides independent capability analysis and assists in structuring follow-on Navy analyses. The program coordinates Navy's position for the enhanced planning process and conducts net assessments. It serves as the lead campaign analysis to approve Navy warfare and support requirements. The program supports "A Cooperative Strategy for 21st Century Seapower 21" as modified by the Maritime Strategy which charts a course for the Navy, Coast Guard and Marine Corps to work collectively with each other and international partners to prevent crises from occurring or reacting quickly should one occur to avoid negative impact to the United States. It serves as an independent assessor providing a broad-view perspective across the Navy staff apart from resource sponsors, with an integrated look at both war fighting and war fighting support programs. The program supports the world class modeling efforts to attain a level of Modeling and Simulation (M&S) capability that is world class and establishes the Navy as a leader in the Department of War (DoW) M&S community. It provides Navy alternatives in assessing the implications embedded within resource decisions in a quantified context of costs versus capability versus risk. The program provides independent analytic support to Navy leadership in conjunction with various executive level decision forums. It develops tools and analytical methodologies that assist in evaluating Navy programs and provides technical leadership for the analysis functional area of Naval Modeling and Simulation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                  Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E               PE 0605853N / Management, Technical & Intl Supt Management Support PU 3017 Enterprise Information Systems: This project funds the Office of Naval Research (ONR) Next Generation Enterprise Network (NGEN) Information Technology corporate costs. PU 3312 MTMD - Maritime Theater Missile Defense Forum: This project funds two interdependent efforts: developing the next generation of interoperability capabilities to support burden sharing with high-end warfighting nations (including Australia, Belgium, Canada, Denmark, France, Germany, Italy, Netherlands, Norway, Spain, United Kingdom and the United States) and testing warfighter proficiency against high-end targets that emulate complex threats. This project assesses to participating nations' ability to share the burden of NATO Ballistic Missile Defense (BMD), currently filled by US forces in Europe. Engineering analysis and data analytics from sponsored test events are provided to European and Pacific Combatant Commands in direct support of theater Integrated Air and Missile Defense (IAMD) priorities. The MTMD Forum addresses challenges associated with integrating maritime Allied Air Defense in Support of Ballistic Missile Defense Operations into joint IAMD command and control. MTMD Forum nations leverage At- Sea Demonstration (ASD) test events, coupled with operational Fleet Exercises (Formidable Shield and Pacific Dragon), to integrate technology and validate national capabilities in operational constructs, supportive of operational force employment. The MTMD Forum accelerates national development of systems and practices that enhance protection and defense against the proliferation of short, medium and long- range Ballistic Missile (BM) and Advanced Anti-Ship Cruise Missile (ASCM) threats through the development of interoperable sea-based Integrated Air and Missile Defense (IAMD) capability among MTMD Forum nations. The MTMD Forum enhances utilization of existing sea-based IAMD systems to protect against current threats, while measuring progressive improvement and development of compatible systems to better counter evolving threats. The program encompasses the spectrum from in-service testing and demonstration in order to evaluate participating nations' ability to fight tonight, to theoretical development of the replacement technologies for current link interoperability. Leveraging modeling and simulation, hardware in the loop testing, and at sea exercises, this program is able to quantitatively deliver improvements in IAMD within partner nations. PU 3330 Naval Research Laboratory (NRL) Facilities Modernization: This program has been established to provide a systematic and planned approach to improve vital in-house science and technology (S&T) laboratory facilities which are reaching or have reached critical stages of deterioration. The program includes restoration and modernization (R&M) initiatives for about 350,000 net square feet, where the average age of the buildings is 67 years old. PU 3363 PACOM Initiative: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E                  PE 0605853N / Management, Technical & Intl Supt Management Support This project supports the China Strategic Initiative (CSI) and Pacific Multi-Domain Training and Experimentation Capability (PMTEC) efforts. The CSI program is U.S. Indo-Pacific Command's (INDOPACOM) first Asia Rebalance initiative and provides cutting-edge research on adversary approaches to warfare, monitoring and analysis of adversary social media and censorship, unique understanding of effects of U.S. actions at the strategic and operational levels, sponsorship of Track 1.5/2 Strategic Nuclear Dialogue with China, etc. This funding is for a classified effort and details can be provided at a higher classification level. Pacific Multi-Domain Training and Experimentation Capability (PMTEC) is foundational to meeting Commander, USINDOPACOM's high-end warfighting capability, theater force posture, and Ally & Partner (A&P) objectives through the execution of joint experimentation in the Indo-Pacific. PMTEC is the joint synchronizer and integrator by bringing together OSW, Service RDT&E, other government agencies, industry, and academia with Combatant Commands, Service Components, warfighting units, and A&Ps to expedite experimentations of R&D projects/prototypes and to facilitate more rapid modernization and interoperability. In FY 2027, the Joint Fires Network (JFN) will deliver and test new software capabilities, multi-level security (MLS) capability enhancements and infrastructure deployments. JFN will deliver new command and control software capabilities and establish automated connections between JFN and service command and control systems, ISR systems and fires systems to enable collaborative planning and execution monitoring. The JFN system will integrate Generative AI models in special access facilities to enable decision superiority for fires across the joint force. Additionally, FY 2027 will see the delivery of JFN Operations Centers and nodes in both USINDOPACOM and USEUCOM. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation. The FY 2026 spend plan amount for Research, Development, Test and Evaluation, Navy includes $133,538 thousand of discretionary and $68,292 thousand of mandatory (reconciliation) for a total of $201,830.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605856N$$, $$Strategic Technical Support$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2026, 3709000, 3897000, 3536000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605856N", "page_header": "Department of the Navy"}$$::jsonb, $$This program element supports technical studies and analyses as directed by the Director for Submarine Warfare to support major policy and procurement decisions. This program is divided into two elements to support decision making in the areas of submarine and antisubmarine warfare and undersea surveillance.$$, NULL, 4132000, 3907000, 3931000, NULL, NULL, 194, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 3400000, 3709000, 4260000, 4260000, NULL, 4260000, 4007000, $$This program element supports technical studies and analyses as directed by the Director for Submarine Warfare to support major policy and procurement decisions. This program is divided into two elements to support decision making in the areas of submarine and antisubmarine warfare and undersea surveillance.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605857A$$, $$Environmental Quality Technology Mgmt Support$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 2857000, 1570000, 1659000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0605857A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) funds environmental quality technology related management support functions including support of research, development, test, and evaluation required for technical integration efforts at demonstration/validation test sites, technical information and activities, test facilities and general test instrumentation, and requirement assessments. Funds support the management of technology transfer associated with technology demonstrated and validated as part of Army environmental quality technology related projects. In addition, this PE provides support to the Army weapon system acquisition community to address environmental quality requirements under the Environmentally Sustainable Acquisition/Logistics Program. This PE also funds the Army Executive Agent responsibilities for the Unexploded Ordnance Center of Excellence (UXOCOE). The Environmentally Sustainable Acquisition/Logistics Project includes program management for developing acquisition strategies that achieve system key performance parameters and sustain the environment without permanent and unacceptable change to the natural environment or human health from system concept refinement through disposal. The Project involves systematic consideration of environmental impacts, energy use, natural resources, installation impacts, economics and quality of life. It provides support to the installation and system acquisition community (Program and Project Managers) to integrate environmental quality analyses into the system acquisition process. The goal of the effort is to resolve environmental quality issues related to weapon systems that are identified during design, development, testing, operation, or support to reduce Army environmental liabilities and total ownership costs, including efforts to eliminate the use of hazardous and ozone-depleting materials from weapon systems and facilities. The Environmentally Sustainable Acquisition/Logistics Project also funds Army Executive Agent Responsibilities for the Unexploded Ordnance Center of Excellence (UXOCOE). The UXOCOE centrally coordinates the DoD's Counter Explosive Hazards (C-EH) research and engineering (R&E) investment efforts by collecting, maintaining and sharing C-EH technology information across the DoD enabling the DoD to efficiently, effectively, and economically acquire C-EH technology derived capabilities. In application, the UXOCOE supports, seeks and manages the accuracy, timeliness, availability, and accessibility of scientific, technical, and management information for the DoD Components efforts to address C-EH requirements and operational needs at budget activity levels 1 to 4. It addresses Congressional concern to increase the availability of scientific, engineering, and technical information sharing throughout the DoD's Explosive Hazards Community of Interest, Academia, Industry, and other Federal Agencies Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E              PE 0605857A / Environmental Quality Technology Mgmt Support Management Support The Environmental Quality Technology Support Project funds the management support costs to execute the Toxic Metals Reduction, Airborne Lead Reduction, and American Innovation and Manufacturing (AIM) Act compliance environmental quality technology programs, which support Cross Functional Teams and the Army's top modernization priorities by addressing potential obsolescence of legacy materials and current and emerging impacts on human health and the environment. The FY 2026 request was reduced by $0.007 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 3301000, 3330000, 3370000, NULL, NULL, 192, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 1598000, 2857000, 3256000, 3256000, NULL, 3256000, 3408000, $$This Program Element (PE) funds environmental quality technology related management support functions including support of research, development, test, and evaluation required for technical integration efforts at demonstration/validation test sites, technical information and activities, test facilities and general test instrumentation, and requirement assessments. Funds support the management of technology transfer associated with technology demonstrated and validated as part of Army environmental quality technology related projects. In addition, this PE provides support to the Army weapon system acquisition community to address environmental quality requirements under the Environmentally Sustainable Acquisition/Logistics Program. This PE also funds the Army Executive Agent responsibilities for the Unexploded Ordnance Center of Excellence (UXOCOE). The Environmentally Sustainable Acquisition/Logistics Project includes program management for developing acquisition strategies that achieve system key performance parameters and sustain the environment without permanent and unacceptable change to the natural environment or human health from system concept refinement through disposal. The Project involves systematic consideration of environmental impacts, energy use, natural resources, installation impacts, economics and quality of life. It provides support to the installation and system acquisition community (Program and Project Managers) to integrate environmental quality analyses into the system acquisition process. The goal of the effort is to resolve environmental quality issues related to weapon systems that are identified during design, development, testing, operation, or support to reduce Army environmental liabilities and total ownership costs, including efforts to eliminate the use of hazardous and ozone-depleting materials from weapon systems and facilities. The Environmentally Sustainable Acquisition/Logistics Project also funds Army Executive Agent Responsibilities for the Unexploded Ordnance Center of Excellence (UXOCOE). The UXOCOE centrally coordinates the DoW's Counter Explosive Hazards (C-EH) research and engineering (R&E) investment efforts by collecting, maintaining and sharing C-EH technology information across the DoW enabling the DoW to efficiently, effectively, and economically acquire C-EH technology derived capabilities. In application, the UXOCOE supports, seeks and manages the accuracy, timeliness, availability, and accessibility of scientific, technical, and management information for the DoW Components efforts to address C-EH requirements and operational needs at budget activity levels 1 to 4. It addresses Congressional concern to increase the availability of scientific, engineering, and technical information sharing throughout the DoW's Explosive Hazards Community of Interest, Academia, Industry, and other Federal Agencies Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E              PE 0605857A / Environmental Quality Technology Mgmt Support Management Support The Environmental Quality Technology Support Project funds the management support costs to execute the Toxic Metals Reduction, Airborne Lead Reduction, and American Innovation and Manufacturing (AIM) Act compliance environmental quality technology programs, which support Cross Functional Teams and the Army's top modernization priorities by addressing potential obsolescence of legacy materials and current and emerging impacts on human health and the environment.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605863N$$, $$RDT&E Ship & Aircraft Support$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2026, 151479000, 198624000, 152176000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605863N", "page_header": "Department of the Navy"}$$::jsonb, $$This continuing program provides support for the Self Defense Test Ship and developmental test squadron aircraft required to support Research, Development, Test and Evaluation (RDT&E) of new systems. The RDT&E ship and aircraft inventory is required to adequately test modifications and improvements to fielded weapon systems and sensors and new weapon systems and sensors and evaluate modifications to address new threat capabilities to increase the warfighting capability of the fleet. The program provides integrated logistics support for aircraft at selected field activities, provides depot-level maintenance of aircraft, engines and components for the Navy's inventory of RDT&E aircraft; and provides support for DON aircraft in the custody of contractors in support of RDT&E. The Self Defense Test Ship is a remotely operated platform that supports the test and evaluation of surface ship sensors, combat systems and weapons within the close-in self defense zone. Cost covered under this element include test execution for the Air Warfare Ship Self-Defense Enterprise, aircrew training and proficiency, fuel, supplies, equipment, repair and Aviation Depot Level Repairables, as well as organizational, intermediate and depot maintenance of aircraft in the Navy RDTE inventory and the Self Defense Test Ship. Threat engineering provides test and evaluation (T&E) modeling and simulation (M&S) products and informs targets, simulators, and stimulator designs and development. This project satisfies Surface Navy advanced missile system threat characterization and verification, validation, & accreditation (VV&A) requirements for testing JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E           PE 0605863N / RDT&E Ship & Aircraft Support Management Support$$, NULL, 173382000, 149625000, 150955000, NULL, NULL, 195, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 150974000, 151479000, 170699000, 170699000, NULL, 170699000, 153211000, $$This continuing program provides support for the Self Defense Test Ship and developmental test squadron aircraft required to support Research, Development, Test and Evaluation (RDT&E) of new systems. The RDT&E ship and aircraft inventory is required to adequately test modifications and improvements to fielded weapon systems and sensors and new weapon systems and sensors and evaluate modifications to address new threat capabilities to increase the warfighting capability of the fleet. The program provides integrated logistics support for aircraft at selected field activities, provides depot-level maintenance of aircraft, engines and components for the Navy's inventory of RDT&E aircraft; and provides support for DON aircraft in the custody of contractors in support of RDT&E. The Self Defense Test Ship is a remotely operated platform that supports the test and evaluation of surface ship sensors, combat systems and weapons within the close-in self defense zone. Cost covered under this element include test execution for the Air Warfare Ship Self-Defense Enterprise, aircrew training and proficiency, fuel, supplies, equipment, repair and Aviation Depot Level Repairables, as well as organizational, intermediate and depot maintenance of aircraft in the Navy RDTE inventory and the Self Defense Test Ship. Threat engineering provides test and evaluation (T&E) modeling and simulation (M&S) products and informs targets, simulators, and stimulator designs and development. This project satisfies Surface Navy advanced missile system threat characterization and verification, validation, & accreditation (VV&A) requirements for testing JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                      Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E          PE 0605863N / RDT&E Ship & Aircraft Support Management Support$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605864N$$, $$Test & Evaluation Support$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2026, 463725000, 485476000, 477823000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605864N", "page_header": "Department of the Navy"}$$::jsonb, $$JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations and maintenance required to support research, development, test and evaluation. This program provides institutional maintenance and operations support for: the Naval Undersea Warfare Center Detachment Atlantic Undersea Test and Evaluation Center, Andros Island, Bahamas; the Environmental Compliance Program; Naval Air Warfare Center Weapons Division, Point Mugu and China Lake, CA; Naval Air Warfare Center Aircraft Division, Patuxent River, MD; Test and Evaluation related capabilities at the Pacific Missile Range Facility, Barking Sands, HI; Maintenance and Repair at Naval Air Warfare Center Weapons Division, Naval Air Warfare Center Aircraft Division, and Naval Undersea Warfare Center Detachment Atlantic Undersea Test and Evaluation Center. The program also provides marine vessels overhauls and preventative maintenance in support of the 23 Major Range and Test Facility Base (MRTFB) marine vessels located at Naval Air Warfare Center Weapons Division, Point Mugu, CA, Pacific Missile Range Facility, Honolulu, HI, Naval Undersea Warfare Center Keyport Nanoose and Dabob Bay Ranges, Keyport, WA, Naval Air Warfare Center Aircraft Division, Patuxent River, MD, and Naval Undersea Warfare Center Detachment Atlantic Undersea Test and Evaluation Center. The Test and Evaluation activities make up the Navy portion of the Department of Defense's Major Range and Test Facility Base. These activities are chartered to perform Test and Evaluation for the development and acquisition of technologically advanced weapons Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                             Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E              PE 0605864N / Test & Evaluation Support Management Support systems. Core Test and Evaluation capabilities and capacity are operated to obtain weapons system performance documentation for acquisition program milestone decisions to provide operational forces with effective weapons systems. This program provides Navy Acquisition Program Managers required test capabilities; lowers cost of Test and Evaluation; removes cost and scheduling impact of developing and providing their own Test and Evaluation capabilities; and retains the physical airspace, land space and sea space needed to conduct testing.$$, NULL, 500768000, 500096000, 517017000, NULL, NULL, 196, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 476655000, 463725000, 470492000, 470492000, NULL, 470492000, 524673000, $$JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations and maintenance required to support research, development, test and evaluation. This program provides institutional maintenance and operations support for: the Naval Undersea Warfare Center Detachment Atlantic Undersea Test and Evaluation Center, Andros Island, Bahamas; the Environmental Compliance Program; Naval Air Warfare Center Weapons Division, Point Mugu and China Lake, CA; Naval Air Warfare Center Aircraft Division, Patuxent River, MD; Test and Evaluation related capabilities at the Pacific Missile Range Facility, Barking Sands, HI; Maintenance and Repair at Naval Air Warfare Center Weapons Division, Naval Air Warfare Center Aircraft Division, and Naval Undersea Warfare Center Detachment Atlantic Undersea Test and Evaluation Center. The program also provides marine vessels overhauls and preventative maintenance in support of the 23 Major Range and Test Facility Base (MRTFB) marine vessel located at Naval Air Warfare Center Weapons Division, Point Mugu, CA, Pacific Missile Range Facility, Barking Sands, HI, Naval Undersea Warfare Center Keyport Nanoose and Dabob Bay Ranges, Keyport, WA, Naval Air Warfare Center Aircraft Division, Patuxent River, MD, and Naval Undersea Warfare Center Detachment Atlantic Undersea Test and Evaluation Center. The Test and Evaluation activities make up the Navy portion of the Department of War's Major Range and Test Facility Base. These activities are chartered to perform Test and Evaluation for the development and acquisition of technologically advanced weapons systems. Core Test and Evaluation capabilities and capacity are operated to obtain weapons system performance documentation for acquisition program Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E              PE 0605864N / Test & Evaluation Support Management Support milestone decisions to provide operational forces with effective weapons systems. This program provides Navy Acquisition Program Managers required test capabilities; lowers cost of Test and Evaluation; removes cost and scheduling impact of developing and providing their own Test and Evaluation capabilities; and retains the physical airspace, land space and sea space needed to conduct testing.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605865N$$, $$Operational Test & Eval Capability$$, $$rdte_navy_ba6$$, $$dw_dote$$, 2026, 30880000, 28863000, 30603000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605865N", "page_header": "Department of the Navy"}$$::jsonb, $$This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing facilities and conducting operations required for general research, development, test and evaluation. Headquartered in Norfolk, Virginia, OPTEVFOR serves as the Service Operational Test Agency for the Navy and for Marine Corps Aviation. In addition to the headquarters element, OPTEVFOR includes a Fleet-scheduling detachment in San Diego, a detachment supporting the Joint Strike Fighter, and the US Operational Test Team at Nellis, Air Force Base (AFB), NV. There are four Navy and Marine Corps Squadrons that conduct OT&E under the direction of the OPTEVFOR Director. Air Test and Evaluation Squadron ONE (VX-1), located at Patuxent River, MD, is under the administrative control of Commander, Naval Air Forces, Atlantic. Air Test and Evaluation Squadron NINE (VX-9), located at China Lake, CA, is under the administrative control of Commander, Naval Air Forces, Pacific. Marine Operational Test and Evaluation Squadron ONE (VMX-1), located at Yuma, AZ is administratively aligned under the Deputy Commandant for Aviation. Marine Helicopter Squadron ONE (HMX-1), located at Quantico, VA, responsible for OT of aircraft assigned for Presidential transport. OPTEVFOR utilizes a competency- and warfare-aligned organizational structure to apply rigorous scientific and technical methods within mission-based evaluations of complex systems and capabilities being delivered to the Fleet. OPTEVFOR's Warfare Divisions are responsible for delivering test documents ready for the Director's signature and executing adequate operational test and evaluation (OT&E) for Naval systems and reporting defendable conclusions about capabilities potentially being fielded. They are supported by Competency Divisions, who ensure the product meets technical requirements, and DoN and OPTEVFOR standards. There are six warfare divisions: Undersea Warfare (40), Air Warfare (50), Information Warfare (60), Surface Warfare (70), Expeditionary Warfare (80), and Advanced Programs (90). Each warfare division is led by a Navy Captain as the Division Director with a senior civil servant as the Deputy; or led by a senior civil servant with a Navy Captain/Commander as the Deputy. There are four competency divisions: Policy, Operations, and Training (01A); Test Design and Analysis (01B); Test Planning and Evaluation (01C); and Cybersecurity Testing (01D). In addition, the Technical Director (00TD) supports all divisions on technical aspects of the test products. Operations and business support divisions include the Staff Commanding Officer and Administration (10), Chief Information Officer (CIO) (20), Contracts (01K), and the Comptroller (30). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                           Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E           PE 0605865N / Operational Test & Eval Capability Management Support$$, NULL, 34595000, 36474000, 37283000, NULL, NULL, 197, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 30032000, 30880000, 31902000, 31902000, NULL, 31902000, 38036000, $$This program is funded under Research, Development, Test and Evaluation Management Support because it supports efforts directed toward sustaining or modernizing facilities and conducting operations required for general research, development, test, and evaluation. Headquartered in Norfolk, Virginia, OPTEVFOR serves as the Service Operational Test Agency for the Navy and Marine Corps Aviation. In addition to the headquarters element, OPTEVFOR includes a Fleet scheduling detachment in San Diego, a detachment supporting the Joint Strike Fighter, and the U.S. Operational Test Team at Nellis Air Force Base, Nevada. Operational test and evaluation is conducted under the direction of the OPTEVFOR Director by four Navy and Marine Corps squadrons: Air Test and Evaluation Squadron ONE (VX-1) at Naval Air Station Patuxent River, Air Test and Evaluation Squadron NINE (VX-9) at Naval Air Weapons Station China Lake, Marine Operational Test and Evaluation Squadron ONE (VMX-1) at Marine Corps Air Station Yuma, and Marine Helicopter Squadron ONE (HMX-1) at Marine Corps Base Quantico. OPTEVFOR utilizes a competency- and warfare-aligned organizational structure to apply rigorous scientific and technical methods within mission-based evaluations of complex systems and capabilities being delivered to the Fleet. OPTEVFOR's Warfare Divisions are responsible for delivering test documents ready for the Director's signature and executing adequate operational test and evaluation (OT&E) for Naval systems and reporting defendable conclusions about capabilities potentially being fielded. They are supported by Competency Divisions, who ensure OPTEVFOR products meet technical requirements, and DoN and OPTEVFOR standards. There are six warfare divisions: Undersea Warfare (40), Air Warfare (50), Information Warfare (60), Surface Warfare (70), Expeditionary Warfare (80), and Advanced Programs (90). Each warfare division is led by a Navy Captain serving as Division Director with a senior civilian deputy, or a senior civilian director with a Navy Captain/ Commander as the deputy. Competency divisions include Test Design and Analysis (01B), Test Planning and Evaluation (01C), and Cybersecurity Testing (01D). The Technical Director (00TD) supports all divisions on test and evaluation and technical aspects of test products. Operations and business support divisions include Administrative Services Division (10), Chief Information Office (20), Human Resources, Training and Integrated Risk Management (01A), Contracts (01K), and Comptroller (30). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E               PE 0605865N / Operational Test & Eval Capability Management Support$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605866N$$, $$Navy Space & Electr Warfare Supt$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2026, 22563000, 26551000, 23668000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605866N", "page_header": "Department of the Navy"}$$::jsonb, $$Project 0706, Electromagnetic Compatibility (EMC) and Radio Frequency (RF) Management Program: This project develops tools, processes, EMC Criteria for Navy Systems, and algorithms to identify and mitigate Electromagnetic Interference (EMI) sources for Navy systems and platforms. Project 3239, The Real-Time Spectrum Operations (RTSO) Program: This project develops software to automate analyses of the electromagnetic (EM) environmental effects (E3) between shipboard transmitters and receivers and the interactions of the EM systems with the other systems installed on units within a strike group. The RTSO program develops and updates numerical models, algorithms, databases, and software aiding and supporting warfighter spectrum planning, sensing and monitoring of the EM environment, EM spectrum characterization and prediction, and managing and maneuvering within the EM spectrum.$$, NULL, 21014000, 21186000, 21559000, NULL, NULL, 198, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 22983000, 22563000, 21498000, 21498000, NULL, 21498000, 21955000, $$Project 0706, Electromagnetic Compatibility (EMC) and Radio Frequency (RF) Management Program: This project develops tools, processes, EMC Criteria for Navy Systems, and algorithms to identify and mitigate Electromagnetic Interference (EMI) sources for Navy systems and platforms. Project 3239, The Real-Time Spectrum Operations (RTSO) Program: This project develops software to automate analyses of the electromagnetic (EM) environmental effects (E3) between shipboard transmitters and receivers and the interactions of the EM systems with the other systems installed on units within a strike group. The RTSO program develops and updates numerical models, algorithms, databases, and software aiding and supporting warfighter spectrum planning, sensing and monitoring of the EM environment, EM spectrum characterization and prediction, and managing and maneuvering within the EM spectrum.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
