INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L065$$, $$RADIAC$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 5105000, 3341000, 7287000, NULL, $${"page": 99, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "65", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 60", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 54487, "p1_line_num": 60, "fy27_total_K": 54487}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 60058, "li_num": 60, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 5105000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 348370000, NULL, NULL, NULL, FALSE, 38688000, 31289000, 54487000, 54487000, 0, 54487000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605873M$$, $$Marine Corps Program Wide Supt$$, $$rdte_navy_ba6$$, $$dw_dote$$, 2026, 28816000, 33641000, 32700000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "mc", "page_num": 36, "original_pe": "0605873M", "page_header": "Department of the Navy"}$$::jsonb, $$This program element (PE) provides the analytical foundation for the Marine Corps Studies System (MCSS), including mandated Mission Area Analyses and Cost and Operational Effectiveness Analyses. It also includes capabilities that facilitate force development, war plan assessment, and concept and combat development. The MCSS is the front end of the Marine Corps' acquisition system. This PE also supports the material acquisition process as follows: managing Marine Corps Operational Test and Evaluations; providing Chemical and Biological Consequence Management capabilities for Weapons of Mass Destruction incident response forces; development of the Wargaming capability; and conducting analyses to inform the development and integration of Marine Corps Information Environment Operations (IE Ops).$$, NULL, 31102000, 31962000, 36547000, NULL, NULL, 200, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 30088000, 28816000, 70013000, 70013000, NULL, 70013000, 39308000, $$This program element (PE) provides the analytical foundation for the Marine Corps Studies System (MCSS), including mandated Mission Area Analyses and Cost and Operational Effectiveness Analyses. It also includes capabilities that facilitate force development, war plan assessment, and concept and combat development. The MCSS is the front end of the Marine Corps' acquisition system. This PE also supports the material acquisition process as follows: managing Marine Corps Operational Test and Evaluations; providing Chemical and Biological Consequence Management capabilities for Weapons of Mass Destruction incident response forces; development of the Wargaming capability; and conducting analyses to inform the development and integration of Marine Corps Information Environment Operations (IE Ops).$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605898A$$, $$Army Direct Report Headquarters - R&D - MHA$$, $$rdte_army_ba6$$, $$afc$$, 2026, 53436000, 55497000, 59727000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0605898A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line supports testing of Army Transformation Priority Programs. This Program Element (PE) provides funding for the salaries and related personnel benefits for authorized civilian personnel positions that provide for the management functions and the technical direction of the United States (U.S.) Army Test and Evaluation Command (ATEC) Headquarters mission located at Aberdeen Proving Ground (APG), Maryland (Project M65 Army Test and Evaluation Command). It also provides funds for Army Headquarters to study and improve the Sexual Harassment / Assault Response and Prevention program (Project FJ2 Army SHARP RDTE). ATEC plans, conducts and integrates developmental testing, independent operational testing, independent evaluations, and assessments to provide essential information to Soldiers and acquisition decision makers supporting the American Warfighter. Additionally, ATEC provides Direct Support to Army Futures Command (AFC). ATEC provides testing and independent evaluation support to AFC Cross Functional Team (CFT) efforts including risk reduction support to experiments, demonstrations, requirements, research, development, and acquisition. As such, ATEC priorities are aligned to the Army's Transformation priorities. Project M65 includes the following functions: human resources, safety, security, environmental, strategic planning, operations, engineering and logistics, resource management, test capabilities management, policy and standardization, public affairs, legal, Inspector General, Equal Opportunity, and information/technology support for command-wide efforts in support of the developmental, evaluation and operational test missions with technical direction to the Army Evaluation Center (AEC), APG, Maryland; to the Operational Test Command (OTC), Fort Cavazos, Texas which consists of three forward Test Directorates (Airborne and Special Operations Test Directorate, Fort Liberty, North Carolina; Air Defense Artillery Test Directorate, Fort Bliss, Texas; and the Fires Test Directorate, Fort Sill, Oklahoma) together with four other Test Directorates (Aviation; Maneuver; Mission Command; Maneuver Support and Sustainment) at Ft Cavazos, Texas; and to the seven Major Range and Test Facility Base (MRTFBs) and one non-MRTFB test range: Aberdeen Test Center (ATC) at APG, Maryland; West Desert Test Center (WDTC) at Dugway Proving Ground (DPG), Utah; Electronic Proving Ground (EPG) at Fort Huachuca, Arizona; White Sands Test Center (WSTC) at White Sands Missile Range (WSMR), New Mexico; Yuma Test Center (YTC) at Yuma Proving Ground (YPG), Arizona; Arctic Regions Test Center (ARTC) at Fort Greely, Alaska; and Tropic Regions Test Center (TRTC) at various locations, as well as for Redstone Test Center (RTC) at Redstone Arsenal, Alabama. This is the operating budget for ATEC Headquarters, which provides technical direction for the annual execution of over 2,500 developmental tests; over 755 operational events; and over 700 Evaluation and Safety documents supporting Army transformation and other acquisition programs. It also provides funding to address enterprise level operating requirements that support the entire command and its three missions. ATEC's total program averages around $2 billion in direct and reimbursable funding. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E          PE 0605898A / Army Direct Report Headquarters - R&D - MHA Management Support Project FJ2 provides Army Management Headquarters a critical research capability to improve the Army Sexual Harassment / Assault Response and Prevention (SHARP) program, with a specific focus on prevention. This PE does not finance test facility operations, test instrumentation, or test equipment. The FY 2026 request was reduced by $0.427 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.337 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 55103000, 55522000, 55260000, NULL, NULL, 193, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 59381000, 53436000, 54276000, 54276000, NULL, 54276000, 55821000, $$This Program Element (PE) provides funding for the salaries and related personnel benefits for authorized civilian personnel positions that provide for the management functions and the technical direction of the United States (U.S.) Army Test and Evaluation Command (ATEC) Headquarters mission located at Aberdeen Proving Ground (APG), Maryland (project M65 Army Test and Evaluation Command). It also provides funds for Army Headquarters to study and improve the Sexual Harassment / Assault Response and Prevention program (project FJ2 Army SHARP RDTE). ATEC plans, conducts and integrates developmental testing, independent operational testing, independent evaluations, and assessments to provide essential information to Soldiers and acquisition decision makers supporting the American Warfighter. Additionally, ATEC provides Direct Support to Army Futures Command (AFC). ATEC provides testing and independent evaluation support to AFC Cross Functional Team (CFT) efforts including risk reduction support to experiments, demonstrations, requirements, research, development, and acquisition. As such, ATEC priorities are aligned to the Army's Transformation priorities. This M65 project includes the following functions: human resources, safety, security, environmental, strategic planning, operations, engineering and logistics, resource management, test capabilities management, policy and standardization, public affairs, legal, Inspector General, Equal Opportunity, and information/technology support for command-wide efforts in support of the developmental, evaluation and operational test missions with technical direction to the Army Evaluation Center (AEC), APG, Maryland; to the Operational Test Command (OTC), Fort Cavazos, Texas which consists of three forward Test Directorates (Airborne and Special Operations Test Directorate, Fort Liberty, North Carolina; Air Defense Artillery Test Directorate, Fort Bliss, Texas; and the Fires Test Directorate, Fort Sill, Oklahoma) together with four other Test Directorates (Aviation; Maneuver; Mission Command; Maneuver Support and Sustainment) at Ft Cavazos, Texas; and to the seven Major Range and Test Facility Base (MRTFBs) and one non-MRTFB test range: Aberdeen Test Center (ATC) at APG, Maryland; West Desert Test Center (WDTC) at Dugway Proving Ground (DPG), Utah; Electronic Proving Ground (EPG) at Fort Huachuca, Arizona; White Sands Test Center (WSTC) at White Sands Missile Range (WSMR), New Mexico; Yuma Test Center (YTC) at Yuma Proving Ground (YPG), Arizona; Arctic Regions Test Center (ARTC) at Fort Greely, Alaska; and Tropic Regions Test Center (TRTC) at various locations, as well as for Redstone Test Center (RTC) at Redstone Arsenal, Alabama. This is the operating budget for ATEC Headquarters, which provides technical direction for the annual execution of over 2,500 developmental tests; over 755 operational events; and over 700 Evaluation and Safety documents supporting Army transformation and other acquisition programs. It also provides funding to address enterprise level operating requirements that support the entire command and its three missions. ATEC's total program averages around $2 billion in direct and reimbursable funding. This FJ2 project provides Army Management Headquarters a critical research capability to improve the Army Sexual Harassment / Assault Response and Prevention (SHARP) program, with a specific focus on prevention. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                            Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E                 PE 0605898A / Army Direct Report Headquarters - R&D - MHA Management Support This PE does not finance test facility operations, test instrumentation, or test equipment.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605898E$$, $$MANAGEMENT HQ - R&D$$, $$rdte_dw_ba6$$, $$dw_darpa$$, 2026, 13623000, 15176000, 14577000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0605898E", "page_header": "Defense-Wide"}$$::jsonb, $$The Management HQ - R&D Program Element provides funding for the administrative support costs of the Defense Advanced Research Projects Agency. This project provides funding for DARPA Management Headquarters Activities (MHA). The funds provide personnel compensation for management headquarters civilians as well as associated travel and support contract costs.$$, NULL, 5507000, 5644000, 5738000, NULL, NULL, 193, $$RDTE_Vol1_DARPA_MasterJustificationBook_PB_2026.pdf$$, $$DARPA$$, FALSE, 15587000, 13623000, 5383000, 5383000, NULL, 5383000, 5846000, $$The Management HQ - R&D Program Element provides funding for the administrative support costs of the Defense Advanced Research Projects Agency. This project provides funding for DARPA Management Headquarters Activities (MHA). The funds provide personnel compensation for management headquarters civilians as well as associated travel and support contract costs.$$, $$Budget J-Books/FY27/DW/RDTE_Vol1_DARPA_MasterJustificationBook_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605898F$$, $$Management HQ - R&D$$, $$rdte_af_ba6$$, $$aflcmc$$, 2026, 5960000, 6705000, 6291000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605898F"}$$::jsonb, $$The Management Headquarters program element 0605898F includes management headquarters personnel for Air Force Life Cycle Management Center. The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E     PE 0605898F / Management HQ - R&D Management Support$$, NULL, 6132000, 6261000, 6393000, NULL, NULL, 137, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 6541000, 5960000, 6209000, 6209000, 0, 6209000, 6527000, $$The Management Headquarters program element 0605898F includes management headquarters personnel for Air Force Life Cycle Management Center. The Air Force Life Cycle Management Center (AFLCMC) equips U.S. and allied forces with operational weapon systems in support of military and national security operations. The acquisition and product support workforce provides cutting edge weapon systems, sustainment capabilities, and is charged with providing management, tools, and technical and business capabilities needed to oversee acquisition programs throughout their life cycle. The direct funded acquisition workforce funded in this program element will support all phases of acquisition programs to include material solution analysis, technology development, engineering and manufacturing development, production and deployment, and operations and support. This funding does not include costs for base operating support civilian personnel. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605898N$$, $$Management HQ - R&D$$, $$rdte_navy_ba6$$, $$onr$$, 2026, 42751000, 40638000, 42381000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0605898N", "page_header": "Department of the Navy"}$$::jsonb, $$The Management HQ - R&D program funds management headquarter civilian personnel salaries at the Office of Naval Research (ONR). These personnel support the management of the Naval Science and Technology (S&T) programs. This program also funds management headquarter contractor support for the Integrated Warfare Systems (IWS) Program Executive Office.$$, NULL, 33923000, 34501000, 34666000, NULL, NULL, 201, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 41405000, 42751000, 33533000, 33533000, NULL, 33533000, 35327000, $$The Management HQ - R&D program funds management headquarter civilian personnel salaries at the Office of Naval Research (ONR). These personnel support the management of the Naval Science and Technology (S&T) programs. This program also funds management headquarter contractor support for the Integrated Warfare Systems (IWS) Program Executive Office.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605976F$$, $$Facilities Restoration and Modernization - Test and Evaluation Support$$, $$rdte_af_ba6$$, $$aftc$$, 2026, 217761000, 116389000, 94828000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605976F"}$$::jsonb, $$Restoration includes repair or replacement work to restore facilities damaged by inadequate sustainment, excessive age, natural disaster, fire, accident, or other causes. Modernization includes alteration or replacement of facilities to implement new or higher standards, to accommodate new functions, or to replace aging building components that typically last more than 50 years (such as framework or foundation). Environmental compliance costs, facility leases, and other tasks associated with facilities operations (such as custodial services, grounds services, waste disposal and the provision of central utilities) are not included. Restoration/modernization funds support the following Air Force test organizations and their associated test and evaluation facilities: the 96th Test Wing (TW) at Eglin AFB, FL; the 412TW at Edwards AFB, CA; and the Arnold Engineering and Development Complex (AEDC), to include assets at Arnold AFB, TN, the 704th Test Group (TG) at Holloman AFB, NM, the 704TG Landing Gear Test Facility (LGTF) at Wright-Patterson AFB, OH, the Hypersonic Wind Tunnel 9 at White Oak, MD, and the National Full-Scale Aerodynamics Complex (NFAC) at Moffett Field, CA. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 314271000, 283952000, 288913000, NULL, NULL, 138, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 94828000, 199363000, 367369000, 367369000, 0, 367369000, 273433000, $$This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605807F. Restoration includes repair or replacement work to restore facilities damaged by inadequate sustainment, excessive age, natural disaster, fire, accident, or other causes. Modernization includes alteration or replacement of facilities to implement new or higher standards, to accommodate new functions, or to replace aging building components that typically last more than 50 years (such as framework or foundation). Environmental compliance costs, facility leases, and other tasks associated with facilities operations (such as custodial services, grounds services, waste disposal and the provision of central utilities) are not included. Restoration/modernization funds support the following Air Force test organizations and their associated test and evaluation facilities: the 96th Test Wing (TW) at Eglin AFB, FL; the 412TW at Edwards AFB, CA; and the Arnold Engineering and Development Complex (AEDC), to include assets at Arnold AFB, TN, the 704th Test Group (TG) at Holloman AFB, NM, the 704TG Landing Gear Test Facility (LGTF) at Wright-Patterson AFB, OH, the Hypersonic Wind Tunnel 9 at White Oak, MD, and the National Full-Scale Aerodynamics Complex (NFAC) at Moffett Field, CA. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605978F$$, $$Facilities Sustainment - Test and Evaluation Support$$, $$rdte_af_ba6$$, $$aftc$$, 2026, 91969000, 56218000, 63579000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0605978F"}$$::jsonb, $$Sustainment is defined as the maintenance and repair activities necessary to keep facilities in good working order and includes regularly scheduled adjustments and inspections, preventative maintenance tasks, and emergency response and service calls for minor repairs. It also includes major repairs or replacement of facility components (usually accomplished by contract) that are expected to occur periodically throughout the lifecycle of facilities. This work includes regular roof replacement, refinishing of wall and floor surfaces, repairing and replacing of heating and cooling systems, replacing tile and carpeting, and similar types of work. This work also includes inspection and repair of heavy plant machinery, high-power electrical switching gear, hydraulic, lubrication, forced-air and fluid cooling systems, high pressure vessel health monitoring, facility control and remote monitoring systems, liquid oxygen systems, steam systems, test instrumentation, and fire detection and suppression systems. Environmental compliance costs, facility leases, or other tasks associated with facilities operations (such as custodial services, grounds services, waste disposal, and the provision of central utilities) are not included. Sustainment funds support the following Air Force organizations and their associated test and evaluation facilities: the 96th Test Wing (TW) at Eglin AFB, FL; the 412 TW at Edwards AFB, CA; the Arnold Engineering and Development Complex (AEDC), to include assets at Arnold AFB, TN, the 704th Test Group (704TG) at Holloman AFB, NM, the 704TG Landing Gear Test Facility (LGTF) at Wright-Patterson AFB, OH, the Hypersonic Wind Tunnel 9 at White Oak, MD, and the National Full-Scale Aerodynamics Complex (NFAC) at Moffett Field, CA. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 287858000, 269850000, 277176000, NULL, NULL, 139, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 63579000, 91969000, 298924000, 298924000, 0, 298924000, 279697000, $$This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605807F. Sustainment is defined as the maintenance and repair activities necessary to keep facilities in good working order and includes regularly scheduled adjustments and inspections, preventative maintenance tasks, and emergency response and service calls for minor repairs. It also includes major repairs or replacement of facility components (usually accomplished by contract) that are expected to occur periodically throughout the lifecycle of facilities. This work includes regular roof replacement, refinishing of wall and floor surfaces, repairing and replacing of heating and cooling systems, replacing tile and carpeting, and similar types of work. This work also includes inspection and repair of heavy plant machinery, high-power electrical switching gear, hydraulic, lubrication, forced-air and fluid cooling systems, high pressure vessel health monitoring, facility control and remote monitoring systems, liquid oxygen systems, steam systems, test instrumentation, and fire detection and suppression systems. Environmental compliance costs, facility leases, or other tasks associated with facilities operations (such as custodial services, grounds services, waste disposal, and the provision of central utilities) are not included. Sustainment funds support the following Air Force organizations and their associated test and evaluation facilities: the 96th Test Wing (TW) at Eglin AFB, FL; the 412 TW at Edwards AFB, CA; the Arnold Engineering and Development Complex (AEDC), to include assets at Arnold AFB, TN, the 704th Test Group (704TG) at Holloman AFB, NM, the 704TG Landing Gear Test Facility (LGTF) at Wright-Patterson AFB, OH, the Hypersonic Wind Tunnel 9 at White Oak, MD, and the National Full-Scale Aerodynamics Complex (NFAC) at Moffett Field, CA. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E        PE 0605978F / Facilities Sustainment - Test and Evaluation Support Management Support$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605998KA$$, $$Management HQ - Defense Technical Information Center (DTIC)$$, $$rdte_dw_ba6$$, $$dw_dtic$$, 2026, 3466000, 3752000, 3505000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0605998KA", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 3528000, 3569000, 3626000, NULL, NULL, NULL, NULL, NULL, FALSE, 3505000, 3466000, 3489000, 3489000, NULL, 3489000, 3697000, $$This program element (PE) provides funding for the Management Headquarters (HQ) element of the Defense Technical Information Center (DTIC), a DoW Field Activity. The PE supports personnel compensation for HQ-assigned civilians, along with related administrative and contract support costs. This PE was established in FY 2017, designed to support activities deemed as headquarters functions, with no operational efficiencies or enhancement to mission. This PE supports the following HQ functions and mission essential activities critical to the success of DTIC’s operations, and mandated by law or regulation: - Activity leadership, strategic planning, and Front Office support staff. -- The front office staff represents a small component of this PE. Most of the specialized functions and skill sets described below are centralized activities within the PE yet support the larger organization and its employees. These activities were consolidated to improve efficiencies throughout DTIC and are essential to the operation of DTIC’s primary PE 0605801KA. - Financial Management and Comptroller. Provides integrated resource management at the Agency level to obtain, control, and execute budget and manpower authorities to support the organization's mission requirements. Develops and prepares agency budget documents and exhibits for submission to both OSW and Congress. -- Accounting support to DTIC’s mission operations; partners with the Defense Finance and Accounting Service (DFAS) and Washington Headquarters Service (WHS) to present accurate financial reporting and Fund Balance with Treasury. -- Financial Improvement and Audit Remediation (FIAR) activities and oversight in compliance with the Department’s audit goals, objectives, and milestones. - Human Resources (HR) Liaison Support. Partners with DFAS to provide the DTIC enterprise with payroll processing and “Hire to Retire” mission support; oversees and organizes employee training, professional development, and staff certification programs (e.g., Acquisition, Financial Management, and IT programs). -- Coordinates recruitment placement and classification action for the mission areas; liaison to DFAS for HR servicing and the Defense Logistics Agency (DLA) for Equal Employment Opportunity (EEO) program maintenance. - Mandatory Records Management compliance activities and administration programs. - IT Management and DTIC Platform Management. Collects, analyzes, and reports information necessary to effectively and efficiently manage enterprise IT resources; functions are performed in compliance with DoW-CIO guidance, instructions and mandates and performed by a service provider through a SLA with the Defense Information Services Agency (DISA)in the case of DTIC internal needs and by infrastructure and platform services’ providers (currently the Department of the Air Force’s Cloud One; in transition to CDAO’s War Data Platform. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Technical Information Center                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:           PE 0605998KA / Management HQ - Defense Technical Information Center (DTIC) RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_DTIC_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606002A$$, $$Ronald Reagan Ballistic Missile Defense Test Site$$, $$rdte_army_ba6$$, $$dw_mda$$, 2026, 72302000, 89911000, 73400000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0606002A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line supports testing of Army Modernization Priority Programs. The Ronald Reagan Ballistic Missile Defense Test Site (RTS), with its remote location and one-of-a-kind instrumentation systems, provides a valuable strategic test environment that cannot be replicated. Its function is to: 1) support test and evaluation of major Army and Department of Defense (DOD) acquisition programs of strategic importance to the national defense; and 2) provide space operations and intelligence data (Space Situational Awareness, object tracking & identification) in support of United States Strategic Command (USSTRATCOM), acting as a high value contributing sensor to the United States (U.S.) Space Surveillance Network. Due to its unique geography and instrumentation, RTS is able to provide unmatched data collection capabilities that provide critical test data for programs of national interest to include: Army Missile Defense; Defense Advanced Research Projects Agency hypersonic Boost-Glide developmental tests; Air Force and Navy Intercontinental Ballistic Missile (ICBM) developmental and operational tests; Army, Air Force, Navy, and Missile Defense Agency (MDA) operational, demonstration, and validation tests; National Aeronautics and Space Administration (NASA) scientific and unique space programs; NASA ionospheric studies; space debris tracking; and data collection in support of space experiments. Funding in this Program Element (PE) covers management and contracting personnel support (salaries and travel) to enable the management of the test and evaluation of major Army and DoD missile systems for the RTS. Funds also provide contracting support for end item procurement, life cycle acquisition planning, and solicitation, negotiation, award, execution and management for weapon systems contracts. This PE provides contractors to accomplish key operations and maintenance functions for RTS instrumentation suites and also provides mission essential bandwidth via a fiber optic cable system. Funds provide the expertise required for operating and maintaining a number of one-of-a-kind radar, optical, telemetry, command/control/communications, safety, and data reduction systems. These systems include: the four unique radars of the Kiernan Reentry Measurement Site; Super Recording Automatic Digital Optical Tracker long range video-metric tracking systems; high density data recorders for high data-rate telemetry collected by ten antennas; an underwater acoustic impact location system; and data analysis/reduction hardware/software and Continental United States (CONUS) based mission control center. The Advanced Research Project Agency Long-Range Tracking and Instrumentation Radar and the Target Resolution Discrimination Experiment radars located at RTS are the only radars in this area of operation that have deep-space tracking capability. The Millimeter Wave Radar is one of the highest resolution imaging radars in the world, providing critical intelligence data. Funding also enables weapon system assessment of operational effectiveness and suitability for the Army, Air Force, Navy and MDA, which all have programs planned that have significant test and data gathering requirements at RTS. This test data cannot be obtained except through the use of technical facilities available on and in the vicinity of RTS. Program supports Army's PATRIOT air defense system; Air Force's Minuteman III ICBM and the Space and Missile Center's associated programs; MDA's Ballistic Missile Defense System, ICBM Targets, and Layered Ballistic Missile Defense operational tests (including: PATRIOT, Terminal High-Altitude Area Defense, and Aegis Weapon System), and NASA's space experiments. FY25 funding in the amount of $22.880 million is in support of the Pacific Defense Initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0606002A / Ronald Reagan Ballistic Missile Defense Test Site Management Support The FY 2026 request was reduced by $1.151 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." The FY 2026 request was reduced by $0.305 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative."$$, NULL, 118193000, 108937000, 111567000, NULL, NULL, 194, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 70964000, 72302000, 118585000, 118585000, NULL, 118585000, 113065000, $$The Ronald Reagan Ballistic Missile Defense Test Site (RTS), with its remote location and one-of-a-kind instrumentation systems, provides a valuable strategic test environment that cannot be replicated. Its function is to: 1) support test and evaluation of major Army and Department of War (DOW) acquisition programs of strategic importance to the national defense; and 2) provide space operations and intelligence data (Space Situational Awareness, object tracking & identification) in support of United States Strategic Command (USSTRATCOM), acting as a high value contributing sensor to the United States (U.S.) Space Surveillance Network. Due to its unique geography and instrumentation, RTS is able to provide unmatched data collection capabilities that provide critical test data for programs of national interest to include: Army Missile Defense; Defense Advanced Research Projects Agency hypersonic Boost-Glide developmental tests; Air Force and Navy Intercontinental Ballistic Missile (ICBM) developmental and operational tests; Army, Air Force, Navy, and Missile Defense Agency (MDA) operational, demonstration, and validation tests; National Aeronautics and Space Administration (NASA) scientific and unique space programs; NASA ionospheric studies; space debris tracking; and data collection in support of space experiments. Funding in this Program Element (PE) covers management and contracting personnel support (salaries and travel) to enable the management of the test and evaluation of major Army and DoW missile systems for the RTS. Funds also provide contracting support for end item procurement, life cycle acquisition planning, and solicitation, negotiation, award, execution and management for weapon systems contracts. This PE provides contractors to accomplish key operations and maintenance functions for RTS instrumentation suites and also provides mission essential bandwidth via a fiber optic cable system. Funds provide the expertise required for operating and maintaining a number of one-of-a-kind radar, optical, telemetry, command/control/communications, safety, and data reduction systems. These systems include: the four unique radars of the Kiernan Reentry Measurement Site; Super Recording Automatic Digital Optical Tracker long range video-metric tracking systems; high density data recorders for high data-rate telemetry collected by ten antennas; an underwater acoustic impact location system; and data analysis/reduction hardware/software and Continental United States (CONUS) based mission control center. The Advanced Research Project Agency Long-Range Tracking and Instrumentation Radar and the Target Resolution Discrimination Experiment radars located at RTS are the only radars in this area of operation that have deep-space tracking capability. The Millimeter Wave Radar is one of the highest resolution imaging radars in the world, providing critical intelligence data. Funding also enables weapon system assessment of operational effectiveness and suitability for the Army, Air Force, Navy and MDA, which all have programs planned that have significant test and data gathering requirements at RTS. This test data cannot be obtained except through the use of technical facilities available on and in the vicinity of RTS. Program supports Army's PATRIOT air defense system; Air Force's Minuteman III ICBM and the Space and Missile Center's associated programs; MDA's Ballistic Missile Defense System, ICBM Targets, and Layered Ballistic Missile Defense operational tests (including: PATRIOT, Terminal High-Altitude Area Defense, and Aegis Weapon System), and NASA's space experiments. FY26 funding in the amount of $23.301 Million is in support of the Pacific Defense Initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0606002A / Ronald Reagan Ballistic Missile Defense Test Site Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606003A$$, $$CounterIntel and Human Intel Modernization$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 5660000, 6348000, 9574000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0606003A", "page_header": "Department of the Army"}$$::jsonb, $$The Counterintelligence (CI) and Human Intelligence (HUMINT) Modernization Project supports ongoing rejuvenation and development of new critical CI and HUMINT systems, applications, tools, equipment, and capabilities necessary to defeat foreign intelligence, international terrorist, and insider threats while enhancing our HUMINT collection capability, management processes, and responsiveness. CI Support to Force Protection (CIFP) provides for development and testing of software code of Atlas, the planned successor of Army Counterintelligence Operations Portal and further development of the CI and HUMINT Software (CHS) system for forces echelon Corps and below to be integrated into the CI and HUMINT Equipping Program Army, replacing CI and HUMINT Automated Reporting Computer System. The Castle Keep Portal is the Army's enterprise capability to automate workflow services, SCI program reporting, metrics, analysis, and information sharing to protect classified information within and across the defense elements of the Intelligence Community. The Multi-Source Data Fusion Platform curates and integrates Army Counterintelligence (CI) and Human Intelligence (HUMINT) data with Army Identity Intelligence architecture, establishes application programming interfaces, leverages and trains Artificial Intelligence/Machine Learning (AI/ML) tools and models, and develops new workflows and user interfaces with the Military Threat Actor knowledge base and Defense Watchlisting activities that supports sharing of information across the Army CI, HUMINT, and I2 capabilities for timely decisions on persons of interest. The FY 2026 request will support development and testing of software code integrating existing and new algorithms to analyze multiple data sources. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                        Date: June 2025 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E        PE 0606003A / CounterIntel and Human Intel Modernization Management Support$$, NULL, 5909000, 6004000, 6057000, NULL, NULL, 195, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 9574000, 5660000, 5802000, 5802000, NULL, 5802000, 6117000, $$The Counterintelligence (CI) and Human Intelligence (HUMINT) Modernization Project supports ongoing rejuvenation and development of new critical CI and HUMINT systems, applications, tools, equipment, and capabilities necessary to defeat foreign intelligence, international terrorist, and insider threats while enhancing our HUMINT collection capability, management processes, and responsiveness. CI Support to Force Protection (CIFP) provides for development and testing of software code of Atlas, the planned successor of Army Counterintelligence Operations Portal and further development of the CI and HUMINT Software (CHS) system for forces echelon Corps and below to be integrated into the CI and HUMINT Equipping Program Army, replacing CI and HUMINT Automated Reporting Computer System. The Castle Keep Portal is the Army's enterprise capability to automate workflow services, SCI program reporting, metrics, analysis, and information sharing to protect classified information within and across the defense elements of the Intelligence Community. The Multi-Source Data Fusion Platform curates and integrates Army Counterintelligence (CI) and Human Intelligence (HUMINT) data with Army Identity Intelligence architecture, establishes application programming interfaces, leverages and trains Artificial Intelligence/Machine Learning (AI/ML) tools and models, and develops new workflows and user interfaces with the Military Threat Actor knowledge base and Defense Watchlisting activities that supports sharing of information across the Army CI, HUMINT, and I2 capabilities for timely decisions on persons of interest. The FY 2027 request will support development and testing of software code integrating existing and new algorithms to analyze multiple data sources. The FY 2027 request enables GEOINT modernization through work to integrate raw pixel Artificial Intelligence and Machine Learning (AI/ML) models to enable automated imagery inferencing, cloud & virtualization approaches, and integrating localized, centralized, and cloud environments. The activity is producing tangible reductions in the time required to produce and disseminate findings that support over the horizon targeting, battlespace awareness, and preparation of the battlefield. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0606003A / CounterIntel and Human Intel Modernization Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606004F$$, $$Nuclear Enterprise Research & Development$$, $$rdte_af_ba4$$, $$dw_osd$$, 2026, 1097000, 0, 0, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0606004F"}$$::jsonb, $$Commercial Capabilities Integration & Transition uses the Small Business Innovation Research process to discover, prototype, and rapidly field commercial solutions to solve combatant commander and warfighter requirements. Commercial Capabilities Integration & Transition partners with OSD in rapid prototyping and experimentation activities. Additionally, Commercial Capabilities Integration & Transition partners with various agencies to include AFRL, DIU, OSD R&E, Rapid Defense Experimentation Reserve, and Defense Innovation Accelerator, FFRDCs, NNSA and others to identify critical science and technology capabilities. Furthermore, Commercial Capabilities Integration & Transition leverages the U.S.'s small business community, accelerating the Department's acquisition process, to rapidly prototype and demonstrate these critical science and technology capabilities for integration into AF systems. This energizes the Nation's small business community and increases the industrial base to meet the emerging challenges of incorporating revolutionary technologies like AI/ML, quantum, cyber, advanced communications/networks, advanced propulsion, directed energy, training systems, etc. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 1105000, 1103000, 1101000, NULL, NULL, 63, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 94782000, 1105000, 1105000, 0, 1105000, 1124000, $$Commercial Capabilities Integration & Transition uses the Small Business Innovation Research process to discover, prototype, and rapidly field commercial solutions to solve combatant commander and warfighter requirements. Commercial Capabilities Integration & Transition partners with Office of the Secretary of War (OSW) in rapid prototyping and experimentation activities. Additionally, Commercial Capabilities Integration & Transition partners with various agencies to include Air Force Research Laboratory, Defense Innovation Unit, OSW R&E, Rapid Defense Experimentation Reserve, and Defense Innovation Accelerator, Federally Funded Research and Development Centers, National Nuclear Security Administration and others to identify critical science and technology capabilities. Furthermore, Commercial Capabilities Integration & Transition leverages the U.S.'s small business community, accelerating the Department's acquisition process, to rapidly prototype and demonstrate these critical science and technology capabilities for integration into AF systems. This energizes the Nation's small business community and increases the industrial base to meet the emerging challenges of incorporating revolutionary technologies like artificial intelligence/machine learning, quantum, cyber, advanced communications/ networks, advanced propulsion, directed energy, training systems, etc. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0606004F / Nuclear Enterprise Research & Development Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606005D8Z$$, $$Special Activities$$, $$rdte_dw_ba6$$, $$dw_ousd_re$$, 2026, 18594000, 17452000, 18263000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0606005D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. For further information, please contact the Assistant Secretary of Defense for Mission Capabilities in the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)).$$, NULL, 19947000, 20333000, 20741000, NULL, NULL, 195, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 17768000, 18384000, 19260000, 19260000, NULL, 19260000, 20741000, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. For further information, please contact the Assistant Secretary of War for Science & Technology in the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)).$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L034$$, $$Utility Helicopter Mods$$, $$proc_army_2031_ba2$$, $$peo_aviation$$, 2026, 33659000, 56379000, 39565000, NULL, $${"page": 12, "ba_num": "02", "source": "p1_fy26", "ba_name": "Modification of aircraft", "line_no": "34", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 38659, "li_num": 20, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 33659000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 39565000, 38659000, 120013000, 120013000, 0, 120013000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606005F$$, $$Digital Transformation Office$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 15997000, 57511000, 9800000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0606005F"}$$::jsonb, $$This program encompasses the acquisition and development of common digital tools, software, and training to expedite the delivery of pertinent technologies, capabilities, and weapons throughout the enterprise. This program ensures the swift and cost-effective deployment of software tools to acquisition programs by developing common, enterprise-level, cloud-hosted software tool environments; this will equip the acquisition enterprise with Model-Based Systems Engineering, analytics, requirements management, and product life cycle management tools that will accelerate the delivery of war fighting capabilities. The program's objective is to develop and deploy enterprise-wide approaches for standardizing and scaling digital tool capabilities, resulting in reduced program delivery times. This holistic approach enables unprecedented collaboration with industry, lowers contract deliverable costs through government-approved data architectures and model delivery, and enhances foundational capability across the DAF by providing access to cloud-hosted tools to empower the acquisition workforce. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 196045000, 200247000, 100154000, NULL, NULL, 64, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 19227000, 73478000, 183398000, 183398000, 0, 183398000, 103599000, $$The Digital Transformation Office (DTO) encompasses the acquisition and development of common digital tools, software, and training to expedite the delivery of pertinent technologies, capabilities, and weapons throughout the enterprise. This program ensures the swift and cost-effective deployment of software tools to acquisition programs by developing common, enterprise-level, cloud-hosted software tool environments; this will equip the acquisition enterprise with Model-Based Systems Engineering, analytics, requirements management, and product life cycle management tools that will accelerate the delivery of war fighting capabilities. The program's objective is to develop and deploy enterprise-wide approaches for standardizing and scaling digital tool capabilities, resulting in reduced program delivery times. This holistic approach enables unprecedented collaboration with industry, lowers contract deliverable costs through government-approved data architectures and model delivery, and enhances foundational capability across the Department of Air Force (DAF) by providing access to cloud-hosted tools to empower the acquisition workforce. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in Operations and Maintenance program element 0901212F. The Digital Transformation Office, received a Congressional Add for FY2026 4.000 million for Platform Visualization Tools for Multi-Domain Threat Analysis. Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning the funding to PE 0604317F for proper execution. The Digital Transformation Office, received a Congressional Add for FY2026 2.000 million for Next Generation Aircraft Surface Inspections. Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning the funding to PE 0606004F for proper execution. The Digital Transformation Office, received a Congressional Add for FY2026 2.000 million for Digital Transformation Office. Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning the funding to PE 0604317F for proper execution. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0606005F / Digital Transformation Office Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606017F$$, $$Requirements Analysis and Maturation$$, $$rdte_af_ba6$$, $$saf_aq$$, 2026, 28157000, 114631000, 31450000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0606017F"}$$::jsonb, $$Capability development provides the analytic, technical, and programmatic rigor necessary to address capability gaps and opportunities to refine and mature future programs of record, prioritizing and accelerating transition of capabilities in collaboration with operational stakeholders. The Capability Development Enterprise is focused on maturing and transitioning high-impact warfighting capabilities aligned to Air Force Future Force Design through robust capability development. The Requirements Analysis and Maturation (RAM) program element funds Modeling, Simulation and Analysis, USAF Science and Technology (S&T) attribute refinement, and trade space studies in support of the Capability Development Enterprise to achieve the force design. Mission Engineering (ME) is the cornerstone for documenting Air Force Future Force Design and prioritizing capability development activities and recommendations. These efforts focus on Development Planning of operationally relevant capabilities, emerging technologies, and disruptive capability applications. Modern integrated digital environments are used in rendering problem decomposition, technology-focused requirements analysis, capability decomposition, trade space characterization, technology-enabled concept development, architecture design for technology integration, cost implications and assessments, model validation, analytical tool development, and focused technology risk characterization. Studies by Federally Funded Research and Development Centers (FFRDC) and University Affiliated Research Center (UARC) may augment this analysis when specific knowledge areas or technical understanding is required. Engagements with industry and academia may involve contracted analysis or requests for information at appropriate security levels. Outcomes of RAM are capability development characterization data that is used for acquisition planning of technically feasible and operationally relevant system to realize the Air Force Future Force Design. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver RAM capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E       PE 0606017F / Requirements Analysis and Maturation Management Support$$, NULL, 32316000, 32838000, 33392000, NULL, NULL, 140, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 30774000, 45786000, 21678000, 21678000, 0, 21678000, 34069000, $$Capability development provides the analytic, technical, and programmatic rigor necessary to address capability gaps and opportunities to refine and mature future programs of record, prioritizing and accelerating transition of capabilities in collaboration with operational stakeholders. The Capability Development Enterprise is focused on maturing and transitioning high-impact warfighting capabilities aligned to Air Force Future Force Design through robust capability development. The Requirements Analysis and Maturation (RAM) Program funds Modeling, Simulation and Analysis, requirement attribute refinement, and trade space studies in support of the Capability Development Enterprise to achieve the force design. Mission Engineering (ME) is the cornerstone for translating Air Force Future Force Design into Acquistion activities and prioritizing capability development activities and recommendations. These efforts focus on Development Planning of operationally relevant capabilities, emerging technologies, and disruptive capability applications. Modern integrated digital environments are used in rendering problem decomposition, technology-focused requirements analysis, capability decomposition, trade space characterization, technology-enabled concept development, architecture design for technology integration, cost implications and assessments, model validation, analytical tool development, and focused technology risk characterization. Studies by Federally Funded Research and Development Centers (FFRDC) and University Affiliated Research Center (UARC) may augment this analysis when specific knowledge areas or technical understanding is required. Engagements with industry and academia may involve contracted analysis or requests for information at appropriate security levels. Outcomes of RAM are capability development characterization data that is used for acquisition planning of technically feasible and operationally relevant system to realize the Air Force Future Force Design. In addition to traditional hardware and software, high-impact capabilities could include autonomy and Artificial Intelligence technologies that are stand-alone or embedded into specific, existing systems. They could also include broad enablers such as open architectures, digital infrastructure, test infrastructure, or simulation environments. Identified gaps and opportunities will be addressed through continued development in the Requirements Analysis & Concept Maturation program (PE 0604609F). Program management support costs including, but not limited to, hardware, software, travel, contractor support services, civilian pay, supplies, facilities, and infrastructure. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E       PE 0606017F / Requirements Analysis and Maturation Management Support This Program may include necessary civilian pay expenses required to manage, execute, and deliver RAM capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, and 0605898F. Requirements Analysis and Maturation, PE 0606017F, line 140, received a Congressional add for FY2026 18.000 million for Air Force Global Strike Command innovation and technology transition. Upon Congressional spend plan approval, an Internal Reprogramming (IR) will be processed aligning the funding to PE 0606004F for proper execution. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606018F$$, $$NC3 Integration$$, $$rdte_af_ba7$$, $$afnwc_nc$$, 2026, 40066000, 22222000, 21864000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0606018F"}$$::jsonb, $$Nuclear Command, Control, and Communications (NC3) is critical to our Nation's nuclear deterrence. Nuclear Deterrence Operations (NDO) is an Air Force Core Function. Within this core function, Nuclear Command and Control (NC2) is the exercise of authority and direction by the President, as Commander in Chief, through established command lines, over nuclear weapon operations of military forces. The President's authority and direction are exercised through the Nuclear Command and Control System (NCCS). The NCCS is the designated combination of flexible and enduring elements including facilities, equipment, communications, procedures, personnel, and the structure in which these elements are integrated, all of which are essential for planning, directing, and controlling nuclear weapon operations. These functions are accomplished through the NC3 system of systems. The NC3 system of systems provides connectivity from the President or Secretary of Defense through the National Military Command System (NMCS) to nuclear execution forces worldwide. To enhance NC3 mission success, the Air Force (AF) formalized AF NC3 elements as a specified AF Weapon System (WS), AN/USQ-225. Activities funded in this Program integrate legacy systems, ongoing NC3 programs, and future capabilities for the overall AF NC3 WS. The AF Nuclear Weapon Center NC3 Integration Directorate (AFNWC/NC) ensures current, new, and future NC3 capabilities are fully integrated as part of the Air Force's overall effort to sustain, modernize, and recapitalize the nuclear enterprise. AFNWC/NC is responsible for integrating NC3 materiel management across Air Force Materiel Command (AFMC) to include authority and responsibility for weapon system architecture, weapon system configuration management, weapon system state-of-health reporting, risk management, supply chain management, overall integration, system test, verification, and certification. AFNWC/NC is responsible for analyzing, defining, building, and sustaining current and future AF NC3 WS system of systems configuration baselines, and marshaling necessary Supporting Centers in AFMC and other units/agencies in the Air Force and the Department of Defense (DoD) to support and/or accomplish these tasks. AFNWC/NC collaborates with AFMC Supporting Centers to champion the full spectrum of doctrine, organization, training, materiel, leadership and education, personnel, facilities, and policy (DOTMLPF-P) efforts, in support of U.S. Strategic Command as the Enterprise Lead for NC3, the Under Secretary of Defense for Acquisition and Sustainment as the NC3 Enterprise Capability Portfolio Manager, and Air Force Global Strike Command (AFGSC) as the Lead Command championing NDO requirements for all Combatant Commands. This program funds activities for integrating AF NC3 WS materiel, authority and responsibility for model-based systems engineering (modeling, simulation and visualization) of the NC3 WS, digital engineering, configuration management, change management, risk management, weapon system state-of-health and mission worthiness assessments and reporting, supply chain supportability and risk management, and overall AF NC3 WS integration, development, system test, experimentation, modeling and simulation of capability gaps with potential solution alternative trade space assessments, verification, fielding, and certification. This program also supports capability gap analyses, predictive analysis of impacts to the weapon system, modernization and integration activities in support of AFGSC's Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0606018F / NC3 Integration Operational Systems Development Capability Development Process (ACDP), Joint All Domain Command and Control (JADC2) and Advanced Battle Management System (ABMS) initiatives. Starting in FY25, this PE will also be supporting NC3 baseline integration into the Sentinel Weapon System Program, to include new equipment purchases and the transfer of Minuteman III (MMIII) NC3 equipment to the Sentinel Weapon System. The FY 2026 request was reduced by [1.586] million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” The FY 2026 total adjustment was an increase of 15.022M. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 37480000, 37561000, 30867000, NULL, NULL, 159, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 21289000, 39599000, 36521000, 36521000, 0, 36521000, 31492000, $$Nuclear Command, Control, and Communications (NC3) is critical to our Nation's nuclear deterrence. Nuclear Deterrence Operations (NDO) is an Air Force Core Function. Within this core function, Nuclear Command and Control (NC2) is the exercise of authority and direction by the President, as Commander in Chief, through established command lines, over nuclear weapon operations of military forces. The President's authority and direction are exercised through the Nuclear Command and Control System (NCCS). The NCCS is the designated combination of flexible and enduring elements including facilities, equipment, communications, procedures, personnel, and the structure in which these elements are integrated, all of which are essential for planning, directing, and controlling nuclear weapon operations. These functions are accomplished through the NC3 system of systems. The NC3 system of systems provides connectivity from the President or Secretary of Defense through the National Military Command System (NMCS) to nuclear execution forces worldwide. To enhance NC3 mission success, the Air Force (AF) formalized AF NC3 elements as a specified AF Weapon System (WS), AN/USQ-225. Activities funded in this Program integrate legacy systems, ongoing NC3 programs, and future capabilities for the overall AF NC3 WS. The AF Nuclear Weapon Center NC3 Integration Directorate (AFNWC/NC) ensures current, new, and future NC3 capabilities are fully integrated as part of the Air Force's overall effort to sustain, modernize, and recapitalize the nuclear enterprise. AFNWC/NC is responsible for integrating NC3 materiel management across Air Force Materiel Command (AFMC) to include authority and responsibility for weapon system architecture, weapon system configuration management, weapon system state-of-health reporting, risk management, supply chain management, overall integration, system test, verification, and certification. AFNWC/NC is responsible for analyzing, defining, building, and sustaining current and future AF NC3 WS system of systems configuration baselines, and marshaling necessary Supporting Centers in AFMC and other units/agencies in the Air Force and the Department of War (DoW) to support and/or accomplish these tasks. AFNWC/NC collaborates with AFMC Supporting Centers to champion the full spectrum of doctrine, organization, training, materiel, leadership and education, personnel, facilities, and policy Defense, Organization, Training, Materiel, Leadership, Personnel, and Facilities (DOTMLPF-P) efforts, in support of U.S. Strategic Command as the Enterprise Lead for NC3, the Under Secretary of Defense for Acquisition and Sustainment as the NC3 Enterprise Capability Portfolio Manager, and Air Force Global Strike Command (AFGSC) as the Lead Command championing NDO requirements for all Combatant Commands. This program funds activities for integrating AF NC3 WS materiel, authority and responsibility for model-based systems engineering (modeling, simulation and visualization) of the NC3 WS, digital engineering, configuration management, change management, risk management, weapon system state-of-health and mission worthiness assessments and reporting, supply chain supportability and risk management, and overall AF NC3 WS integration, development, system test, experimentation, modeling and simulation of capability gaps with potential solution alternative trade space assessments, verification, fielding, and certification. This Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0606018F / NC3 Integration Operational Systems Development program also supports capability gap analyses, predictive analysis of impacts to the weapon system, modernization and integration activities in support of AFGSC's Capability Development Process (ACDP), Joint All Domain Command and Control (JADC2) and Advanced Battle Management System (ABMS) initiatives. Starting in FY25, this PE will also be supporting NC3 baseline integration into the Sentinel Weapon System Program, to include new equipment purchases and the transfer of Minuteman III (MMIII) NC3 equipment to the Sentinel Weapon System. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606100D8Z$$, $$Budget and Program Assessments$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 13084000, 13863000, 14272000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0606100D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to Deter Aggression, Defend the Homeland, and Build Sustainable and Long-Term Advantage. This program supports the Office of the Director, Cost Assessment & Program Evaluation (CAPE) by funding assessments that help to resolve budget and programmatic issues across the full range of the Department’s activities. Projects that support this effort help to inform leadership on program alternatives, capability concept development, design and cost, as well as the appropriate balance of capabilities across the force. They also help to identify how well the Department is meeting its expenditure goals, and how well the force can implement the interim National Defense Strategy. These RDT&E resources support critical studies and analyses to assist senior DoD leaders in optimally balancing the lethality, partnership, and reform levels of effort to carry out the interim National Defense Strategy. This program provides for analytical research across the entire spectrum of defense issues and concerns. The research agenda focuses on near to long-term problems identified by the Secretary of Defense, addressing difficult and complex questions linked to program alternatives for current and future capabilities and forces in order to enhance senior leadership's deliberations and decision-making. This program provides the scientific and technical engineering services needed for research studies in the development of models and simulations and the evaluation of current analytical tools and scientific methods used to evaluate and assess weapons systems and warfighting capabilities for warfighting environments and scenarios, and related force structure. Deliverables from this program will include reports, briefings, and analyses designed to illuminate critical issues facing the Department. Outcomes include recommendations for new modeling techniques, programmatic alternatives, and scenario development. The FY 2024 budget proposal continues resources to support the Enterprise Visibility and Maintainability of Operation and Support Costs (EVAMOSC). EVAMOSC supports CAPE's responsibility to develop and maintain a database of actual operating and support (O&S) costs for major weapons systems, as required in 10 USC Ch. 137, Sec. 2337a and further refined by Sec. 832 of the 2019 NDAA. Additionally, the EVAMOSC data capability will directly support development and reporting of readiness metrics associated with implementation of the interim National Defense Strategy. In FY 2024, CAPE will continue to design and develop an enterprise data platform to serve as the authoritative source of O&S cost data for major weapon systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                            Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:           PE 0606100D8Z / Budget and Program Assessments RDT&E Management Support$$, NULL, 10908000, 11838000, 12110000, NULL, NULL, 196, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 13749000, 12899000, 10678000, 10678000, NULL, 10678000, 12352000, $$This program supports the Office of the Director, Cost Assessment & Program Evaluation (CAPE) by funding assessments that help to resolve budget and programmatic issues across the full range of the Department’s activities. Projects that support this effort help to inform leadership on program alternatives, capability concept development, design and cost, as well as the appropriate balance of capabilities across the force. They also help to identify how well the Department is meeting its expenditure goals, and how well the force can implement the interim National Defense Strategy. These RDT&E resources support critical studies and analyses to assist senior DoW leaders in optimally balancing the lethality, partnership, and reform levels of effort to carry out the interim National Defense Strategy. This program provides for analytical research across the entire spectrum of defense issues and concerns. The research agenda focuses on near to long-term problems identified by the Secretary of War, addressing difficult and complex questions linked to program alternatives for current and future capabilities and forces in order to enhance senior leadership's deliberations and decision-making. This program provides the scientific and technical engineering services needed for research studies in the development of models and simulations and the evaluation of current analytical tools and scientific methods used to evaluate and assess weapons systems and warfighting capabilities for warfighting environments and scenarios, and related force structure. Deliverables from this program will include reports, briefings, and analyses designed to illuminate critical issues facing the Department. Outcomes include recommendations for new modeling techniques, programmatic alternatives, and scenario development. The FY 2027 budget proposal continues resources to support the Enterprise Visibility and Maintainability of Operation and Support Costs (EVAMOSC). EVAMOSC supports CAPE's responsibility to develop and maintain a database of actual operating and support (O&S) costs for major weapons systems, as required in 10 USC Ch. 137, Sec. 2337a and further refined by Sec. 832 of the 2019 NDAA. Additionally, the EVAMOSC data capability will directly support development and reporting of readiness metrics associated with implementation of the interim National Defense Strategy. In FY 2027, CAPE will continue to develop an enterprise data platform to serve as the authoritative source of O&S cost data for major weapon systems. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0606100D8Z / Budget and Program Assessments RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606114D8Z$$, $$Analysis Working Group (AWG) Support$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 5229000, 4046000, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0606114D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiative to Take Care of People, and Build Sustainable and Long-Term Advantage. This program supports the Office of the Director, Cost Assessment & Program Evaluation (CAPE). It funds assessments that help the Analysis Working Group (AWG) to assist the Secretary and Deputy Secretary in guiding the analytic community and ensuring strategic analysis products are robust and of the highest quality. The end goal is an analytic enterprise that is agile, responsive, and provides sound decision support for the Secretary and Deputy Secretary. This program provides for analytic research across the Department to guide reform of the Departments analytic enterprise. Projects that support this effort help to develop a high performing and innovative analytic enterprise with the right policies, structures, people, and tools to support timely strategic decision that create an advantage for the U.S Military now and into the future.$$, NULL, 11902000, 11392000, 11618000, NULL, NULL, 197, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 879000, 5155000, 11668000, 11668000, NULL, 11668000, 11850000, $$This program supports the Office of the Director, Cost Assessment & Program Evaluation (CAPE). It funds assessments that help the Analysis Working Group (AWG) as required in the FY 2024 NDAA Sec 902 to assist the Secretary and Deputy Secretary in guiding the analytic community and ensuring strategic analysis products are robust and of the highest quality. The end goal is an analytic enterprise that is agile, responsive, and provides sound decision support for the Secretary and Deputy Secretary. This program provides for analytic research across the Department to guide reform of the Department’s analytic enterprise. Projects that support this effort help to develop a high performing and innovative analytic enterprise with the right policies, structures, people, and tools to support timely strategic decisions that create an advantage for the U.S Military now and into the future.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606118A$$, $$AIAMD Software Development & Integration$$, $$rdte_army_ba6$$, $$peo_ms$$, 2026, 461854000, 0, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0606118A", "page_header": "Department of the Army", "fy26_v182_disc_K": 368812, "fy26_v182_supp_K": 63000, "fy26_v182_total_K": 431812, "fy26_v182_note_name": "AIAMD Software Development & Integration", "fy26_v182_source_file": "RDTE - Vol 4 - Budget Activity 6.txt", "fy26_v182_source_line": 9667}$$::jsonb, $$Agile software development is the key pacing activity for introducing enhanced Army Integrated Air and Missile Defense (AIAMD) system capabilities, integrating with emerging AMD effectors and sensors, and interoperating with joint and higher echelon mission command systems. The Defense Acquisition Executive (DAE) approved AIAMD entry into the Software Acquisition Pathway (SWP) Execution Phase on September 21, 2021. This pathway facilitates rapid and iterative delivery of software capability to the user and enables multiple 1-N capability items to be worked concurrently as defined by emerging joint Warfighter priorities. The IAMD Battle Command System (IBCS) based AIAMD architecture is a software intensive capability that enables net-centric, system of systems (SoS) command and control of AIAMD. The AMD Mission Command Product Office executes the IBCS program in accordance with the SWP utilizing the Scaled Agile Framework (SAFe) development methodology. This approach delivers Program Increments (PI) in the form of quarterly software-based improvements and annual capability releases that address Warfighter priorities (1-N), emerging threats, and weapon and sensor integration requirements. Software testing occurs at the end of each PI cycle with functional testing at the Contractor System Integration Lab (C-SIL), followed by validation of performance requirements at the Government System Integration Lab (G-SIL). The software is then delivered to White Sands Missile Range (WSMR) for testing with tactical sensors and weapons. Funding of $358.854 million in FY 2026 supports Integrated Fires System of Systems agile software development, updates and integration, developmental testing, requirements verification of the software build, operational testing, modeling and simulation and integration activities for integrated fires capabilities to include Patriot, IFPC, LTAMDS, and Forward Area Air Defense Command and Control (FAAD C2) Convergence into IBCS. The program also expands development capacity to meet increasing integration demands to support 1-N capability. Development and testing in FY26 contributes to the Guam Defense System (GDS) architecture including countering advanced threats and capability integration with LTAMDS, IFPC, Sentinel A4, RIG-360, and ALPS. The FY 2026 request for AIAMD Software Development & Integration includes $358,854 thousand of discretionary and $103,000 thousand of mandatory (reconciliation) for a total of $461,854 thousand. The mandatory funds support full THAAD integration into the AIAMD architecture and foundational requirements for Golden Dome for America (GDA) to include remotely operated autonomous system and AI enabled fire control. Software development activities for GDA support significantly reducing human-in-the-loop interactions across sensor and effector platforms, leverage AI technologies and techniques reducing human cognitive load, augmenting required tasks, and increasing system performance and enabling consolidated remote operations of sensors and shooters. Further information for this reconciliation request is provided in section 20003 (Missile Defense) of the Reconciliation Exhibit. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E              PE 0606118A / AIAMD Software Development & Integration Management Support The FY 2026 request for AIAMD Software Development & Integration includes $358,854 thousand of discretionary and $103,000 thousand of mandatory (reconciliation) for a total of $461,854 thousand. The mandatory funds support full THAAD integration into the AIAMD architecture and foundational requirements for Golden Dome for America (GDA) to include remotely operated autonomous system and AI enabled fire control. Software development activities for GDA support significantly reducing human-in-the-loop interactions across sensor and effector platforms, leverage AI technologies and techniques reducing human cognitive load, augmenting required tasks, and increasing system performance and enabling consolidated remote operations of sensors and shooters. Further information for this reconciliation request is provided in section 20003 (Missile Defense) of the Reconciliation Exhibit.$$, NULL, 640731000, 678636000, 676479000, NULL, NULL, 196, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, NULL, 431812000, 653653000, 653653000, NULL, 653653000, 680753000, $$Agile software development is the key pacing activity for introducing enhanced Army Integrated Air and Missile Defense (AIAMD) system capabilities, integrating with emerging AMD effectors and sensors, and interoperating with joint and higher echelon mission command systems. The Defense Acquisition Executive (DAE) approved AIAMD entry into the Software Acquisition Pathway (SWP) Execution Phase on September 21, 2021. This pathway facilitates rapid and iterative delivery of software capability to the user and enables multiple 1-N capability items to be worked concurrently as defined by emerging joint Warfighter priorities. The IAMD Battle Command System (IBCS) based AIAMD architecture is a software intensive capability that enables net-centric, system of systems (SoS) command and control of AIAMD. The AMD Mission Command Product Office executes the IBCS program in accordance with the SWP utilizing the Scaled Agile Framework (SAFe) development methodology. This approach delivers Program Increments (PI) in the form of quarterly software-based improvements and annual capability releases that address Warfighter priorities (1-N), emerging threats, and weapon and sensor integration requirements. Software testing occurs at the end of each PI with functional testing at the Contractor System Integration Lab (C-SIL), followed by validation of performance requirements at the Government System Integration Lab (G-SIL). The software is then delivered to White Sands Missile Range (WSMR) for testing with tactical sensors and weapons. Funding of $653.653 million in FY 2027 supports Integrated Fires System of Systems agile software development, updates and integration, developmental testing, requirements verification of the software build, operational testing, modeling and simulation and integration activities for integrated fires capabilities to include Patriot, IFPC, LTAMDS, and migration of Forward Area Air Defense Command (FAAD) and AMDWS capabilities into IBCS. The program also expands development capacity, to include lab hardware refresh, required to meet increasing integration demands to support 1-N capability and IBCS configuration changes to fielded assets. Development and testing in FY 2027 contribute to the Guam Defense System (GDS) architecture including countering advanced threats and capability integration with LTAMDS, IFPC, Sentinel A4, RIG-360, and ALPS. In addition, FY 2027 supports THAAD integration into the AIAMD architecture and includes remotely operated autonomous system and AI enabled fire control. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 6: RDT&E             PE 0606118A / AIAMD Software Development & Integration Management Support$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606220D8Z$$, $$Office of the Secretary of War Enterprise Transformation and Moderni$$, $$rdte_dw_ba6$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 76000000, 77020000, 78061000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 75000000, 75000000, NULL, 75000000, 79123000, $$This program supports the integration of data across multiple sources that currently reside on antiquated and disparate systems. The outcome of this program funding will be a modern, unified analytical platform that supports Department-wide analytic products for informing key resourcing decisions. Outdated systems limit the ability of analysts to perform deep analysis across the broad portfolio of the Department’s programs and prohibit data integration across multiple streams, affecting the efficient responsiveness to decision makers. This new platform will empower the Department to more effectively fuse data across currently stove-piped organizational and functional boundaries, leveraging modern tools and the ongoing data investments of other organizations in the Department to increase the speed and efficiency of cost analyses and funding projections. The development and utilization of advanced software, including the integration of AI and Large Language Models (LLMs), will enhance analytical fidelity, increase the efficiency of data modeling, and be a significant leap forward in analytical capabilities. With more powerful and efficient tools, this program will provide senior Department leaders with the data-driven insights necessary to optimize budgets, identify potential savings, and ensure resources are directed to our most critical national security priorities. Key Fiscal Year 2027 activities include: A) foundational systems engineering analysis to ensure synergies with other Department data efforts, B) replacing the data environment and computing capacity, and C) building and piloting the first tranche of tools and applications. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0606220D8Z / Office of the Secretary of War Enterprise Transformation and Moderni RDT&E Management Support                                                     zation$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L036$$, $$Network And Mission Plan$$, $$proc_army_2031_ba2$$, $$peo_aviation$$, 2026, 40472000, 44558000, 52862000, NULL, $${"page": 12, "ba_num": "02", "source": "p1_fy26", "ba_name": "Modification of aircraft", "line_no": "36", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 43472, "li_num": 21, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 40472000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 43472000, 29235000, 29235000, 0, 29235000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606225D8Z$$, $$ODNA Technology & Resource Analysis$$, $$rdte_dw_ba6$$, $$dw_osd$$, 2026, 3461000, 3386000, 2903000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0606225D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Office of Net Assessment provides the Secretary of Defense, the Deputy Secretary of Defense, and other senior DoD leaders with independent, rigorous, and long-term analytical assessments of fundamental security issues. This includes, but is not limited to, identifying and analyzing emerging threats, technologies, and geopolitical trends that could significantly impact U.S. national security interests, and developing analyses that examine the standing trends and future prospects of U.S. and other military capabilities and military potential. The net assessments address near and long-term problems and opportunities for the U.S. military forces to help counter technological advantages of potential U.S. adversaries. These efforts will pursue research to analyze the future security environment. This request directly supports the interim National Defense Strategy (NDS) and the Department's initiatives to Defend the Homeland, Deter Aggression and Prevail in Conflict, Build Enduring Advantage and and critically aligns with the Department's priorities of accelerating warfighting capabilities, strengthening alliances, fostering a culture of innovation and accountability.$$, NULL, 3109000, 3144000, 3210000, NULL, NULL, 199, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 2903000, 3461000, 3264000, 3264000, NULL, 3264000, 3275000, $$The Office of Net Assessment (ONA) is reestablished to provide the Secretary of War, Deputy Secretary of War, and other senior DoW leaders with independent, long- term assessments of fundamental security issues. The ONA is administratively realigned under the Director of Administration and Management (DA&M), while the Deputy Secretary of War provides direct functional management of the Director of Net Assessment (DNA). The office identifies emerging threats, technologies, and geopolitical trends, examining the comparative military capabilities and potential of the U.S. and its adversaries. These net assessments address near and long-term challenges, enabling U.S. military forces to counter the technological advantages of potential adversaries. This effort directly supports the National Defense Strategy (NDS) and aligns with the Department's priorities to Defend the Homeland, Deter China, accelerate warfighting capabilities, and strengthen alliances.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606295M$$, $$(U)MARINE AVIATION DEVEL MANAGEMENT & SUPPORT$$, $$rdte_navy_ba6$$, $$dw_osd$$, 2026, 4732000, 0, 5000000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "mc", "page_num": 36, "original_pe": "0606295M", "page_header": "Department of the Navy"}$$::jsonb, $$Marine Aviation Developmental Management and Support enables the development of Marine Aviation's future capability concepts through analytically rigorous study, modeling, simulation, and validation. This Program Element (PE) includes funding for the integration of Marine Aviation into the USMC's Navy Capabilities- Based Assessments Integration Process - Marine Corps (NCIP-MC) processes as well as support to ongoing joint warfighting effectiveness efforts lead by OSD Cost Assessment and Program Evaluation (CAPE) and Research & Engineering (R&E). Fully informed wargaming and operational analysis conducted via this PE will ensure Marine Aviation development programs are driven by threat data and analysis resulting in impactful, comprehensive investment decisions. This PE will inform development and prototype efforts, which progress high-risk technology areas in support of future Marine Aviation capabilities. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation.$$, NULL, 4861000, 4951000, 4996000, NULL, NULL, 202, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 4922000, 4732000, 19165000, 19165000, NULL, 19165000, 5085000, $$Marine Aviation Developmental Management and Support enables the development of Marine Aviation's future capability concepts through analytically rigorous study, modeling, simulation, and validation. This PE includes funding for the integration of Marine Aviation into the USMC's Navy Capabilities-Based Assessments Integration Process - Marine Corps (NCIP-MC) processes, integration of USMC Artificial Intelligence (AI) analysis and prototyping efforts, as well as support to ongoing joint warfighting effectiveness efforts lead by OSW Cost Assessment and Program Evaluation (CAPE) and Research & Engineering (R&E). Fully informed wargaming and operational analysis conducted via this PE will ensure Marine Aviation development programs are driven by threat data and analysis resulting in impactful, comprehensive investment decisions. This PE will inform development and prototype efforts, which progress high-risk technology areas in support of Marine Aviation capabilities. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under RESEARCH, DEVELOPMENT, TEST and EVALUATION MANAGEMENT SUPPORT because it supports efforts directed toward sustaining or modernizing installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E            PE 0606295M / (U)MARINE AVIATION DEVEL MANAGEMENT & SUPPORT Management Support$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606300D8Z$$, $$Defense Science Board (DSB)$$, $$rdte_dw_ba6$$, $$dw_osd$$, 2026, 6563000, 2266000, 4444000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0606300D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to Build Long-Term Advantage, and Build a Resilient Joint Force and Defense Ecosystem. The Secretary of Defense established the Defense Science Board (DSB) as a discretionary advisory committee, in accordance with chapter 10 of title 5, U.S. Code (commonly known as “the Federal Advisory Committee Act” or “FACA" and 41 C.F.R. § 102- 3.50(d). The DSB provides independent advice and recommendations on matters supporting the Department of Defense’s (DoD) scientific and technical enterprise to the Secretary of Defense, the Deputy Secretary of Defense, the Under Secretary of Defense for Research & Engineering, the Chairman of the Joint Chiefs of Staff, and other Department officials. The DSB focuses on matters concerning science, technology, manufacturing, acquisition processes, and other topics of special interest to the DoD in response to specific tasks, and is not established to advise on individual DoD procurements. The DSB is concerned with the pressing and complex technological problems facing the DoD in such areas as research, engineering, organizational structure and process, business and functional concepts, and manufacturing, and ensures identification of new technologies and new applications of technology in those areas to strengthen national security. The funds provided allow for the procurement of professional, analytical, and administrative services, to include the tasks of planning, preparation, execution, administrative support, logistics, documentation, and travel for DSB, Subcommittee and Task Force meetings and conferences. The vendors contracted provide essential services in support of the DSB and the DSB staff in the following areas: technical, business, and administrative planning; organizing, managing, coordinating, and tracking (e.g., cost, schedule, and deliverables); and performance management, data management, and subcontract management along with refining initial and final reports of the various study groups. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:              PE 0606300D8Z / Defense Science Board RDT&E Management Support$$, NULL, 6477000, 6597000, 6754000, NULL, NULL, 200, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 4287000, 6481000, 6307000, 6307000, NULL, 6307000, 6887000, $$The Defense Innovation Board (DIB) has merged into the Defense Science Board (DSB) to create a singular advisory body, the Science, Technology, and Innovation Board (STIB). The STIB is a discretionary advisory committee chartered to provide independent advice and recommendations on matters supporting the Department of War’s (DoW’s) scientific, technological, and innovative enterprises. The STIB operates under the provisions of the Federal Advisory Committee Act (FACA) (chapter 10 of Title 5, United States Code (U.S.C.), Government in the Sunshine Act, and other applicable federal statutes, regulations, and policies. STIB RDT&E Funding covers travel and contract costs associated with the completion of five to six studies annually at the direction of Department leadership pursuant to the Federal Advisory Committee Act (FACA) of 1972 (chapter 10 of Title 5, United States Code (U.S.C.), Government in the Sunshine Act, the STIB charter, DoD Instruction 5105.04, "Department of War Federal Advisory Committee Management Program”, and other applicable federal statutes, regulations, and policy. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0606300D8Z / Defense Science Board (DSB) RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606301D8Z$$, $$Aviation Safety Technologies$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 1702000, 0, 1885000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0606301D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This effort supports the Department's priority of Taking Care of Our People. The requirements are aligned to Department of Defense (DoD)/Federal strategic direction, including the DoD Digital Modernization Strategy, DoD and Federal Data Strategies, Personnel and Readiness Strategy for 2030, and the DoD Safety and Occupational Health (SOH) Strategic Plan. To protect the lives, safety, health, and welfare of the DoD workforce, and the significant investments we make in our weapons systems, platforms, and infrastructure, we must acknowledge and provide adequate resources for SOH. Ensuring the safety of our workforce requires an enduring culture of safety, where consistent and standardized mishap, near-miss, and hazard reporting is the norm – at least on-par with industry and the private sector aviation and industrial communities. According to the 2020 National Commission on Military Aviation Safety (NCMAS) report, this begins with a centralized system and processes with which to gather, synthesize, and report Safety information at all levels. In addition to the NCMAS report, 10 United States Code Service (USCS) 184 directs the Department to establish uniform data collection standards and a centralized collection system and repository for mishap information. Currently, the DoD collects SOH information from disparate, incomplete, and often overlapping sources - a process that hinders opportunities for timely and in-depth trending and analysis to support Department-wide risk mitigation and mishap prevention efforts. Many of the DoD Components, including some of the Combatant Commands, do not have a safety information management system to enter, track, or manage mishaps, near-misses, or hazards. Without such a system and process, the Department is unable to adequately identify and analyze trends across the DoD Components, efficiently share lessons learned, and track corrective actions in response to recommendations. This effort addresses the Congressional requirements and fulfills capability gaps through modernization of the Force Risk Reduction tool to a safety information case management system. The system will be based on the Department’s safety business processes and data standards, which are being incorporated into Department of Defense Instruction (DoDI) 6055.07 “Mishap Notification, Investigation, Reporting, and Record Keeping.” A central SOH information management system based on the safety business processes and data standards will be available for all DoD Components, providing the capability to those DoD Components without an existing automated tool. It will continue to consolidate all SOH information serving as the Department’s authoritative repository for all standardized SOH data, and ensuring leaders have current, accurate, and actionable safety information and insights to forecast, mitigate, and prevent future mishaps, injuries, and occupational illnesses, and to drive safety innovation and modernization. Failure to receive this funding will result in non-compliance with Title 10 U.S.C. §184 requirements. Expanding FR2 functionality is the most efficient and effective approach to providing a compliant centralized safety collection and information management capability and repository. Without this funding, the Department will continue to lack a complete understanding of safety impacts to our personnel and operational readiness. Mishap reporting will continue to be inconsistent, and the Department will struggle to manage and share recommendations and lessons learned across the enterprise and respond effectively to external inquiries (e.g., Congress, Government Accountability Office). These persistent gaps will negatively impact our ability to make timely and informed risk decisions and resource investments for mishap Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:            PE 0606301D8Z / Aviation Safety Technologies RDT&E Management Support prevention solutions. Oversight of the Department’s safety enterprise requires a deliberate data informed focus and priority commensurate with the Department’s overall governance approach.$$, NULL, 992000, 958000, 992000, NULL, NULL, 201, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 1850000, 1690000, 986000, 986000, 0, 986000, 993000, $$The Department of War’s (DoW) priorities regarding safety and occupational readiness are comprehensive and revolve around the core principle of taking care of its people to ensure a resilient, ready, and lethal Total Force. This effort supports that core principle, and its requirements are aligned to DoW/Federal strategic direction, including the DoW Digital Modernization Strategy, DoW and Federal Data Strategies, the DoW Safety and Occupational Health (SOH) Strategic Plan, and other priorities, including Warfighter Performance Optimization and enterprise-wide data analytics. To protect the force, preserve combat power, and multiply readiness, we must provide sufficient resources to integrate safety, occupational health, and warfighter performance optimization into Department operations and investments in our weapons systems, platforms, and infrastructure. Ensuring the safety and occupational readiness of our workforce requires an enduring culture of safety-mindedness with consistent and standardized mishap, near-miss, and hazard reporting. According to the 2020 National Commission on Military Aviation Safety (NCMAS) report, this begins with a centralized system and processes with which to gather, synthesize, and report Safety information at all levels. In addition to the NCMAS report, Section 184 of Title 10, United States Code Service (10 USC 184) directs the Department to establish uniform data collection standards and a centralized collection system and repository for mishap information. Currently, the DoW collects SOH information from disparate, incomplete, and often overlapping sources - a process that hinders opportunities for timely and in-depth trending and analysis to support Department- wide risk management and mishap prevention efforts. Many of the DoW Components, including some of the Combatant Commands, do not have an adequate safety information management system to enter, track, or manage mishaps, near-misses, or hazards. Without such a system and process, the Department is unable to effectively identify and analyze trends across the Department, share lessons learned, and track corrective actions in response to recommendations. This effort addresses the Congressional requirements and fulfills capability gaps through modernization of the Total Force Risk Reduction (TFRR) (formerly Force Risk Reduction or FR2) tool to a safety information case management system. The system will be based on the Department’s safety business processes and data standards, which are being incorporated into Department of War Instruction (DoWI) 6055.07 “Mishap Notification, Investigation, Reporting, and Record Keeping.” A central SOH information management system based on the safety business processes and data standards will be available for all DoW Components, providing the capability to those Components without an existing automated tool. It will continue to consolidate all SOH information serving as the Department’s authoritative repository for standardized, enterprise-wide data, and ensuring leaders have current, accurate, and actionable safety information and insights to forecast, mitigate, and prevent future mishaps, injuries, and occupational illnesses, and to drive safety innovation and modernization. Additionally, these analytics serve as a basis for creating standardized, enterprise-wide metrics for warfighter performance, allowing the Department to connect safety outcomes directly to operational readiness and lethality. Expanding TFRR functionality is the most efficient and effective approach to providing a compliant centralized safety collection and information management capability and repository. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                              Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:             PE 0606301D8Z / Aviation Safety Technologies RDT&E Management Support Oversight of the Department’s safety enterprise requires a deliberate data informed focus and priority commensurate with the Department’s overall governance approach.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606355N$$, $$Warfare Innovation Management$$, $$rdte_navy_ba6$$, $$navwar$$, 2026, 37551000, 36460000, 50652000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0606355N", "page_header": "Department of the Navy"}$$::jsonb, $$Allied/Coalition Maritime Environment (ACME) 0798: This project promotes interoperability with allied and coalition forces by facilitating maritime interoperability in both processes and communication systems, including emerging capabilities, to counter growing high-end asymmetric threats. Space & Electronic Warfare (SEW) Engineering 2144: This project is a systems engineering non-acquisition program to develop, test, implement Technical Authority (TA) products, and validate Naval Command, Control, Communications, Computers, Intelligence, Surveillance, and Reconnaissance (C4ISR), Business Information Technology (IT), and Space System architectures to support naval, joint and coalition missions across normal, contested, and degraded cyber/operational environments. The objective of this project is performed through multiple tasks that ensure development and delivery of Naval Information Warfare (IW) capabilities that are well integrated, interoperable, secure, and resilient to meet validated warfighting requirements. NAVWAR leads SECNAV guidance under Cybersecurity Technical Authority (CSTA) to define and employ a uniform objective recursive approach employing Cyber Ready strategy shifting away from a compliance only methodology. Efforts will automate program engineering reviews and speed IW capability certification and authorization to overmatch our adversaries in a Cyber contested environment. Fleet Experimentation 3319: The U.S. Navy's Fleet Experimentation (FLEX) project advances operational and tactical warfighter capabilities through the experimentation of high payoff initiatives, technologies and concepts, Fleet Concepts of Operations (CONOPS), doctrine, and new tactics, techniques and procedures (TTP). The primary focus of FLEX between 2026 and 2030 is to address priority warfighting gaps identified by the four-star Fleet Commanders through the execution of experimentation events focused on materiel/ non-materiel capabilities. Trident Warrior Project 3320: Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Navy                                                                                Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E           PE 0606355N / Warfare Innovation Management Management Support The U.S. Navy's Trident Warrior (TW) experimentation campaign enables early delivery of capabilities to the warfighter via Fleet-directed Trident Warrior operational events with an emphasis on United States Fleet Forces/Commander Pacific Fleet (USFF/CPF) directed focus areas.$$, NULL, 39658000, 43989000, 44282000, NULL, NULL, 203, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 49590000, 37551000, 35931000, 35931000, NULL, 35931000, 44971000, $$Allied/Coalition Maritime Environment (ACME) 0798: The Department removed funding and zeroed out the program starting in FY2026. Space & Electronic Warfare (SEW) Engineering 2144: This project is a systems engineering non-acquisition program to develop, test, implement Technical Authority (TA) products, and validate Naval Command, Control, Communications, Computers, Intelligence, Surveillance, and Reconnaissance (C4ISR), Business Information Technology (IT), and Space System architectures to support naval, joint and coalition missions across normal, contested, and degraded cyber/operational environments. The objective of this project is performed through multiple tasks that ensure development and delivery of Naval Information Warfare (IW) capabilities that are well integrated, interoperable, secure, and resilient to meet validated warfighting requirements. NAVWAR leads SECNAV guidance under Cybersecurity Technical Authority (CSTA) to define and employ a uniform objective recursive approach employing Cyber Ready strategy shifting away from a compliance only methodology. Efforts will automate program engineering reviews and speed IW capability certification and authorization to overmatch our adversaries in a Cyber contested environment. Fleet Experimentation 3319: The U.S. Navy's Fleet Experimentation (FLEX) project advances operational and tactical warfighter capabilities through the experimentation of high payoff initiatives, technologies and concepts, Fleet Concepts of Operations (CONOPS), doctrine, and new tactics, techniques and procedures (TTP). The primary focus of FLEX between 2026 and 2031 is to address priority warfighting gaps identified by the four-star Fleet Commanders through the execution of experimentation events focused on materiel/ non-materiel capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 6: RDT&E             PE 0606355N / Warfare Innovation Management Management Support$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L066$$, $$CANES Intell$$, $$proc_navy_1810_ba2$$, $$peo_c4i$$, 2026, 60058000, 34724000, 42326000, NULL, $${"page": 99, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "66", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 61", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 0, "p1_line_num": 61, "fy27_total_K": 0}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "fy26t_qty": null, "fy26d_cost": 60058000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, 130090000, 1084193000, NULL, NULL, NULL, FALSE, 50654000, 46281000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606398F$$, $$Management HQ - T&E$$, $$rdte_af_ba6$$, $$aftc$$, 2026, 7417000, 7748000, 7647000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0606398F"}$$::jsonb, $$This program element funds civilian salaries of Air Force Test Center (AFTC) management headquarters personnel who lead, guide and direct the operation of AFTC test activities which are included in the Department of Defense (DoD) Major Range and Test Facility Base (MRTFB). This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 7643000, 7803000, 7966000, NULL, NULL, 141, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 8081000, 7417000, 7507000, 7507000, 0, 7507000, 8131000, $$This program element funds civilian salaries of Air Force Test Center (AFTC) management headquarters personnel who lead, guide and direct the operation of AFTC test activities which are included in the Department of War (DoW) Major Range and Test Facility Base (MRTFB). This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606771D8Z$$, $$Cyber Resiliency & Cybersecurity Policy$$, $$rdte_dw_ba6$$, $$dw_osd$$, 2026, 39220000, 40608000, 45401000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0606771D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 23899, "fy26_v182_supp_K": 60000, "fy26_v182_total_K": 83899, "fy26_v182_note_name": "Research, Development, Test & Evaluation, Defense-Wide for Cyber Resiliency & Cybersecurity Policy", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 44867}$$::jsonb, $$FY 2026 request for program element includes $14.220 million of discretionary and $25.000 million of mandatory (reconciliation) for a total of $39.220 million. The mandatory funds are for Golden Dome Cybersecurity (U). Further information for this reconciliation request is provided in section 20003 of the Reconciliation Exhibit. This PE supports the Department's initiatives to Revive the Warrior Ethos, Rebuild Our Military, and Reestablish Deterrence. The Cyber Resiliency & Cybersecurity Policy program supports the efforts of the Office of the Under Secretary of Defense, Acquisition and Sustainment (OUSD A&S), focusing on the defense of the Department’s critical mission weapon systems and supporting DoD Installation Critical Infrastructure (ICI)and supporting Commercial Critical Infrastructure (CCI)from cyber attack, protecting the Department’s sensitive unclassified information residing within the Defense Industrial Base (DIB) sector and supply chain , and capability portfolio management for Joint Cyber Capabilities used by the Cyber Mission Force. This program funds the following critical efforts: 1) Cybersecurity for Weapon Systems and Critical Infrastructure: Conduct Capability Portfolio Management and lead the Department’s Strategic Cybersecurity Program (SCP) to continue critical weapon systems and ICI cybersecurity assessments and mitigations and cyber harden priority Department of Defense (DoD) missions. Office of Assistant Secretary of Defense for Acquisition (ASD(A))/Cyber Warfare Directorate (CWD) Cyber Resiliency efforts are aligned with the following initiatives: Assess: - Conduct mission level cyber risk assessments for priority Defense Missions in support of Combatant Commands (CCMDs). Conduct enhanced mission level cyber risk assessments/wargames for the Missile Defense Mission in support of Golden Dome for America. Conduct supporting table top exercises (TTXs). - Conduct Cyber Risk Assessments for ICI and CCI in support of CCMDs and asset owners. - Conduct Integrated Sensing Monitoring Experiments (ISMX)and Sensing and Monitoring Pilots to assess the performance of Cybersecurity Sensing and Monitoring capabilities for WS and ICI. Inventory / Prioritize: - Develop, sustain, and employ the Cyber Risk Mitigation Tool (CRMT), an Enterprise-wide decision support tool for tracking and prioritizing cyber vulnerability assessments and mitigations. Develop CCMD specific cyber risk scorecards/risk matrices. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:            PE 0606771D8Z / Cyber Resiliency & Cybersecurity Policy RDT&E Management Support - Prioritize and advocate for Cyber Risk Mitigations based upon mission analysis conducted by program offices, the National Security Agency (NSA), Deep Cyber Resiliency Assessment teams, USCYBERCOM (USCC), and other cybersecurity professionals. Mitigate: - Advocate and oversee funding for priority ICI and commercial critical infrastructure (CCI) supporting Golden Dome for America based on a prioritized list of assets. - Conduct SCP POAM periodic updates with Services and Agencies for prioritized DoD weapon systems. Enhance Governance: Conduct 4-Star Level Integrated Acquisition Portfolio Reviews (IAPRs) that address cybersecurity / cyber hardening / cyber defense for priority DoD missions. 2) Weapon System Cyber Security – CCI Cybersecurity // Cybersecurity Supply Chain Risk Management (C-SCRM): In collaboration with the Department of Defense Chief Information Office (DoD CIO), conduct the C-SCRM in support of FY2019 NDAA Section 889, and Title 10 USC Section 3252 and Section 4713 . Partner with other DoD organizations and the DIB / CCI sectors to demonstrate / assess cost-effective and scalable cybersecurity services that augment and/or enhance existing commercial capabilities and services. Focus on identifying options and assessing the efficacy of cybersecurity services for small-to-medium sized DIB / CCI companies that are critical to the DoD supply chain but lack sufficient cybersecurity capabilities to protect CUI , data integrity, and availability of DIB supply chain. 3) Capability Portfolio Management for Cyberspace Operations: Conduct Capability Portfolio Management of the Joint Cyber Capabilities employed by Cyber Mission Force in collaboration with USCYBERCOM. Improve cyber lethality of the capabilities of Joint Cyber Warfighting Architecture (JWCA) supporting offensive and defensive cyberspace operations and improve the readiness of the Cyber Operations Forces to operate in a cyber-contested environment including the ability to Defend the Homeland and key capabilities such as Golden Dome. Work across the Department to reform acquisition processes and accelerate the adoption of modern software practices to deliver warfighting capability at the speed of need.$$, NULL, 35206000, 35168000, 20866000, NULL, NULL, 202, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 43755000, 83899000, 30746000, 30746000, NULL, 30746000, 21285000, $$The FY 2026 spend plan amount for Research, Development, Test & Evaluation, Defense-Wide for Cyber Resiliency & Cybersecurity Policy includes $23,899 thousands of discretionary and $60,000 thousands of mandatory (reconciliation) for a total of $83,899 thousands. This program supports the Department's initiatives to Revive the Warrior Ethos, Rebuild Our Military, and Reestablish Deterrence. The Cyber Resiliency & Cybersecurity Policy (CR&CP) program supports the efforts of the Office of the Under Secretary of War, Acquisition and Sustainment (OUSW A&S) to cyber harden priority Department of War (DoW) missions and enhance the cyber lethality of the Joint Force. The CR&CP program enables the Cyber Warfare Directorate (CWD) to conduct Capability Portfolio Management to enhance the Department’s capability to cyber harden priority DoW missions, enabling weapon systems, supporting DoW Installation Critical Infrastructure (ICI) and defend supporting Commercial Critical Infrastructure (CCI) from cyber-attack. The CR&CP program funds Cybersecurity Supply Chain Risk Management (C-SCRM) efforts that implement DoW priorities and Congressional direction aligned with enhancing C-SCRM. In addition, this program funds initiatives that enhance the security of the Department’s sensitive unclassified information residing within the Defense Industrial Base (DIB) and enhance the cybersecurity of priority DoW production lines. The CR&CP program also funds Capability Portfolio Management for Joint Cyber Capabilities used by the Cyber Mission Force. This program funds the following critical efforts: 1) Cybersecurity for Weapon Systems and Critical Infrastructure: Conduct Capability Portfolio Management and lead the Department’s Strategic Cybersecurity Program (SCP) to continue critical weapon systems and ICI cybersecurity assessments and mitigations and cyber harden priority Department of War (DoW) missions. Office of Assistant Secretary of War for Acquisition (ASW(A))/Cyber Warfare Directorate (CWD) Cyber Resiliency efforts are aligned with the following initiatives: Assess: - Conduct mission level cyber risk assessments for priority War Missions in support of Combatant Commands (CCMDs). Conduct enhanced mission level cyber risk assessments/wargames for the Missile Defense Mission and key supporting missions in support of Golden Dome for America. Conduct supporting tabletop exercises (TTXs). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                 Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:       PE 0606771D8Z / Cyber Resiliency & Cybersecurity Policy RDT&E Management Support - Conduct Cyber Risk Assessments for ICI and CCI in support of CCMDs and asset owners. - Conduct Integrated Sensing Monitoring Experiments (ISMX)and Sensing and Monitoring Pilots to assess the performance of Cybersecurity Sensing and Monitoring capabilities for WS and ICI. Inventory / Prioritize: - Develop, sustain, and employ the Cyber Risk Mitigation Tool (CRMT), an Enterprise-wide decision support tool for tracking and prioritizing cyber vulnerability assessments and mitigations. Develop CCMD specific cyber risk scorecards/risk matrices. - Prioritize and advocate for Cyber Risk Mitigations based upon mission analysis conducted by program offices, the National Security Agency (NSA), Cyber Risk Assessment teams, USCYBERCOM (USCC), and other cybersecurity professionals. Mitigate: - Advocate and oversee cyber risk mitigation funding for priority ICI and commercial critical infrastructure (CCI) supporting Golden Dome for America based on a prioritized list of assets. - Advocate for and oversee cyber risk mitigation funding aligned with cyber hardening priority DoW production lines. - Advocate for and oversee cyber risk mitigation funding aligned with cyber hardening priority USTRANSCOM missions. - Conduct SCP POAM periodic updates with Services and Agencies for prioritized DoW weapon systems. Enhance Governance: Conduct 4-Star Level Integrated Acquisition Portfolio Reviews (IAPRs) that address cybersecurity / cyber hardening / cyber defense for priority DoW missions. 2) Weapon System Cyber Security – CCI Cybersecurity // Cybersecurity Supply Chain Risk Management (C-SCRM): In collaboration with the Department of War Chief Information Office (DoW CIO), conduct the C-SCRM in support of FY2019 NDAA Section 889, and Title 10 USC Section 3252 and Section 4713. Partner with other DoW organizations and the DIB / CCI sectors to demonstrate / assess cost-effective and scalable cybersecurity services that augment and/or enhance existing commercial capabilities and services. Focus on identifying options and assessing the efficacy of cybersecurity services for small-to-medium sized DIB / CCI companies that are critical to the DoW supply chain but lack sufficient cybersecurity capabilities to protect CUI, data integrity, and availability of DIB supply chain. 3) Capability Portfolio Management for Cyberspace Operations: Conduct Capability Portfolio Management of the Joint Cyber Capabilities employed by Cyber Mission Force in collaboration with USCYBERCOM. Improve cyber lethality of the capabilities of Joint Cyber Warfighting Architecture (JWCA) supporting offensive and defensive cyberspace operations and improve the readiness of the Cyber Operations Forces to operate in a cyber-contested environment, including the ability to Defend the Homeland and key capabilities such as Golden Dome. Work across the Department to reform acquisition processes and accelerate the adoption of modern software practices to deliver warfighting capability at the speed of need. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0606771D8Z / Cyber Resiliency & Cybersecurity Policy RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606774D8Z$$, $$Defense Civilian Training Corps$$, $$rdte_dw_ba6$$, $$dw_osd$$, 2026, 8752000, 0, 27054000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 77, "original_pe": "0606774D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The FY 2026 request for DCTC includes $8.752 thousands of discretionary and $0 thousands of mandatory (reconciliation) for a total of $8.752 thousands. The Defense Civilian Training Corps (DCTC) program is directed by 10 U.S.C. Ch 113 with the purpose to prepare selected students for public service and meet critical skill gaps in acquisition, digital and critical technologies, science, engineering, finance, and other civilian occupations determined by the Secretary of Defense. Chapter 113 requires the Secretary of Defense, acting through the Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)), to establish units at any accredited civilian educational institution authorized to grant baccalaureate degrees. Using Chapter 113 direction and FY 2023 and FY 2024 DCTC appropriated funding, both an add by Congress (the PB23 and PB24 request did not include a request for DCTC funding), the USD(A&S) initiated in August 2023 a pilot two-year (junior and senior) program preparing future acquisition and sustainment civilians, with four DCTC pilot units deployed at four universities. The first DCTC cohort was comprised of 85 undergraduate scholars who started DCTC in August 2023 and graduated May 2025.. The second DCTC cohort started in August 2024 and is comprised of 100 undergraduate scholars (juniors). The third cohort was selected in December 2024 and graduates in May 2027. The DCTC pilot program is completed and ends with graduation of the third cohort. The DCTC program provides scholar education and development through DoD-context undergraduate classes and DoD real-world challenge projects sponsored by DoD field organizations which also host project-based summer internships with mentoring. DCTC classes cover DoD mission, structure and functions, the defense acquisition system and functions, innovation and technical literacy. The DCTC program includes completion of scholar security clearances and use of hiring authorities at graduation for immediate placement in jobs at DoD organizations. DCTC strengthens the DoD talent (supply-side) pipeline with new-hire DoD civilians, prepared for DoD acquisition and sustainment mission careers, accelerated in development and readiness for public service and contributing day-one as national security professionals to the DoD acquisition and sustainment mission. Again, the DCTC pilot program is completed and ends with graduation of the third cohort. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0606774D8Z / Defense Civilian Training Corps RDT&E Management Support$$, NULL, 31000, 31000, 32000, NULL, NULL, 203, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 26064000, 8636000, 0, 0, NULL, 0, 33000, $$The Defense Civilian Training Corps (DCTC) program was established in FY 2023 and funded under the Department of Defense Acquisition Workforce Development Account (DAWDA). DCTC is aligned under the Office of Under Secretary of War for Acquisition and Sustainment (OUSW(A&S)). The DCTC program is directed by 10 U.S.C. Ch 113 with the purpose to prepare selected students for public service and meet critical skill gaps in acquisition, digital and critical technologies, science, engineering, finance, and other civilian occupations determined by the Secretary of War. Chapter 113 requires the Secretary of War, acting through the Under Secretary of War for Acquisition and Sustainment (USW(A&S)), to establish units at any accredited civilian educational institution authorized to grant baccalaureate degrees. Using Chapter 113 direction and FY 2023 and FY 2024 DCTC appropriated funding, both an add by Congress (the PB23 and PB24 request did not include a request for DCTC funding), the USW(A&S) deployed in August 2023 a pilot two-year (junior and senior) ROTC-like program preparing future acquisition and sustainment civilians, with DCTC pilot units at four universities. The first DCTC cohort was comprised of 85 undergraduate scholars who started DCTC in August 2023 and graduated May 2025. The second DCTC cohort is comprised of 100 undergraduate scholars (juniors) who graduate in May 2026. The third cohort is comprised of 100 participants and will graduate May 2027. The DCTC pilot program is completed and ends with graduation of the third cohort. The DCTC program provides scholar education and development through DoW-context undergraduate classes and DoW real-world challenge projects sponsored by DoW field organizations which also host project- based summer internships with mentoring. DCTC classes cover DoW mission, structure and functions, the defense acquisition system and functions, innovation and technical literacy. The DCTC program includes completion of scholar security clearances and use of hiring authorities at graduation for immediate placement in jobs at DoW organizations. DCTC strengthens the DoW talent (supply-side) pipeline with new-hire DoW civilians, prepared with a high state of readiness and the warfighting acquisition mission ethos needed to achieve the Secretary of War priorities to Rebuild the Military and Reestablish Deterrence. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                    Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:      PE 0606774D8Z / Defense Civilian Training Corps RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606775D8Z$$, $$Joint Production Accelerator Cell (JPAC)$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 5493000, 0, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0606775D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Department of Defense (DoD) needs a reliable supply of diverse weapons systems and supplies to ensure operational readiness amidst unpredictable volatile global events. These national security challenges place variable stresses on the DoD’s munitions inventory and generate a range of production needs, limiting the utility of addressing capability requirements strictly on a program-by-program basis. This Program Element (PE) advances promising manufacturing technologies and processes with the intention of improving operational readiness across the Joint Force. This PE furthers the Department’s efforts to rebuild the military and reestablish deterrence by accelerating the delivery of critical weapon systems through advanced manufacturing. It identifies and prototypes ways to build and maintain surge production capacity and resilience for critical weapons. It identifies areas for advanced manufacturing, works with piloting entities to analyze approaches, and collaborates with critical weapons programs. The outcomes will include scalable demonstrations and guidance on advanced manufacturing and acquisition reforms.$$, NULL, 6877000, 7548000, 7710000, NULL, NULL, 204, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 0, 5458000, 6215000, 6215000, 0, 6215000, 7864000, $$Current national security challenges impose varied and unpredictable demands on the Department of War's munitions inventories. The requirement of the Department is to produce rapidly and at scale, a reliable supply of diverse weapons systems and supplies to ensure operational readiness amidst unpredictable volatile global events. A rigid, program-by-program approach to funding and production is insufficient to meet these diverse and evolving needs, highlighting the necessity for a more flexible and holistic acquisition strategy. This program directly addresses this shortfall by advancing promising manufacturing technologies and processes to improve operational readiness across the Joint Force. By accelerating the delivery of critical weapon systems through novel designs, innovative production techniques, and advanced manufacturing, this program is a key component of the Department’s strategy to rebuild our military capabilities and re-establish credible deterrence. This program identifies and pilots ways to build and maintain surge production capacity and resilience for critical weapons. Additionally, it draws lessons from novel designs, innovative production techniques, advanced manufacturing, affordable mass systems, and a modular open system approach. To execute the National Defense Strategy's (NDS) goal of allied industrial integration, this program develops interoperable manufacturing technologies and processes. These advancements create tangible pathways for allied and partner nations to co-produce critical capabilities, accelerating fielding timelines and strengthening our collective defense posture. The efforts will include scalable pilots that further the Acquisition Transformation Strategy. This program develops and implements policy, procurement, and production best practices to build enduring industrial capacity. It supports the NDS’s drive to supercharge the U.S. Defense Industrial Base to modernize and strengthen our military to maintain a competitive edge. The analysis and assessment of flexible and scalable manufacturing approaches will further enable the Office of the Undersecretary of War for Acquisition & Sustainment (OUSW(A&S)) to mobilize the defense and commercial industrial base and arm U.S. troops, as well as allies and partners so they can expand their role in burden-sharing. These efforts support the mission of the future Wartime Production Unit to rebuild the U.S. defense industry to be able to maintain and surge American manufacturing capability and capacity and to deliver weapons at the speed of relevance. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0606775D8Z / Joint Production Accelerator Cell (JPAC) RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606853BR$$, $$MANAGEMENT TECHNICAL AND INTERNATIONAL SUPPORT$$, $$rdte_dw_ba6$$, $$dw_dtra$$, 2026, 14841000, 11617000, 10039000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0606853BR", "page_header": "Defense-Wide"}$$::jsonb, $$The Defense Threat Reduction Agency (DTRA), as the DoD Center of Excellence for Mission Assurance Assessments, has been tasked by Deputy Assistant Secretary of Defense for Defense Continuity and Mission Assurance with leading change within the MA community on behalf of Office of the Under Secretary of Defense to ensure best practices are documented during the Joint Mission Assurance Assessments (JMAA), Balanced Survivability Assessments (BSA), and Red Team Assessments. Including but not limited to dependency analysis, asymmetric threats, cyber operations, general engineering, security operations, and emergency management. In partnership with the Critical Infrastructure Defense Analysis Center (CIDAC) and the U.S. Department of the Navy's Defense Critical Infrastructure - Mission Assurance program, DTRA’s Mission Assurance program will perform mission analysis; engineering and commercial infrastructure network interdependency analysis; MA assessments; information enterprise design, implementation, and support; and defense industrial base supply chain network and related analysis. Efforts provide broad leadership, best practices, research, development, coordination, support to DoD Components around specific focus areas to drive solution-oriented efficiencies, collaboration, and results that benefit the entire DoD MA enterprise.$$, NULL, 0, 0, 0, NULL, NULL, 206, $$RDTE_DTRA_PB_2026.pdf$$, $$DTRA$$, FALSE, 9791000, 14672000, 0, 0, 0, 0, 0, $$Beginning in FY 2023, the Defense Threat Reduction Agency (DTRA), as the DoW Center of Excellence for Mission Assurance Assessments, was tasked by the Deputy Assistant Secretary of War for Defense Continuity and Mission Assurance to provide oversight and program management of the Critical Infrastructure Defense Analysis Center (CIDAC) program in coordination with the Office of the Under Secretary of War for Policy (OUSW(P)), the U.S. Navy, and the U.S. Air Force. In FY 2027, this mission responsibility and funding transferred from DTRA to the Office of the Deputy Assistant Secretary of the Navy for Installations and Facilities DASN(I&F).$$, $$Budget J-Books/FY27/Remaining/RDTE_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0606942A$$, $$Assessments and Evaluations Cyber Vulnerabilities$$, $$rdte_army_ba6$$, $$asa_alt$$, 2026, 6354000, 6025000, 10105000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0606942A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line reduces the Army's risk to adversarial cyber intrusions or attacks that could compromise critical weapon/business systems and kill chains. Cyberspace Operational-Resilience Assessment - Platform (CORA-P) is the Army program to improve survivability across Army modernization efforts and maintain readiness of operational capabilities. CORA-P addresses Congressional requirements beginning with FY16 NDAA Section-1647, and through FY24 NDAA Section-1502, which directs the Services to identify and mitigate cyberspace vulnerabilities in critical weapon systems. Under CORA-P, the Army identifies and prioritizes capabilities most-relevant to National Defense Strategy priorities based on input from mission planning, JROC guidance, and sensitive threat intelligence. The Army then reviews the security posture of these critical components, develops remediation strategies, and facilitates delivery of fixes at mission-relevant speed. CORA- P is helping move the DoD from system-oriented compliance to system-of-systems resilience that addresses defensive gaps between individual components; this is necessary to prevent adversaries from denying critical kill chains. CORA-P ensures Army cyberspace remediation investments address areas of highest operational risk.$$, NULL, 6541000, 6592000, 6661000, NULL, NULL, 197, $$RDTE - Vol 4 - Budget Activity 6.pdf$$, NULL, FALSE, 10105000, 6354000, 6468000, 6468000, NULL, 6468000, 6728000, $$This funding line reduces the Army's risk to adversarial cyber intrusions or attacks that could compromise critical weapon/business systems and kill chains. Cyberspace Operational-Resilience Assessment - Platform (CORA-P) is the Army program to improve survivability across Army modernization efforts and maintain readiness of operational capabilities. CORA-P addresses Congressional requirements beginning with FY16 NDAA Section-1647, and through FY24 NDAA Section-1502, which directs the Services to identify and mitigate cyberspace vulnerabilities in critical weapon systems. Under CORA-P, the Army identifies and prioritizes capabilities most-relevant to National Defense Strategy priorities based on input from mission planning, JROC guidance, and sensitive threat intelligence. The Army then reviews the security posture of these critical components, develops remediation strategies, and facilitates delivery of fixes at mission-relevant speed. CORA- P is helping move the DoW from system-oriented compliance to system-of-systems resilience that addresses defensive gaps between individual components; this is necessary to prevent adversaries from denying critical kill chains. CORA-P ensures Army cyberspace remediation investments address areas of highest operational risk.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 6.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607101A$$, $$Combating Weapons of Mass Destruction (CWMD) Product Improvement$$, $$rdte_army_ba7$$, $$asa_alt$$, 2026, 115000, 0, 271000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0607101A", "page_header": "Department of the Army"}$$::jsonb, $$The Combating Weapons of Mass Destruction Product Improvement (CWMD) line supports obsolescence management efforts for overall chemical, radiological, and biological detection and protection for the warfighter for multiple programs of record, including the Radiological Detection System (RDS). FY2026 Base amount of $0.115 million supports RDS.$$, NULL, NULL, NULL, NULL, NULL, NULL, 201, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 261000, 115000, 488000, 488000, NULL, 488000, NULL, $$The Combating Weapons of Mass Destruction (CWMD) Product Improvement line supports obsolescence management and product improvement efforts for overall chemical, radiological, and biological detection and protection for efforts that have been fielding or have received approval for full rate production. Project DJ7 Radiological Detection System (RDS) Development supports continued product improvement and obsolescence management for RDS as it fields to the warfighter.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607131A$$, $$Weapons and Munitions Product Improvement Programs$$, $$rdte_army_ba7$$, $$peo_ammo$$, 2026, 13687000, 61735000, 31563000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0607131A", "page_header": "Department of the Army", "fy26_v182_disc_K": 80762, "fy26_v182_supp_K": 2400, "fy26_v182_total_K": 83162, "fy26_v182_note_name": "Weapons and Munitions Product Improvement Programs", "fy26_v182_source_file": "RDTE - Vol 4 - Budget Activity 7.txt", "fy26_v182_source_line": 1781}$$::jsonb, $$Project CP2 / Precision Fire Technology Improvements, supports required Precision Guided Munitions (PGMs), and Precision Fuze and Fuze Setter assessment and improvement initiatives to support increased rates of fire for items that have been fielded or in full rate production, such as the M1155 Enhanced Portable Inductive Artillery Fuze Setter (EPIAFS), Excalibur and Precision Guidance Kit (PGK). Efforts will identify, characterize, study, analyze, test, and develop PGM and Fuze technologies to increase range, lethality, effectiveness, survivability, and accuracy in support of the Army's Cannon Transformation Strategy. Project ER2 / Close Combat Technology includes development efforts to upgrade Close Combat technologies, energetics, and munitions, such as counter explosives, grenades, demolitions, shoulder launched munitions, pyrotechnic simulators, countermeasure flares, non-lethal ammunition/systems, and networked munitions and mines, that have been fielded or have received approval for full rate production. Funding will allow the project to identify, characterize, study, analyze, test and develop technologies to resolve close combat munition reliability, safety, environmental, storage, standardization, obsolescence and manufacturing/producibility issues. Project ER5 / The Indirect Fire and Fuze Technology Project includes product improvement, and development efforts to upgrade indirect fire weapon systems and munitions that are fielded and/or are in production. Initiatives include improved target engagement, increased reliability, availability, maintainability, and safety, standardization and interoperability with weapons and munitions of Allied Nations, defense exportability features, reduction of failure mechanisms, and supply chain risk through introduction of new and alternative technology and materiel solutions, improvement of manufacturing methods and their associated production and life cycle support processes, new capabilities in response to the evolving and emerging threats and countermeasures, and reduction/elimination of potential environmental and health risks associated with these products. The Indirect Fire and Fuze Technology Project will enhance the Department of Defense's (DoD) portfolio. Project ER6 / The Direct Fire Technology funding will be used to support direct fire ammunition from small caliber ammunition, medium caliber ammunition and large caliber ammunition enhancements to lethality, effectiveness, survivability, accuracy and general product improvements. Funding supports a number of small caliber ammunition projects including improvements to training ammunition; improvements to make small caliber primers more environmentally friendly; optimization of handgun ammunition; exploring precision sniper improvements and continuing the effort to reduce Soldier load by developing lightweight ammunition. Improvements to medium caliber ammunition include lethality and safety enhancements including Counter Unmanned Aircraft System (C-UAS) technology. Improvements to 105mm and 120mm Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                             Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational   PE 0607131A / Weapons and Munitions Product Improvement Programs Systems Development tank ammunition include examination and implementation of performance enhancement and improvements to tracer, combustible cartridge case and 105mm Advanced Multipurpose (AMP). The FY 2026 request was reduced by $0.03 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 12622000, 7663000, 7604000, NULL, NULL, 202, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 31285000, 83162000, 21553000, 21553000, NULL, 21553000, 7681000, $$Project CP2 / Precision Fire Technology Improvements supports developmental initiatives for precision artillery munitions to include projectiles and fuzes, and fuze setter. Efforts will drive artillery fuze setter platform integration requirements as well as developmental precision artillery munitions and artillery weapon system requirements. Efforts will identify, characterize, study, analyze, test, and develop Precision Guided Munition (PGM), platform, communications and Fuze technologies to increase range, lethality, effectiveness, survivability, and accuracy required to support the Army's Field Artillery modernization objectives. Fiscal Year (FY) 2027 funding will support software development and integration activities as well as continued monitoring of upgrade strategies and requirements of interfacing PGMs, platforms, fire control systems, and Fuzes in support of artillery ammunition and platform modernization. Funding will also support fuze setter development activities necessary for compatibility with PGMs and increased power, and data handling capabilities. Project ER2 / Close Combat Technology includes development efforts to upgrade Close Combat technologies, energetics, and munitions, such as counter explosives, grenades, demolitions, shoulder launched munitions, pyrotechnic simulators, countermeasure flares, non-lethal ammunition/systems, networked munitions and mines, and sUAS lethal & protective payloads that have been fielded or have received approval for full rate production. Funding will allow the project to identify, characterize, study, analyze, test and develop technologies to resolve close combat munition reliability, safety, environmental, storage, standardization, obsolescence and manufacturing/producibility issues. Project ER5 / Indirect Fire and Fuze Technology includes product improvement and development efforts to upgrade indirect fire weapon systems and munitions, as well as fuzed munitions that are fielded and/or are in production. Initiatives include improved target engagement, increased reliability, availability, maintainability, and safety, standardization and interoperability with weapons and munitions of Allied Nations, defense exportability features, reduction of failure mechanisms, and supply chain risks through the introduction of new and alternative technology and materiel solutions, improvement of manufacturing methods and their associated production and life cycle support processes, new capabilities in response to the evolving and emerging threats and countermeasures, and reduction/elimination of potential environmental Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                             Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational        PE 0607131A / Weapons and Munitions Product Improvement Programs Systems Development and health risks associated with these products. This endeavor will sustain and enhance indirect fire weapon systems and fuzed munitions for the U.S. Army and the Department of War (DoW). Fiscal Year (FY) 2027 funding will continue to support analysis/risk mitigation efforts to deliver the Setback Generator Tester to provide standardized test methods; continue Mortar and Medium Caliber proximity signal processor Application-Specific Integrated Circuits (ASIC) second source qualifications. Block Upgrade: deliver the M739A1 Spinlock Spring Redesign for Automation to production; deliver Medium Caliber Miniature Battery dynamic modeling & simulation to support design changes; continue the common artillery ESAD; continue the extended duration M782 artillery fuze thermal battery integration; and start AMP ESAD integration. Project ER6 / The Direct Fire Technology funding will be used to support direct fire ammunition from small caliber ammunition, medium caliber ammunition and large caliber ammunition enhancements to lethality, effectiveness, survivability, accuracy and general product improvements. Funding supports a number of small caliber ammunition projects including improvements to training ammunition; improvements to make small caliber primers more environmentally friendly; optimization of handgun ammunition; exploring precision sniper improvements and continuing the effort to reduce Soldier load by developing lightweight ammunition. Improvements to medium caliber ammunition include lethality and safety enhancements including Counter Unmanned Aircraft System (C-UAS) technology. Improvements to 105mm and 120mm tank ammunition include examination and implementation of performance enhancement and improvements to tracer and combustible cartridge case.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607136A$$, $$Blackhawk Product Improvement Program$$, $$rdte_army_ba7$$, $$peo_aviation$$, 2026, 23998000, 40923000, 125000000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0607136A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line is a key enabler of the Army's development and modernization priorities in support of the H-60 Black Hawk helicopter. The program develops, tests, qualifies, and integrates the next generation capability for integration and implementation to the H-60 fleet to increase combat capability and reduce cognitive workload. The two overarching efforts are digital backbone and airframe enhancements. The digital backbone design supports rapid integration of future capabilities that align with Future Vertical Lift (FVL) Family of Systems (FoS), as well as airframe enhancements aligned with Launched Effects (LE).$$, NULL, 47209000, 53120000, 53150000, NULL, NULL, 203, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 124047000, 123998000, 35147000, 35147000, NULL, 35147000, 53681000, $$This funding line is a key enabler of the Army's development and modernization priorities in support of the H-60 Black Hawk helicopter. The program develops, tests, qualifies, and integrates the next generation capability for integration and implementation to the H-60 fleet to increase combat capability and reduce cognitive workload.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607137A$$, $$Chinook Product Improvement Program$$, $$rdte_army_ba7$$, $$peo_aviation$$, 2026, 10859000, 20386000, 4816000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0607137A", "page_header": "Department of the Army"}$$::jsonb, $$NOTE: The increase in funding from FY2025 to FY2026 is required to complete production configuration flight testing to qualify the CH-47F Block II as described in paragraph three (3) below. Program Element (PE) 0607137A Chinook Product Improvement Helicopter Program is critical to achieving heavy lift capability in support of Transformation in Contact (TiC) and Continuous Transformation objectives. The CH-47F Block II helicopter, with an increased payload and operational reach, is the only platform that can lift the Joint Light Tactical Vehicle (JLTV), M777 and medium girder bridge to enable the TiC Forces to Compete, Penetrate, Disintegrate, and Exploit at operationally relevant distances. CH-47 Modernization Product Management Office includes the Block II acquisition program that upgrades existing CH-47F aircraft and procures common hardware between the CH-47F and MH-47G aircraft. The CH-47F Block II program reduces Operating and Support (O&S) costs, increases maximum gross weight to 54,000 pounds, provides additional capability to the field with greater reach, and increases payload capability. CH-47F Block II upgrades improve the aircraft's safety and reliability with a strengthened airframe, and improvements to the rotor, fuel and electrical systems. The CH-47F Block II program includes updates to software packages, Common Avionics Architecture System (CAAS), Digital Advanced Flight Control System (DAFCS), and incorporates other avionics changes introduced into the final CH-47F Block I production lots. In addition to providing significant increased capability to the field, the program includes provisions for anticipated future upgrades, and weight and cost savings initiatives. The increased capabilities ensure the TiC has a platform with the flexibility and performance necessary to meet the needs of current and future operations. The Cargo Project Management Office awarded the CH-47F Block II Engineering and Manufacturing Development (EMD) contract in July 2017. The EMD phase produced three production representative test articles to support a Production Decision. This phase includes contractor and government led ground and flight system level qualification testing, which requires Electromagnetic Environmental Effects (E3), operation assessments, and aircraft subsystem Live-Fire Test and Evaluation (LFTE). System Level testing is required to complete an Operational Assessment and Material Release (MR). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                               Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational        PE 0607137A / Chinook Product Improvement Program Systems Development$$, NULL, 7387000, 7427000, 7431000, NULL, NULL, 204, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 4640000, 25859000, 7277000, 7277000, NULL, 7277000, 7505000, $$The PE is critical to achieving heavy lift capability in support of Transformation in Contact (TiC) and Continuous Transformation objectives. The CH-47F Block II helicopter, with an increased payload and operational reach, is the only platform that can lift the Light Medium Tactical Vehicle (LMTV), M777 and medium girder bridge to enable the TiC Forces to Compete, Penetrate, Disintegrate, and Exploit at operationally relevant distances. The CH-47 Block II Middle Tier Acquisition Rapid Fielding (MTA RF) effort inserts critical and affordable technologies into the Chinook fleet to maintain platform operational capabilities, while continuing to meet the Warfighter requirements. The CH-47F Block II provides additional capability to the field with increased payload, extended reach, improved sustainability, and an increased maximum gross weight to 54,000 pounds. Key improvements to the aircraft's safety and reliability include refinement to the rotor system, drivetrain, fuel, and electrical systems and a strengthened airframe providing commonality with the MH-47G. The Chinook Block II program updates the Common Avionics Architecture System (CAAS) and Digital Automatic Flight Control System (DAFCS) software packages of the aircraft and incorporates other avionics changes introduced into the final CH-47F production aircraft. The program includes provisions for anticipated future upgrades, weight savings, and cost savings that provide significantly increased capability to the field. These initiatives ensure the Army has a platform with the flexibility and performance needed to meet the needs of TiC operations. The total cost of the CH-47F Block II MTA RF effort is $1,228.5 billion (APA $1,184.1 billion, RDTE $44.4 million), including RDT&E from FY2025 through FY2030, per the Acquisition Decision Memorandum dated 12 Sep 2025. The CH-47F Block II MTA RF is fully funded across the Future Years Defense Program. This PE utilized FY2025 $4.640 million and FY2026 $10.859 million for the CH-47F Block II MTA RF requirement. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational       PE 0607137A / Chinook Product Improvement Program Systems Development$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607139A$$, $$Improved Turbine Engine Program$$, $$rdte_army_ba7$$, $$peo_aviation$$, 2026, 0, 182204000, 130029000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 21, "original_pe": "0607139A", "page_header": "Department of the Army", "fy26_v182_disc_K": 175000, "fy26_v182_supp_K": 63000, "fy26_v182_total_K": 238000, "fy26_v182_note_name": "Improved Turbine Engine Program", "fy26_v182_source_file": "RDTE - Vol 4 - Budget Activity 7.txt", "fy26_v182_source_line": 4102}$$::jsonb, $$This funding line is a key enabler of the Army Modernization Priorities in support of the Improved Turbine Engine Program (ITEP). ITEP develops, tests, qualifies, and integrates the next generation turboshaft engine on Black Hawk and Apache aircraft. The Improved Turbine Engine (ITE) replaces the existing T700 engine design originated in the 1970s and meets the operational requirement of 6,000 feet pressure altitude and 95 degrees (6K/95). The ITE will fit inside the existing engine bays of the Black Hawk and Apache Helicopters and provides a significant power enhancement of up to fifty percent (total of 3,000 class shaft horsepower) with increased fuel efficiency. Additional benefits include improved design life, enhanced reliability, lower maintenance cost and restored capability lost due to aircraft weight growth without an increase to the logistics footprint. The program consists of systems engineering and program management, detailed design engineering, design assurance, hardware manufacturing and testing, component and module level development and testing, system level testing and qualification, and platform integration and qualification. Improved Turbine Engine Program is part of the Army Transformation Initiative. The FY 2026 request was reduced by $0.18 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, NULL, NULL, NULL, NULL, NULL, 205, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 127582000, 238000000, NULL, NULL, NULL, NULL, NULL, $$This funding line is a key enabler of the Army Modernization Priorities in support of the Improved Turbine Engine Program (ITEP). ITEP develops, tests, qualifies, and integrates the next generation turboshaft engine on Black Hawk and Apache aircraft. The Improved Turbine Engine (ITE) replaces the existing T700 engine design originated in the 1970s and meets the operational requirement of 6,000 feet pressure altitude and 95 degrees (6K/95). The ITE will fit inside the existing engine bays of the Black Hawk and Apache Helicopters and provides a significant power enhancement of up to fifty percent (total of 3,000 class shaft horsepower) with increased fuel efficiency. Additional benefits include improved design life, enhanced reliability, lower maintenance cost and restored capability lost due to aircraft weight growth without an increase to the logistics footprint. The program consists of systems engineering and program management, detailed design engineering, design assurance, hardware manufacturing and testing, component and module level development and testing, system level testing and qualification, and platform integration and qualification. Improved Turbine Engine Program is part of the Army Transformation Initiative.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607142A$$, $$Aviation Rocket System Product Improvement and Development$$, $$rdte_army_ba7$$, $$tradoc$$, 2026, 0, 2904000, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0607142A", "page_header": "Department of the Army"}$$::jsonb, $$The Aviation Rockets and Small Guided Munitions Product Improvement and Development line funds the development, integration and test of current and future munitions and launchers, and their interface to platforms. Additionally, it will fund a range of improvement initiatives to modernize the Hydra-70 2.75 inch rocket and launcher system. The current Hydra-70 2.75 inch rocket system requires performance improvements to comply with 1) US Code - Title 10, Chapter 141, Section 2389 "Ensuring Safety regarding Insensitive Munitions", 2) Department of Defense (DoD) Directive 5000.1, Chairman of the Joint Chiefs of Staff (CJCS) Instruction 3170.01C, Under Secretary of Defense for Acquisition, Technology, and Logistics (OUSD (AT&L)) Memorandum of January 26, 1999, "Exemption for Existing Inventory Items to Insensitive Munitions (IM) Requirements", 3) signed Initial Capability Document (ICD) for Army Aviation Weapons, Sub-Systems and Munitions (AAWSSM), 4) Air Launched Effects (ALE) Initial Capability Refinement Document (ICRD) dated 21 October 2019, and 5) existing/emerging Headquarters, Department of the Army (HQDA) G-3/5/7 and U.S. Army Training and Doctrine Command (TRADOC) aviation weapon requirements for guided and unguided rocket and munition systems. Improvements to existing rocket systems and munitions will include design, qualification and integration of precision guidance capability, increased lethality, improved target suppression, increased standoff range, reduced minimum engagement range, improved pre-launch constraints and munitions communications/programmability, increased stowed kills, increased product reliability, improved hardness against unplanned stimuli, reduced Warfighter workload, and reduced environmental impact for both manned and unmanned applications. PE 0607142A EW9 has no FY 2026 funding request$$, NULL, NULL, NULL, NULL, NULL, NULL, 206, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607143A$$, $$Unmanned Aircraft System Universal Products$$, $$rdte_army_ba7$$, $$asa_alt$$, 2026, 0, 24466000, 24539000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0607143A", "page_header": "Department of the Army"}$$::jsonb, $$Scalable Control Interface (SCI) is a permissions-based software control suite used by Soldiers to simultaneously control multiple, disparate types of uncrewed or optionally-manned aircraft and payloads through a universal interface with scalable levels of authority. SCI distributes Unmanned Aircraft Systems (UAS) capabilities by greatly increasing the number of UAS control devices available to Soldiers, Commanders, and Battle Staff. SCI provides simultaneous employment of multiple aircraft/ payloads from a single control node. SCI leverages a Modular Open System Approach (MOSA) to software in order to reduce time and cost to integrate new hardware and software in response to the dynamic future operating environment. Deployment of SCI includes devices in the Mobile/Handheld Computing Environment (such as Nett Warrior), Mounted Computing Environment such as Mounted Family of Computer Systems (MFoCS), Command Post Computing Environment such as Tactical Services Infrastructure (TSI), fixed wing aircraft, and rotary wing aircraft. SCI will integrate decision aiding, autonomy, and artificial intelligence improvements as they technically mature, in order to support Multi-Domain Operations and reduce cognitive workload.$$, NULL, NULL, NULL, NULL, NULL, NULL, 207, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 23643000, 0, NULL, NULL, NULL, NULL, NULL, $$Uncrewed Vehicle Control (UVC) is a permissions-based software control suite used by Soldiers to simultaneously control multiple, disparate types of uncrewed or optionally-manned aircraft and payloads through a universal interface with scalable levels of authority. UVC distributes Unmanned Aircraft Systems (UAS) capabilities by greatly enabling more control devices available to Soldiers, Commanders, and Battle Staff. UVC provides simultaneous employment of multiple aircraft/payloads from a single control node. UVC leverages a Modular Open System Approach (MOSA) to software in order to reduce time and cost to integrate new hardware and software in response to the dynamic future operating environment. Deployment of UVC includes devices in the Mobile/Handheld Computing Environment (such as Nett Warrior), Mounted Computing Environment such as Mounted Family of Computer Systems (MFoCS), Command Post Computing Environment such as Tactical Services Infrastructure (TSI), fixed wing aircraft, and rotary wing aircraft. UVC will integrate decision aiding, autonomy, and artificial intelligence improvements as they technically mature, in order to support Multi-Domain Operations and reduce cognitive workload.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607145A$$, $$Apache Future Development$$, $$rdte_army_ba7$$, $$peo_aviation$$, 2026, 44371000, 44762000, 8243000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "original_pe": "0607145A", "page_header": "Department of the Army"}$$::jsonb, $$The Apache Product Improvement program prioritizes, informs, influences, matures, tracks, statuses, and packages technologies and/or material solutions to address known capability gaps identified during real-world combat missions and associated with current/emerging threats for the transition to Apache development for integration and implementation to the AH-64E fleet to increase combat capability.$$, NULL, 27967000, NULL, NULL, NULL, NULL, 208, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 7942000, 44371000, 30759000, 30759000, NULL, 30759000, NULL, $$The Apache Product Improvement program prioritizes, informs, influences, matures, tracks, statuses, and packages technologies and/or material solutions to address known capability gaps identified during real-world combat missions and associated with current/emerging threats for the transition to Apache development for integration and implementation to the AH-64E fleet to increase combat capability.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607148A$$, $$AN/TPQ-53 Counterfire Target Acquisition Radar System$$, $$rdte_army_ba7$$, $$cft_lrpf$$, 2026, 43054000, 52190000, 53652000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "original_pe": "0607148A", "page_header": "Department of the Army"}$$::jsonb, $$This funding line supports the AN/TPQ-53 Counterfire target Acquisition Radar program, a key enabler of the Army Long Range Precision Fires (LRPF) Modernization Priority. The AN/TPQ-53 Counterfire Target Acquisition Radar System is a highly mobile radar set that automatically detects, classifies, tracks, and locates the point of origin of projectiles fired from mortar, artillery, and rocket systems. It mitigates close combat radar coverage gaps by providing a 90 degree search sector (stare mode) as well as 360 degree coverage (rotating). The AN/TPQ-53 system incorporates Multi-Mission Radar (MMR) software into the system baseline, enabling air surveillance for Commander's situational awareness of UAS. The AN/TPQ-53 system interoperates with mission command systems to provide the maneuver commander increased counterfire radar flexibility, providing data to the Forward Area Air Defense Command and Control (FAAD C2) node for the sense and warn force protection capability. The AN/TPQ-53 is provided to Brigade Combat Teams (BCTs), Field Artillery Brigades (FABs) and Division Artilleries (DIVARTYs) and serves as an enabler for systems requiring target in-flight updates.$$, NULL, 99995000, 80129000, 80647000, NULL, NULL, 209, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 51694000, 43054000, 90981000, 90981000, NULL, 90981000, 81452000, $$This funding line supports the AN/TPQ-53 Counterfire target Acquisition Radar program, a key enabler of the Army Long Range Precision Fires (LRPF) Modernization Priority. The AN/TPQ-53 Counterfire Target Acquisition Radar System is a highly mobile radar set that automatically detects, classifies, tracks, and locates the point of origin of projectiles fired from mortar, artillery, and rocket systems. It mitigates close combat radar coverage gaps by providing a 90 degree search sector (stare mode) as well as 360 degree coverage (rotating). The AN/TPQ-53 system incorporates Multi-Mission Radar (MMR) software into the system baseline, enabling air surveillance for Commander's situational awareness of Unmanned Aerial Systems (UAS). The AN/TPQ-53 system interoperates with mission command systems to provide the maneuver commander increased counterfire radar flexibility, providing data to the Forward Area Air Defense Command and Control (FAAD C2) node for the sense and warn force protection capability. The AN/TPQ-53 is provided to Brigade Combat Teams (BCTs), Field Artillery Brigades (FABs) and Division Artilleries (DIVARTYs) and serves as an enabler for systems requiring target in-flight updates.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607150A$$, $$Intel Cyber Development$$, $$rdte_army_ba7$$, $$asa_alt$$, 2026, 13129000, 4345000, 9753000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "original_pe": "0607150A", "page_header": "Department of the Army"}$$::jsonb, $$The Rapid Capability Development Program provides cutting edge Signals Intelligence, Electronic Warfare, and Cyberspace (SIGINT/EW/Cyber) capabilities to gain an advantage over rapidly emerging and changing threats in multiple domains. The capabilities enable Army mission commanders to execute overarching mission command and gain a significant competitive advantage inside of the threat's decision cycle. Further, rapid development efforts address capabilities needed to realize specified tasks outlined in the DoD Cyber Strategy and The Army's Operating Concept by integrating these multi-domain capabilities into modular and scalable platforms and architectures that are tailored to conduct expeditionary operations and accelerate the decision cycle across the range of military operations. Development of capabilities is derived from established JCIDs, CRDs, and ONS, and in response to Theater Army Commands and Functional/Geographic Combatant Command named operations.$$, NULL, 14194000, 14678000, 14685000, NULL, NULL, 210, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 9753000, 13129000, 13694000, 13694000, NULL, 13694000, 14832000, $$The INSCOM Rapid Capability Office (RCO) provides multi-domain Signals Intelligence (SIGINT), Electromagnetic Warfare (EW), and Cyberspace capabilities to gain an advantage over rapidly emerging and changing threats. These capabilities enable Army mission commanders to mitigate risk, achieve technological superiority, and ensure the Warfighter's success. These efforts directly support Army requirements and directed missions, aligned with the 2025 Army Transformation Initiative and the Secretary of War's guidance on modern software acquisition to maximize lethality (Memorandum, 6 March 2025). Development is derived from Army requirements and directed missions in response to INSCOM's Major Subordinate Commands, Theater Army Commands and Functional/Geographic Combatant Command named operations. INSCOM G7 Capability Evaluation Center (CEC), on behalf of the Deputy Chief of Staff G-2 and the Commanding General of INSCOM, conducts comprehensive test and evaluation (T&E) for assigned systems while also managing and executing DoW-mandated standard T&E of Cyber Effects and Enabling Capabilities. The CEC provides automated testing for the evaluation of capabilities. The test and evaluation of these capabilities by CEC ensures that mission commanders receive a full risk profile of the capability and that the capability meets the requirements of the supported organization. Without adequate test and evaluation support to capabilities under development, the full operational risk profile of a capability's employment is not understood and significantly jeopardizes mission success. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational       PE 0607150A / Intel Cyber Development Systems Development$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607162D8Z$$, $$ChemBio Weapons Elimination Technology Improvement$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 2360000, 0, 11754000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0607162D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$Chemical and biological weapons (CBW)-based threats continue to evolve in response to changing geopolitics and emerging technologies. Each of the nations that are deemed as threats to United States (U.S.) national security are believed to have and/or be developing chemical and/or biological weapons. The Department of Defense (DoD) must be prepared to eliminate these threats during and/or after the execution of a contingency operation or in support of a diplomatic breakthrough, enabling the U.S. to achieve peace through strength and strengthening deterrence. Chemical Weapons Convention (CWC) and Biological Weapons Convention (BWC) obligations and DoD strategic guidance demand the Department maintain a complete and enduring capability to assess and destroy CBW, regardless of location or environment. In accordance with the CWC and BWC, the U.S. must be prepared to “destroy [chemical/biological] weapons…in its possession or…under its jurisdiction or control.” It is critical for the DoD to possess the capabilities to directly disable or defeat WMD threats prior to use. This capability must provide operational flexibility that enables early action and expedient destruction, from small-scale disablement and defeat in a non-permissive or austere environment to large-scale destruction of a foreign CBW stockpile in a post-contingency or permissive environment. Our current capabilities are inadequate to support these requirements, and we are currently unable to invest in the development and/or improvement of capabilities to eliminate CBW on the scale required. The Department must be proactive in ensuring we are prepared to eliminate known and expected CBW threats before adversary use against U.S. military or civilian personnel at home or abroad or our allies. The Chemical and Biological Weapons Elimination (CBWE) Research and Development Activities (RDAs)support the Department’s initiatives to rebuild our military and reestablish deterrence by ensuring a complete and enduring capability to assess and destroy chemical and biological weapons (CBW), regardless of location or operational environment. This program addresses Joint Force priorities, tasks, and requirements. Fiscal Year (FY) 2026 funding is for the advanced development of chemical weapons destruction capabilities in support of Joint Warfighter and U.S. Recovered Chemical Warfare Material requirements. The CBWE portfolio provides material solutions that enable DoD to prevent adversary acquisition, transfer, deployment, and use of CBW as well as meet U.S. Chemical Warfare Convention (CWC) treaty obligations. The CBWE portfolio will execute along several Lines of Effort (LOEs) to help prepare the Joint Force for a future operating environment in which adversary possession of Weapons of Mass Destruction (WMDs) pose threats ranging from tactical to existential, and limit U.S. strategic choices. These LOEs will create options for assessment Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:             PE 0607162D8Z / ChemBio Weapons Elimination Technology Improvement Operational Systems Development and destruction of recovered chemical warfare material within the U.S., as well as chemical and biological warfare material across the continuum of conflict, including materiel solutions for the destruction of small-scale and bulk CBW agents, and solutions for the elimination of nation state CBW programs and stockpiles. The Office of the Secretary of Defense uses the CBWE Portfolio to invest strategically in projects to fill validated requirements from the Services, Combatant Commands, combat support agencies, and defense agencies. Funding is prioritized for projects that close Joint Force and domestic assess, disable and/or destroy capability gaps. An annual investment strategy is used to prioritize and meet capability needs. The CBWE Technology Improvement program invests in upgrades and enhancements to fielded systems used to assess, disable, and/or destroy chemical and biological weapons and material – foreign and domestic. Funds are used for integration of operational prototypes into fielded systems, or other upgrades and enhancements, including any necessary test and evaluation. This program funds labor, materials, and travel requirements, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including Research, Development, Test & Evaluation (RDT&E), assessments and analyses, and other activities related to capability development and fielding.$$, NULL, 2851000, 2065000, 2110000, NULL, NULL, 223, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 11478000, 14319000, 2931000, 2931000, NULL, 2931000, 2152000, $$Chemical and biological weapons (CBW)-based threats continue to evolve in response to changing geopolitics and emerging technologies. Each of the nations that are deemed as threats to United States (U.S.) national security are believed to have and/or be developing chemical and/or biological weapons. The Department of War (DoW) must be prepared to eliminate these threats during and/or after the execution of a contingency operation or in support of a diplomatic breakthrough, enabling the U.S. to achieve peace through strength and strengthen deterrence. Chemical Weapons Convention (CWC) and Biological Weapons Convention (BWC) obligations and DoW strategic guidance demand the Department maintain a complete and enduring capability to assess and destroy CBW, regardless of location or environment. In accordance with the CWC and BWC, the U.S. must be prepared to “destroy [chemical/biological] weapons in its possession or under its jurisdiction or control.” It is critical for the DoW to match CBW-based threats by possessing the capabilities to directly disable or defeat WMD threats prior to use. This capability must provide operational flexibility that enables early action and expedient destruction, from small-scale disablement and defeat in a non-permissive or austere environment to large-scale destruction of a foreign CBW stockpile in a post-contingency or permissive environment. These capabilities will positively influence deterrence and project Peace Through Strength. Our current capabilities are inadequate to support these requirements, and we are currently unable to invest in the development and/or improvement of capabilities to eliminate CBW on the scale required. The Department must be proactive in ensuring we are prepared to eliminate known and expected CBW threats before adversary use against U.S. military or civilian personnel at home or abroad or our allies. The Chemical and Biological Weapons Elimination (CBWE) Research and Development Activities (RDAs) support the Department’s initiatives to rebuild our military and reestablish deterrence by ensuring a complete and enduring capability to assess and destroy chemical and biological weapons (CBW), regardless of location or operational environment. This program addresses Joint Force priorities, tasks, and requirements. Fiscal Year (FY) 2027 request is for the advanced development and improvement of chemical weapons assessment, disablement, and destruction technologies in support of service and joint warfighter requirements. The CBWE portfolio provides material solutions that enable DoW to prevent adversary acquisition, transfer, deployment, and use of CBW as well as meet U.S. Chemical Warfare Convention (CWC) treaty obligations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:             PE 0607162D8Z / ChemBio Weapons Elimination Technology Improvement Operational Systems Development The CBWE portfolio will execute along several Lines of Effort (LOEs) to help prepare the Joint Force for a future operating environment in which adversary possession of Weapons of Mass Destruction (WMDs) pose threats ranging from tactical to existential, and limit U.S. strategic choices. These LOEs will create options for assessment and destruction of recovered chemical warfare material within the U.S., as well as chemical and biological warfare material across the continuum of conflict, including materiel solutions for the destruction of small-scale weaponized and bulk CBW agents, and solutions for the elimination of nation state CBW programs and stockpiles. The Office of the Secretary of War uses the CBWE Portfolio to invest strategically in projects to fill validated requirements from the Services, Combatant Commands, combat support agencies, and defense agencies. Funding is prioritized for projects that close Joint Force and domestic assess, disable and/or destroy capability gaps. An annual investment strategy is used to prioritize and meet capability needs. The CBWE Technology Improvement program invests in upgrades, enhancements, and modifications to systems used to assess, disable, and/or destroy chemical and biological weapons and material – foreign and domestic. Funds are used for integration of operational prototypes into fielded systems, or other upgrades and enhancements, including any necessary test and evaluation. This program funds labor, materials, and travel requirements, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including Research, Development, Test & Evaluation (RDT&E), assessments and analyses, and other activities related to capability development and fielding.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607210D8Z$$, $$Industrial Base Analysis and Sustainment Support$$, $$rdte_dw_ba7$$, $$dw_osd$$, 2026, 2328370000, 897631000, 1013920000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "fy27_mand_k": 40646927, "original_pe": "0607210D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy26_v184_disc_K": 801720, "fy26_v184_reason": "manual_override_first_note_only_per_v34_F-NEW-V34-4", "fy26_v184_supp_K": 10465004, "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy26_v184_total_K": 11266724, "fy27_mand_section": "Defense Industrial Base", "fy26_v182_deferred": true, "fy26_v184_note_name": "Industrial Base Analysis and Sustainment Support (IBAS)", "fy26_v184_applied_at": "2026-05-09", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 47223, "fy26_v184_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_supp_K_skipped": 21390008, "fy26_v182_deferred_reason": "duplicate_supp_notes_in_R2_double_counted_IBAS", "fy26_v184_source_line_first_note": 45930, "fy26_v184_supersedes_v182_deferred": true, "fy26_v184_source_line_second_note_ignored": 46112}$$::jsonb, $$The Industrial Base Analysis and Sustainment Support (IBAS) program element line is one component of a broader Department of Defense (DoD) investment strategy to strengthen the competitive posture of the Defense Industrial Base (DIB) and secure domestic supply chains. Residing within the Manufacturing Capability Expansion and Investment Prioritization (MCEIP) Directorate within the Office of the Assistant Secretary of Defense for Industrial Base Policy (OASD(IBP)), IBAS investments are used both discretely and in combination with other DoD investment programs, such as MCEIP’s Defense Production Act (DPA) Title III, to ensure collaborative and non-duplicative investment supporting critical DIB and United States (U.S.) supply chain issues. The IBAS program element supports MCEIP priorities through investment in prime and sub-tier suppliers, which mitigate supply chain risks and eliminate production capacity bottlenecks in accordance with current Presidential, National Security Council, and Secretary of Defense guidance during times of presidential transition priorities, goals and objectives. IBAS program element investments are further synchronized across the Department through coordination with other research and development programs, including but not limited to the Defense-Wide Manufacturing Science and Technology Program (MSTP) residing in the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)). IBAS Support was established in accordance with 10 United States Code (U.S.C.) Section 4817, Industrial Base Fund. The ability of the United States to maintain readiness and to surge and sustain in response to an emergency directly relates to the capacity, capabilities, and resiliency of our manufacturing industry, and the DIB and relevant supply chains. IBAS authorities and flexibility are key components to building the industrial capabilities needed to innovate, produce, and sustain the weapon systems for today and tomorrow. The IBAS program element provides the Department with a unique capability to achieve the strategic aims of the Interim National Defense Strategic Guidance (INDSCG) and the 2023 National Defense Industrial Strategy, which call for a strong, resilient, responsive and healthy U.S. Defense Industrial Base that underpins current and future U.S. force readiness. This program element is uniquely positioned to improve the U.S. DIB’s competitiveness and ability to respond to the Department’s needs by applying focused investments to 1) monitor and assess the current state of the DIB, 2) address critical issues in the DIB relating to urgent operational needs, 3) address supply chain vulnerabilities, and 4) support efforts to expand the DIB. Global supply chain disruptions have become more common, with recent events highlighting risks and vulnerabilities that undermine our national security. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:             PE 0607210D8Z / Industrial Base Analysis and Sustainment Support Operational Systems Development Management Process – In order to successfully execute the FY 2026 budget, the IBAS Program Office within the OASD(IBP) will oversee the health of the IBAS portfolio and projects. The IBAS Program Office collaborates with relevant Military Department or defense agency technical leads to develop, coordinate, and execute acquisition strategies and implementation plans for each strategic focus area. FY 2026 strategic focus areas that will be executed in IBAS Project Code P819 include workforce, critical minerals and materials, castings and forgings, kinetic capabilities, energy storage and batteries, and microelectronics. Descriptions of each focus area are included in the P819 R-2a exhibit. The FY 2026 request for IBAS includes $273.379 million of discretionary and $2,054.991 million of mandatory (reconciliation) for a total of $2,328.370 billion. The mandatory funds support the Workforce, Critical Minerals and Materials, Castings and Forgings, Kinetic Capabilities, Energy Storage and Batteries and Microelectronics sectors. Further information for this reconciliation request is provided in Section 20004 (Munitions & Supply Chain) and 20009 (INDOPACOM Capabilities) of the Reconciliation Exhibit.$$, NULL, 9462425000, 7209679000, 8562502000, NULL, NULL, 224, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 975130000, 11266724000, 1177356000, 1177356000, 40646927000, 41824283000, 6407330000, $$The Industrial Base Analysis and Sustainment Support (IBAS) program element line is one component of a broader Department of War (DoW) investment strategy to strengthen the competitive posture of the Defense Industrial Base (DIB) and secure domestic supply chains. Residing within the Warfighting Investments, Resourcing, and Execution (WIRE) Directorate within the Office of the Assistant Secretary of War for Industrial Base Policy (OASW(IBP)), IBAS investments are used both discretely and in combination with other DoW investment programs, such as WIRE’s Defense Production Act (DPA) Title III, to ensure collaborative and non-duplicative investment supporting critical DIB and United States (U.S.) supply chain issues. The IBAS program element supports WIRE priorities through investment in prime and sub-tier suppliers, which mitigate supply chain risks and eliminate production capacity bottlenecks in accordance with current Presidential, National Security Council, and Secretary of War guidance during times of presidential transition priorities, goals and objectives. IBAS program element investments are further synchronized across the Department through coordination with other research and development programs, including but not limited to the Defense-Wide Manufacturing Science and Technology Program (MSTP) residing in the Office of the Under Secretary of War for Research and Engineering (OUSW(R&E)). IBAS Support was established in accordance with 10 United States Code (U.S.C.) Section 4817 and Section 865 of the FY 2026 NDAA, Industrial Base Fund. The ability of the United States to maintain readiness and to surge and sustain in response to an emergency directly relates to the capacity, capabilities, and resiliency of our manufacturing industry, and the DIB and relevant supply chains. IBAS authorities and flexibility are key components to building the industrial capabilities needed to innovate, produce, and sustain the weapon systems for today and tomorrow. The IBAS program provides the Department with a unique capability to achieve the strategic aims of the National Defense Strategic Guidance (NDSCG) which calls for a strong, resilient, responsive and healthy U.S. Defense Industrial Base that underpins current and future U.S. force readiness. This program is uniquely positioned to improve the U.S. DIB’s competitiveness and ability to respond to the Department’s needs by applying focused investments to 1) monitor and assess the current state of the DIB, 2) address critical issues in the DIB relating to urgent operational needs, 3) address supply chain vulnerabilities, and 4) support efforts to expand the DIB. Global supply chain disruptions have become more common, with recent events highlighting risks and vulnerabilities that undermine our national security. Management Process – In order to successfully execute the FY 2027 budget, the IBAS Program Office within the OASW(IBP) will oversee the health of the IBAS portfolio and projects. The IBAS Program Office collaborates with relevant Military Department or defense agency technical leads to develop, coordinate, and execute acquisition strategies and implementation plans for each strategic focus area. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                  Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:            PE 0607210D8Z / Industrial Base Analysis and Sustainment Support Operational Systems Development FY 2027 strategic focus areas that will be executed in IBAS Project Code P819 include Strategic & Critical Minerals, Kinetic Capabilities, Microelectronics, Manufacturing (Castings & Forgings, Extended Deterrence), Workforce, and Energy Storage & Batteries. Descriptions of each focus area are included in the P819 R-2a exhibit. The FY 2027 request for IBAS includes $1,177,356 thousand of discretionary and $40,646,927 thousand of mandatory for a total of $41,824,283 thousand. The FY 2027 mandatory funds continue efforts from FY 2026 to support the Strategic & Critical Minerals, Kinetic Capabilities, Microelectronics, Manufacturing (Castings & Forgings, Extended Deterrence), Workforce, and Energy Storage & Batteries. The FY 2026 spend plan amount for Research, Development, Test & Evaluation, Defense-Wide for IBAS includes $801,720 thousand of discretionary and $10,465,004 thousand of mandatory (reconciliation) for a total of $11,266,724 thousands. The FY 2025 spend plan amount Research, Development, Test & Evaluation, Defense-Wide for Industrial Base Analysis and Sustainment Support (IBAS) includes $515,130 thousand of discretionary and $460,000 thousand of mandatory (reconciliation) for a total of $975,130 thousand.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607212A$$, $$TENCAP Enhancements$$, $$rdte_army_ba7$$, $$asa_alt$$, 2026, 6800000, 0, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0607212A", "page_header": "Department of the Army"}$$::jsonb, $$B. Program Change Summary ($ in Millions)                                            FY 2024             FY 2025             FY 2026 Base            FY 2026 OOC             FY 2026 Total Previous President's Budget                                                      0.000               0.000                   0.000                       -                    0.000 Current President's Budget                                                       0.000               0.000                   0.000                       -                    0.000 Total Adjustments                                                                0.000               0.000                   0.000                       -                    0.000 • Congressional General Reductions                                          -                   - • Congressional Directed Reductions                                         -                   - • Congressional Rescissions                                                 -                   - • Congressional Adds                                                        -                   - • Congressional Directed Transfers                                          -                   - • Reprogrammings                                                            -                   - • SBIR/STTR Transfer                                                        -                   -$$, NULL, 19841000, 23509000, 38775000, NULL, NULL, 211, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, NULL, 0, 20982000, 20982000, NULL, 20982000, 44815000, $$Tactical Exploitation of National Capabilities (TENCAP) exploits national capabilities to pace evolving threats in support of operations during conflict and competition. TENCAP systems and technologies provide deep sensing to support commanders' situational understanding (patterns of life, threat intentions, etc.), indications & warnings (detection of enemy mobilization and hostile activity), and intelligence support to targeting (order of battle, electronic target folders, target detection, Battle Damage Assessment, etc.). TENCAP systems and technologies support Theater-level fires and effects, TENCAP systems enable integrated Signals Intelligence (SIGINT) / Electronic Warfare (EW) / and Cyberspace operations. TENCAP is a key enabler to defeating peer competitor Anti-Access / Area-Denial (A2/AD) strategies. The Tactical Exploitation of National Capabilities (TENCAP) Enhancements project will enable Army TENCAP to fulfill its Congressionally mandated mission to exploit National Intelligence Capabilities to pace rapidly emerging and evolving threats in support of operations during conflict and competition, enabling development, refinement and enhancements of critical capabilities that satisfy current and/or emerging Army-wide capabilities. TENCAP leverages National Partners capabilities in order to access/capture technologies, develop protypes, field capabilities, provide continuous enhancements and integration, and deliver solutions and capabilities to Army warfighters. This Project will address Army imperatives to sense farther, support precision long range fires, and communicate/share data with partners. This Program Element includes TENCAP Operational Systems Development. This project provides development efforts to upgrade delivered systems to pace rapidly emerging and evolving threats in support of operations during conflict and competition, enabling development, refinement and enhancements of critical capabilities that satisfy current and/or emerging Army-wide capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational       PE 0607212A / TENCAP Enhancements Systems Development$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607310D8Z$$, $$Counterproliferation Modernization$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 12704000, 12364000, 11309000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0607310D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$Counterproliferation (CP) Modernization supports the 2025 Interim National Defense Strategic Guidance objective of peace through strength with modernized capabilities that reestablish deterrence and rebuild our military. Program investments in CP capabilities, including pathway defeat and WMD device defeat activities, enable the Department to maintain credible options to defend the homeland against WMD use. Investments result in capabilities that take action against actors of concern and reduce access to WMD development pathways and delay further development, degrade capabilities where possible, and prevent WMD use. (2023 DoD Strategy to Counter Weapons of Mass Destruction (CWMD)). This Program Element (PE) modernizes currently fielded capabilities for operating units with assigned CP/CWMD missions to disrupt, degrade, delay, deny, and defeat adversary nuclear, chemical, and biological weapons, delivery platforms, command and control systems, and hardened and deeply buried targets. Program investments enable modernized WMD deterrence and CP capabilities that provide flexible options across all domains, including tactical situational awareness, low visibility methods of maneuver, and the ability to employ immediate effects without diminishing future capabilities, enabling active campaigning that supports the Administration’s CP priorities, mitigating risk to mission and risk to force. Funding is prioritized for projects that close Joint Force warfighter capability gaps to defend Taiwan and the homeland. An annual investment strategy is used to meet emergent operational needs validated by the Joint Force, yielding new fielded capabilities within one to two years. This program funds labor, materials, and travel in support of its requirements, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including Research, Development, Test & Evaluation (RDT&E), assessments and analyses, , education, and other activities related to capability development and fielding of nuclear modernization, homeland missile defense, one-way attack autonomous systems, critical cybersecurity and counter-small UAS initiatives. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                 Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:           PE 0607310D8Z / Counterproliferation Modernization Operational Systems Development$$, NULL, 11610000, 11789000, 12043000, NULL, NULL, 225, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 11151000, 12697000, 11304000, 11304000, NULL, 11304000, 12285000, $$Counterproliferation (CP) Advanced Development prioritizes investments aligned to the Defense Planning Guidance (DPG) approved on August 7, 2025, and supports the 2026 National Defense Strategy (NDS) objective of peace through strength with advanced development of capabilities that reestablish deterrence and rebuild our military. Program investments in CP capabilities, enable the Department to maintain credible options to defend the homeland against WMD use. Investments result in capabilities that take action to neutralize nuclear, chemical, biological and radiological materials of concern (2026 NDS). This program modernizes currently fielded capabilities for operating units with assigned CP/CWMD missions to disrupt, degrade, delay, deny, and defeat adversary nuclear, chemical, and biological weapons, delivery platforms, command and control systems, and hardened and deeply buried targets. Program investments enable modernized WMD deterrence and CP capabilities that provide flexible options across all domains, including tactical situational awareness, low visibility methods of maneuver, and the ability to employ immediate effects without diminishing future capabilities, enabling active campaigning that supports the Administration’s CP priorities, mitigating escalatory risk. In accordance with the DPG, funding is prioritized for projects that close Joint Force warfighter capability gaps to defend territory along the First Island Chain (FIC) and the western hemisphere. An annual investment strategy is used to meet emergent operational needs validated by the Joint Force, yielding new fielded capabilities within one to two years. This program funds labor, materials, and travel in support of its requirements, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including Research, Development, Test & Evaluation (RDT&E), assessments and analyses, education, and other activities related to capability development and fielding of bio-deterrence, nuclear modernization, homeland missile defense, one-way attack autonomous systems, and maritime/FIC territory superiority. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:         PE 0607310D8Z / Counterproliferation Modernization Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607312A$$, $$Army Operational Systems Development$$, $$rdte_army_ba7$$, $$asa_alt$$, 2026, 0, 19000000, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0607312A", "page_header": "Department of the Army"}$$::jsonb, $$The Army Operational System Development budget line includes development efforts across all Army Battlefield Operating Systems to upgrade systems that have been fielded or have received approval for full rate production. Systems in this budget line are characterized as having, or supporting programs that have received, Milestone C or Low Rate Initial Production (LRIP) approval. Selected programs within this budget line will exhibit a logical progression of program phases, development and production funding within the FYDP, consistent with the Department's full funding policy.$$, NULL, NULL, NULL, NULL, NULL, NULL, 212, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607313A$$, $$Electronic Warfare Development$$, $$rdte_army_ba7$$, $$asa_alt$$, 2026, 0, 6389000, 5559000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0607313A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element encompasses operational system development for this tactical ground-based Electronic Warfare (EW) and Terrestrial Signals Intelligence (SIGINT) system and employment applications. The systems under this program provide the Army with the capability to detect, identify, locate, collect/process, report, and engage (disrupt, degrade or deny) hostile forces to prevent their effective use of communications & non-communications networks, counter-mortar/counter- battery radars, surveillance radars, electronically fused munitions and other enemy threats using the Electro-Magnetic Spectrum (EMS). Prophet enables integration, interoperability and force modernization with emerging capabilities in support of Multi-Domain Operations.$$, NULL, NULL, NULL, NULL, NULL, NULL, 213, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 5559000, 0, NULL, NULL, NULL, NULL, NULL, $$This PE encompasses operational system development for this tactical ground-based Electronic Warfare (EW) and Terrestrial Signals Intelligence (SIGINT) system and employment applications. The systems under this program provide the Army with the capability to detect, identify, locate, collect/process, report, and engage (disrupt, degrade or deny) hostile forces to prevent their effective use of communications & non-communications networks, counter-mortar/counter-battery radars, surveillance radars, electronically fused munitions and other enemy threats using the Electro-Magnetic Spectrum (EMS). Prophet enables integration, interoperability and force modernization with emerging capabilities in support of Multi-Domain Operations.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607327T$$, $$Global Theater Security Cooperation Management Information Systems ($$, $$rdte_dw_ba7$$, $$dw_dsca$$, 2026, 6173000, 8193000, 8654000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0607327T", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 8338000, 6056000, 6010000, 6010000, NULL, 6010000, 0, $$The Global Theater Security Cooperation Management Information Systems Program was an Office of the Secretary of War initiative to develop and deploy a common web-based, centrally hosted management information system to serve as the information focal point for the Department of War’s (DoW) security cooperation efforts. The Global Theater Security Cooperation Management Information Systems program provides decision makers, security cooperation planners, and other users with the ability to view, manage, assess, and report security cooperation activities and events. The Global Theater Security Cooperation Management Information Systems was adopted from a theater-specific system and lacked basic functionality. Since 2010, the security cooperation enterprise, consisting of combatant commands, Military Departments, and Defense Agencies, have called for security cooperation activity life-cycle management, activity alignment to strategic guidance, adaptability and scalability for all security cooperation organizations, and interfaces with security cooperation authoritative data sources. The National Defense Authorization Act for FY 2017 enacted several DoW security cooperation enterprise reforms and consolidated various security cooperation authorities under a single chapter (16) in Title 10. Through these reforms, the DoW was assigned the responsibility to manage approximately 100,000 security cooperation activities per year, organized into more than 40 distinct authorities that support dozens of different organizations. On February 11, 2019, the office of the Secretary of Defense assigned the Defense Security Cooperation Agency (DSCA) as the lead for the Global Theater Security Cooperation Management Information Systems and any successor comprehensive security management information system. DSCA has since developed and deployed “Socium” (Latin for “partner”) as a successor system. In Fiscal Year 2026, the Socium program continued to develop a strategic optimization platform, directly advancing our strategic interests by setting conditions for increased user adoption and system integration. This was accomplished through the implementation of numerous capabilities and application enhancements. Key developments included the modernization of critical security cooperation workflows, with new processes deployed for legal authorities such as Sections 333, 332, 341, and 312, as well as for the Maritime Security Initiative. In parallel, targeted enhancements were delivered to the existing Significant Security Cooperation Initiatives (SSCI) workflow, while the program also began development of next-generation SSCI capabilities to meet future demands. To improve data-driven decision- making, the core Analytics Dashboard was enhanced and powerful new tools were launched, including the 5-Year Plan tool, the Objective Tree, and new Geospatial Information System (GIS) dashboards covering Risks and Opportunities, Global Health Engagements, and Golden Sentry. Foundational to these efforts was a significant infrastructure modernization, which included a critical migration to Enterprise Identity, Credential, and Access Management (ICAM), the completion of unclassified and classified host migrations, and the transition of GIS capabilities to the Joint Engineer Common Operating Picture. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Security Cooperation Agency                                             Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:          PE 0607327T / Global Theater Security Cooperation Management Information Systems ( Operational Systems Development                                               G-TSCMIS)$$, $$Budget J-Books/FY27/DW/RDTE_DSCA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607384BP$$, $$Chemical and Biological Defense (Operational Systems Development)$$, $$rdte_dw_ba7$$, $$dw_cbdp$$, 2026, 79118000, 65922000, 74463000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0607384BP", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 74031000, 64121000, 70485000, NULL, NULL, NULL, NULL, NULL, FALSE, 73489000, 77337000, 82695000, 82695000, 0, 82695000, 94582000, $$This program element (PE) resources Operational System Development across the Understand, Protect, and Mitigate portfolios. Chemical and Biological Defense Program (CBDP) investments provide an integrated, layered capability to enable Department of War (DoW) missions in a chemical and biological environment, ranging from combat operations to domestic incident prevention and response. The Projects in this PE support the upgrade of systems that have been fielded or have received approval for full-rate production in order to maintain Joint Force readiness. Individual Projects include: - Understand (UN7): Modernization and ongoing engineering of software and information systems. Continued development and testing of CB sensor equipment to ensure interoperability with emerging information technology and reduce size, weight, and power requirements, thereby easing logistical burdens. Refresh fielded medical diagnostic systems and capabilities, such as assays, to strengthen defenses against biological warfare agents. Upgrade medical nerve agent treatment systems to enhance defenses against chemical warfare threats facing U.S. Forces. - Protect (PT7): Efforts to refresh technology of fielded individual and protective equipment that enables the Joint Force to operate in a contaminated chemical and biological (CB) environment with little or no degradation of performance. Technology refresh efforts for fielded collective protection systems that are smaller, lighter, less costly to produce and maintain, and more logistically supportable, enabling mission accomplishment in spaces safe from the effects of CB contamination. - Mitigate (MT7): Technology refresh of fielded Contamination Mitigation systems that will remove and/or detoxify contaminated material without damaging combat equipment, personnel, or the environment. The projects in this PE support operational systems development necessary to maintain operational effectiveness and are, therefore, correctly placed in Budget Activity 7. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Chemical and Biological Defense Program                                         Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:          PE 0607384BP / Chemical and Biological Defense (Operational Systems Development) Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_CBDP_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607385BR$$, $$COUNTER WEAPONS OF MASS DESTRUCTION OPERATIONAL SY$$, $$rdte_dw_ba7$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 4179000, 3701000, 3773000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 4108000, 4108000, NULL, 4108000, 3849000, $$The Counter Weapons of Mass Destruction (CWMD) Operational Systems Development program element resources development efforts for operational CWMD systems that have been fielded to fulfill mission requirements in the below systems. (1) The Mission Assurance Risk Management System (MARMS) is a Department of War (DoW) risk management system that directly supports the Secretary of War Mission Assurance responsibilities as defined in the DoD Directive 3020.40, Mission Assurance, with the objectives of creating resilience and supporting critical processes to enable the protection of assets and ensuring defense critical missions across 17 Mission Assurance Related Programs and Activities. MARMS functions as an integration framework spanning multiple security domains that will support risk-informed decision-making, resource investment, and improved synchronization at different levels within DoW. MARMS supports multiple Joint Capability Areas: Command and Control, Logistics, and Protection. MARMS is a joint program and an acquisition category Ill software-intensive and situational awareness program in the agile-based Adaptive Acquisition Framework – Software Pathway. (2) The Nuclear, Chemical, Biological, Radiological and high-Explosive (NCBRE) Analysis Toolset (NATs) is fielded on multiple Department of War information systems, providing modeling and simulation capabilities for decision support. Upgrades to Development, Security, and Operations (DevSecOps) will address continuous integration and delivery requirements across multiple networks, enabling more rapid fielding of system improvements.$$, $$Budget J-Books/FY27/Remaining/RDTE_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L037$$, $$Comms, Nav Surveillance$$, $$proc_army_2031_ba2$$, $$cft_fvl$$, 2026, 11566000, 74912000, 61362000, NULL, $${"page": 12, "ba_num": "02", "source": "p1_fy26", "ba_name": "Modification of aircraft", "line_no": "37", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 11566, "li_num": 22, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 11566000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 11566000, 14384000, 14384000, 0, 14384000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607658N$$, $$Cooperative Engagement Capability$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 136436000, 136251000, 142552000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0607658N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 135777000, 131385000, 129859000, NULL, NULL, NULL, NULL, NULL, FALSE, 138660000, 136436000, 120782000, 120782000, NULL, 120782000, 132271000, $$PE 0607658N: The Command and Control RDT&E funding will be used for the research, design, development, integration testing, and documentation of the Cooperative Engagement Capability (CEC), Submarine Speed Sensors, and AN/WSN-12 Inertial Navigation System (INS). In FY26, Navigation Systems RDT&E transition from PE 0204228N to PE 0607658N. PU 2039 COOP Engagement: Cooperative Engagement Capability (CEC) significantly improves Battle Force Anti-Air Warfare (AAW) capability by coordinating all Battle Force AAW sensors into a single, real-time, composite track picture to support integrated fire control. In FY26, the Antenna Development line in PU 2039 COOP Engagement ended and the associated RDT&E transitioned to the PU 3240 CEC Increment 2 Hardware Modernization and System Integration lines. This was a zero-sum transition, there is no growth. PU 3240 CEC Increment II: The Cooperative Engagement Capability (CEC) Increment 2 (Inc 2) Capability Development Document (CDD) evolves CEC capabilities by enhancing the current Naval air defense and sensor network system capabilities through extension of kill chains, extension of communications Beyond Line of Sight (BLOS), expansion of composite track management capability-Joint and Force Level, expansion of network capacity, as well as expansion into other warfare mission domains. The CEC Inc 2 CDD integrates new sensor types and track data sources into the network, such as surface search radars and passive detection sensors, as well as relevant data from other networks. The CEC Inc 2 CDD provides a more complete, robust, and resilient situational awareness picture, composite identification, and Integrated Fire Control. It also accommodates more Cooperating Units with assured communications for Integrated Air and Missile Defense, Surface Warfare, and Electronic Warfare domains. The CEC Inc 2 CDD was signed by Vice Chief of Naval Operations (VCNO) on 26 June 2019 and approved by the Joint Capabilities Board (JCB) on 18 March 2020. The CEC Program has realigned RDT&E funding from PU 2039 COOP Engagement to PU 3240 CEC Increment 2 for the incremental development of CEC software and hardware improvements necessary to meet the requirements in the CEC Increment 2 CDD. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                           Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational     PE 0607658N / Cooperative Engagement Capability Systems Development PU 3311 Navigation Systems: Navigation Systems RDT&E funding will be used for the research, design, development, integration testing, and documentation of the AN/WSN-12 Inertial Navigation System (INS) and Submarine Speed Sensors.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607665A$$, $$Family of Biometrics$$, $$rdte_army_ba7$$, $$asa_alt$$, 2026, 1594000, 768000, 590000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "original_pe": "0607665A", "page_header": "Department of the Army"}$$::jsonb, $$DU2 / Non-MIP Biometrics - Biometrics Enabling Capability 0 (BEC 0), aka DoD Automated Biometrics Identification System (DoD ABIS), is an Army information technology system supporting identity superiority by providing the critical core capability for Warfighters to identify known or suspected threat actors in Multi Domain Operations (MDO) to include peer adversaries, terrorists and third country nationals. BEC 0 is an Army Program of Record and DoD's only authoritative biometric repository, providing 24/7 operational support for the Warfighter and interagency partners to decide and act in near-real time with timely identification and identity verification of known or suspected threat actors across the full range of military operations. DoD ABIS enables actionable intelligence supporting offensive operations and preventing espionage, sabotage, terrorist operations and other coercive actions against US forces and partner nations. DoD ABIS enables the Army, all other DOD components, Interagency and International Partners to effectively impede adversary's ability to conceal their identity and intentions. DoD ABIS supports all three objectives of the National Defense Strategy to increase lethality, enhance International Cooperation, and improve business practices. The Defense Forensics and Biometrics Agency (DFBA), under the Provost Marshal General, fulfills the Secretary of the Army's Executive Agent (EA) responsibilities for DoD forensics and biometrics activities. In addition, DFBA is the proponent to establish and maintain Research, Development, Test & Evaluation (RDT&E) and information management support throughout the Armed Services and DoD. DFBA leads and facilitates the development, improvement, and implementation of efficiencies to developed and deployed biometric technologies for Combatant Commands (CCMDs), Services, DoD, and Agencies; facilitates transition of capabilities that contribute to the enhancement of the biometric community; increases Joint Service interoperability; and empowers the warfighter by improving operational effectiveness on the battlefield. The DFBA strategy pursues technology opportunities through scientific discovery and makes investments responsive to specific requirements identified by combat developers. Justification: FY 2026 funding in the amount of $1.594 million for Project DU2 will provide DFBA the ability to actively manage research efforts to address DoD biometrics objectives and requirements. DFBA supports the conduct of biometric and forensics activities (e.g. standards conformance and interoperability assessments), provides guidance to the research and development community, assists DoD acquisition organizations, and coordinates efforts with DoD and interagency stakeholders. This level of engagement promotes information sharing across the biometrics community to maximize utility of RDT&E efforts. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                          Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational    PE 0607665A / Family of Biometrics Systems Development$$, NULL, 1676000, 1710000, 1731000, NULL, NULL, 215, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 568000, 1594000, 1640000, 1640000, NULL, 1640000, 1748000, $$DU2 / Non-MIP Biometrics - Biometrics Enabling Capability 0 (BEC 0), aka DoW Automated Biometrics Identification System (DoW ABIS), is an Army information technology system supporting identity superiority by providing the critical core capability for Warfighters to identify known or suspected threat actors in Multi Domain Operations (MDO) to include peer adversaries, terrorists and third country nationals. BEC 0 is an Army Program of Record and DoW's only authoritative biometric repository, providing 24/7 operational support for the Warfighter and interagency partners to decide and act in near-real time with timely identification and identity verification of known or suspected threat actors across the full range of military operations. DoW ABIS enables actionable intelligence supporting offensive operations and preventing espionage, sabotage, terrorist operations and other coercive actions against US forces and partner nations. DoW ABIS enables the Army, all other DOW components, Interagency and International Partners to effectively impede adversary's ability to conceal their identity and intentions. DoW ABIS supports all three objectives of the National Defense Strategy to increase lethality, enhance International Cooperation, and improve business practices. The Defense Forensics and Biometrics Agency (DFBA), under the Provost Marshal General, fulfills the Secretary of the Army's Executive Agent (EA) responsibilities for DoW forensics and biometrics activities. In addition, DFBA is the proponent to establish and maintain Research, Development, Test & Evaluation (RDT&E) and information management support throughout the Armed Services and DoW. DFBA leads and facilitates the development, improvement, and implementation of efficiencies to developed and deployed biometric technologies for Combatant Commands (CCMDs), Services, DoW, and Agencies; facilitates transition of capabilities that contribute to the enhancement of the biometric community; increases Joint Service interoperability; and empowers the warfighter by improving operational effectiveness on the battlefield. The DFBA strategy pursues technology opportunities through scientific discovery and makes investments responsive to specific requirements identified by combat developers.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0607757D8Z$$, $$Radiological and Nuclear Defense Modernization Operational System$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 2945000, 0, 1668000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0607757D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This Program Element (PE) supports the Department's Defense Priorities to Rebuild our Military and Reestablish Deterrence. This PE supports the modernization of radiological and nuclear (R/N) defense capabilities that enable the Department to prevent R/N attacks on the homeland and Joint Force abroad through deterrence, as well as survive and operate in and through a R/N environment. This aligns with the Interim National Defense Strategy and addresses the challenges of keeping pace with our increasingly nuclear-capable adversaries by developing modern R/N detection and identification capabilities that are networked into secure and hardened communications, command, and control (C3) systems. This PE supports the Office of the Under Secretary of Defense for Acquisition and Sustainment (OUSD(A&S)) Radiological and Nuclear Defense Capability Development (RNDCD) Program. The RNDCD Program is addressing the strategic objective of ‘fielding modernized R/N detection capabilities to enable the Joint Force to operate more effectively in a R/N contaminated environment’ (Department of Defense (DoD) Strategic Management Plan for FY2022-2026). The RNDCD Program enhances DoD’s capabilities to campaign across the domains of threats and spectrums of conflict by improving the Department’s capability to campaign, fight, and win in a R/N environment. By building a R/N resilient Joint Force and National Guard Bureau, this program contributes to reestablishing deterrence by denying any strategic advantage our adversaries may perceive in using nuclear weapons on the homeland or Joint Force stationed abroad. This program is specifically geared to provide modern, networked R/N detection, indication, and identification capabilities to the warfighter and to upgrade obsolescing equipment, increasing capability to operate in a R/N environment (2023 CWMD Strategy). The RNDCD Program enables DoD to: prepare for and respond to any emergency involving nuclear and/or radiological events in the United States; provide a capability for the Joint Force to withstand, operate through, and recover from an R/N event; improve resilience; and promote integrated layered deterrence of WMD with state, local, and other federal agencies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                    Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:              PE 0607757D8Z / Radiological and Nuclear Defense Modernization Operational System Operational Systems Development                                                   Development This funding line is the only Budget Authority (BA)-7 funding in the Department dedicated to modernizing R/N capabilities for the warfighter. The Office of the Secretary of Defense uses the RNDCD Program to invest strategically in projects across the Military Services, Combatant Commands, and Defense Agencies. Funding is prioritized for projects that close Joint Force warfighter capability gaps. An annual investment strategy is used to meet emergent operational and capability needs which are validated by the Joint Force and the National Guard Bureau, yielding new fielded capabilities within one to three years. Through the Radiological and Nuclear Defense Modernization Operational Systems Development PE, the RNDCD Program will invest in the modernization of fielded capabilities to improve DoD’s capability to detect and identify radiological and nuclear threats; integration of technologies, systems and components; operational test and evaluation of fielded capabilities to new end users; and delivery of field and table top exercises to identify, refine, and address materiel and non-materiel gaps and requirements in R/N defense. This program seeks to merge previous research, development, and acquisitions efforts across DoD to field common and interoperable capabilities across the Joint Force and the National Guard Bureau. Specifically in FY 2026, this PE will support the modernization of 1) the Radioisotope Identification Detector (RIID); 2) the Radiological Detection System (RDS); 3) the Gamma Detector Response and Analysis Software (GADRAS) suite; 4) the Vehicle Integrated Platform Enhanced Radiation Detection, Indication, and Computation (VIPER) system; 5) a test and evaluation article for Army mobile radiation sensors; and 6) a R/N detector for use in a GPS denied environment. This program funds labor, materials, and travel to support the requirements of this program, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including Research, Development, Test, and Evaluation (RDT&E), assessments and analyses, research studies, education, and other activities related to capability development and fielding.$$, NULL, 2868000, 2892000, 2957000, NULL, NULL, 228, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 912000, 2941000, 2794000, 2794000, NULL, 2794000, 3016000, $$This program supports the DoW’s priorities to Rebuild our Military and Reestablish Deterrence and supports the Office of the Under Secretary of War for Acquisition and Sustainment (OUSW(A&S)) Radiological and Nuclear Defense Capability Development (RNDCD) Program. An annual investment strategy is used to meet emergent operational needs which are validated by the Joint Force and yield fielded capabilities within one to three years. The program supports the modernization of radiological and nuclear (R/N) defense capabilities that enable the Department to prevent R/N attacks on the homeland and the Joint Force abroad through integrated deterrence. The program provides the Joint Forces the tools needed to survive and operate in and through a R/N environment through networked R/N detection, indication, and identification capabilities in support of the National Defense Strategy’s deterrence by denial strategy and prioritization of the Nuclear Deterrence Posture within the FY2027 Defense Planning Guidance. This program funds labor, materials, and travel to support the requirements of this program, performed by a government agency or by private individuals or organizations under a contract with the government, for activities and acquisitions including Research, Development, Test, and Evaluation (RDT&E), assessments and analyses, research studies, education, and other activities related to capability development and fielding. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:         PE 0607757D8Z / Radiological and Nuclear Defense Modernization Operational System Operational Systems Development                                              Development$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0608013N$$, $$RISK MANAGMEMENT INFO - SOFTWARE PILOT PROGRAM$$, $$rdte_navy_ba8$$, $$navy$$, 2026, 13341000, 11551000, 14522000, NULL, $${"act": "08", "ba_raw": "6.8", "source": "r1_fy26", "service": "navy", "page_num": 40, "original_pe": "0608013N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 11350000, 11574000, 11800000, NULL, NULL, NULL, NULL, NULL, FALSE, 14307000, 13341000, 13017000, 13017000, NULL, 13017000, 12015000, $$Section 872 of the National Defense Authorization Act (NDAA) for FY 2018 (P.L. 115-91) directed the Secretary of War to task the Defense Innovation Board (DIB) to undertake a study on "streamlining [the Department's] software development and acquisition regulations." The Under Secretary of War for Acquisition and Sustainment (USW(A&S)) submitted the final report to Congress in May 2019. The DIB's report made recommendations aimed at transforming the way the Department acquires, develops, and deploys software and manages digital talent. The DIB encouraged the creation of a "new appropriation category for software capability delivery that allows (relevant types of) software to be funded as a single budget item, with no separation between RDT&E, production and sustainment." The recommendation stemmed from the DIB's observation that current law, regulations, and policies (including those governing program funding and appropriations) treat software acquisition and development as a series of discrete, sequential steps; and that this approach is at odds with modern software, which is continuously updated to provide new functionality. This program has been designated as a Software and Digital Technology Pilot Program by the Secretary of War or the explanatory statement regarding this Act. The funding in this line is requested to be used for expenses necessary for agile procurement, production, modification and operation and maintenance of the pilot program requirements. The Risk Management Information (RMI) software pilot program is a consolidation of Department of the Navy (DON) risk management requirements into a single Program of Record (PoR) to provide modern safety reporting and management capabilities for both active and reserve Navy and Marine Corps commands. RMI enables agile responses to business rule changes, automation of routine actions, improved data integrity, and facilitates self-service for organizations and individuals. RMI is being developed in three increments of capabilities: Streamlined Incident Reporting (SIR), Safety Program Management (SPM), and Analysis & Dissemination (A&D). A fourth requirement, Portal Integration, will be accomplished as part of the development of the three RMI increments since each will be built on the same Commercial-Off- the-Shelf (COTS) platform. Each of these capabilities will be acquired as individual Abbreviated Acquisition Programs using an incremental development approach for reengineered business processes, while consolidating five legacy systems: Web-Enabled Safety System (WESS), Enterprise Safety Application Management Systems (ESAMS), Portsmouth Occupational Accident and Illness Reporting System (POAIRS), Medical Mishap and Compensation (MMAC), and Injury Tracker (INJTRK). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 8: Software and    PE 0608013N / RISK MANAGMEMENT INFO - SOFTWARE PILOT PROGRAM Digital Technology Pilot Programs$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0608041A$$, $$Defensive CYBER - Software Prototype Development$$, $$rdte_army_ba8$$, $$arcyber$$, 2026, 89238000, 104048000, 74548000, NULL, $${"act": "08", "ba_raw": "6.8", "source": "r1_fy26", "service": "army", "page_num": 23, "original_pe": "0608041A", "page_header": "Department of the Army"}$$::jsonb, $$- Defensive Cyber Operations (DCO) programs are key elements of the DCO Maneuver Baseline infrastructure, platform, and tools. The employment of defensive capabilities achieves the following objectives: deter, destroy and defeat cyberspace threats; gain time; economy of force; control key terrain; protect tasked critical assets and infrastructure; and develop intelligence. DCO consists of platform and software programs which are key elements of the DCO Maneuver Baseline infrastructure, platform, and tools. DCO supports the Army Cyber Command (ARCYBER), Information Warfare Operations Center (IWOC), Army Forces Command (FORSCOM), five (5) Regional Cyber Centers (RCCs), Cyber Warfare Battalion (CWB), Multi-Domain Task Force (MDTF), Cyber Protection Brigade (CPB), and twenty-one (21) Cyber Protection Teams (CPTs) in COMPO 1/2/3. Fiscal Year (FY) 2026 funding in the amount of $88.393 million supports Cyber Analytics (CA), Tools Suite, User Activity Monitoring (UAM), Forensics and Malware Analysis (F&MA), DCO Development Environment (DCODE), Garrison DCO Platform (GDP), and Deployable DCO System (DDS) capabilities. Funding will be executed by Program Executive Office - Intelligence, Electronic Warfare and Sensors (PEO IEW&S). - Army Cyber Command (ARCYBER) Rapid Cyber Prototyping (RCP) provides software-based capabilities that can quickly respond to emerging cyber threats and keep up with threat technology, while supporting multi-Domain operations. ARCYBER identifies potential development and prototyping efforts via Cyber Needs Forms (CNFs) based on operational feedback, changes in the operational information environment and/or trends of adversarial activity, which drive concept of operation (CONOP) and Tactics Techniques and Procedures (TTPs) modifications. These are separate and distinct from DCO programmed efforts already funded or budgeted for by Project Manager (PM) DCO and are used to rapidly address a network threat/vulnerability. FY 2026 funding in the amount of $0.845 million will be executed by ARCYBER. The FY 2026 request was reduced by $0.455 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                     Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 8: Software and    PE 0608041A / Defensive CYBER - Software Prototype Development Digital Technology Pilot Programs$$, NULL, 95122000, 94927000, 94990000, NULL, NULL, 238, $$RDTE - Vol 4 - Budget Activity 8.pdf$$, NULL, FALSE, 74548000, 89238000, 94095000, 94095000, NULL, 94095000, 95836000, $$- Defensive Cyber Operations (DCO) programs are key elements of the DCO Maneuver Baseline infrastructure, platform, and tools. The employment of defensive capabilities achieves the following objectives: deter, destroy and defeat cyberspace threats; gain time; economy of force; control key terrain; protect tasked critical assets and infrastructure; and develop intelligence. DCO consists of software and platform programs which are key elements of the DCO Maneuver Baseline infrastructure, platform, and tools. DCO supports the Army Cyber Command (ARCYBER), Information Warfare Operations Center (IWOC), Army Forces Command (FORSCOM), Global Cyber Centers (GCC), Regional Cyber Centers (RCCs), Cyber Warfare Battalion (CWB), Multi-Domain Task Force (MDTF), Cyber Protection Brigade (CPB), and Cyber Protection Teams (CPTs) in the Active Army, Army National Guard, and the Army Reserve. Fiscal Year (FY) 2027 funding in the amount of $92.786 million supports Cyber Analytics (CA), DCO Tools Suite, User Activity Monitoring (UAM), Forensics and Malware Analysis (F&MA), DCO Development Environment (DCODE), Garrison DCO Platform (GDP), and Deployable DCO System (DDS) capabilities. Funding will be executed by Program Executive Office - Intelligence, Electronic Warfare and Sensors (CPE IEW&S). - ARCYBER Rapid Cyber Prototyping (RCP) provides software-based capabilities that can quickly respond to emerging cyber threats and keep up with threat technology, while supporting multi-Domain operations. ARCYBER identifies potential development and prototyping efforts via Cyber Needs Forms (CNFs) based on operational feedback, changes in the operational information environment and/or trends of adversarial activity, which drive concept of operation (CONOP) and Tactics Techniques and Procedures (TTPs) modifications. These are separate and distinct from DCO programmed efforts already funded or budgeted for by Project Manager (PM) DCO and are used to rapidly address a network threat/vulnerability. FY 2027 funding in the amount of $1.309 million will be executed by ARCYBER. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 8: Software and      PE 0608041A / Defensive CYBER - Software Prototype Development Digital Technology Pilot Programs$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 8.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L067$$, $$Gen Purp Elec Test Equip (GPETE)$$, $$proc_navy_1810_ba2$$, $$dw_dla$$, 2026, 0, 7905000, 7809000, NULL, $${"page": 99, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "67", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 62", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 48262, "p1_line_num": 62, "fy27_total_K": 48262}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 64901, "li_num": 62, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, 234594000, 500720000, NULL, NULL, NULL, FALSE, 32005000, 33395000, 48262000, 48262000, 0, 48262000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0608140D8Z$$, $$Enterprise Platform and Capabilities Software Pilot Program$$, $$rdte_dw_ba8$$, $$dw_osd$$, 2026, 402783000, 0, 0, NULL, $${"act": "08", "ba_raw": "6.8", "source": "r1_fy26", "service": "dw", "page_num": 82, "original_pe": "0608140D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This PE funds capabilities and activities to make disparate DoD datasets more widely accessible, understandable, interoperable, and actionable across the DoD enterprise by providing the government-owned, contractor operated enterprise data stack, analytic and AI tools, and data and AI engineering expertise to improve DoD decision making across multiple functional areas and organization levels. It includes the ability to develop, train, and support the DoD workforce to effectively leverage the data, analytics, and AI capabilities provided through Advana.$$, NULL, 508620000, 521609000, 531042000, NULL, NULL, 299, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 0, 387238000, 481775000, 481775000, NULL, 481775000, 542731000, $$This program funds capabilities and activities to make disparate DoW datasets more widely accessible, understandable, interoperable, and actionable across the DoW enterprise by providing the enterprise data stack, analytic tools, and data engineering expertise to improve DoW decision making across multiple functional areas and organization levels. Furthermore, these foundational investments are essential to enable advanced AI inference, allowing for the operational deployment of machine learning models to generate predictive insights and accelerate decision-making. This includes enhancing user platform and data, increasing the number of data sources, improving data quality, and driving enablement across the DoW workforce to effectively leverage the data and analytic capabilities provided through War Data Platform. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 8:         PE 0608140D8Z / Enterprise Platform and Capabilities Software Pilot Program Software and Digital Technology Pilot Programs$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0608231N$$, $$MARITIME TACT CMD & CONTROL - SOFT PLT PRGM$$, $$rdte_navy_ba8$$, $$navy_cno$$, 2026, 12520000, 10221000, 10289000, NULL, $${"act": "08", "ba_raw": "6.8", "source": "r1_fy26", "service": "navy", "page_num": 40, "original_pe": "0608231N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 22647000, 8944000, 9119000, NULL, NULL, NULL, NULL, NULL, FALSE, 10289000, 31827000, 25299000, 25299000, NULL, 25299000, 9287000, $$Section 872 of the National Defense Authorization Act (NDAA) for FY 2018 (P.L. 115-91) directed the Secretary of War to task the Defense Innovation Board (DIB) to undertake a study on "streamlining [the Department's] software development and acquisition regulations." The Under Secretary of War for Acquisition and Sustainment (USW(A&S)) submitted the final report to Congress in May 2019. The DIB's report made recommendations aimed at transforming the way the Department acquires, develops, and deploys software and manages digital talent. The DIB encouraged the creation of a "new appropriation category for software capability delivery that allows (relevant types of) software to be funded as a single budget item, with no separation between Research, Development, Test & Evaluation (RDT&E), production and sustainment." The recommendation stemmed from the DIB's observation that current law, regulations, and policies (including those governing program funding and appropriations) treat software acquisition and development as a series of discrete, sequential steps; and that this approach is at odds with modern software, which is continuously updated to provide new functionality. This program has been designated as a Software and Digital Technology Pilot Program by the Secretary of War. The funding in this line is requested to be used for expenses necessary for agile procurement, production, modification and operation and maintenance of the pilot program requirements. (Project 3323) Maritime Tactical Command and Control (MTC2) is a next generation Command and Control (C2) software program that delivers Battle Management Aids (BMA) and Maritime Planning Tools (MPT) to dynamically plan, direct, monitor, and assess maritime operations in support of Joint, Multi-Service, and Coalition Force planning. MTC2 will leverage a System of Services to deliver capabilities improving decision speed and dynamic synchronization of forces. BMAs / MPTs are small, capability-focused deliveries that can be rapidly developed, tested, and fielded. MTC2 engages with the Office of the Chief of Naval Operations (OPNAV) and Fleet via the Capability Requirements Council (CRC) to define and prioritize the BMAs and MPTs that MTC2 will deliver and align to the Program Executive Office (PEO) Command, Control, Communications, and Intelligence (C4I) enterprise architecture Consolidated Afloat Network Enterprise Service (CANES), Agile Core Services (ACS) and other hosting platforms for fielding to all echelons of command (Afloat and Ashore) within the Navy. The program's objective is to provide a suite of maritime applications (BMAs / MPTs) that enable planning, execution, monitoring, and assessment in support of operational, strategic, and tactical level of war requirements. MTC2 fields BMAs / MPTs designed to provide automated and structured support for tactical, strategic, and operational planning, decision-making, and execution. MTC2 incorporates distributed data transfer capability for enhanced operational data exchange between command and control systems, combat systems, logistics, and intelligence systems for timely threat identification, location, and status alongside blue force data. MTC2 is the Navy's only solution to fulfill a portion of the Joint Global Force Management - Data Initiative (GFM-DI) Allocation requirements. GFM-DI is the Department-wide enterprise solution that enables visibility/accessibility/ sharing of data applicable to the entire Department of War (DoW) force structure. MTC2 will begin to develop a containerized Web-Based Scheduling (WebSked) replacement, Employment Readiness Scheduler (EMPRESS), leveraging existing Development, Security, Operations (DevSecOps) Pipelines. EMPRESS will enable the Navy to conduct Unit Employment and Service Scheduling functions that support force readiness generation for planning/unplanning to maintain the Global Naval Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 8: Software and PE 0608231N / MARITIME TACT CMD & CONTROL - SOFT PLT PRGM Digital Technology Pilot Programs Force Presence Policy Schedule and Fleet Response Plan. MTC2 supports alignment and provides interoperability of Navy C2 with the DoW joint C2 way-forward. The program will fully align with joint C2 data and service exposure and consumption goals, architectures, and Net-Centric Enterprise Service efforts. The sustainment activities include support for evolutionary acquisition, program management, training and training events, help desk, software licenses, and sustaining MTC2 instances currently installed in the Fleet through Continuous Improvement/Continuous Delivery (CI/CD). By digitally enabling the horizontal across Joint Forces and vertical across the Echelons alignment of capabilities, the acceleration of MTC2 requirements and enablement of operational Battle Management Aids will enhance operational effectiveness during a wartime posture. MTC2 funding increased in FY 2027 and FY 2028 to support the acceleration effort for Rapid Operational Planning (OneBrief). In FY 2027, funding will be utilized for the procurement of Commercial off the Shelf (COTS) software, tools, integration, and services. In addition, in FY 2027, MTC2 will support INDOPACOM's operations across three Pacific Fleet Maritime Operations Centers (MOCs), with expansion plans to six MOCs in FY 2028. (Project 9999) This Congressional Add provides for the demonstration of a ship-integrated coaxial drone prototype for autonomous Intelligence, Surveillance and Reconnaissance (ISR). This project will integrate Command and Control (C2), rigorous on-shore testing, and a final proof-of-concept demonstration within a representative fleet operational environment. The project directly supports the Chief of Naval Operations' objectives for Joint All-Domain Command and Control (JADC2) objectives in preparation for a 2027 peer or near-peer conflict.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0608500D8Z$$, $$Weaponeering Code Sustainment$$, $$rdte_dw_ba8$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 23071000, 23071000, 23071000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 23071000, 23071000, NULL, 23071000, 23071000, $$The Department of War (DoW) relies on a multitude of mission-critical modeling and simulation (M&S) codes and tools that are utilized across the munitions, platforms and warfighter communities. This program’s mission is for the sustainment of these M&S codes to keep them functioning at appropriate levels to support key DoW mission spaces. M&S codes have been previously developed by OUSW(R&E) and DoW programs and are continuously and incrementally improved and enhanced adding new capabilities that support evolving mission criteria. Enhancements and improvements are commonly distributed in new releases and versions of the software and are increasingly more adaptable to digital engineering frameworks that enable Machine Learning (ML) and automated workflows. M&S codes enable detailed design and performance assessments, augment physical testing to improve system performance and reduce costs, and support weapons employment and mission planning. Sustainment of the M&S codes includes several activities to ensure they are functioning and executing at efficient and optimal levels. Compatibility testing of new releases to assess proper functionality on DoW systems, including within the DoW High Performance Computing ecosystem. Installation and configuration support for compatibility with DoW system requirements. Debugging and troubleshooting user problems, and direct support from the software developers for complex use cases. Developing and updating training materials for efficient implementation with users. Thorough review of the source code for new releases to ensure any sensitive content is stripped, while remaining intelligible. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 8:         PE 0608500D8Z / Weaponeering Code Sustainment Software and Digital Technology Pilot Programs$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0608648D8Z$$, $$Acquisition Visibility - Software Pilot Program$$, $$rdte_dw_ba8$$, $$dw$$, 2026, 17549000, 20572000, 17907000, NULL, $${"act": "08", "ba_raw": "6.8", "source": "r1_fy26", "service": "dw", "page_num": 82, "fy27_mand_k": 109176, "original_pe": "0608648D8Z", "page_header": "Defense-Wide", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Defense Industrial Base"}$$::jsonb, $$The FY 2026 request for Acquisition Visibility includes $17.549 thousands of discretionary and $0 thousands of mandatory (reconciliation) for a total of $17.549 thousands. Acquisition Visibility supports two distinct yet interdependent projects enabling a resilient ecosystem supporting acquisition programs across the Department of Defense (DoD): 1) Data Visibility identifies, matures, and publishes acquisition data standards (definitions and metadata) for enterprise-wide transparency and alignment and implements the Acquisition Data Strategy. Data Visibility helps to make acquisition data visible, accessible, understandable, linked, trustworthy, and interoperable. 2) The Defense Acquisition Visibility Environment (DAVE) provides data access via software applications to enable data analytics, lead the Department’s statutory reporting required by 10 USC §4372 and §4373, share authoritative data with integrated systems, including Advana , and develop, deploy, and maintain acquisition data collection for major programs' statutory reporting and performance measurement of Acquisition Pathways.$$, NULL, 91313000, 98032000, 108780000, NULL, NULL, 300, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 17251000, 17301000, 64364000, 64364000, 109176000, 173540000, 83429000, $$Acquisition Visibility supports the Department’s effort to implement Executive Order 14265 “Modernizing Defense Acquisitions and Spurring Innovation in the Defense Industrial Base.” By leveraging machine learning, artificial intelligence (AI) and other digital tools, Acquisition Visibility will rapidly and iteratively transform the Department’s acquisition digital systems and processes with an emphasis on speed, flexibility, and execution. To achieve this, Acquisition Visibility will build a joint multi-cloud enterprise digital infrastructure for hosting digital platforms and AI tools; provide data engineering, data science, and digital governance expertise to build enterprise data pipelines and develop data governance standards; develop and deploy production joint data integration platform(s) and Department-wide acquisition visibility applications(s); and operational and algorithmic test and evaluation expertise and tools. The FY 2027 request for Acquisition Visibility - Software Pilot Program includes $64,364 thousand of discretionary and $109,176 thousand of mandatory for a total of $173,540 thousand. Acquisition Visibility mandatory funding for $109,176 thousand will allow the Department to scale efforts to leverage digital and AI tools within the acquisition system to reduce administrative burden and plan acquisitions that deliver weapons faster than our adversaries. It will automate the preparation, verification, and approval processes of portfolio/program strategies to enable acquisition professionals to focus on capability delivery and mission outcomes, while simultaneously ensuring greater speed and quality. The funding will also support risk-informed and mission-based analysis and kill chain analysis for mission threads. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                              Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 8:          PE 0608648D8Z / Acquisition Visibility - Software Pilot Program Software and Digital Technology Pilot Programs$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0608775D8Z$$, $$Accelerate the Procurement and Fielding of Innovative Technologies$$, $$rdte_dw_ba8$$, $$dw_js$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 75000000, 0, 0, NULL, 0, 0, $$As directed by the National Defense Authorization Act (NDAA) FY 2025 Sec. 861, the Accelerate the Procurement and Fielding of Innovative Technologies (APFIT) program competitively selects projects in coordination with the Service Acquisition Executives and the Joint Staff. Project selection is guided by the National Defense Strategy with a focus on building enduring advantages through making the right technology investments and strengthening the resiliency and adaptability in our industrial base. APFIT conducts a merit-based, internal Department of War (DoW) process to solicit, evaluate, and select projects for $10 million - $50 million of procurement funding with priority to those provided by small businesses and non-traditional defense contractors. This program helps deliver capabilities to the Services and Agencies by providing critical procurement funding to programs with production-ready capability and a current procurement funding disconnect, thereby enabling the transition of the program across the "valley of death".$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
