INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0609346A$$, $$UAS Launched Effects Agile Development$$, $$rdte_army_ba9$$, $$army$$, 2026, 172898000, 0, 0, NULL, $${"act": "09", "ba_raw": "6.9", "source": "r1_fy26", "service": "army", "page_num": 24, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0609346A", "page_header": "Department of the Army"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0701200F$$, $$Enterprise Select Class II$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 1000000, 0, 0, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0701200F"}$$::jsonb, $$Combat Ready Airman provides resources to perform lead command roles and responsibilities and includes requirements management, test & evaluation, assurance of operational safety, suitability, effectiveness, initial acquisition, and product support management of the enterprise. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 950000, 950000, 950000, NULL, NULL, 78, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 986000, 949000, 949000, 0, 949000, 970000, $$Enterprise Select Class II (formerly Combat Ready Airman) provides resources to perform lead command roles and responsibilities and includes requirements management, test & evaluation, assurance of operational safety, suitability, and effectiveness. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0701212F$$, $$Automated Test Systems$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 30341000, 10007000, 21634000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0701212F"}$$::jsonb, $$The Automatic Test Systems (ATS) program office is responsible for developing, acquiring, delivering and sustaining ATS war-fighting capabilities for the United Stated Air Force (USAF). ATS is responsible for developing, modernizing, acquiring, and sustaining ATS to meet the user's operational needs. ATS Product Group consists of the following: Armament and Stores Avionics Electronic Warfare Software Loader/Verifier and Built-in-Test Radar and Identification Friend or Foe Specialized Automatic Test Systems Innovation and Digital Transformation Requirements for the Common Armament Tester - Fighters and the Aircraft Smart Weapon Test Set programs were combined and is not the Common Armament Tester -Fighters for FY24 through the sustainment of the programs. RDT&E (APPN 3600) funding is essential to maintain operational readiness and technological superiority for our warfighters, requiring a strategic investment in the development, modernization, and technology insertion into over 8,000 testers impacting all major commands and the Joint Force. This investment directly supports the modernization of cyber-resilient, nuclear-certified Automatic Test Systems (ATS) across a wide range of critical USAF platforms, including Armament, Bomber, Fighter/ Advanced Aircraft, Mobility, Training, ISR, and SOF, safeguarding national security and ensuring mission success. These funds will also accelerate the ATS Digital Transformation initiative, integrating Digital Engineering into legacy systems to enhance agility and responsiveness to evolving threats, ultimately improving efficiency and reducing long-term costs for the Air Force. This modernization effort is a vital component of ensuring a strong and capable military prepared to meet the challenges of the 21st century. RDT&E (APPN 3600) funds needed for development of the Common Armament Tester-Fighters (CAT-F). This tester will ensure the readiness and security of our critical fighter platforms (F-15, F-16, and potentially A-10, F-22, and F-35) which requires investment in a modernized testing infrastructure. Currently the fragmented tester environment is vulnerable to outside forces due to not being certified or kept current on needed cyber protections. This common tester would address the critical Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System           PE 0701212F / Automated Test Systems Development & Demonstration (SDD) needs to protecting critical assets across all platforms and reduce vulnerabilities of mission critical data. The development of a common, nuclear-certified, and cyber- secure Automatic Test System (ATS) tester will significantly enhance cyber security, protect sensitive data, and streamline testing processes. This solution will also reduce the logistical burden of maintaining multiple testing systems, improving the mobility and deployment capabilities of our forces. This investment will also decrease long-term sustainment costs by consolidating tester requirements and acquiring government owned data Funds will be utilized to closeout remaining contract actions for the Bomber Armament Tester (BAT) is replacing six legacy testers and combining their capabilities into one tester. The Bomber Armament Tester will support the B-2, B-1 and B-52 platforms. It will ensure the USAF bomber fleet can conduct nuclear deterrence, global power projection and global strike operations to support the President of the United States and Combatant Commanders by providing a reliable, cyber secure, and sustainable tester. The tasks are to develop a common bomber armament tester and the Test Program Sets (Software, Hardware, and Documentation) to test the armament release equipment on the bombers. RDT&E efforts support development, testing, and producibility of the Bomber Armament Tester and Test Program Sets. The program will utilize an incremental development approach with B-2 as Increment 1, B-1 as Increment 2, and B-52 as Increment 3. The Common Aircraft Portable Reprogramming Equipment (CAPRE) Secure Memory Loader Verifier (SMLV) loads operational flight programs to the weapon systems. CAPRE SMLV leads the fleet on Cyber initiatives and is government owned and developed. CAPRE SMLV supports over 45 Mission Design Series (MDS) including but not limited to A-10, B-1, B-52, C-5, C-17, C-130, CV-22, F-15, F-16, H-60 and KC-46. CAPRE SMLV is also capable of supporting future MDSs This RDT&E effort includes developing a Network Interface Module (NIM) that provides additional cyber hardening to the CAPRE system and redesigning the current CAPRE system to adapt to the NIM. Additionally this RDT&E effort includes software development for NIM interfaces and new weapons systems moving to the CAPRE system from other MLV systems. The goal is to provide one common cyber secure MLV for the Air Force to minimize cyber vulnerabilities in weapon systems. RDT&E efforts support prototype development and testing of the CAT-F and Test Program Sets. Aircraft Smart Weapons Test Set (ASWTS) has been combined with the CAT-F The legacy testers do not have the capability to check a multitude of capabilities (such as MIL-STD-1760 signal integrity) added to the Fighter aircraft through avionics and weapons upgrades. A new ASWTS is required in order to fulfill current testing requirements not covered by the legacy Aircraft Circuits Preload Test Set (ACPTS). Program will be completed in an incremental Approach: Capture all Fighter aircraft requirements, Develop F-16 capability for all blocks (3600),Develop F-15 capability (3600) and Develop A-10 capability (3600) This program element also includes program administrative cost for the Automatic Test Systems program office and funds the cost of studies and research to support the Automatic Test Systems fleet, to include digital engineering and transformation. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.303M was expended Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0701212F / Automated Test Systems Development & Demonstration (SDD) for civilian pay expenses in this program element, in FY 2025 $1.715M is forecasted for civilian, and in FY26 $2.169M is forecasted pay expenses in this 0701212F for Direct Cite Authority positions. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 10905000, 12100000, 12333000, NULL, NULL, 122, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 20962000, 29925000, 15900000, 15900000, 0, 15900000, 12581000, $$The Automatic Test Systems (ATS) program office is responsible for developing, acquiring, delivering and sustaining ATS war-fighting capabilities for the United Stated Air Force (USAF). ATS is responsible for developing, modernizing, acquiring, and sustaining ATS to meet the user's operational needs. ATS Product Group consists of the following: Armament and Stores Avionics Electronic Warfare Software Loader/Verifier and Built-in-Test Radar and Identification Friend or Foe Specialized Automatic Test Systems Innovation and Digital Transformation Requirements for the Common Armament Tester - Fighters and the Aircraft Smart Weapon Test Set programs were combined and is not the Common Armament Tester -Fighters for FY24 through the sustainment of the programs. RDT&E (APPN 3600) funding is essential to maintain operational readiness and technological superiority for our warfighters, requiring a strategic investment in the development, modernization, and technology insertion into over 8,000 testers impacting all major commands and the Joint Force. This investment directly supports the modernization of cyber-resilient, nuclear-certified Automatic Test Systems (ATS) across a wide range of critical USAF platforms, including Armament, Bomber, Fighter/ Advanced Aircraft, Mobility, Training, ISR, and SOF, safeguarding national security and ensuring mission success. These funds will also accelerate the ATS Digital Transformation initiative, integrating Digital Engineering into legacy systems to enhance agility and responsiveness to evolving threats, ultimately improving efficiency and reducing long-term costs for the Air Force. This modernization effort is a vital component of ensuring a strong and capable military prepared to meet the challenges of the 21st century. RDT&E (APPN 3600) funds needed for development of the Common Armament Tester-Fighters (CAT-F). This tester will ensure the readiness and security of our critical fighter platforms (F-15, F-16, and potentially A-10, F-22, and F-35) which requires investment in a modernized testing infrastructure. Currently the fragmented tester environment is vulnerable to outside forces due to not being certified or kept current on needed cyber protections. This common tester would address the critical Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System           PE 0701212F / Automated Test Systems Development & Demonstration (SDD) needs to protecting critical assets across all platforms and reduce vulnerabilities of mission critical data. The development of a common, nuclear-certified, and cyber- secure Automatic Test System (ATS) tester will significantly enhance cyber security, protect sensitive data, and streamline testing processes. This solution will also reduce the logistical burden of maintaining multiple testing systems, improving the mobility and deployment capabilities of our forces. This investment will also decrease long-term sustainment costs by consolidating tester requirements and acquiring government owned data Funds will be utilized to closeout remaining contract actions for the Bomber Armament Tester (BAT) is replacing six legacy testers and combining their capabilities into one tester. The Bomber Armament Tester will support the B-2, B-1 and B-52 platforms. It will ensure the USAF bomber fleet can conduct nuclear deterrence, global power projection and global strike operations to support the President of the United States and Combatant Commanders by providing a reliable, cyber secure, and sustainable tester. The tasks are to develop a common bomber armament tester and the Test Program Sets (Software, Hardware, and Documentation) to test the armament release equipment on the bombers. RDT&E efforts support development, testing, and producibility of the Bomber Armament Tester and Test Program Sets. The program will utilize an incremental development approach with B-2 as Increment 1, B-1 as Increment 2, and B-52 as Increment 3. The Common Aircraft Portable Reprogramming Equipment (CAPRE) Secure Memory Loader Verifier (SMLV) loads operational flight programs to the weapon systems. CAPRE SMLV leads the fleet on Cyber initiatives and is government owned and developed. CAPRE SMLV supports over 45 Mission Design Series (MDS) including but not limited to A-10, B-1, B-52, C-5, C-17, C-130, CV-22, F-15, F-16, H-60 and KC-46. CAPRE SMLV is also capable of supporting future MDSs This RDT&E effort includes developing a Network Interface Module (NIM) that provides additional cyber hardening to the CAPRE system and redesigning the current CAPRE system to adapt to the NIM. Additionally this RDT&E effort includes software development for NIM interfaces and new weapons systems moving to the CAPRE system from other MLV systems. The goal is to provide one common cyber secure MLV for the Air Force to minimize cyber vulnerabilities in weapon systems. RDT&E efforts support prototype development and testing of the CAT-F and Test Program Sets. Aircraft Smart Weapons Test Set (ASWTS) has been combined with the CAT-F The legacy testers do not have the capability to check a multitude of capabilities (such as MIL-STD-1760 signal integrity) added to the Fighter aircraft through avionics and weapons upgrades. A new ASWTS is required in order to fulfill current testing requirements not covered by the legacy Aircraft Circuits Preload Test Set (ACPTS). Program will be completed in an incremental Approach: Capture all Fighter aircraft requirements, Develop F-16 capability for all blocks (3600),Develop F-15 capability (3600) and Develop A-10 capability (3600) This program element also includes program administrative cost for the Automatic Test Systems program office and funds the cost of studies and research to support the Automatic Test Systems fleet, to include digital engineering and transformation. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System       PE 0701212F / Automated Test Systems Development & Demonstration (SDD) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2025 1.842M was expended for civilian pay expenses in this program element, in FY 2026 2.169M is forecasted to pay expenses in this 0701212F for Direct Cite Authority positions. In direct support of SecDefs direction to increase readiness across the DoD, efforts within this PEC will be prioritized based on the National Defense Authorization Act (NDAA), USAF Force Design, Agile Combat Employment (ACE), and the Defense Planning Guide (DPG) These efforts will support work and collaboration efforts across the Combat Readiness Directorate in PE's 0708051F, 0701212F, 0702833F, 0604706F, 0605827F, 0202834F, 0502834F, 0208031F, 0401135F and 0207521F) -- to increase readiness across the Air Force Enterprise. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0702207N$$, $$Depot Maintenance (NON-IF)$$, $$rdte_navy_ba7$$, $$peo_tacair$$, 2026, 23372000, 18010000, 28799000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0702207N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 7119000, 3581000, 2273000, NULL, NULL, NULL, NULL, NULL, FALSE, 26752000, 23372000, 8097000, 8097000, NULL, 8097000, 2314000, $$3030: A significant portion of the F/A-18 and EA-18G airframe is believed to have additional inherent capability and a life extension is possible for many portions of the airframe. The F/A-18 and EA-18G Service Life Assessment Program (SLAP) is assessing the structural and subsystem conditions of the F/A-18 and EA-18G fleet in order to determine what modifications are necessary to extend the aircraft design life limits to allow it to achieve Chief of Naval Operations (CNO) inventory requirements. This effort is required to be conducted for these airframes and subsystems to ascertain what actions and modifications must be taken to safely operate each system beyond its designed life until the targeted end of service life. Without SLAP and the follow-on Service Life Extension Program (SLEP), aircraft are retired from the USN inventory when a design service life metric is reached. RDTE funds will support aircraft teardown to validate SLAP analysis, identify unknown fatigue areas and assess the aircraft's material condition. 3182: The T-45 aircraft structure is currently fatigue limited to 13,300 flight hours based on initial full-scale fatigue tests. Studies demonstrate that the 13,300-flight hour service life can be extended, with a Service Life Extension Program (SLEP), to 19,800 flight hours, which will support meeting IPP until 2035. A T-45 Structural Service Life Assessment Program (SLAP) was completed in February 2012. In order for the T-45 to meet IPP, it is also necessary to assess the subsystems of the T-45 in their ability to remain viable. In FY13 an initial subsystem assessment, based on the updated fleet aircraft usage spectrum and future predicted training missions of the T-45 aircraft, found 79 dispositions requiring further analysis, teardowns, age explorations, recertification and/or testing. The assessment of the subsystems that make up these 79 dispositions will address all critical subsystems required and their ability to maintain IPP/NTR until 2035, analysis and studies will be conducted to outline improvements, assess manufacturing capabilities, prototype redesign and test of subsystems for trainer aircraft. 3384: MH-60 SLAP is assessing the primary aircraft structure and subsystem condition of the MH-60 fleet in order to evaluate the airframe's ability to meet its designed service life of 10,000 hours. SLAP will determine the efforts necessary to extend the aircraft design life limits to meet CNO operational inventory requirements through FY 2050. The highest flight time MH-60S helicopters are expected to exceed the design life limit in 2027, at which time as many as 30 aircraft per year could be removed from flight status without a SLAP and follow-on SLEP directly impacting Combat Logistics, Surface Warfare (SUW), Combat Search and Rescue (CSAR), Naval Special Warfare (NSW) Support, Airborne Mine Countermeasures (AMCM), and operational capabilities and capacity. The highest flight time MH-60R helicopters are expected to exceed the design life in 2034. MH-60 SLAP is comprised of two distinct assessments: investigative inspections and analysis of fleet assets, which will identify current trends that either prohibit the MH-60 from reaching its design life or the required life based on operational inventory requirements; and forward-looking analysis, which will identify future risks not yet realized on fleet assets. These assessments will consider the fatigue life of airframe structure as well as the health of aircraft subsystems. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                    Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational             PE 0702207N / Depot Maintenance (NON-IF) Systems Development The airframe structural assessment consists of investigations of the cockpit beams, main gearbox beams/frames, upper deck, engine mount, lower tub, main landing gear, tail landing gear, cargo hook, transition splice and tie-down fittings/structure, tailcone, tail gearbox, intermediate gearbox, stabilator, manufactured joints/splices, and flight controls support structure. The aircraft subsystems assessment will evaluate wiring, engines, rotor brake, hydraulic, flight controls, avionics components and infrastructure, etc., to identify over-and-above inspections, overhaul intervals or replacement schedules to fly beyond the current design limit assumption. Analysis will be further refined, augmented with aircraft, specific system and wiring teardowns, inspections, and tests; data analysis; and development of models and tools, producing results that will continue inform SLEP ECP development. Engineering for design/development will ramp for Engineering Change Proposals (ECPs) for a phased SLEP solution. 9999: The industry partner, in conjunction with F-35 Maintenance PMO office, will focus activities in several unique areas intended to improve inter and intra F-35 services, partners and original equipment manufacturing data interoperability as well as organic F-35 data capture and data security. Topic areas include but are not limited to sustainment data interoperability, sustainment data storage, sustainment data flow, physical aircraft data capture and interoperability of data between the F-35 Joint Programming Office (JPO) information systems and U.S. Department of War (DoW) organic depot-level maintenance activities. The team will focus its efforts on the following main subject matters: 1. F-35 Maintenance PMO Data Interoperability Software (DIS) Zero Trust Architecture (ZTA) Analysis 2. Development of JEDI-X Propulsion Limited Technical Demonstrator at Fleet Readiness Center East (FRCE) 3. Low-Rate Initial Production (LRIP) Program Manager Reporting Tool - Fleet Readiness Center Southeast (FRCSE) JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0702806F$$, $$Acquisition and Management Support$$, $$rdte_af_ba6$$, $$dw_osd$$, 2026, 22670000, 24436000, 25216000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0702806F"}$$::jsonb, $$The program funds efforts to meet the Defense Acquisition Workforce Improvement Act (DAWIA), as well as Congressional, SECDEF, and SECAF mandates to provide program management execution tools, systems integration and architectural analysis, information technology infrastructure development, and technical workforce management. Funding also provides the framework for Air Force business and acquisition transformation in developing capabilities-based architectures, re-engineering and enabling technologies, integrating robust systems engineering into early acquisition processes, acquisition process improvement analysis, and developing and managing a technical workforce with the expertise to uniformly implement OSD and Air Force engineering guidance and policies. These efforts provide stability in Air Force Acquisition by integrating major processes to reverse trends toward unpredictable program cost, schedule, and performance to facilitate quick response to urgent operational needs from across the entire spectrum of potential conflicts. These integrated capabilities will provide OSD and AF acquisition leadership insights needed to effectively manage a complex portfolio of acquisition programs through more timely and reliable access to authoritative acquisition data. The Air Force is refocusing a number of science and technology concept explorations in artificial intelligence (AI) across command, control, communications, sensor, and intelligence areas within PE 0602788F, Dominant Information Sciences and Methods, and PE 0602204F, Aerospace Sensors, to improve and accelerate the delivery of artificial intelligence warfighting capabilities under the direction of both the Vice Chief of Staff of the Air Force and the Assistant Secretary of the Air Force (Acquisition, Technology & Logistics) and exercised through the Air Force Capability Development Council. The Air Force will now perform these science and technology concept explorations under this Program Element as the Air Force continues to respond to and reflect 1) the vision outlined for Artificial Intelligence in the 2018 National Defense Strategy, 2) expectations outlined by the February 2019 White House Executive Order on Artificial Intelligence and the United States Department of Defense (DoD) Artificial Intelligence Strategy, 3) initiatives by other Armed Services to create AI-centric organizations, 4) Senior Air Force leadership goals to develop Artificial Intelligence applications for the United States Air Force in the near term, and 5) senior Department of Defense leadership objectives to enrich and strengthen the broader Air Force and Department Artificial Intelligence ecosystem to impact national security. Additionally, this program supports Great Power Competition through an enterprise decision-making forum with proper authorities and oversight to ensure product support decisions are informed from an AF enterprise perspective to efficiently leverage resources and optimize support to the warfighter at an enterprise level. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E     PE 0702806F / Acquisition and Management Support Management Support 0606398F. In FY24 0M was expended for civilian pay expenses in this program element, and in FY25 0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 12442000, 12695000, 12953000, NULL, NULL, 145, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 19823000, 25359000, 12132000, 12132000, 0, 12132000, 13085000, $$The program funds efforts to meet the Defense Acquisition Workforce Improvement Act (DAWIA), as well as Congressional, SECDEF, and SECAF mandates to provide program management execution tools, systems integration and architectural analysis, information technology infrastructure development, and technical workforce management. Funding also provides the framework for Air Force business and acquisition transformation in developing capabilities-based architectures, re-engineering and enabling technologies, integrating robust systems engineering into early acquisition processes, acquisition process improvement analysis, and developing and managing a technical workforce with the expertise to uniformly implement OSD and Air Force engineering guidance and policies. These efforts provide stability in Air Force Acquisition by integrating major processes to reverse trends toward unpredictable program cost, schedule, and performance to facilitate quick response to urgent operational needs from across the entire spectrum of potential conflicts. These integrated capabilities will provide OSD and AF acquisition leadership insights needed to effectively manage a complex portfolio of acquisition programs through more timely and reliable access to authoritative acquisition data. The Air Force is refocusing a number of science and technology concept explorations in artificial intelligence (AI) across command, control, communications, sensor, and intelligence areas within PE 0602788F, Dominant Information Sciences and Methods, and PE 0602204F, Aerospace Sensors, to improve and accelerate the delivery of artificial intelligence warfighting capabilities under the direction of both the Vice Chief of Staff of the Air Force and the Assistant Secretary of the Air Force (Acquisition, Technology & Logistics) and exercised through the Air Force Capability Development Council. The Air Force will now perform these science and technology concept explorations under this Program Element as the Air Force continues to respond to and reflect 1) the vision outlined for Artificial Intelligence in the 2018 National Defense Strategy, 2) expectations outlined by the February 2019 White House Executive Order on Artificial Intelligence and the United States Department of Defense (DoD) Artificial Intelligence Strategy, 3) initiatives by other Armed Services to create AI-centric organizations, 4) Senior Air Force leadership goals to develop Artificial Intelligence applications for the United States Air Force in the near term, and 5) senior Department of Defense leadership objectives to enrich and strengthen the broader Air Force and Department Artificial Intelligence ecosystem to impact national security. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY25 0M was expended for civilian pay expenses in this program element, and in FY26 0M is forecasted for civilian pay expenses in this program element. Approximately 300K in FY27 was saved in the "acquisition mandates" program as a result of Executive Order #14222 by eliminating a research requirement for Potomac Institute for Policy Studies and reducing reporting by the contractor for a RAND contract. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E       PE 0702806F / Acquisition and Management Support Management Support This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0708012K$$, $$Logistics Support Activities$$, $$rdte_dw_ba7$$, $$dw_disa$$, 2026, 2876000, 1420000, 1406000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 81, "original_pe": "0708012K", "page_header": "Defense-Wide"}$$::jsonb, $$The Distributed Continuity Integrated Network – Top Secret Enterprise Services (DCIN-TS ES) is a Department of Defense (DoD) continuity of operations and continuity of government decision-support collaboration environment that facilitates decision making among principals and staff. Available in Fixed, Transportable, and Mobile configurations; functions on air, ground, rail, and sea platforms.$$, NULL, 2087000, 2136000, 2180000, NULL, NULL, 283, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 1406000, 2876000, 2051000, 2051000, NULL, 2051000, 2180000, $$The Distributed Continuity Integrated Network – Top Secret Enterprise Services (DCIN-TS ES) is a Department of War (DoW) continuity of operations and continuity of government decision-support collaboration environment that facilitates decision making among principals and staff. Available in Fixed, Transportable, and Mobile configurations; functions on air, ground, rail, and sea platforms.$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0708012S$$, $$Pacific Disaster Center Risk Analytics and Readiness$$, $$rdte_dw_ba7$$, $$dw_dla$$, 2026, 2000000, 3762000, 6361000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 81, "original_pe": "0708012S", "page_header": "Defense-Wide"}$$::jsonb, $$The Pacific Disaster Center (PDC) is a public/private partnership managed by the University of Hawaii under a cooperative agreement with the Department of Defense. It is functionally within the organization of the Office of the Under Secretary of Defense (Policy) (OUSD(P)) as Principal Staff Assistant (PSA) and Defense Logistics Agency (DLA) for program management. The PDC is a world-recognized authority and leader in science and information technology applications relating to humanitarian assistance and disaster relief (HA/DR), including real-time assessments, predictive analysis, and disaster risk reduction. PDC develops new and innovative technologies and services, operating an (unclassified) integrated multi-hazard monitoring, early warning, and decision support system, called DoD RAPIDS, for the Department. PDC also provides advanced analytics leveraged by the Department for strategic planning, risk intelligence, impact modeling, strategic competition, and critical asset protection.$$, NULL, NULL, NULL, NULL, NULL, NULL, 284, $$RDTE_DLA_PB_2026.pdf$$, $$DLA$$, FALSE, 6129000, 9500000, 0, 0, NULL, 0, NULL, $$The Pacific Disaster Center (PDC) Risk Analytics and Readiness program is a public/private partnership managed by the University of Hawaii under a cooperative agreement with the DoW. It is functionally within the organization of the Office of the Under Secretary of War(Policy) (OUSW(P)) as Principal Staff Assistant (PSA) and Defense Logistics Agency (DLA) for program management. The PDC is a world-recognized authority and leader in science and information technology applications relating to humanitarian assistance and disaster relief (HA/DR), including real-time assessments, predictive analysis, and disaster risk reduction. PDC develops new and innovative technologies and services, operating an (unclassified) integrated multi-hazard monitoring, early warning, and decision support system, called DoW RAPIDS, for the Department. PDC also provides advanced analytics leveraged by the Department for strategic planning, risk intelligence, impact modeling, strategic competition, and critical asset protection. Since FY 2022, there have been annual congressional adds under the program element specifically for the (separate and unrelated) Global Water Security Center (GWSC) to develop and provide the DoW with a range of unclassified analytical products in support of water security and mission assurance priorities. In FY 2026, funding was provided under the PDC program element specifically for the (separate and unrelated) Logistics Support Activity (LSA) - Reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report.$$, $$Budget J-Books/FY27/Remaining/RDTE_DLA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0708045A$$, $$End Item Industrial Preparedness Activities$$, $$rdte_army_ba7$$, $$dw_cbdp$$, 2026, 67002000, 118797000, 87187000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 23, "original_pe": "0708045A", "page_header": "Department of the Army"}$$::jsonb, $$This Program Element (PE) develops, demonstrates, and transitions manufacturing technologies and processes that enable improvements in producibility and affordability of emerging and enabling components and subsystems of Army ground and air platforms, Soldier systems, weapons systems, air and missile defense systems, as well as sensors and electronics. Initiatives within the PE result in cost savings and reduced risk of transitioning military-unique manufacturing processes into production. Project E25 fosters the transfer of new/improved manufacturing technologies to the industrial base, including manufacturing efforts that have potential for high payoff across the spectrum of Army systems. Work in this PE is performed by United States (U.S.) Army laboratories and research centers, U.S. Army Program Executive Offices and Program Management Offices, and U.S. Army depots and arsenals. Project teams are comprised of both Science and Technology (S&T) Subject Matter Experts (SME) and Program of Record (PoR) technical leads to develop the efforts, execute the efforts, and develop the acquisition plans for incorporating the technology into the PoR upon successful evaluation. The FY 2026 request was reduced by $0.147 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 68790000, 69305000, 69985000, NULL, NULL, 237, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 84752000, 90842000, 68097000, 68097000, NULL, 68097000, 70683000, $$This Program Element (PE) funds the Army Manufacturing Technology (ManTech) program, which develops, demonstrates, and transitions manufacturing technologies and processes that enable improvements in producibility and affordability of components and subsystems of Army weapon platforms and systems. Army ManTech matures technologies from Manufacturing Readiness Level (MRL) 4, which is the capability of producing the technology in a laboratory environment, up to MRL 7, which is the capability of producing systems, subsystems, or components in a production-relevant environment. Army ManTech streamlines the development and insertion of mature manufacturing technologies that support ground and air maneuver; fires; command-and-control (C2) and counter-C2 (CC2); agile sustainment and ammunition; and layered protection plus chemical, biological, radiological, and nuclear defense (CBRND). In doing so, Army ManTech supports Secretary of War and Secretary of the Army Acquisition Reform efforts, resulting in cost savings and reduced transition risk of military-unique manufacturing processes into production. Project E25 fosters the transfer and rapid incorporation of innovative manufacturing technologies to the industrial base, including manufacturing efforts that have potential for high payoff across the spectrum of Army systems. Work in this PE is performed by United States (U.S.) Army program acquisition executives, laboratories and research centers, and depots and arsenals. Project teams comprised of both technology subject matter experts (SME) and Acquisition Program lead the development and execution of the efforts in alignment with program of record (PoR) acquisition plans.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0708047S$$, $$Enterprise Logistics Management System (ELMS)$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 3020000, 3130000, 3004000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 81, "original_pe": "0708047S", "page_header": "Defense-Wide"}$$::jsonb, $$The Defense Property Accountability System (DPAS) provides the Department an asset accountability system which is fully compliant with financial reporting regulations and has a clean audit history. With an integrated accountability, utilization, maintenance, and warehouse capability, DPAS provides the Department an enterprise solution for asset management.$$, NULL, 2895000, 2973000, 3032000, NULL, NULL, 285, $$RDTE_DLA_PB_2026.pdf$$, $$DLA$$, FALSE, 2894000, 3020000, 2829000, 2829000, NULL, 2829000, 3099000, $$The Enterprise Logistics Management System (ELMS), formerly known as Defense Property Accountability System (DPAS), provides the Department an asset accountability system which is fully compliant with financial reporting regulations and has a clean audit history. With an integrated accountability, utilization, maintenance, and warehouse capability, DPAS provides the Department an enterprise solution for asset management.$$, $$Budget J-Books/FY27/Remaining/RDTE_DLA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0708051F$$, $$Rapid Sustainment Modernization (RSM)$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 32666000, 78431000, 50044000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0708051F"}$$::jsonb, $$The Rapid Sustainment Modernization program provides funding to accelerate the delivery of critical technologies to improve readiness and reduce sustainment costs. The Rapid Sustainment Office (RSO) will develop, test, and deploy new technologies for implementation across the Department of the Department of the Air Force (DAF) enterprise. The RSO will achieve this by reaching across the enterprise to include the warfighter, depot maintenance, field maintenance, supply chain, and program offices to identify enterprise needs. The RSO will then identify, assess, develop, validate, and verify new technology projects that support these areas. The Technology Focus Areas are Advanced Manufacturing (Additive Manufacturing/Coldspray), Artificial Intelligence/ Machine Learning (AI/ML), to include but not limited to Condition Based Maintenance Plus (CBM+), RSM Technologies, to include Data and Digital Engineering, Automation/Robotics, Augmented and Virtual Reality, and Rapid and Austere Environments. New technologies in these areas are evaluated in support of the DAF enterprise. Funding in this PE will be used in agile processes to support development activities to rapidly respond to emergent requirements from the DAF enterprise in the year of execution to include but not limited to addressing Diminishing Manufacturing Sources and Material Shortages, reducing unscheduled weapons system maintenance, and enabling maintenance capabilities in austere environments. This PE may fund studies of new technologies to determine applicability to DAF requirements. This program element may include necessary civilian pay expenses and emergent or unanticipated civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2025 up to $5.086 million is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. This requirement supports performance of full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0708051F / Rapid Sustainment Modernization (RSM) Component Development & Prototypes (ACD&P)$$, NULL, 26393000, 26893000, 27405000, NULL, NULL, 79, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 48361000, 45918000, 27475000, 27475000, 0, 27475000, 27957000, $$The Rapid Sustainment Modernization (RSM) program objective is to rapidly modernize sustainment practices, enhancing readiness and cutting costs by identifying, assessing, developing, validating, verifying, and deploying cutting-edge technologies across the sustainment enterprise. This program achieves this by proactively engaging stakeholders across the spectrum, from warfighters to depot and field maintenance teams, supply chains, and program offices, to pinpoint critical enterprise needs. In direct support of the Secretary of War direction to increase readiness across the Department of War, efforts within this PEC will be prioritized based on the National Defense Authorization Act (NDAA), USAF Force Design, Agile Combat Employment (ACE), and the Defense Planning Guide (DPG). These efforts will support work and collaboration efforts across the Combat Readiness Directorate in PEs 78051F, 71212F, 72833F, 64706F, 65827F, 22834F, 52834F, 28031F, 41135F and 27521F to increase readiness across the Air Force enterprise. The program maintains flexibility to adapt to the rapidly evolving technology landscape, pivoting technical areas and solutions as requirements, warfighter needs, and resource environments change. Advanced Manufacturing Program Office (AMPO) leverages innovative technologies to create superior products, refine existing ones, and cultivate advanced production capabilities. This strengthens manufacturing quality and processes, providing warfighters with a distinct competitive advantage. The Advanced Manufacturing (AdvM) program develops additive and other advanced manufacturing capabilities to produce tools, jigs, fixtures, and aircraft components, thereby mitigating diminishing manufacturing sources, addressing material shortages, and accelerating part procurement lead times. Repair Additive Manufacturing (RAM) technologies enhance maintenance capabilities, minimize downtime, and boost operational efficiency. Furthermore, the program develops deployable AdvM and RAM capabilities for contested environments, enabling on-demand parts and tools at the point of need, along with on-site and aircraft-side repair capabilities. Automation and Robotics (A&R) efforts focus on hazardous environments, material handling, and repair, assembly, and test systems. Robotic Laser Paint Removal systems exemplify this, eliminating the need for human presence in hazardous and confined spaces. Expeditionary Combat Technologies (ECT) develops and delivers deployable structures, power and water generation tools, logistics tools to reduce logistics footprints, and enhance Airmen mission effectiveness in expeditionary and austere environments. Prototyping across these areas facilitates the integration and demonstration of emerging technologies, accelerating their transition into warfighter capabilities through iterative development and increased utilization of commercial technology. Digital Architectures and Capabilities (DAC) is comprised of Conditioned Based Maintenance Plus (CBM+), Digital Materiel Management (DMM), and Maintenance Digital Ecosystem (MxDE). Conditioned Based Maintenance Plus is a collaborative Department of War readiness initiative centered on data analysis to transition unscheduled to scheduled maintenance, driving mission readiness improvements. It employs a failure management/data-driven decisions strategy to perform predictive/proactive maintenance, leveraging Artificial Intelligence/Machine Learning (AI/ML) capabilities to identify evidence of need to perform maintenance. Sensor based algorithms leverage AI/ML to transform onboard sensor data into component degradation detection alerts, enabling decision advantage. Predictive Analytics Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0708051F / Rapid Sustainment Modernization (RSM) Component Development & Prototypes (ACD&P) and Decision Assistant (PANDA) serves as the enterprise AI/ML software platform for data analytics and visualization. Digital Materiel Management is a materiel management ecosystem powered by Always Guaranteeing Operationally Ready Aircraft (AGORA), a cloud-based ecosystem of enterprise AdvM and DMM engineering software capabilities that enable Department of Air Force (DAF) stakeholders to leverage AdvM technologies to solve supply chain challenges and improve aircraft readiness, AM Innovation Hub is a cloud-based platform for innovation and collaboration, facilitating the sharing of AM projects and files, SEEKR is a tool that provides program offices the ability to identify viable part candidates, and Part Assessment and Cost Tool (PACT) provides a decision support framework, helping program offices assess the feasibility of using additive manufacturing (AM) technologies to overcome complex supply chain problems. The MxDE leverages Lighthouse Integration Technology Engine (LITE) to integrate developmental, operational, and legacy Air Force Logistics information technology (IT) platforms within a hub-and-spoke framework modernizing USAF systems enabling disparate data to be displayed through a single pane of glass, driving decision advantage. Funding in this PE supports agile development activities that rapidly address emergent requirements from the DAF enterprise during the year of execution. These may include addressing Diminishing Manufacturing Sources and Material Shortages, reducing unscheduled weapons system maintenance, and enabling maintenance capabilities in austere environments. The program may fund studies of new technologies to determine their applicability to DAF requirements. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F This requirement supports performance of full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0708610F$$, $$Logistics Information Technology (LOGIT)$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 18581000, 20682000, 11895000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0708610F"}$$::jsonb, $$The AF requires an integrated logistics capability that provides timely, accurate and reliable information to decision makers at all levels of command and across the full range of military operations. Log IT is a portfolio of programs that currently addresses Transformation, Remediation, and Modernization of Operational Systems. Transformation focuses on transforming the Logistics IT enterprise to a more efficient, cost-effective integrated IT infrastructure. Remediation entails modifying operational Logistics software systems to address congressionally-mandated Financial Improvement & Audit Readiness requirements and remediating critical IT risks. Modernization concentrates on software upgrades for operational systems to increase functional capabilities, reduce sustainment costs, meet statutory IT compliance requirements and improve user performance. Transformation: - The AF must transform its logistics business processes and transition away from using numerous custom stovepipe systems and processes that perform similar tasks. Eliminating process redundancies across the logistics enterprise will enable the AF to execute more secure, resilient, efficient, cost-effective and integrated logistics. The objective of transformation is to conduct Business Process Re-engineering (BPR) to identify and eliminate overlaps in business processes across core logistics systems and, where appropriate, implement new IT systems that employ best commercial practices and modern cloud-based architectures. - The AF will take full advantage of the flexibilities provided by DoDI 5000.75, Business Systems Requirements and Acquisition guidance, as well as Agile development methodologies to identify requirements across the spectrum of Doctrine, Organization, Training, Materiel, Leadership and Education, Personnel, Facilities and Policy (DOTMLPF-P); and to acquire and deploy approved material solutions in the most efficient and effective manner possible utilizing the 5-phased Business Capability Acquisition Cycle (BCAC). The BCAC phases are structured to optimize a joint responsibility of functional and acquisition activities, leading to the successful delivery of the business capability. There will be an emphasis placed on acquisition of business systems aligned to commercial best practices utilizing commercial off-the shelf (COTS), government off-the-shelf (GOTS) solutions, and modern platforms that support continuous integration and continuous deployment (CI/CD) following a development, security, and operations (DevSecOps) methodology. - The AF logistics enterprise is comprised of multiple overarching functional areas, to include base and depot-level maintenance, end-to-end supply chain management, and predictive analysis and forecasting. The AF will standardize its business processes within each major logistics functional area through Transformational Capability Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                   PE 0708610F / Logistics Information Technology (LOGIT) Operational Systems Development Initiatives (TCIs). These TCIs include, but are not limited to: Maintenance, Repair and Overhaul Initiative (MROi PE 0708055F), Foundational Logistics Information Technology Enterprise System (FLITES), Supply Capability Initiative, Air Force Product Lifecycle Management Capability Initiative (AF-PLM), and Field Maintenance Capability Initiative. There may be one or more specific initiatives aligned to each of the major CI areas referenced above. Transformation Capability Initiatives (TCI): - TCI Foundational Logistics Information Technology Enterprise System (FLITES) provides the capability to manage comprehensive, accurate, reliable item master data (e.g., accurate identification and authorization of owners and users of items). FLITES is a key component of the Air Force (AF) Logistics Capability Transformation Plan. It will provide Item standardization and configuration management from a single authoritative source, ensuring foundational logistics processes are executed in concert to support the A4 logistics baseline. It will enable key integration and transformation capabilities, including Item Unique Identification (IUID) association to business transactions; streamlined management of part item attributes across supply, finance, engineering, technology, transportation, maintenance, and vendor communities; and provide translation capabilities between functional and technical business communities and systems. - TCI Supply Capability Initiative is focused on enabling simplified, standardized processes to fundamentally enhance the business operations and provide total asset visibility across the supply chain. These improvements have been identified in the USAF Logistics Capabilities Transformation Plan. • Procurement: Encompasses all business functions necessary to obtain goods (both inventory and expense) and services, sourced internally and externally through strategic partnerships with Trading Partners. • Order Management: Encompasses all business functions necessary to accept and process customer orders (internal/external) for services and/or inventory held for sale or internal consumption. • Inventory Management: Encompasses all business functions necessary to establish and manage inventory for all types of items (repairable, consumable, expense items and other low cost items) including Air Force owned inventory and other items that are sent to the Air Force for repair (Foreign Military Sales and other Services). • Asset Management: Encompasses all business functions necessary to establish in-use accountability and life-cycle management of capital, centrally managed, and local purchased assets. • Financial Management: Encompasses all accounting functions necessary to record and produce auditable financial statements (for GF and WCF) - TCI Field Maintenance Logistics Capability Initiative (LCI) will improve the AF field maintenance capabilities across the Mission Generation Network (MGN) and Repair Network (RN) functionalities supports USAF Strategic Master Plan, Vector 1: Provide Effective 21st-Century Deterrence and Vector 3: Ensure a Full-Spectrum Capable, High-End Focused Force. It also directly supports the future vision of Air Force maintenance being divided between Mission Generation, which takes place on the flight line, and repair networks that provides support to Mission Generation as outlined in the 2015-2025 Enterprise Logistics Flight Plan (ELFP). MGN will address the cumulative effort required to launch, recover, configure, inspect and repair aircraft. It includes activities covering the planning, scheduling and execution of aircraft preparation and maintenance to support sortie production and is predominantly accomplished in an on-equipment environment. MGN and RN will standardize processes where appropriate, allowing for optimization of resources, enhanced visibility of assets, reduced rework, reduced variability, improved documentation and configuration management, all allowing for more rapid and informed decision-making at the base and enterprise level. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0708610F / Logistics Information Technology (LOGIT) Operational Systems Development - Funds will be used to perform studies, analysis, assessments, and innovative integration efforts for common technology capabilities such as cloud migration, technology development and mobile applications that cross and support all of the aforementioned initiatives. Remediation and Modernization: - Remediation and modernization of core logistics systems is necessary for the AF to meet statutory Financial Improvement Audit Readiness (FIAR) requirements and align with the Joint Chiefs of Staff J-4 Concept for Logistics, and the AF Portfolio Board's approved Logistics Flight Plan. Concurrently, the AF sustain and modify identified logistics systems to achieve FIAR remediation by the statutory deadline; execute software upgrades to reduce high operating costs and meet evolving operational demands; implement statutory compliance requirements; improve system performance; and enable system consolidation efforts that lower the cyber threat space and reduce long-term portfolio costs. - Identified systems include, but are not limited to, the Integrated Logistics System-Supply (ILS-S), Enhanced Technical Information Management System (ETIMS), Integrated Maintenance Data System (IMDS), and Reliability and Maintainability Information System (REMIS). Additional logistics systems may be included as financial audits are completed and system consolidation efforts mature. - This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0.424M was expended for civilian pay expenses in this program element, and in FY2025 0.560M is forecasted for civilian pay expenses in this program element. - This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute, and deliver Logistics IT Systems for emergent or unanticipated weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0505829F. - The FY 2026 request for Logistics Information Technology (LOGIT) includes $18.581 million of discretionary for a total of $18.581 million. - This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0708610F / Logistics Information Technology (LOGIT) Operational Systems Development$$, NULL, 21904000, 23408000, 25193000, NULL, NULL, 283, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 11665000, 18326000, 21518000, 21518000, 0, 21518000, 27152000, $$- LOGIT is a portfolio of programs enabling the DAF logistics enterprise including aircraft maintenance, base-level supply operations, and the authoritative source for all DAF items for aircraft and vehicles. The DAF logistics enterprise is currently comprised of disparate, antiquated, stovepiped systems and processes leaving logistics operations inefficient, costly, and vulnerable. The goal of this portfolio is to modernize the logistics IT enterprise for a more efficient, cost-effective, integrated, standardized, and resilient suite of systems. These systems will also incorporate the latest in cybersecurity measures and meet the statutory IT compliance requirements including Financial Improvement and Audit Readiness (FIAR). The DAF logistics enterprise is comprised of multiple overarching functional areas to include field-level maintenance, end-to-end supply chain management, and DAF item cataloging and provisioning. The current programs within this PE include: Enhanced Technical Information Management System (ETIMS), Foundational Logistics Information Technology Enterprise System (FLITES), Supply Capability Initiative (SCI), Integrated Logistics System-Supply (ILS-S), Enterprise Logistics Management System (ELMS), and Field Maintenance (Field Mx). - ETIMS is the system of record for all Technical Orders (TOs) and fully integrates electronic TOs (eTOs) supporting enterprise-wide distribution and viewing along with print-on-demand services. This system supports over 178K users across 385 sites worldwide. ETIMS is set to subsume multiple systems and capabilities terminating duplicate capabilities and achieving statutory IT requirements and FIAR compliance. The development efforts for ETIMS were completed in FY2025. - FLITES provides the capability to manage comprehensive, accurate, reliable item master data (e.g., accurate identification and authorization of owners and users of items). FLITES provides item standardization and configuration management from a single authoritative source ensuring foundational logistics processes are executed in concert to support the A4 logistics baseline. It enables key integration and transformation capabilities including Item Unique Identification (IUID) association to business transactions; streamlined management of part attributes across supply, finance, engineering, technology, transportation, maintenance, and vendor communities; and provide translation capabilities between functional and technical business communities and systems. - SCI is focused on modernizing the business processes and fundamentally enhancing supply operations and provide total asset visibility across the supply chain. These improvements have been identified in the DAF Logistics Capabilities Transformation Plan targeting improvements to manual processes in requisitioning, order management, item cataloging, inventory management, asset management, financial management, and supply chain analytics. This supports the DAF achieving total asset visibility at the base retail level enabling intelligent, data-driven decision-making based on accurate supply chain information. This initiative will drive base-level Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0708610F / Logistics Information Technology (LOGIT) Operational Systems Development supply enhancements in support of financial tracking of general funds and audit readiness. The efforts in SCI identified requirements for development efforts within the supply enterprise which will be met through modernization and capability upgrades in ILS-S and ELMS. - ILS-S is the current DAF Retail Supply System for Classes 2 (organizational equipment such as gear and tools) & 9 (repair parts including engines and aircraft components) for Base Level Users. ILS-S is used to manage procurement, order management, inventory management, asset management and all financial business operations supporting all accounting functions for auditability. - ELMS is a DLA program and the established DoW Joint system for retail supply Class 7 (major end items including large scale equipment such as vehicles, missile systems, etc.) items for base level users. ELMS is used to manage procurement, order management, inventory management, asset management and all financial business operations supporting all accounting functions for auditability. ELMS is currently in use and will be upgraded to meet DAF requirements. - Field Maintenance (Field Mx) is the software system for conducting maintenance operations in the field providing functionalities including planning, scheduling and execution of aircraft maintenance and sortie production. These efforts entail developing a classified Maintenance Information System (MIS) for the Nuclear Command, Control, and Communications (NC3) enterprise. These efforts also support providing effective deterrence, and ensuring a full-spectrum capable, high-end focused force. The development efforts will improve the DAF field maintenance capabilities across the Mission Generation Network (MGN) and Repair Network (RN) functionalities. The modernization of MGN will address the cumulative effort required to launch, recover, configure, inspect and repair aircraft. MGN and RN will standardize processes where appropriate, allowing for optimization of resources, enhanced visibility of assets, reduced rework, reduced variability, improved documentation and configuration management, all allowing for more rapid and informed decision-making at the base and enterprise level. - This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. - This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0708610F / Logistics Information Technology (LOGIT) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0708730N$$, $$Maritime Tech (MARITECH)$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 3600000, 3155000, 4326000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0708730N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 4100000, 3858000, 3281000, NULL, NULL, NULL, NULL, NULL, FALSE, 4156000, 3600000, 1710000, 1710000, NULL, 1710000, 3340000, $$The Advanced Shipyard Technology (AST) seeks to improve the productivity, quality, and reduce costs of maintenance performed by the Navy public shipyards. The resulting technologies developed by this program benefit both the naval shipyard and the US Navy.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0801380F$$, $$AF LVC Operational Training (LVC-OT)$$, $$rdte_af_ba7$$, $$aflcmc_hb$$, 2026, 33898000, 21423000, 27535000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0801380F"}$$::jsonb, $$The Air Force Live Virtual Construct Operational Training (AF LVC-OT) program develops and supports modeling and simulation software used within USAF operational training and exercises. LVC-OT directly improves Joint and USAF core warfighter readiness by ensuring training and mission rehearsal activities are realistic, readily available, and interoperable with other related training and simulation programs. The LVC-OT program includes two complementary and interrelated projects: Project 674567, Modeling & Simulation Foundations, develops and supports a software tool named Air, Space and Cyberspace Collaborative Environment - Information Operations Suite (ACE-IOS). This software is a federation of constructive models to simulate intelligence, surveillance, and reconnaissance (ISR), electronic warfare (EW), information operations (IO), and cyber Effects on combat operations during training and exercises. The program supports multiple training tiers, to include Joint Task Force commanders, Combatant Commanders' battle staff, and the USAF intelligence schoolhouse. Project 675135, Warfighter Readiness, develops and supports a software tool named Command & Control Simulation Environment for Training (C2SET). This software simulates air and space power for training Air and Space Operations Center (AOC) personnel and Combatant Commanders' battle staffs. Due to concurrent AOC modernization, C2SET replaces the legacy Air Force Modeling and Simulation Training Toolkit (AFMSTT) in FY 2026, due to the legacy AFMSTT's outdated capabilities and inoperability with the modernized AOC weapon system. Projects under the LVC-OT program support DoD's training transformation, Joint National Training Capability (JNTC), and USAF priorities and core functions. Activities include studies and analysis to support both program planning, execution, and future program planning. LVC-OT provides the training and mission rehearsal in realistic operational environments required to prepare our warfighters for the full range of military operations and maintain the combat readiness levels required by Combatant Commanders. Live, Virtual, and Constructive integration efforts provided under LVC-OT are a critical piece to the USAF's implementation of the Strategic Plan for Transforming DoD Training. This program is part of the overarching Kessel Run portfolio and is leveraging the All Domain Common Platform (ADCP). The ADCP provides an extensible cloud based infrastructure and platform as a service (IaaS/PaaS) hosting platform built to deliver highly resilient mission applications and data to Airmen deployed around the world. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0801380F / AF LVC Operational Training (LVC-OT) Operational Systems Development The FY 2026 request was reduced by -$0.162 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 1.050 million was expended for civilian pay expenses in this program element, and in FY 2025 1.425 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 24257000, 24742000, 25209000, NULL, NULL, 284, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 23987000, 33478000, 23472000, 23472000, 0, 23472000, 25716000, $$The Air Force Live Virtual Construct Operational Training (AF LVC-OT) program develops and supports modeling and simulation software used within USAF operational training and exercises. LVC-OT directly improves Joint and USAF core warfighter readiness by ensuring training and mission rehearsal activities are realistic, readily available, and interoperable with other related training and simulation programs. The LVC-OT program includes two complementary and interrelated projects: Project 674567, Modeling & Simulation Foundations, develops and supports a software tool named Air, Space and Cyberspace Collaborative Environment - Information Operations Suite (ACE-IOS). This software is a federation of constructive models to simulate intelligence, surveillance, and reconnaissance (ISR), electronic warfare (EW), information operations (IO), and cyber Effects on combat operations during training and exercises. The program supports multiple training tiers, to include Joint Task Force commanders, Combatant Commanders' battle staff, and the USAF intelligence schoolhouse. Project 675135, Warfighter Readiness, develops and supports a software tool named Command & Control Simulation Environment for Training (C2SET). This software simulates air and space power for training Air and Space Operations Center (AOC) personnel and Combatant Commanders' battle staffs. C2SET replaced the legacy Air Force Modeling and Simulation Training Toolkit (AFMSTT) in FY 2026, due to the legacy AFMSTT's outdated capabilities and inoperability with the modernized AOC weapon system. Projects under the LVC-OT program support DoW's training transformation, Joint National Training Capability (JNTC), and USAF priorities and core functions. Activities include studies and analysis to support both program planning, execution, and future program planning. LVC-OT provides the training and mission rehearsal in realistic operational environments required to prepare our warfighters for the full range of military operations and maintain the combat readiness levels required by Combatant Commanders. Live, Virtual, and Constructive integration efforts provided under LVC-OT are a critical piece to the USAF's implementation of the Strategic Plan for Transforming DoW Training. This program is part of the overarching Kessel Run portfolio and is leveraging the All Domain Common Platform (ADCP). The ADCP provides an extensible cloud based infrastructure and platform as a service (IaaS/PaaS) hosting platform built to deliver highly resilient mission applications and data to Airmen deployed around the world. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0801380F / AF LVC Operational Training (LVC-OT) Operational Systems Development Efforts within this program align with and depend upon USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (PE 0207410F), All Domain Common Platform (0303248F), Command and Control Incident Management Emergency Response Application (C2IMERA) (0305836F). Advanced Battle Management System (ABMS) (0604003F) and Flight Ops (PE 0207461F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. This program's efforts directly provide the development, infrastructure, and support necessary for each of these programs and TAP-SoS interdependencies, which provides the capabilities necessary for deliberate planning, dynamic mission replanning, friendly order of battle management, and mission tasking and execution. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2025 0.955 million was expended for civilian pay expenses in this program element, and in FY 2026 0.500 million is forecasted for civilian pay expenses in this program element. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0804743F$$, $$Other Flight Training$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 2371000, 2182000, 1159000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0804743F"}$$::jsonb, $$Other Flight Training (OFT) program provides systems and data sources for recording and managing aircrew training information, aircrew/parachutist management, flying hour tracking, flight pay management, and flying gate tracking for 60,000 Air Force members. The Air Force uses this information to enhance safety-of-flight operations and to determine eligibility to perform aviation related events. OFT includes Aviation Resource Management System (ARMS), which will sunset in FY 2025 and be replaced by a new cloud-based, Aviation Resource Tool Enterprise Mission Information System (ARTEMIS). ARTEMIS will provide common architecture across multiple programs/applications yielding real-time analytics for aircrew, missileer and parachutist training, readiness, and electronic flying hours reports covering 65,000 Aircrew/Parachutists and used by 2,800 1C0X2 Career Field members with 2.2 million transactions per week. New development work is required to provide additional flying operations information to ensure Air Force readiness and interface this data into Defense Readiness Reporting System Strategic (DRRS-S). These enhanced capabilities, to be developed incrementally, include the following but not limited to electronic flight record, flying hour management/execution, simulator and RPA management/utilization, full career logbook, training look-back, aircrew member man-month allocation, enhanced resource and jump module management, and additional interfaces. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                  Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0804743F / Other Flight Training Operational Systems Development$$, NULL, 754000, 768000, 784000, NULL, NULL, 285, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 1116000, 2338000, 1950000, 1950000, 0, 1950000, 799000, $$Other Flight Training (OFT) program provides systems and data sources for recording and managing aircrew training information, aircrew/parachutist management, flying hour tracking, flight pay management, and flying gate tracking for over 68,000 Air Force members to enhance safety-of-flight operations and to determine eligibility to perform aviation related events. The OFT program includes the Aviation Resource Tool Enterprise Management Information System (ARTEMIS) effort, an on-line information system for base-level Deputy Commanders for Operations. ARTEMIS, which replaced the legacy Aviation Resource Management System (ARMS) that sunset in FY 2025, is a cloud-based system providing a common architecture to effectively support the implementation of Air Force flight management policies specified in AFI 11-401 and AFI 11-402. It ensures the accurate tracking of flying and ground training programs and delivers real-time analytics and operations management information for aircrew, missileer, and parachutist training and readiness. Covering over 68,000 aircrew/parachutists and used by 2,800 1C0X2 Career Field members with 2.2 million transactions per week, ARTEMIS provides operations managers with immediate visibility into flying program status, enabling effective resource allocation decisions and robust support for weapon systems requirements. Funding provides continuing developmental efforts that will focus on both the sustainment and continued development of ARTEMIS to enhance adoption and ensure Air Force readiness. Ongoing sustainment activities include minimizing system downtime, resolving escalated issues, maintaining security compliance, improving data quality and architecture for enterprise reporting, sustaining integrations with other Operations Enterprise Architecture (Ops EA) initiatives, and executing feature enhancements to improve the user experience. Concurrently, developmental efforts will provide additional flying operations information and interface this data into the Defense Readiness Reporting System Strategic (DRRS-S). These enhanced capabilities will be developed incrementally and include, but are not limited to, an electronic flight record, flying hour management, simulator and Remote Piloted Aircraft (RPA) management, a full career logbook, training look-back, aircrew member man-month allocation, enhanced resource and jump module management, and additional interfaces. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0804743F / Other Flight Training Operational Systems Development This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0804768J$$, $$Joint Training, Exercise and Evaluation Program (JTEEP)$$, $$rdte_dw_ba6$$, $$dw_dtic$$, 2026, 91952000, 53097000, 131021000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0804768J", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 101593000, 94508000, 98035000, NULL, NULL, NULL, NULL, NULL, FALSE, 128160000, 98303000, 90424000, 90424000, NULL, 90424000, 97894000, $$These programs support readiness of the joint force by creating a joint training environment to replicate the complex and changing operational environment. These investments directly support defense strategic guidance, Joint Operational Training Infrastructure strategy, and enhance joint warfighting readiness by building training capabilities that support the operational readiness of the joint force. The elements associated with this coordinated effort consist of: JNTC: The mission of the Joint National Training Capability (JNTC) program is to advance joint capabilities and interoperability by concentrating on emerging joint training requirements through collective training using a managed set of globally distributed capabilities and activities. The program resources Service and Special Operations Forces joint training to improve interoperability and create realistic tactical and operational joint training. JNTC enables joint training for Combatant Commands and Services by developing joint training content and ensuring global distributed access. JNTC enabling capabilities support Services and USSOCOM requirements to provide trained and ready joint forces in support of Combatant Command operational requirements. The program supports the Joint Operational Training Infrastructure (JOTI). This program focuses efforts on improving readiness and creates a ready surge force that is consistent with the Chairman’s guidance Exhibit R-2, RDT&E Budget Item Justification: PB 2027 The Joint Staff                                                                         Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:                 PE 0804768J / Joint Training, Exercise and Evaluation Program (JTEEP) RDT&E Management Support and will provide the means to train joint forces for the operationalization of the Joint Warfighting Concept. This program also supports the operationalization of the Joint Warfighting Concept by addressing emerging joint training requirements and enabling interoperability across all domains. JKDDC: Joint Knowledge Development & Distribution Capability (JKDDC) Joint Knowledge Online (JKO) is the program of record for online joint training that implements and operationalizes the OSW training transformation JKDDC. JKO directly supports the JTEEP program by developing, delivering, tracking, reporting, and supporting online training for Combatant Command exercises; Combatant Command required training; doctrinally based Joint Operations Core Curriculum; multinational, coalition, interagency training; OSW required training; and administration of the Senior Enlisted Joint Professional Military Education program. JKO utilizes RDT&E funding for leading edge technology review, market research, and integration to directly enhance various aspects of the training capability required to support Combatant Commanders, JTEEP program objectives, and the Chairman's joint training guidance. JKO ensures all requirements are met to provide JTEEP stakeholders with a distributed learning capability, offering persistent global access to web-based training content, learning resources, and distributed online training tools. Air Force Joint National Training Center (JNTC): Air Force JNTC funding provides a focused upgrade to develop models for space-based and cyber capabilities for integration into the Joint Live, Virtual, and Constructive (JLVC) environment as well supporting development of cross-domain solutions. Additionally, the Air Force invests in development of capabilities to enhance the rigor and fidelity of training for live and virtual members of joint training audiences. This funding request is crucial for integrating adversary C2, IADS models, and accurate hardware and software sub-components into cyber and EW ranges. It will support weapon system development, testing, training, TTP development, exercising, and mission rehearsal. Additionally, the integration of hypersonic weapons/vehicles into Joint events using the Digital Integrated Air Defense System (DIADS) will enhance realism and readiness. The introduction of target sets called "Threat Representative Networks (TRNs)" will enable the translation of effects generated by cyber and EW weapon system live fires into the exercise battle space. The unique challenges posed by hypersonic vehicles, including their unpredictability, maneuverability, and short detection/tracking distances, require specialized modeling and defense capabilities. DIADS will be utilized to model red hypersonic vehicle interceptors, enhancing the Joint community's ability to address this emerging threat. The addition of red sensors and the integration of Hypersonic Air Defense Effectiveness and Survivability (HADES) will expand DIADS' capabilities. This extension aims to incorporate hypersonic air defense into exercises, ensuring Joint forces are prepared to engage blue platforms and address the challenges posed by hypersonic threats. Navy JNTC: These funds enable Navy to develop unique maritime capabilities that integrate JLVC elements into a seamless joint training environment. The Navy program activities include conducting research, development, and integration of a common, realistic, joint and partner nation, operational-to- level training architecture to deliver individual and collective constructive joint training for use in Fleet Synthetic Training (FST) events, Ballistic Missile Defense Exercises (BMDEX) certification events, CCMD exercises, and BMD-at-Sea training events in support of CCDR’s training, deployment certification and operational requirements. Joint Staff Live, Virtual and Constructive Modernization: This funding supports the Department's priorities to defend the homeland, deter strategic attacks and aggression, prevail in conflict, build enduring advantage, and build a resilient and ready joint force and defense eco system. China has greatly increased the urgency for realism of joint training using JLVC to improve readiness and interoperability, unearth operational weaknesses to train a joint force to key operational problems. The Joint Live, Virtual and Constructive (JLVC) Modernization project seeks out, develops, and integrates training technologies to provide a reliable, realistic, relevant, repeatable, and recordable training environment to train joint warfighters to successfully execute operational plans (OPLANs). Through analysis driven by a threat-informed China task force study in 2022, the Joint force lacks the training enterprise capability and technical architecture required to provide all-domain, high-end training for global operations. Aligned with the 2026 National Defense Strategy, JLVC Modernization is critical to ensure the Department of War (DoW) can close joint operational training Exhibit R-2, RDT&E Budget Item Justification: PB 2027 The Joint Staff                                                                      Date: April 2026 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:                 PE 0804768J / Joint Training, Exercise and Evaluation Program (JTEEP) RDT&E Management Support gaps, provide a key enabler for the Pacific Multi-Domain Training and Experimentation Capability, provide training for advanced systems that cannot be realistically trained in live environments, provide training for future capabilities the force must be prepared to employ, and to build the readiness of a more lethal force. To meet this objective, the JLVC Modernization project performs the following activities: • Exploit new technologies and leverage industry advances in equipment, modeling and simulation, and networks support the joint training enterprise • Expedite the transition and integration of new training technologies (simulations, network, range integration) from Services, Industry, and Academic environments to the joint training enterprise • Establish data standards to enable the transition to a data-centric architecture, aligned to CJADC2, ensuring consistency and provide ‘analytics-ready’ data to support all domain training; implement Joint LVC interoperability standards to enable all domain joint force training across LVC training ranges • Develop and integrate a fully-informed (Program to S/REL) Space, Cyber, Electromagnetic Spectrum (EMS), and 5th/6th Gen synthetic capabilities for the joint training enterprise • Work with CCMDs and Services to optimize existing service programs while beginning to develop Next Generation simulations and simulators that are inherently interoperable across warfighting and security domains • Advance the use of innovative applications of Artificial Intelligence for scenario generation, dynamic threat, smart opposing force (OPFOR), and after-action review (AAR) for the joint training enterprise Additionally, the JLVC Modernization project examines emerging joint training requirements resulting from new operational concepts, wargames, experiments, and exercises to identify training technology needs and develop a long-range roadmap for technology insertion into the joint training enterprise. The project leverages and employs applicable applied research efforts from the highly developed technology base in the DoW/DOE laboratories, Service System Engineering Centers, test and evaluation centers, other Government agencies, and industry to accelerate development and integration of new training capabilities. The project outreaches and engages Academia to address joint training technology challenges in DoW. This program provides travel funds for JLVC Modernization project oversight, special studies, analyses, and strategic planning related to modernization of training capabilities and infrastructure.$$, $$Budget J-Books/FY27/Remaining/RDTE_TJS_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0804772F$$, $$Training Developments$$, $$rdte_af_ba5$$, $$aetc$$, 2026, 5067000, 1248000, 4960000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0804772F"}$$::jsonb, $$Training Developments is one part of the Pilot Training Transformation (PTT) program initiative to modernize pilot training, improve both quality and quantity of pilots —through implementing advanced technology and up-to-date instructional techniques. Training Developments program harvests cutting edge technology to provide a faster, more cost effective and more comprehensive training model to get the warfighter to the cockpit in half the time. Training Developments will utilize new training technologies to develop effective processes and procedures to increase pilot production, improve and streamline existing training programs that will directly aid AETC's flying training enterprise to address the USAF Pilot Shortage. In 2018, as part of this initiative, Air Education and Training Command (AETC) launched the Pilot Training Next (PTN) program in an effort to produce more pilots in less time at a reduced cost. Located at Randolph Air Force Base, TX, Detachment 24, PTN explores technological and instructional innovations designed to improve upon Specialized Undergraduate Pilot Training (SUPT). Detachment 24 trained small groups of students using experimental syllabi. In 2018, the first class of 13 students graduated from a 24-week course and trained 41 students over three different experimental classes. Like SUPT, PTN graduates received a basic aeronautical rating and went to follow-on training in airframes like the F-35/F-16 fighter aircraft and C-17 cargo aircraft. In 2022, AETC adopted the innovations tested at Detachment 24 and launched a new pilot training syllabus at the all major pilot training bases. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                             Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System    PE 0804772F / Training Developments Development & Demonstration (SDD)$$, NULL, 5050000, 5144000, 5241000, NULL, NULL, 123, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 4778000, 8198000, 4947000, 4947000, 0, 4947000, 5347000, $$Training Developments program is part of Pilot Training Transformation (PTT) program initiative to modernize pilot training, improve both quality and quantity of pilots through implementing advanced technology and up-to-date instructional techniques. In 2018, as part of this initiative, Air Education and Training Command (AETC) launched the Pilot Training Next (PTN) program in an effort to produce more pilots in less time at a reduced cost. PTN explores technological and instructional innovations designed to improve upon Specialized Undergraduate Pilot Training (SUPT) at Located at Randolph Air Force Base, TX, Detachment 24. PTN program train small groups of students using experimental syllabi, and in 2018, the first class of 13 students graduated from a 24-week course. PTN graduates receive a basic aeronautical rating and go to follow-on training in airframes like the F-35/F-16 fighter aircraft and C-17 cargo aircraft. In 2022, innovations tested at Detachment 24 were adopted and AETC launched a new pilot training syllabus at the all major pilot training bases. Training Developments program harvests cutting edge technology to provide a faster, more cost effective and comprehensive training model to get the warfighter in the cockpit in half the time. Training Developments program will utilize new training technologies to develop effective processes and procedures to increase pilot production, improve and streamline existing training programs that will directly aid AETC's flying training enterprise to address the Air Force's pilot shortage. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System    PE 0804772F / Training Developments Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0804776F$$, $$Advanced Distributed Learning$$, $$rdte_af_ba6$$, $$aetc$$, 2026, 1698000, 0, 828000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0804776F"}$$::jsonb, $$TECHNICAL TRAINING MANAGEMENT SYSTEM [TTMS]: TTMS provides AETC organizations with a world class commercial-off-the-shelf [COTS] / government- off-the-shelf [GOTS] learning management system which supports six functions: course design and development; student evaluation; instructor management; student management; data analysis; and resource administration. TTMS is a centralized web-based system which provides productivity enhancements and higher degree of efficiency to AETC. The primary requirement objectives currently under development are: 1] Integration of Basic Training Management System [BTMS] capabilities and student records into the TTMS. Prior to FY25 these efforts were funded by to PE 0804731F, General Skill Training This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 286000, 334000, 327000, NULL, NULL, 146, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 797000, 1675000, 238000, 238000, 0, 238000, 136000, $$TECHNICAL TRAINING MANAGEMENT SYSTEM (TTMS): TTMS provides the Air Education and Training Command (AETC) organizations with a world class commercial-off-the-shelf (COTS) / government-off-the-shelf (GOTS) learning management system which supports six functions: course design and development; student evaluation; instructor management; student management; data analysis; and resource administration. TTMS is a centralized web-based system which provides productivity enhancements and higher degree of efficiency to AETC. The primary requirement objectives currently under development are: 1) Integration of Basic Training Management System (BTMS) capabilities and student records into the TTMS. Prior to FY25 these efforts were funded by to PE 0804731F, General Skill Training This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0808709SE$$, $$Defense Equal Opportunity Management Institute (DEOMI)$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 388000, 740000, 315000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0808709SE", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 315000, 388000, 0, 0, NULL, 0, 0, $$DEOMI's mission is to foster cultures of excellence through learning, research, and integrated knowledge management to optimize total force readiness. To accomplish this mission, DEOMI uses RDT&E funds to conduct Management Support. This includes: • Research and analysis to inform advanced learning technologies, training methodologies, and modalities, competency models, learning objectives, human relations job-aids, publications, and recommendations for improvements. • Studies on human relations topics to understand how human relations, organizational performance, team performance, and other related topics impact individuals, units, organizations and their performance to enhance learning outcomes. • DEOMI’s Summer Science, Technology, Engineering, and Mathematics (STEM) program (e.g., Office of Naval Research programs), partnerships with the Military Service Academies, and other formal and informal collaborations with external academic, research, and government agencies across the world. Together, these initiatives ensure DEOMI fields up-to-date training programs and deploys cutting-edge training and support technologies/materials across the DoW. This is required by Executive Orders 13111 and 13218, which mandate all federal agencies to take full advantage of technological advances to educate and train the workforce, to ensure employees acquire the skills and learning needed to succeed in a changing workplace, and to report on the training technologies used. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 DoD Human Resources Activity                                                      Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:           PE 0808709SE / Defense Equal Opportunity Management Institute (DEOMI) RDT&E Management Support$$, $$Budget J-Books/FY27/DW/RDTE_DHRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0808736F$$, $$Special Victim Accountability and Investigation$$, $$rdte_af_ba4$$, $$dw_osd$$, 2026, 1997000, 0, 3006000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0808736F"}$$::jsonb, $$This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0 was expended for civilian pay expenses in this program element, and in FY2025 0 is forecasted for civilian pay expenses in this program element. Funds moved from PE 808737F to this PE (808736F) beginning in FY25. This is not a new start. Following completion of a Presidentially-directed Independent Review Committee (IRC) on Sexual Assaults for the Department of Defense, the Secretary of Defense (SECDEF) directed the implementation of multiple IRC recommendations. The Integrated Prevention PE contains two programs in support of those recommendations: The Air Force Office of Special Investigations (OSI), Records, Investigations and Operations Network (ORION) program and the Interpersonal Self-Directed Violence (ISDV) Prevention program. Air Force Office of Special Investigations (OSI), Records, Investigations and Operations Network (ORION): The Department of the Air Force (DAF) Office of Special Investigations (OSI) is DAF's sole felony-level criminal investigative agency mandated to investigate criminal offenses, to include sexual offenses and interpersonal violence. IRC recommendations C2, C3, C4, 1.8, 2.6a, 3.1, and 3.3a, directed the DAF to increase its ability to collect, analyze, and integrate data related to sexual offenses and interpersonal violence to inform and guide prevention and response. The DAF will develop and deploy the OSI Investigations, Operations, and Records Network (ORION) information system as to satisfy SECDEF requirements. In tandem with the context above, another key driver for development of ORION is the DAF's requirement to identify a central case management system solution to allow for more effective oversight of and more efficient execution of the DAF's criminal indexing process. ORION will be a cloud-based, next-generation case management system used to document, manage, store, and report criminal investigative and counterintelligence information involving violations of the Uniform Code of Military Justice and the United States Code. ORION will serve as OSI's central mission application capable of Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0808736F / Special Victim Accountability and Investigation Component Development & Prototypes (ACD&P) ensuring sexual assaults, intimate partner violence, violent extremism, service-member deaths, and dozens of other crimes are properly investigated and recorded. ORION will be used by over 3,000 OSI personnel including nearly 2,000 federally-credentialed Special Agents at OSI's 300+ global operating locations. ORION will enable the DAF to modernize criminal indexing processes both operationally and technologically. Operationally, ORION will reduce redundancy, streamline processes, encourage standardization, and decrease administrative burden. The DAF is exploring options to use ORION to replace other systems and enable data transfer to other stakeholders with the goal to increase integration and productivity and avoid duplicative data entry. ORION could also be leveraged to be placed on one or more Special Access Programs (SAP) networks to become a system of record for OSI investigative and security support to DAF SAP programs. Technologically, ORION leverages the affordability, scalability, security, and services provided by cloud computing. Additionally, ORION will be mobile-ready, enabling agents to securely access and document investigative data from mobile devices whenever and wherever needed, thereby increasing efficiency and reducing delays. Lastly, ORION will be built on a low-code/no-code enterprise platform which enables the rapid development, deployment, and sustainment of capability. The DAF is considering options to leverage ORION and its enterprise low-code/no-code platform for other DAF case management and/or business process management requirements. Such a platform, operated and sustained at the enterprise level, has potential to yield cost savings, operational enhancements, and technical efficiencies as well as reduce DAF overheard. With ORION serving as the initial application, the case management platform could promote the expedited development, deployment, and sustainment of future case management systems at economies of scale. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 1651000, 1649000, 1680000, NULL, NULL, 80, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 3023000, 1970000, 1652000, 1652000, 0, 1652000, 1712000, $$This program